'use client'

import { useState, useEffect, Suspense } from 'react'
import { createClient } from '@/lib/supabase/client'
import { useRouter, useSearchParams } from 'next/navigation'
import type { UserRole } from '@/lib/types/database.types'

type AuthTab = 'email' | 'phone'
type AuthMode = 'login' | 'register'
type OtpStep = 'phone' | 'code'

const REGISTER_ROLES = [
  { value: 'admin_global', label: 'Directeur / Admin' },
  { value: 'professeur', label: 'Professeur' },
  { value: 'surveillant', label: 'Surveillant Général' },
  { value: 'parent', label: 'Parent d\'élève' },
]

const ERROR_MESSAGES: Record<string, string> = {
  suspended: 'Votre compte a été suspendu. Contactez l\'administration.',
  no_profile: 'Aucun profil trouvé. Contactez l\'administration.',
}

const DEMO_ROLES = [
  { role: 'admin_global', label: 'Directeur / Admin', icon: '👨‍💼', route: '/admin', desc: 'Tableau de bord complet, finances, gestion' },
  { role: 'professeur', label: 'Professeur', icon: '👨‍🏫', route: '/professeur', desc: 'Notes, pointage GPS, cahier de texte' },
  { role: 'surveillant', label: 'Surveillant Général', icon: '🛡️', route: '/surveillant', desc: 'Suivi temps réel, absences, alertes' },
  { role: 'parent', label: 'Parent d\'élève', icon: '👩‍👧', route: '/parent', desc: 'Bulletins, paiements, absences' },
]

export default function LoginPage() {
  return (
    <Suspense fallback={
      <div className="min-h-screen bg-[#0A0E27] flex items-center justify-center">
        <div className="text-slate-400">Chargement...</div>
      </div>
    }>
      <LoginContent />
    </Suspense>
  )
}

function LoginContent() {
  const [tab, setTab] = useState<AuthTab>('email')
  const [mode, setMode] = useState<AuthMode>('login')
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState('')
  const [success, setSuccess] = useState('')
  const router = useRouter()
  const searchParams = useSearchParams()

  // Email/Password state
  const [email, setEmail] = useState('')
  const [password, setPassword] = useState('')

  // Register state
  const [nom, setNom] = useState('')
  const [prenom, setPrenom] = useState('')
  const [telephone, setTelephone] = useState('')
  const [registerRole, setRegisterRole] = useState('parent')
  const [confirmPassword, setConfirmPassword] = useState('')

  // Phone OTP state
  const [phone, setPhone] = useState('')
  const [otpCode, setOtpCode] = useState('')
  const [otpStep, setOtpStep] = useState<OtpStep>('phone')

  const supabase = createClient()

  const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL ?? ''
  const isSupabaseConfigured = supabaseUrl.length > 0
    && !supabaseUrl.includes('placeholder')
    && !supabaseUrl.includes('[PROJECT_REF]')

  // Afficher erreur depuis query params (middleware redirect)
  useEffect(() => {
    const errorParam = searchParams.get('error')
    if (errorParam && ERROR_MESSAGES[errorParam]) {
      setError(ERROR_MESSAGES[errorParam])
    }
  }, [searchParams])

  // Mode démo : login par sélection de rôle
  const handleDemoLogin = (role: string, route: string) => {
    localStorage.setItem('ss_demo_role', role)
    router.push(route)
  }

  // Après auth réussie, récupérer le rôle et rediriger
  const redirectByRole = async () => {
    const { data: { session } } = await supabase.auth.getSession()
    if (!session) {
      setError('Échec de connexion')
      setLoading(false)
      return
    }

    const { data } = await supabase
      .from('utilisateurs')
      .select('*')
      .eq('id', session.user.id)
      .single()

    const utilisateur = data as { role: UserRole; actif: boolean } | null

    if (!utilisateur) {
      setError('Aucun profil trouvé. Contactez l\'administration.')
      setLoading(false)
      return
    }

    if (!utilisateur.actif) {
      setError('Votre compte a été suspendu. Contactez l\'administration.')
      await supabase.auth.signOut()
      setLoading(false)
      return
    }

    const roleRoutes: Record<string, string> = {
      admin_global: '/admin',
      surveillant: '/surveillant',
      professeur: '/professeur',
      eleve: '/eleve',
      parent: '/parent',
    }

    router.push(roleRoutes[utilisateur.role] || '/login')
  }

  // Login Email/Password
  const handleEmailLogin = async (e: React.FormEvent) => {
    e.preventDefault()
    setLoading(true)
    setError('')

    const { error } = await supabase.auth.signInWithPassword({ email, password })
    if (error) {
      setError(error.message === 'Invalid login credentials'
        ? 'Email ou mot de passe incorrect'
        : error.message)
      setLoading(false)
      return
    }

    await redirectByRole()
  }

  // Inscription
  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault()
    setLoading(true)
    setError('')
    setSuccess('')

    if (password !== confirmPassword) {
      setError('Les mots de passe ne correspondent pas')
      setLoading(false)
      return
    }

    if (password.length < 6) {
      setError('Le mot de passe doit contenir au moins 6 caractères')
      setLoading(false)
      return
    }

    if (!nom.trim() || !prenom.trim()) {
      setError('Le nom et le prénom sont obligatoires')
      setLoading(false)
      return
    }

    // 1. Créer le compte auth
    const { data: authData, error: authError } = await supabase.auth.signUp({
      email,
      password,
    })

    if (authError) {
      setError(authError.message === 'User already registered'
        ? 'Un compte existe déjà avec cet email'
        : authError.message)
      setLoading(false)
      return
    }

    if (!authData.user) {
      setError('Erreur lors de la création du compte')
      setLoading(false)
      return
    }

    // 2. Récupérer l'école par défaut (première école active)
    const { data: ecoleData } = await (supabase.from('ecoles') as any)
      .select('id')
      .eq('actif', true)
      .limit(1)
      .single() as { data: { id: string } | null }

    // 3. Créer le profil utilisateur
    const { error: profileError } = await (supabase.from('utilisateurs') as any).insert({
      id: authData.user.id,
      ecole_id: ecoleData?.id || null,
      nom: nom.trim(),
      prenom: prenom.trim(),
      telephone: telephone.trim() || null,
      role: registerRole,
      actif: true,
    })

    if (profileError) {
      setError('Compte créé mais erreur lors de la création du profil : ' + profileError.message)
      setLoading(false)
      return
    }

    setSuccess('Compte créé avec succès ! Vous pouvez maintenant vous connecter.')
    setMode('login')
    setPassword('')
    setConfirmPassword('')
    setNom('')
    setPrenom('')
    setTelephone('')
    setLoading(false)
  }

  // Envoyer OTP SMS
  const handleSendOtp = async (e: React.FormEvent) => {
    e.preventDefault()
    setLoading(true)
    setError('')

    let formattedPhone = phone.replace(/\s/g, '')
    if (formattedPhone.startsWith('0')) {
      formattedPhone = '+221' + formattedPhone.substring(1)
    } else if (!formattedPhone.startsWith('+')) {
      formattedPhone = '+221' + formattedPhone
    }

    const { error } = await supabase.auth.signInWithOtp({ phone: formattedPhone })
    if (error) {
      setError(error.message)
      setLoading(false)
      return
    }

    setPhone(formattedPhone)
    setOtpStep('code')
    setLoading(false)
  }

  // Vérifier OTP
  const handleVerifyOtp = async (e: React.FormEvent) => {
    e.preventDefault()
    setLoading(true)
    setError('')

    const { error } = await supabase.auth.verifyOtp({
      phone,
      token: otpCode,
      type: 'sms',
    })

    if (error) {
      setError('Code incorrect ou expiré')
      setLoading(false)
      return
    }

    await redirectByRole()
  }

  return (
    <>
    {/* Bande tricolore sénégalaise */}
    <div className="fixed top-0 left-0 right-0 h-1 flex z-50">
      <div className="flex-1 bg-[#00853F]" />
      <div className="flex-1 bg-[#FDEF42]" />
      <div className="flex-1 bg-[#E31B23]" />
    </div>
    <div className="min-h-screen relative flex items-center justify-center px-4 overflow-hidden bg-[#020617]">
      {/* ── Vidéo background login ── */}
      <div className="absolute inset-0 z-0">
        <video
          autoPlay
          muted
          loop
          playsInline
          className="w-full h-full object-cover object-center"
        >
          <source src="/Vidéo/bg-login.mp4" type="video/mp4" />
        </video>
        {/* Overlay sombre pour lisibilité du formulaire */}
        <div className="absolute inset-0 bg-gradient-to-br from-[#020617]/92 via-[#020617]/80 to-[#0B1120]/90" />
        {/* Grain cinématique */}
        <div className="absolute inset-0 opacity-[0.03]"
          style={{ backgroundImage: 'url("data:image/svg+xml,%3Csvg viewBox=\'0 0 256 256\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cfilter id=\'noise\'%3E%3CfeTurbulence type=\'fractalNoise\' baseFrequency=\'0.9\' numOctaves=\'4\' stitchTiles=\'stitch\'/%3E%3C/filter%3E%3Crect width=\'100%25\' height=\'100%25\' filter=\'url(%23noise)\' opacity=\'1\'/%3E%3C/svg%3E")', backgroundRepeat: 'repeat', backgroundSize: '256px 256px' }} />
      </div>
      <div className="w-full max-w-md relative z-10">
        {/* Logo */}
        <div className="text-center mb-8">
          <div className="w-16 h-16 bg-[#00853F] rounded-2xl flex items-center justify-center mx-auto mb-4">
            <span className="text-white text-2xl font-bold">SS</span>
          </div>
          <h1 className="text-2xl font-bold text-white">SmartSchool SN</h1>
          <p className="text-slate-400 text-sm mt-1">Plateforme de gestion scolaire</p>
        </div>

        {/* Mode Démo */}
        {true && (
          <div className="bg-[#141833] rounded-2xl border border-slate-700/50 p-6">
            <div className="bg-ss-cyan/10 border border-ss-cyan/30 rounded-xl px-4 py-3 mb-5">
              <p className="text-ss-cyan text-sm font-semibold">Mode Démonstration</p>
              <p className="text-slate-400 text-xs mt-0.5">Choisissez un profil pour explorer l&apos;application</p>
            </div>

            <div className="space-y-3">
              {DEMO_ROLES.map(r => (
                <button
                  key={r.role}
                  onClick={() => handleDemoLogin(r.role, r.route)}
                  className="w-full flex items-center gap-4 p-4 bg-[#0A0E27] border border-slate-700/50 rounded-xl hover:border-ss-cyan/50 hover:bg-ss-bg-card transition-all text-left group min-h-[64px]"
                >
                  <span className="text-2xl">{r.icon}</span>
                  <div className="flex-1 min-w-0">
                    <p className="text-white font-semibold text-sm group-hover:text-ss-cyan transition-colors">{r.label}</p>
                    <p className="text-slate-500 text-xs mt-0.5">{r.desc}</p>
                  </div>
                  <span className="text-slate-600 group-hover:text-ss-cyan transition-colors">→</span>
                </button>
              ))}
            </div>
          </div>
        )}

        {/* Mode Réel (Supabase configuré) */}
        {isSupabaseConfigured && (
          <div className="bg-[#141833] rounded-2xl border border-slate-700/50 p-6">
            {/* Toggle Connexion / Inscription */}
            <div className="flex bg-[#0A0E27] rounded-xl p-1 mb-6">
              <button
                onClick={() => { setMode('login'); setError(''); setSuccess('') }}
                className={`flex-1 py-2.5 text-sm font-medium rounded-lg transition ${
                  mode === 'login'
                    ? 'bg-ss-green text-white'
                    : 'text-slate-400 hover:text-white'
                }`}
              >
                Connexion
              </button>
              <button
                onClick={() => { setMode('register'); setError(''); setSuccess('') }}
                className={`flex-1 py-2.5 text-sm font-medium rounded-lg transition ${
                  mode === 'register'
                    ? 'bg-ss-green text-white'
                    : 'text-slate-400 hover:text-white'
                }`}
              >
                Inscription
              </button>
            </div>

            {/* Message de succès */}
            {success && (
              <div className="bg-green-500/10 border border-green-500/30 text-green-400 px-4 py-3 rounded-lg text-sm mb-4">
                {success}
              </div>
            )}

            {/* Message d'erreur */}
            {error && (
              <div className="bg-red-500/10 border border-red-500/30 text-red-400 px-4 py-3 rounded-lg text-sm mb-4">
                {error}
              </div>
            )}

            {/* ===== MODE CONNEXION ===== */}
            {mode === 'login' && (
              <>
                {/* Onglets Email / SMS */}
                <div className="flex bg-[#0A0E27] rounded-xl p-1 mb-5">
                  <button
                    onClick={() => { setTab('email'); setError('') }}
                    className={`flex-1 py-2 text-xs font-medium rounded-lg transition ${
                      tab === 'email'
                        ? 'bg-slate-700 text-white'
                        : 'text-slate-400 hover:text-white'
                    }`}
                  >
                    Email / Mot de passe
                  </button>
                  <button
                    onClick={() => { setTab('phone'); setError(''); setOtpStep('phone') }}
                    className={`flex-1 py-2 text-xs font-medium rounded-lg transition ${
                      tab === 'phone'
                        ? 'bg-slate-700 text-white'
                        : 'text-slate-400 hover:text-white'
                    }`}
                  >
                    SMS / OTP
                  </button>
                </div>

                {/* Formulaire Email/Password */}
                {tab === 'email' && (
                  <form onSubmit={handleEmailLogin} className="space-y-4">
                    <div>
                      <label className="block text-sm font-medium text-slate-300 mb-1.5">Adresse email</label>
                      <input
                        type="email"
                        value={email}
                        onChange={e => setEmail(e.target.value)}
                        required
                        placeholder="admin@ecole.sn"
                        className="w-full bg-[#0A0E27] border border-slate-600 text-white rounded-lg px-4 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-ss-green focus:border-transparent placeholder:text-slate-500"
                      />
                    </div>
                    <div>
                      <label className="block text-sm font-medium text-slate-300 mb-1.5">Mot de passe</label>
                      <input
                        type="password"
                        value={password}
                        onChange={e => setPassword(e.target.value)}
                        required
                        placeholder="Votre mot de passe"
                        className="w-full bg-[#0A0E27] border border-slate-600 text-white rounded-lg px-4 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-ss-green focus:border-transparent placeholder:text-slate-500"
                      />
                    </div>
                    <button
                      type="submit"
                      disabled={loading}
                      className="w-full bg-ss-green text-white py-3 rounded-lg font-semibold hover:bg-ss-green/80 disabled:opacity-50 transition text-sm min-h-[48px]"
                    >
                      {loading ? 'Connexion en cours...' : 'Se connecter'}
                    </button>
                  </form>
                )}

                {/* Formulaire SMS OTP */}
                {tab === 'phone' && otpStep === 'phone' && (
                  <form onSubmit={handleSendOtp} className="space-y-4">
                    <div>
                      <label className="block text-sm font-medium text-slate-300 mb-1.5">Numéro de téléphone</label>
                      <div className="flex gap-2">
                        <div className="flex items-center bg-[#0A0E27] border border-slate-600 rounded-lg px-3 text-slate-400 text-sm">+221</div>
                        <input
                          type="tel"
                          value={phone}
                          onChange={e => setPhone(e.target.value)}
                          required
                          placeholder="77 123 45 67"
                          className="flex-1 bg-[#0A0E27] border border-slate-600 text-white rounded-lg px-4 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-ss-green placeholder:text-slate-500"
                        />
                      </div>
                    </div>
                    <button
                      type="submit"
                      disabled={loading}
                      className="w-full bg-ss-green text-white py-3 rounded-lg font-semibold hover:bg-ss-green/80 disabled:opacity-50 transition text-sm min-h-[48px]"
                    >
                      {loading ? 'Envoi du code...' : 'Recevoir le code SMS'}
                    </button>
                  </form>
                )}

                {/* Vérification OTP */}
                {tab === 'phone' && otpStep === 'code' && (
                  <form onSubmit={handleVerifyOtp} className="space-y-4">
                    <div className="text-center mb-2">
                      <p className="text-slate-300 text-sm">
                        Code envoyé au <span className="text-white font-medium">{phone}</span>
                      </p>
                    </div>
                    <input
                      type="text"
                      value={otpCode}
                      onChange={e => setOtpCode(e.target.value.replace(/\D/g, '').slice(0, 6))}
                      required
                      placeholder="000000"
                      maxLength={6}
                      className="w-full bg-[#0A0E27] border border-slate-600 text-white rounded-lg px-4 py-2.5 text-sm text-center tracking-[0.5em] font-mono text-lg focus:outline-none focus:ring-2 focus:ring-ss-green placeholder:text-slate-500 placeholder:tracking-[0.5em]"
                    />
                    <button
                      type="submit"
                      disabled={loading || otpCode.length < 6}
                      className="w-full bg-ss-green text-white py-3 rounded-lg font-semibold hover:bg-ss-green/80 disabled:opacity-50 transition text-sm min-h-[48px]"
                    >
                      {loading ? 'Vérification...' : 'Vérifier le code'}
                    </button>
                    <button
                      type="button"
                      onClick={() => { setOtpStep('phone'); setOtpCode('') }}
                      className="w-full text-slate-400 text-sm hover:text-white transition"
                    >
                      Renvoyer un nouveau code
                    </button>
                  </form>
                )}
              </>
            )}

            {/* ===== MODE INSCRIPTION ===== */}
            {mode === 'register' && (
              <form onSubmit={handleRegister} className="space-y-4">
                <div className="grid grid-cols-2 gap-3">
                  <div>
                    <label className="block text-sm font-medium text-slate-300 mb-1.5">Prénom</label>
                    <input
                      type="text"
                      value={prenom}
                      onChange={e => setPrenom(e.target.value)}
                      required
                      placeholder="Mamadou"
                      className="w-full bg-[#0A0E27] border border-slate-600 text-white rounded-lg px-4 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-ss-green focus:border-transparent placeholder:text-slate-500"
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-slate-300 mb-1.5">Nom</label>
                    <input
                      type="text"
                      value={nom}
                      onChange={e => setNom(e.target.value)}
                      required
                      placeholder="Diallo"
                      className="w-full bg-[#0A0E27] border border-slate-600 text-white rounded-lg px-4 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-ss-green focus:border-transparent placeholder:text-slate-500"
                    />
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-medium text-slate-300 mb-1.5">Adresse email</label>
                  <input
                    type="email"
                    value={email}
                    onChange={e => setEmail(e.target.value)}
                    required
                    placeholder="votre@email.sn"
                    className="w-full bg-[#0A0E27] border border-slate-600 text-white rounded-lg px-4 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-ss-green focus:border-transparent placeholder:text-slate-500"
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-slate-300 mb-1.5">Téléphone</label>
                  <div className="flex gap-2">
                    <div className="flex items-center bg-[#0A0E27] border border-slate-600 rounded-lg px-3 text-slate-400 text-sm">+221</div>
                    <input
                      type="tel"
                      value={telephone}
                      onChange={e => setTelephone(e.target.value)}
                      placeholder="77 123 45 67"
                      className="flex-1 bg-[#0A0E27] border border-slate-600 text-white rounded-lg px-4 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-ss-green placeholder:text-slate-500"
                    />
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-medium text-slate-300 mb-1.5">Rôle</label>
                  <select
                    value={registerRole}
                    onChange={e => setRegisterRole(e.target.value)}
                    className="w-full bg-[#0A0E27] border border-slate-600 text-white rounded-lg px-4 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-ss-green focus:border-transparent"
                  >
                    {REGISTER_ROLES.map(r => (
                      <option key={r.value} value={r.value}>{r.label}</option>
                    ))}
                  </select>
                </div>

                <div>
                  <label className="block text-sm font-medium text-slate-300 mb-1.5">Mot de passe</label>
                  <input
                    type="password"
                    value={password}
                    onChange={e => setPassword(e.target.value)}
                    required
                    placeholder="Minimum 6 caractères"
                    className="w-full bg-[#0A0E27] border border-slate-600 text-white rounded-lg px-4 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-ss-green focus:border-transparent placeholder:text-slate-500"
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-slate-300 mb-1.5">Confirmer le mot de passe</label>
                  <input
                    type="password"
                    value={confirmPassword}
                    onChange={e => setConfirmPassword(e.target.value)}
                    required
                    placeholder="Retapez le mot de passe"
                    className="w-full bg-[#0A0E27] border border-slate-600 text-white rounded-lg px-4 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-ss-green focus:border-transparent placeholder:text-slate-500"
                  />
                </div>

                <button
                  type="submit"
                  disabled={loading}
                  className="w-full bg-ss-green text-white py-3 rounded-lg font-semibold hover:bg-ss-green/80 disabled:opacity-50 transition text-sm min-h-[48px]"
                >
                  {loading ? 'Création en cours...' : 'Créer mon compte'}
                </button>
              </form>
            )}
          </div>
        )}

        <p className="text-center text-slate-600 text-xs mt-6">
          SmartSchool SN v2.0 &copy; 2025-2026
        </p>
      </div>
    </div>
    </>
  )
}

'use client'

import { useState, useEffect } from 'react'
import { createBrowserClient } from '@supabase/ssr'
import { StatCard } from '@/components/dashboard/StatCard'

interface EleveRisque {
  id: string
  nom: string
  prenom: string
  classe_nom: string
  moyenne: number | null
  nb_absences: number
  nb_absences_non_justifiees: number
  tendance_notes: 'baisse' | 'stable' | 'hausse'
  score_risque: number // 0-100
  niveau_risque: 'faible' | 'moyen' | 'eleve' | 'critique'
}

interface StatsGlobales {
  total_eleves: number
  eleves_a_risque: number
  moyenne_generale: number
  taux_assiduite: number
}

export default function AnalytiquePage() {
  const [eleves, setEleves] = useState<EleveRisque[]>([])
  const [stats, setStats] = useState<StatsGlobales>({ total_eleves: 0, eleves_a_risque: 0, moyenne_generale: 0, taux_assiduite: 0 })
  const [loading, setLoading] = useState(true)
  const [filtreRisque, setFiltreRisque] = useState<string>('tous')
  const [tri, setTri] = useState<'risque' | 'moyenne' | 'absences'>('risque')

  const supabase = createBrowserClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!
  )

  useEffect(() => {
    loadData()
  }, [])

  async function loadData() {
    setLoading(true)

    // 1. Charger tous les élèves avec leurs classes
    const { data: elevesData } = await (supabase.from('eleves') as any)
      .select('id, nom, prenom, classe_id, classes(nom)')
      .eq('actif', true)

    if (!elevesData || elevesData.length === 0) {
      setLoading(false)
      return
    }

    const eleveIds = elevesData.map((e: any) => e.id)

    // 2. Charger les moyennes (v_moyennes_generales)
    const { data: moyennes } = await (supabase.from('v_moyennes_generales') as any)
      .select('eleve_id, trimestre, moyenne_generale')
      .in('eleve_id', eleveIds)
      .order('trimestre', { ascending: true })

    // 3. Charger les absences (mois en cours + mois précédent)
    const debutMoisPrec = new Date()
    debutMoisPrec.setMonth(debutMoisPrec.getMonth() - 1)
    debutMoisPrec.setDate(1)

    const { data: absences } = await (supabase.from('absences_eleves') as any)
      .select('eleve_id, date_absence, type, justifiee')
      .in('eleve_id', eleveIds)
      .gte('date_absence', debutMoisPrec.toISOString().split('T')[0])

    // 4. Charger les notes récentes pour tendance
    const { data: notesRecentes } = await (supabase.from('notes') as any)
      .select('eleve_id, valeur, created_at')
      .in('eleve_id', eleveIds)
      .order('created_at', { ascending: true })

    // 5. Calculer le score de risque pour chaque élève
    const elevesRisque: EleveRisque[] = elevesData.map((eleve: any) => {
      // Moyenne la plus récente
      const moyennesEleve = (moyennes || []).filter((m: any) => m.eleve_id === eleve.id)
      const derniereMoyenne = moyennesEleve.length > 0
        ? moyennesEleve[moyennesEleve.length - 1].moyenne_generale
        : null

      // Absences
      const absencesEleve = (absences || []).filter((a: any) => a.eleve_id === eleve.id)
      const nbAbsences = absencesEleve.filter((a: any) => a.type === 'absence').length
      const nbNonJustifiees = absencesEleve.filter((a: any) => !a.justifiee).length

      // Tendance des notes
      const notesEleve = (notesRecentes || []).filter((n: any) => n.eleve_id === eleve.id)
      let tendance: 'baisse' | 'stable' | 'hausse' = 'stable'
      if (notesEleve.length >= 3) {
        const moitieLongueur = Math.floor(notesEleve.length / 2)
        const premiereMoitie = notesEleve.slice(0, moitieLongueur)
        const deuxiemeMoitie = notesEleve.slice(moitieLongueur)
        const moyPremiere = premiereMoitie.reduce((s: number, n: any) => s + (n.valeur || 0), 0) / premiereMoitie.length
        const moyDeuxieme = deuxiemeMoitie.reduce((s: number, n: any) => s + (n.valeur || 0), 0) / deuxiemeMoitie.length
        if (moyDeuxieme < moyPremiere - 1) tendance = 'baisse'
        else if (moyDeuxieme > moyPremiere + 1) tendance = 'hausse'
      }

      // Score de risque (0-100)
      let score = 0

      // Facteur 1: Moyenne basse (max 40 points)
      if (derniereMoyenne !== null) {
        if (derniereMoyenne < 5) score += 40
        else if (derniereMoyenne < 8) score += 30
        else if (derniereMoyenne < 10) score += 20
        else if (derniereMoyenne < 12) score += 10
      } else {
        score += 15 // pas de moyenne = alerte modérée
      }

      // Facteur 2: Absences non justifiées (max 30 points)
      score += Math.min(nbNonJustifiees * 5, 30)

      // Facteur 3: Nombre total d'absences (max 15 points)
      score += Math.min(nbAbsences * 3, 15)

      // Facteur 4: Tendance des notes en baisse (max 15 points)
      if (tendance === 'baisse') score += 15
      else if (tendance === 'hausse') score -= 5

      score = Math.max(0, Math.min(100, score))

      let niveauRisque: 'faible' | 'moyen' | 'eleve' | 'critique' = 'faible'
      if (score >= 70) niveauRisque = 'critique'
      else if (score >= 45) niveauRisque = 'eleve'
      else if (score >= 25) niveauRisque = 'moyen'

      return {
        id: eleve.id,
        nom: eleve.nom,
        prenom: eleve.prenom,
        classe_nom: eleve.classes?.nom || '—',
        moyenne: derniereMoyenne ? Number(Number(derniereMoyenne).toFixed(2)) : null,
        nb_absences: nbAbsences,
        nb_absences_non_justifiees: nbNonJustifiees,
        tendance_notes: tendance,
        score_risque: score,
        niveau_risque: niveauRisque,
      }
    })

    // Trier par score de risque décroissant
    elevesRisque.sort((a, b) => b.score_risque - a.score_risque)

    // Stats globales
    const moyennesValides = elevesRisque.filter(e => e.moyenne !== null)
    const moyenneGenerale = moyennesValides.length > 0
      ? moyennesValides.reduce((s, e) => s + (e.moyenne || 0), 0) / moyennesValides.length
      : 0

    const totalAbsencesPossibles = elevesRisque.length * 30 // approximation
    const totalAbsences = elevesRisque.reduce((s, e) => s + e.nb_absences, 0)
    const tauxAssiduite = totalAbsencesPossibles > 0
      ? ((totalAbsencesPossibles - totalAbsences) / totalAbsencesPossibles) * 100
      : 100

    setStats({
      total_eleves: elevesRisque.length,
      eleves_a_risque: elevesRisque.filter(e => e.niveau_risque === 'eleve' || e.niveau_risque === 'critique').length,
      moyenne_generale: Number(moyenneGenerale.toFixed(2)),
      taux_assiduite: Number(tauxAssiduite.toFixed(1)),
    })

    setEleves(elevesRisque)
    setLoading(false)
  }

  const elevesFiltres = eleves
    .filter(e => filtreRisque === 'tous' || e.niveau_risque === filtreRisque)
    .sort((a, b) => {
      if (tri === 'risque') return b.score_risque - a.score_risque
      if (tri === 'moyenne') return (a.moyenne || 0) - (b.moyenne || 0)
      return b.nb_absences - a.nb_absences
    })

  const niveauColors = {
    faible: { bg: 'bg-green-500/20', text: 'text-green-400', label: 'Faible' },
    moyen: { bg: 'bg-yellow-500/20', text: 'text-yellow-400', label: 'Moyen' },
    eleve: { bg: 'bg-orange-500/20', text: 'text-orange-400', label: 'Élevé' },
    critique: { bg: 'bg-red-500/20', text: 'text-red-400', label: 'Critique' },
  }

  const tendanceIcons = {
    baisse: { icon: '📉', color: 'text-red-400' },
    stable: { icon: '➡️', color: 'text-ss-text-secondary' },
    hausse: { icon: '📈', color: 'text-green-400' },
  }

  if (loading) {
    return (
      <div className="p-6 space-y-6">
        <h1 className="text-2xl font-bold text-ss-text">📊 Analytique prédictif</h1>
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          {[1, 2, 3, 4].map(i => (
            <div key={i} className="bg-ss-bg-secondary rounded-xl p-5 h-[120px] ss-shimmer" />
          ))}
        </div>
        <div className="bg-ss-bg-secondary rounded-xl p-6 h-[400px] ss-shimmer" />
      </div>
    )
  }

  return (
    <div className="p-6 space-y-6">
      {/* Header */}
      <div>
        <h1 className="text-2xl font-bold text-ss-text">📊 Analytique prédictif</h1>
        <p className="text-ss-text-secondary text-sm mt-1">
          Identification des élèves à risque de décrochage scolaire
        </p>
        {/* Bande tricolore */}
        <div className="flex h-1 rounded-full overflow-hidden mt-3 max-w-xs">
          <div className="flex-1 bg-[#00853F]" />
          <div className="flex-1 bg-[#FDEF42]" />
          <div className="flex-1 bg-[#E31B23]" />
        </div>
      </div>

      {/* Stat Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
        <StatCard
          title="Élèves suivis"
          value={stats.total_eleves}
          icon="🎓"
          color="sn-green"
        />
        <StatCard
          title="Élèves à risque"
          value={stats.eleves_a_risque}
          icon="⚠️"
          subtitle={`${stats.total_eleves > 0 ? ((stats.eleves_a_risque / stats.total_eleves) * 100).toFixed(0) : 0}% des élèves`}
          color="sn-red"
        />
        <StatCard
          title="Moyenne générale"
          value={`${stats.moyenne_generale}/20`}
          icon="📝"
          color={stats.moyenne_generale >= 10 ? 'sn-green' : 'sn-red'}
        />
        <StatCard
          title="Taux d'assiduité"
          value={`${stats.taux_assiduite}%`}
          icon="📋"
          color={stats.taux_assiduite >= 90 ? 'sn-green' : 'sn-yellow'}
        />
      </div>

      {/* Jauge de risque global */}
      <div className="bg-ss-bg-secondary rounded-xl p-5">
        <h3 className="text-sm font-semibold text-ss-text-secondary mb-3">Répartition des niveaux de risque</h3>
        <div className="flex h-8 rounded-lg overflow-hidden">
          {(['faible', 'moyen', 'eleve', 'critique'] as const).map(niveau => {
            const count = eleves.filter(e => e.niveau_risque === niveau).length
            const pct = eleves.length > 0 ? (count / eleves.length) * 100 : 0
            if (pct === 0) return null
            const colors = {
              faible: 'bg-green-500',
              moyen: 'bg-yellow-500',
              eleve: 'bg-orange-500',
              critique: 'bg-red-500',
            }
            return (
              <div
                key={niveau}
                className={`${colors[niveau]} flex items-center justify-center text-xs font-bold text-white`}
                style={{ width: `${pct}%` }}
                title={`${niveauColors[niveau].label}: ${count} élèves (${pct.toFixed(0)}%)`}
              >
                {pct >= 10 && `${count}`}
              </div>
            )
          })}
        </div>
        <div className="flex gap-4 mt-2 text-xs text-ss-text-muted">
          <span className="flex items-center gap-1"><span className="w-3 h-3 rounded bg-green-500 inline-block" /> Faible ({eleves.filter(e => e.niveau_risque === 'faible').length})</span>
          <span className="flex items-center gap-1"><span className="w-3 h-3 rounded bg-yellow-500 inline-block" /> Moyen ({eleves.filter(e => e.niveau_risque === 'moyen').length})</span>
          <span className="flex items-center gap-1"><span className="w-3 h-3 rounded bg-orange-500 inline-block" /> Élevé ({eleves.filter(e => e.niveau_risque === 'eleve').length})</span>
          <span className="flex items-center gap-1"><span className="w-3 h-3 rounded bg-red-500 inline-block" /> Critique ({eleves.filter(e => e.niveau_risque === 'critique').length})</span>
        </div>
      </div>

      {/* Filtres et tri */}
      <div className="flex flex-wrap gap-3 items-center">
        <div className="flex gap-1 bg-ss-bg-secondary rounded-lg p-1">
          {[
            { val: 'tous', label: 'Tous' },
            { val: 'critique', label: '🔴 Critique' },
            { val: 'eleve', label: '🟠 Élevé' },
            { val: 'moyen', label: '🟡 Moyen' },
            { val: 'faible', label: '🟢 Faible' },
          ].map(f => (
            <button
              key={f.val}
              onClick={() => setFiltreRisque(f.val)}
              className={`px-3 py-1.5 rounded-md text-xs font-medium transition-colors ${
                filtreRisque === f.val
                  ? 'bg-[#00853F] text-white'
                  : 'text-ss-text-secondary hover:text-ss-text'
              }`}
            >
              {f.label}
            </button>
          ))}
        </div>

        <select
          value={tri}
          onChange={(e) => setTri(e.target.value as any)}
          className="bg-ss-bg-secondary text-ss-text border border-ss-border rounded-lg px-3 py-1.5 text-sm"
        >
          <option value="risque">Trier par risque</option>
          <option value="moyenne">Trier par moyenne</option>
          <option value="absences">Trier par absences</option>
        </select>

        <span className="text-sm text-ss-text-muted ml-auto">
          {elevesFiltres.length} élève{elevesFiltres.length > 1 ? 's' : ''}
        </span>
      </div>

      {/* Tableau des élèves */}
      <div className="bg-ss-bg-secondary rounded-xl overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead>
              <tr className="text-left text-xs text-ss-text-muted uppercase border-b border-ss-border">
                <th className="p-3">Score</th>
                <th className="p-3">Élève</th>
                <th className="p-3">Classe</th>
                <th className="p-3">Moyenne</th>
                <th className="p-3">Absences</th>
                <th className="p-3">Tendance</th>
                <th className="p-3">Risque</th>
              </tr>
            </thead>
            <tbody>
              {elevesFiltres.map((eleve) => {
                const niveau = niveauColors[eleve.niveau_risque]
                const tendance = tendanceIcons[eleve.tendance_notes]
                return (
                  <tr key={eleve.id} className="border-b border-ss-border/50 hover:bg-ss-bg-card/50">
                    {/* Score barre */}
                    <td className="p-3">
                      <div className="flex items-center gap-2">
                        <div className="w-12 h-2 bg-ss-bg-card rounded-full overflow-hidden">
                          <div
                            className={`h-full rounded-full ${
                              eleve.score_risque >= 70 ? 'bg-red-500' :
                              eleve.score_risque >= 45 ? 'bg-orange-500' :
                              eleve.score_risque >= 25 ? 'bg-yellow-500' : 'bg-green-500'
                            }`}
                            style={{ width: `${eleve.score_risque}%` }}
                          />
                        </div>
                        <span className="text-xs font-mono text-ss-text-muted">{eleve.score_risque}</span>
                      </div>
                    </td>

                    {/* Nom */}
                    <td className="p-3 font-medium text-ss-text">
                      {eleve.prenom} {eleve.nom}
                    </td>

                    {/* Classe */}
                    <td className="p-3 text-ss-text-secondary text-sm">
                      {eleve.classe_nom}
                    </td>

                    {/* Moyenne */}
                    <td className="p-3">
                      {eleve.moyenne !== null ? (
                        <span className={`font-semibold ${eleve.moyenne >= 10 ? 'text-green-400' : 'text-red-400'}`}>
                          {eleve.moyenne}/20
                        </span>
                      ) : (
                        <span className="text-ss-text-muted text-sm">—</span>
                      )}
                    </td>

                    {/* Absences */}
                    <td className="p-3">
                      <span className="text-ss-text">{eleve.nb_absences}</span>
                      {eleve.nb_absences_non_justifiees > 0 && (
                        <span className="text-red-400 text-xs ml-1">
                          ({eleve.nb_absences_non_justifiees} nj)
                        </span>
                      )}
                    </td>

                    {/* Tendance */}
                    <td className="p-3">
                      <span className={tendance.color}>{tendance.icon}</span>
                    </td>

                    {/* Badge risque */}
                    <td className="p-3">
                      <span className={`px-2 py-1 rounded-full text-xs font-medium ${niveau.bg} ${niveau.text}`}>
                        {niveau.label}
                      </span>
                    </td>
                  </tr>
                )
              })}
            </tbody>
          </table>
        </div>

        {elevesFiltres.length === 0 && (
          <div className="p-8 text-center text-ss-text-muted">
            <p className="text-4xl mb-3">✅</p>
            <p>Aucun élève ne correspond à ce filtre</p>
          </div>
        )}
      </div>

      {/* Légende algorithme */}
      <div className="bg-ss-bg-secondary rounded-xl p-5">
        <div className="flex items-start gap-3">
          <span className="text-2xl">🧠</span>
          <div>
            <p className="font-medium text-ss-text">Algorithme de détection</p>
            <p className="text-sm text-ss-text-secondary mt-1">
              Le score de risque (0-100) est calculé à partir de 4 facteurs :
            </p>
            <ul className="text-xs text-ss-text-muted mt-2 space-y-1">
              <li>📝 <strong>Moyenne générale</strong> — plus la moyenne est basse, plus le risque augmente (40 pts max)</li>
              <li>❌ <strong>Absences non justifiées</strong> — chaque absence non justifiée ajoute 5 points (30 pts max)</li>
              <li>📋 <strong>Absences totales</strong> — volume global d'absences (15 pts max)</li>
              <li>📉 <strong>Tendance des notes</strong> — une baisse constante ajoute 15 points</li>
            </ul>
          </div>
        </div>
      </div>
    </div>
  )
}

'use client'

import { useEffect, useState } from 'react'
import { createClient } from '@/lib/supabase/client'
import { useUser } from '@/hooks/useUser'
import { isDemoMode, DEMO_CLASSES, DEMO_ELEVES } from '@/lib/demo-data'

interface Classe { id: string; nom: string; niveau: string }
interface Eleve { id: string; nom: string; prenom: string; matricule: string }

export default function AdminBulletinsPage() {
  const { user, loading: userLoading } = useUser()
  const [classes, setClasses] = useState<Classe[]>([])
  const [eleves, setEleves] = useState<Eleve[]>([])
  const [selectedClasse, setSelectedClasse] = useState('')
  const [trimestre, setTrimestre] = useState(2)
  const [selected, setSelected] = useState<Set<string>>(new Set())
  const [generating, setGenerating] = useState(false)
  const [progress, setProgress] = useState({ current: 0, total: 0 })
  const [loading, setLoading] = useState(true)

  const ecoleId = user?.ecole_id

  // Charger classes
  useEffect(() => {
    if (!ecoleId) return
    const load = async () => {
      if (isDemoMode()) {
        setClasses(DEMO_CLASSES.map(c => ({ id: c.id, nom: c.nom, niveau: c.niveau })))
        setLoading(false)
        return
      }
      const supabase = createClient()
      const { data } = await (supabase.from('classes') as any)
        .select('id, nom, niveau')
        .eq('ecole_id', ecoleId)
        .order('niveau')
      setClasses((data || []) as Classe[])
      setLoading(false)
    }
    load()
  }, [ecoleId])

  // Charger eleves quand classe change
  useEffect(() => {
    if (!selectedClasse) { setEleves([]); return }
    const load = async () => {
      if (isDemoMode()) {
        setEleves(DEMO_ELEVES.filter(e => e.classe_id === selectedClasse)
          .map(e => ({ id: e.id, nom: e.nom, prenom: e.prenom, matricule: e.matricule })))
        return
      }
      const supabase = createClient()
      const { data } = await (supabase.from('eleves') as any)
        .select('id, nom, prenom, matricule')
        .eq('classe_id', selectedClasse)
        .eq('actif', true)
        .order('nom')
      setEleves((data || []) as Eleve[])
    }
    load()
    setSelected(new Set())
  }, [selectedClasse])

  const toggleAll = () => {
    if (selected.size === eleves.length) {
      setSelected(new Set())
    } else {
      setSelected(new Set(eleves.map(e => e.id)))
    }
  }

  const toggleOne = (id: string) => {
    const next = new Set(selected)
    if (next.has(id)) next.delete(id)
    else next.add(id)
    setSelected(next)
  }

  const handleGenerate = async () => {
    const ids = Array.from(selected)
    if (ids.length === 0) return
    setGenerating(true)
    setProgress({ current: 0, total: ids.length })

    for (let i = 0; i < ids.length; i++) {
      setProgress({ current: i + 1, total: ids.length })
      try {
        const res = await fetch('/api/bulletins/generate', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ eleveId: ids[i], trimestre }),
        })
        if (res.ok) {
          const blob = await res.blob()
          const el = eleves.find(e => e.id === ids[i])
          const url = URL.createObjectURL(blob)
          const a = document.createElement('a')
          a.href = url
          a.download = `Bulletin_T${trimestre}_${el?.prenom || ''}_${el?.nom || ''}.pdf`
          document.body.appendChild(a)
          a.click()
          document.body.removeChild(a)
          URL.revokeObjectURL(url)
        }
      } catch (err) {
        console.error(`Erreur bulletin ${ids[i]}:`, err)
      }
      if (i < ids.length - 1) await new Promise(r => setTimeout(r, 500))
    }

    setGenerating(false)
  }

  if (userLoading) {
    return (
      <div>
        <div className="h-8 w-64 bg-ss-bg-secondary rounded-lg ss-shimmer mb-6" />
        <div className="h-64 bg-ss-bg-secondary rounded-xl ss-shimmer" />
      </div>
    )
  }

  return (
    <div className="space-y-6">
      <h1 className="text-2xl font-bold text-ss-text">Génération des Bulletins</h1>

      {/* Sélecteur trimestre */}
      <div className="flex gap-2">
        {[1, 2, 3].map(t => (
          <button
            key={t}
            onClick={() => setTrimestre(t)}
            className={`px-6 py-2.5 rounded-xl text-sm font-semibold min-h-[44px] transition-colors ${
              trimestre === t
                ? 'bg-[#00853F] text-white'
                : 'bg-ss-bg-secondary text-ss-text-secondary border border-ss-border'
            }`}
          >
            T{t}
          </button>
        ))}
      </div>

      {/* Sélecteur classe */}
      <div>
        <label className="block text-sm font-medium text-ss-text-secondary mb-2">Classe</label>
        {loading ? (
          <div className="h-11 bg-ss-bg-secondary rounded-xl ss-shimmer" />
        ) : (
          <select
            value={selectedClasse}
            onChange={e => setSelectedClasse(e.target.value)}
            className="w-full sm:w-72 px-4 py-2.5 rounded-xl bg-[#0A0E27] border border-ss-border text-ss-text text-sm min-h-[44px]"
          >
            <option value="">-- Sélectionner une classe --</option>
            {classes.map(c => (
              <option key={c.id} value={c.id}>{c.niveau} {c.nom}</option>
            ))}
          </select>
        )}
      </div>

      {/* Liste des élèves */}
      {selectedClasse && (
        <div className="bg-ss-bg-secondary rounded-xl border border-ss-border overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead>
                <tr className="border-b border-ss-border bg-ss-bg-card">
                  <th className="px-4 py-3 text-left">
                    <input
                      type="checkbox"
                      checked={eleves.length > 0 && selected.size === eleves.length}
                      onChange={toggleAll}
                      className="w-4 h-4 rounded accent-[#00853F]"
                    />
                  </th>
                  <th className="px-4 py-3 text-left text-xs font-semibold text-ss-text-secondary">Nom</th>
                  <th className="px-4 py-3 text-left text-xs font-semibold text-ss-text-secondary">Prénom</th>
                  <th className="px-4 py-3 text-left text-xs font-semibold text-ss-text-secondary">Matricule</th>
                </tr>
              </thead>
              <tbody>
                {eleves.length === 0 ? (
                  <tr>
                    <td colSpan={4} className="px-4 py-8 text-center text-ss-text-muted text-sm">
                      Aucun élève dans cette classe
                    </td>
                  </tr>
                ) : (
                  eleves.map((el, idx) => (
                    <tr
                      key={el.id}
                      className={`border-b border-ss-border/50 hover:bg-ss-bg-card/50 transition-colors ${
                        idx % 2 === 0 ? '' : 'bg-ss-bg-card/30'
                      }`}
                    >
                      <td className="px-4 py-3">
                        <input
                          type="checkbox"
                          checked={selected.has(el.id)}
                          onChange={() => toggleOne(el.id)}
                          className="w-4 h-4 rounded accent-[#00853F]"
                        />
                      </td>
                      <td className="px-4 py-3 text-sm font-medium text-ss-text">{el.nom}</td>
                      <td className="px-4 py-3 text-sm text-ss-text">{el.prenom}</td>
                      <td className="px-4 py-3 text-sm text-ss-text-muted">{el.matricule}</td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>

          {/* Compteur sélection */}
          {eleves.length > 0 && (
            <div className="px-4 py-3 border-t border-ss-border flex items-center justify-between">
              <p className="text-sm text-ss-text-secondary">
                {selected.size} élève{selected.size > 1 ? 's' : ''} sélectionné{selected.size > 1 ? 's' : ''}
              </p>
              <button
                onClick={toggleAll}
                className="text-sm text-ss-cyan hover:underline"
              >
                {selected.size === eleves.length ? 'Tout désélectionner' : 'Tout sélectionner'}
              </button>
            </div>
          )}
        </div>
      )}

      {/* Bouton générer + progress */}
      {selectedClasse && selected.size > 0 && (
        <div className="space-y-3">
          <button
            onClick={handleGenerate}
            disabled={generating}
            className="w-full sm:w-auto flex items-center justify-center gap-2 px-6 py-3 bg-[#00853F] text-white rounded-xl font-semibold hover:bg-[#00853F]/90 disabled:opacity-50 transition text-sm min-h-[48px]"
          >
            {generating ? (
              <>
                <span className="animate-spin">&#9203;</span>
                Génération en cours... ({progress.current}/{progress.total})
              </>
            ) : (
              <>
                &#128196; Générer les bulletins sélectionnés ({selected.size})
              </>
            )}
          </button>

          {generating && (
            <div className="w-full bg-ss-bg-card rounded-full h-3 overflow-hidden">
              <div
                className="h-full bg-[#00853F] rounded-full transition-all duration-300"
                style={{ width: `${progress.total > 0 ? (progress.current / progress.total) * 100 : 0}%` }}
              />
            </div>
          )}
        </div>
      )}
    </div>
  )
}

'use client'

import { useEffect, useState, useCallback } from 'react'
import { createClient } from '@/lib/supabase/client'
import { useUser } from '@/hooks/useUser'

// ── Types ───────────────────────────────────────────────────────
type TabKey = 'menu' | 'abonnements' | 'pointage'
type JourEnum = 'lundi' | 'mardi' | 'mercredi' | 'jeudi' | 'vendredi' | 'samedi'
type AbonnementStatut = 'actif' | 'suspendu'

interface MenuCantine {
  id: string
  ecole_id: string
  semaine_debut: string
  jour: JourEnum
  entree: string
  plat_principal: string
  dessert: string
  prix: number
}

interface AbonnementCantine {
  id: string
  ecole_id: string
  eleve_id: string
  eleve_nom: string
  eleve_prenom: string
  classe_nom: string
  montant_mensuel: number
  statut: AbonnementStatut
  regime_special: string | null
  date_debut: string
}

interface RepasPris {
  id?: string
  eleve_id: string
  menu_id: string | null
  date_repas: string
  present: boolean
}

interface EleveOption {
  id: string
  nom: string
  prenom: string
  classe_nom: string
  classe_id: string
}

interface ClasseOption {
  id: string
  nom: string
  niveau: string
}

const ONGLETS: { key: TabKey; label: string; icon: string }[] = [
  { key: 'menu', label: 'Menu de la semaine', icon: '📋' },
  { key: 'abonnements', label: 'Abonnements', icon: '👨‍🎓' },
  { key: 'pointage', label: 'Pointage repas', icon: '🍽️' },
]

const JOURS: { key: JourEnum; label: string; short: string }[] = [
  { key: 'lundi', label: 'Lundi', short: 'Lun' },
  { key: 'mardi', label: 'Mardi', short: 'Mar' },
  { key: 'mercredi', label: 'Mercredi', short: 'Mer' },
  { key: 'jeudi', label: 'Jeudi', short: 'Jeu' },
  { key: 'vendredi', label: 'Vendredi', short: 'Ven' },
