          prenom: e.prenom,
          matricule: e.matricule,
          date_naissance: e.date_naissance,
          classe_id: e.classe_id,
          classe_nom: cl ? cl.nom : '',
          classe_niveau: cl ? cl.niveau : '',
          photo_url: null,
        }
      })
      setClasses(demoClasses)
      setEleves(demoEleves)
      setEcole({ id: 'ecole-demo-001', nom: 'Lycee Blaise Diagne', ville: 'Dakar' })
      setLoading(false)
      return
    }

    const supabase = createClient()
    const [elevesRes, classesRes, ecoleRes] = await Promise.all([
      (supabase.from('eleves') as any)
        .select('id, nom, prenom, matricule, date_naissance, classe_id, photo_url, classes(nom, niveau)')
        .eq('ecole_id', ecoleId)
        .eq('actif', true)
        .order('nom', { ascending: true }),
      supabase
        .from('classes')
        .select('id, nom, niveau')
        .eq('ecole_id', ecoleId)
        .order('niveau', { ascending: true }),
      (supabase.from('ecoles') as any)
        .select('id, nom, ville')
        .eq('id', ecoleId)
        .single(),
    ])

    const rawEleves = (elevesRes.data || []) as any[]
    setEleves(
      rawEleves.map((e: any) => ({
        id: e.id,
        nom: e.nom,
        prenom: e.prenom,
        matricule: e.matricule,
        date_naissance: e.date_naissance,
        classe_id: e.classe_id,
        classe_nom: e.classes?.nom ?? '',
        classe_niveau: e.classes?.niveau ?? '',
        photo_url: e.photo_url,
      }))
    )
    setClasses((classesRes.data || []) as Classe[])
    if (ecoleRes.data) {
      setEcole(ecoleRes.data as Ecole)
    }
    setLoading(false)
  }, [ecoleId])

  useEffect(() => {
    loadData()
  }, [loadData])

  // Filtrage
  const filteredEleves = eleves.filter(e => {
    const matchClasse = !selectedClasse || e.classe_id === selectedClasse
    const matchSearch =
      !search ||
      `${e.prenom} ${e.nom}`.toLowerCase().includes(search.toLowerCase()) ||
      e.matricule.toLowerCase().includes(search.toLowerCase())
    return matchClasse && matchSearch
  })

  const handlePrint = () => {
    window.print()
  }

  const handleGenerateAll = () => {
    setGenerated(true)
  }

  const ecoleNom = ecole?.nom ?? 'SmartSchool SN'

  if (userLoading) {
    return (
      <div>
        <div className="h-8 w-56 bg-ss-bg-secondary rounded-lg ss-shimmer mb-6" />
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
          {[...Array(6)].map((_, i) => (
            <div key={i} className="h-64 bg-ss-bg-secondary rounded-xl ss-shimmer" />
          ))}
        </div>
      </div>
    )
  }

  if (!ecoleId) return null

  return (
    <>
      {/* Print CSS */}
      <style jsx global>{`
        @media print {
          body * {
            visibility: hidden;
          }
          .print-area, .print-area * {
            visibility: visible;
          }
          .print-area {
            position: absolute;
            left: 0;
            top: 0;
            width: 100%;
          }
          .no-print {
            display: none !important;
          }
          .student-card {
            break-inside: avoid;
            page-break-inside: avoid;
            margin-bottom: 16px;
          }
        }
      `}</style>

      <div className="space-y-6">
        {/* En-tete */}
        <div className="flex items-center justify-between flex-wrap gap-3 no-print">
          <h1 className="text-2xl font-bold text-ss-text">Cartes Scolaires Numeriques</h1>
          <div className="flex items-center gap-2">
            <button
              onClick={handleGenerateAll}
              className="flex items-center gap-2 bg-ss-cyan text-white font-medium text-sm px-4 py-2.5 rounded-xl hover:opacity-90 transition-opacity"
            >
              <span className="text-lg leading-none">&#9881;</span>
              Generer toutes les cartes
            </button>
            <button
              onClick={handlePrint}
              className="flex items-center gap-2 bg-green-600 text-white font-medium text-sm px-4 py-2.5 rounded-xl hover:opacity-90 transition-opacity"
            >
              <span className="text-lg leading-none">&#128424;</span>
              Imprimer
            </button>
          </div>
        </div>

        {/* Filtres */}
        <div className="flex flex-col sm:flex-row gap-3 no-print">
          <div className="flex-1">
            <input
              type="text"
              value={search}
              onChange={e => setSearch(e.target.value)}
              placeholder="Rechercher un eleve (nom, prenom, matricule)..."
              className="w-full bg-ss-bg-secondary border border-ss-border text-ss-text rounded-xl px-4 py-2.5 text-sm placeholder:text-ss-text-muted focus:outline-none focus:ring-2 focus:ring-ss-cyan/40"
            />
          </div>
          <select
            value={selectedClasse}
            onChange={e => setSelectedClasse(e.target.value)}
            className="bg-ss-bg-secondary border border-ss-border text-ss-text rounded-xl px-4 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-ss-cyan/40 min-w-[200px]"
          >
            <option value="">Toutes les classes</option>
            {classes.map(c => (
              <option key={c.id} value={c.id}>
                {c.niveau} {c.nom}
              </option>
            ))}
          </select>
        </div>

        {/* Stats */}
        <div className="no-print">
          <p className="text-sm text-ss-text-muted">
            {filteredEleves.length} carte{filteredEleves.length > 1 ? 's' : ''} a afficher
            {selectedClasse && ` pour la classe selectionnee`}
          </p>
        </div>

        {/* Grille des cartes */}
        {loading ? (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
            {[...Array(6)].map((_, i) => (
              <div key={i} className="h-64 bg-ss-bg-secondary rounded-xl ss-shimmer" />
            ))}
          </div>
        ) : filteredEleves.length === 0 ? (
          <div className="text-center py-16">
            <p className="text-ss-text-muted text-lg">Aucun eleve trouve</p>
            <p className="text-ss-text-muted text-sm mt-1">
              Essayez de modifier vos filtres de recherche.
            </p>
          </div>
        ) : (
          <div className="print-area grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
            {filteredEleves.map(eleve => (
              <StudentCard
                key={eleve.id}
                eleve={eleve}
                ecoleNom={ecoleNom}
                ecoleId={ecoleId}
                generated={generated}
              />
            ))}
          </div>
        )}
      </div>
    </>
  )
}

/* ─── Composant Carte Scolaire ─── */

function StudentCard({
  eleve,
  ecoleNom,
  ecoleId,
  generated,
}: {
  eleve: Eleve
  ecoleNom: string
  ecoleId: string
  generated: boolean
}) {
  const initials = `${eleve.prenom[0] ?? ''}${eleve.nom[0] ?? ''}`.toUpperCase()
  const avatarColor = getAvatarColor(eleve.id)
  const classeLabel = eleve.classe_niveau
    ? `${eleve.classe_niveau} ${eleve.classe_nom}`
    : eleve.classe_nom ?? ''

  const qrData = {
    id: eleve.id,
    matricule: eleve.matricule,
    ecole: ecoleId,
    nom: `${eleve.prenom} ${eleve.nom}`,
  }
  const qrUrl = buildQrUrl(qrData)

  return (
    <div
      className="student-card bg-white rounded-2xl shadow-lg overflow-hidden"
      style={{ aspectRatio: '85.6 / 53.98' }}
    >
      {/* Bande tricolore senegalaise */}
      <div className="flex h-2">
        <div className="flex-1 bg-[#00853F]" />
        <div className="flex-1 bg-[#FDEF42]" />
        <div className="flex-1 bg-[#E31B23]" />
      </div>

      {/* Contenu de la carte */}
      <div className="px-4 py-2 flex flex-col h-[calc(100%-8px)] justify-between">
        {/* Nom de l'ecole */}
        <div className="text-center">
          <h3 className="text-xs font-bold text-gray-800 uppercase tracking-wide leading-tight">
            {ecoleNom}
          </h3>
          <p className="text-[9px] text-gray-500 font-medium uppercase tracking-widest">
            Carte Scolaire Numerique
          </p>
        </div>

        {/* Zone principale: avatar + infos */}
        <div className="flex items-center gap-3 flex-1 py-1">
          {/* Avatar */}
          <div className="shrink-0">
            {eleve.photo_url ? (
              <img
                src={eleve.photo_url}
                alt={`${eleve.prenom} ${eleve.nom}`}
                className="w-14 h-14 rounded-full object-cover border-2 border-gray-200"
              />
            ) : (
              <div
                className={`w-14 h-14 rounded-full flex items-center justify-center ${avatarColor} border-2 border-white shadow-md`}
              >
                <span className="text-white font-bold text-lg">{initials}</span>
              </div>
            )}
          </div>

          {/* Infos eleve */}
          <div className="min-w-0 flex-1">
            <p className="text-sm font-bold text-gray-900 truncate">
              {eleve.prenom} {eleve.nom}
            </p>
            <div className="mt-0.5 space-y-0.5">
              <p className="text-[10px] text-gray-600">
                <span className="font-semibold text-gray-700">Matricule:</span>{' '}
                {eleve.matricule}
              </p>
              <p className="text-[10px] text-gray-600">
                <span className="font-semibold text-gray-700">Classe:</span>{' '}
                {classeLabel}
              </p>
              <p className="text-[10px] text-gray-600">
                <span className="font-semibold text-gray-700">Annee:</span>{' '}
                2025-2026
              </p>
            </div>
          </div>

          {/* QR Code */}
          <div className="shrink-0">
            {generated ? (
              <img
                src={qrUrl}
                alt="QR Code"
                width={56}
                height={56}
                className="rounded"
              />
            ) : (
              <div className="w-14 h-14 bg-gray-100 rounded flex items-center justify-center">
                <span className="text-[8px] text-gray-400 text-center leading-tight">
                  QR Code
                </span>
              </div>
            )}
          </div>
        </div>

        {/* Pied de carte */}
        <div className="flex items-center justify-between border-t border-gray-200 pt-1">
          <p className="text-[8px] text-gray-400">
            Republique du Senegal
          </p>
          <p className="text-[8px] text-gray-400 font-medium">
            SmartSchool SN
          </p>
        </div>
      </div>
    </div>
  )
}

'use client'

import { useEffect, useState, useCallback } from 'react'
import { createClient } from '@/lib/supabase/client'
import { useUser } from '@/hooks/useUser'
import { isDemoMode, DEMO_CLASSES, DEMO_PROFESSEURS, DEMO_ELEVES } from '@/lib/demo-data'

interface ClasseRow {
  id: string
  nom: string
  niveau: string
  effectif_max: number
  titulaire_id: string | null
  titulaire_nom?: string
  nb_eleves: number
}

interface Prof {
  id: string
  nom: string
  prenom: string
}

const NIVEAUX = ['6ème', '5ème', '4ème', '3ème', 'Seconde', 'Première', 'Terminale']

export default function ClassesPage() {
  const { user, loading: userLoading } = useUser()
  const [classes, setClasses] = useState<ClasseRow[]>([])
  const [profs, setProfs] = useState<Prof[]>([])
  const [loading, setLoading] = useState(true)
  const [showModal, setShowModal] = useState(false)
  const [editId, setEditId] = useState<string | null>(null)
  const [saving, setSaving] = useState(false)
  const [error, setError] = useState('')

  // Champs formulaire
  const [formNiveau, setFormNiveau] = useState('6ème')
  const [formNom, setFormNom] = useState('')
  const [formEffectif, setFormEffectif] = useState('40')
  const [formTitulaire, setFormTitulaire] = useState('')

  const ecoleId = user?.ecole_id

  const loadData = useCallback(async () => {
    if (!ecoleId) return
    setLoading(true)

    if (isDemoMode()) {
      const demoClasses: ClasseRow[] = DEMO_CLASSES.map(c => {
        const titulaire = DEMO_PROFESSEURS[0]
        const nb = DEMO_ELEVES.filter(e => e.classe_id === c.id).length
        return {
          id: c.id,
          nom: c.nom,
          niveau: c.niveau,
          effectif_max: c.effectif_max,
          titulaire_id: titulaire.id,
          titulaire_nom: `${titulaire.prenom} ${titulaire.nom}`,
          nb_eleves: nb,
        }
      })
      setClasses(demoClasses)
      setProfs(DEMO_PROFESSEURS.map(p => ({ id: p.id, nom: p.nom, prenom: p.prenom })))
      setLoading(false)
      return
    }

    const supabase = createClient()
    const [classesRes, profsRes] = await Promise.all([
      (supabase.from('classes') as any)
        .select('*, eleves(count), utilisateurs!titulaire_id(nom, prenom)')
        .eq('ecole_id', ecoleId)
        .order('niveau', { ascending: true }),
      supabase
        .from('utilisateurs')
        .select('id, nom, prenom')
        .eq('ecole_id', ecoleId)
        .eq('role', 'professeur')
        .order('nom', { ascending: true }),
    ])

    const rawClasses = (classesRes.data || []) as any[]
    setClasses(
      rawClasses.map((c: any) => ({
        id: c.id,
        nom: c.nom,
        niveau: c.niveau,
        effectif_max: c.effectif_max,
        titulaire_id: c.titulaire_id,
        titulaire_nom: c.utilisateurs
          ? `${c.utilisateurs.prenom} ${c.utilisateurs.nom}`
          : undefined,
        nb_eleves: c.eleves?.[0]?.count ?? 0,
      }))
    )
    setProfs((profsRes.data || []) as Prof[])
    setLoading(false)
  }, [ecoleId])

  useEffect(() => {
    loadData()
  }, [loadData])

  const resetForm = () => {
    setFormNiveau('6ème')
    setFormNom('')
    setFormEffectif('40')
    setFormTitulaire('')
    setEditId(null)
    setError('')
  }

  const openAdd = () => {
    resetForm()
    setShowModal(true)
  }

  const openEdit = (c: ClasseRow) => {
    setFormNiveau(c.niveau)
    setFormNom(c.nom)
    setFormEffectif(String(c.effectif_max))
    setFormTitulaire(c.titulaire_id ?? '')
    setEditId(c.id)
    setError('')
    setShowModal(true)
  }

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!ecoleId) return
    if (!formNom.trim()) {
      setError('Le nom de la classe est obligatoire.')
      return
    }

    setSaving(true)
    setError('')

    if (isDemoMode()) {
      if (editId) {
        setClasses(prev =>
          prev.map(c =>
            c.id === editId
              ? {
                  ...c,
                  nom: formNom.trim(),
                  niveau: formNiveau,
                  effectif_max: Number(formEffectif) || 40,
                  titulaire_id: formTitulaire || null,
                  titulaire_nom: formTitulaire
                    ? (() => {
                        const p = profs.find(p => p.id === formTitulaire)
                        return p ? `${p.prenom} ${p.nom}` : undefined
                      })()
                    : undefined,
                }
              : c
          )
        )
      } else {
        const newClasse: ClasseRow = {
          id: `classe-demo-${Date.now()}`,
          nom: formNom.trim(),
          niveau: formNiveau,
          effectif_max: Number(formEffectif) || 40,
          titulaire_id: formTitulaire || null,
          titulaire_nom: formTitulaire
            ? (() => {
                const p = profs.find(p => p.id === formTitulaire)
                return p ? `${p.prenom} ${p.nom}` : undefined
              })()
            : undefined,
          nb_eleves: 0,
        }
        setClasses(prev => [...prev, newClasse])
      }
      setShowModal(false)
      setSaving(false)
      return
    }

    try {
      const supabase = createClient()
      const payload = {
        ecole_id: ecoleId,
        nom: formNom.trim(),
        niveau: formNiveau,
        effectif_max: Number(formEffectif) || 40,
        titulaire_id: formTitulaire || null,
        annee_scolaire: '2025-2026',
      }

      if (editId) {
        await (supabase.from('classes') as any).update(payload).eq('id', editId)
      } else {
        await (supabase.from('classes') as any).insert(payload)
      }

      await loadData()
      setShowModal(false)
    } catch {
      setError('Une erreur inattendue est survenue.')
    } finally {
      setSaving(false)
    }
  }

  if (userLoading) {
    return (
      <div>
        <div className="h-8 w-48 bg-ss-bg-secondary rounded-lg ss-shimmer mb-6" />
        <div className="space-y-3">
          {[...Array(6)].map((_, i) => (
            <div key={i} className="h-14 bg-ss-bg-secondary rounded-xl ss-shimmer" />
          ))}
        </div>
      </div>
    )
  }

  if (!ecoleId) return null

  return (
    <div className="space-y-6">
      {/* En-tête */}
      <div className="flex items-center justify-between flex-wrap gap-3">
        <h1 className="text-2xl font-bold text-ss-text">Gestion des Classes</h1>
        <button
          onClick={openAdd}
          className="flex items-center gap-2 bg-ss-cyan text-white font-medium text-sm px-4 py-2.5 rounded-xl hover:opacity-90 transition-opacity"
        >
          <span className="text-lg leading-none">+</span>
          Nouvelle classe
        </button>
      </div>

      {/* Tableau */}
      {loading ? (
        <div className="space-y-3">
          {[...Array(6)].map((_, i) => (
            <div key={i} className="h-14 bg-ss-bg-secondary rounded-xl ss-shimmer" />
          ))}
        </div>
      ) : (
        <div className="bg-ss-bg-secondary rounded-xl border border-ss-border overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead>
                <tr className="border-b border-ss-border">
                  <th className="text-left text-ss-text-muted font-medium px-4 py-3">Niveau</th>
                  <th className="text-left text-ss-text-muted font-medium px-4 py-3">Nom</th>
                  <th className="text-left text-ss-text-muted font-medium px-4 py-3 hidden sm:table-cell">Effectif max</th>
                  <th className="text-left text-ss-text-muted font-medium px-4 py-3 hidden md:table-cell">Titulaire</th>
                  <th className="text-left text-ss-text-muted font-medium px-4 py-3">Eleves</th>
                  <th className="text-left text-ss-text-muted font-medium px-4 py-3">Actions</th>
                </tr>
              </thead>
              <tbody>
                {classes.length === 0 ? (
                  <tr>
                    <td colSpan={6} className="text-center text-ss-text-muted py-12">
                      Aucune classe trouvee
                    </td>
                  </tr>
                ) : (
                  classes.map((c, i) => (
                    <tr
                      key={c.id}
                      className={`border-b border-ss-border/50 hover:bg-ss-bg-card/50 transition-colors ${
                        i % 2 === 0 ? 'bg-ss-bg-secondary' : 'bg-transparent'
                      }`}
                    >
                      <td className="px-4 py-3">
                        <span className="text-xs font-medium px-2 py-1 rounded-md bg-ss-cyan/10 text-ss-cyan">
                          {c.niveau}
                        </span>
                      </td>
                      <td className="px-4 py-3 text-ss-text font-medium">{c.nom}</td>
                      <td className="px-4 py-3 text-ss-text-muted hidden sm:table-cell">
                        {c.effectif_max}
                      </td>
                      <td className="px-4 py-3 text-ss-text-muted hidden md:table-cell">
                        {c.titulaire_nom ?? '—'}
                      </td>
                      <td className="px-4 py-3">
                        <span
                          className={`text-xs font-medium px-2 py-1 rounded-md ${
                            c.nb_eleves >= c.effectif_max
                              ? 'bg-red-500/10 text-red-400'
                              : 'bg-green-500/10 text-green-400'
                          }`}
                        >
                          {c.nb_eleves} / {c.effectif_max}
                        </span>
                      </td>
                      <td className="px-4 py-3">
                        <button
                          onClick={() => openEdit(c)}
                          className="text-xs font-medium px-3 py-1.5 rounded-lg border border-ss-border text-ss-text-muted hover:text-ss-text transition-colors"
                        >
                          Modifier
                        </button>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Modal Ajout / Edition */}
      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 px-4">
          <div className="bg-[#141833] rounded-2xl p-6 max-w-md w-full shadow-2xl">
            <div className="flex items-center justify-between mb-5">
              <h2 className="text-lg font-bold text-ss-text">
                {editId ? 'Modifier la classe' : 'Nouvelle classe'}
              </h2>
              <button
                onClick={() => setShowModal(false)}
                className="text-ss-text-muted hover:text-ss-text text-xl leading-none"
              >
                x
              </button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                <label className="block text-xs text-ss-text-muted mb-1">Niveau *</label>
                <select
                  value={formNiveau}
                  onChange={e => setFormNiveau(e.target.value)}
                  className="w-full bg-ss-bg-secondary border border-ss-border text-ss-text rounded-xl px-3 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-ss-cyan/40"
                >
                  {NIVEAUX.map(n => (
                    <option key={n} value={n}>{n}</option>
                  ))}
                </select>
              </div>

              <div>
                <label className="block text-xs text-ss-text-muted mb-1">Nom (A, B, S1...) *</label>
                <input
                  type="text"
                  value={formNom}
                  onChange={e => setFormNom(e.target.value)}
                  placeholder="A"
                  maxLength={10}
                  className="w-full bg-ss-bg-secondary border border-ss-border text-ss-text rounded-xl px-3 py-2.5 text-sm placeholder:text-ss-text-muted focus:outline-none focus:ring-2 focus:ring-ss-cyan/40"
                  required
                />
              </div>

              <div>
                <label className="block text-xs text-ss-text-muted mb-1">Effectif maximum</label>
                <input
                  type="number"
                  value={formEffectif}
                  onChange={e => setFormEffectif(e.target.value)}
                  min="1"
                  max="100"
                  className="w-full bg-ss-bg-secondary border border-ss-border text-ss-text rounded-xl px-3 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-ss-cyan/40"
                />
              </div>

              <div>
                <label className="block text-xs text-ss-text-muted mb-1">Professeur titulaire</label>
                <select
                  value={formTitulaire}
                  onChange={e => setFormTitulaire(e.target.value)}
                  className="w-full bg-ss-bg-secondary border border-ss-border text-ss-text rounded-xl px-3 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-ss-cyan/40"
                >
                  <option value="">Aucun titulaire</option>
                  {profs.map(p => (
                    <option key={p.id} value={p.id}>
                      {p.prenom} {p.nom}
                    </option>
                  ))}
                </select>
              </div>

              {error && (
                <div className="bg-red-500/10 border border-red-500/30 text-red-400 text-sm rounded-xl px-4 py-3">
                  {error}
                </div>
              )}

              <div className="flex gap-3 pt-2">
                <button
                  type="button"
                  onClick={() => setShowModal(false)}
                  className="flex-1 bg-ss-bg-secondary border border-ss-border text-ss-text-muted font-medium text-sm py-2.5 rounded-xl hover:text-ss-text transition-colors"
                >
                  Annuler
                </button>
                <button
                  type="submit"
                  disabled={saving}
                  className="flex-1 bg-ss-cyan text-white font-medium text-sm py-2.5 rounded-xl hover:opacity-90 transition-opacity disabled:opacity-50"
                >
                  {saving ? 'Enregistrement...' : editId ? 'Modifier' : 'Creer'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  )
}

'use client'

import { useEffect, useState, useMemo, useCallback } from 'react'
import { createClient } from '@/lib/supabase/client'
import { useUser } from '@/hooks/useUser'
import { isDemoMode, DEMO_ELEVES, DEMO_CLASSES } from '@/lib/demo-data'

interface Eleve {
  id: string
  nom: string
  prenom: string
  classe_id: string
  sexe: string
  matricule: string
  actif: boolean
  classe_nom?: string
}

interface Classe {
  id: string
  nom: string
  niveau: string
}

export default function ElevesPage() {
  const { user, loading: userLoading } = useUser()
  const [eleves, setEleves] = useState<Eleve[]>([])
  const [classes, setClasses] = useState<Classe[]>([])
  const [loading, setLoading] = useState(true)
  const [search, setSearch] = useState('')
  const [classeFilter, setClasseFilter] = useState('')

  const ecoleId = user?.ecole_id

  const loadData = useCallback(async () => {
    if (!ecoleId) return
    setLoading(true)

    if (isDemoMode()) {
      const mappedEleves: Eleve[] = DEMO_ELEVES.map(e => {
        const cl = DEMO_CLASSES.find(c => c.id === e.classe_id)
        return {
          id: e.id,
          nom: e.nom,
          prenom: e.prenom,
          classe_id: e.classe_id,
          sexe: e.sexe,
          matricule: e.matricule,
          actif: e.actif,
          classe_nom: cl ? `${cl.niveau} ${cl.nom}` : '',
        }
      })
      setEleves(mappedEleves)
      setClasses(DEMO_CLASSES.map(c => ({ id: c.id, nom: c.nom, niveau: c.niveau })))
      setLoading(false)
      return
    }

    const supabase = createClient()
    const [elevesRes, classesRes] = await Promise.all([
      (supabase.from('eleves') as any)
        .select('id, nom, prenom, classe_id, sexe, matricule, actif, classes(nom, niveau)')
        .eq('ecole_id', ecoleId)
        .order('nom', { ascending: true }),
      supabase
        .from('classes')
        .select('id, nom, niveau')
        .eq('ecole_id', ecoleId)
        .order('niveau', { ascending: true }),
    ])

    const rawEleves = (elevesRes.data || []) as any[]
    setEleves(rawEleves.map((e: any) => ({
      id: e.id,
      nom: e.nom,
      prenom: e.prenom,
      classe_id: e.classe_id,
      sexe: e.sexe,
      matricule: e.matricule,
      actif: e.actif,
      classe_nom: e.classes ? `${e.classes.niveau} ${e.classes.nom}` : '',
    })))
    setClasses((classesRes.data || []) as Classe[])
    setLoading(false)
  }, [ecoleId])

  useEffect(() => {
    loadData()
  }, [loadData])

  const filtered = useMemo(() => {
    let result = eleves
    if (classeFilter) {
      result = result.filter(e => e.classe_id === classeFilter)
    }
    if (search.trim()) {
      const q = search.toLowerCase().trim()
      result = result.filter(e =>
        e.nom.toLowerCase().includes(q) ||
        e.prenom.toLowerCase().includes(q) ||
        e.matricule.toLowerCase().includes(q)
      )
    }
    return result
  }, [eleves, classeFilter, search])

  if (userLoading || loading) {
    return (
      <div>
        <div className="h-8 w-56 bg-ss-bg-secondary rounded-lg ss-shimmer mb-6" />
        <div className="h-12 w-full bg-ss-bg-secondary rounded-xl ss-shimmer mb-4" />
        <div className="space-y-3">
          {[...Array(8)].map((_, i) => (
            <div key={i} className="h-14 bg-ss-bg-secondary rounded-xl ss-shimmer" />
          ))}
        </div>
      </div>
    )
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between flex-wrap gap-3">
        <h1 className="text-2xl font-bold text-ss-text">Gestion des Eleves</h1>
        <span className="text-sm text-ss-text-muted">
          {filtered.length} eleve{filtered.length > 1 ? 's' : ''}
        </span>
      </div>

      {/* Filtres */}
      <div className="flex flex-col sm:flex-row gap-3">
        <div className="relative flex-1">
          <span className="absolute left-3 top-1/2 -translate-y-1/2 text-ss-text-muted text-lg">🔍</span>
          <input
            type="text"
            placeholder="Rechercher par nom, prenom ou matricule..."
            value={search}
            onChange={e => setSearch(e.target.value)}
            className="w-full bg-ss-bg-secondary border border-ss-border text-ss-text rounded-xl pl-10 pr-4 py-3 min-h-[48px] text-sm placeholder:text-ss-text-muted focus:outline-none focus:ring-2 focus:ring-ss-cyan/40 transition-colors"
          />
        </div>
        <select
          value={classeFilter}
          onChange={e => setClasseFilter(e.target.value)}
          className="bg-ss-bg-secondary border border-ss-border text-ss-text rounded-xl px-4 py-3 min-h-[48px] text-sm focus:outline-none focus:ring-2 focus:ring-ss-cyan/40 transition-colors"
        >
          <option value="">Toutes les classes</option>
          {classes.map(c => (
            <option key={c.id} value={c.id}>
              {c.niveau} {c.nom}
            </option>
          ))}
        </select>
      </div>

      {/* Tableau */}
      <div className="bg-ss-bg-secondary rounded-xl border border-ss-border overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-sm">
            <thead>
              <tr className="border-b border-ss-border">
                <th className="text-left text-ss-text-muted font-medium px-4 py-3">Nom</th>
                <th className="text-left text-ss-text-muted font-medium px-4 py-3">Prenom</th>
                <th className="text-left text-ss-text-muted font-medium px-4 py-3 hidden sm:table-cell">Classe</th>
                <th className="text-left text-ss-text-muted font-medium px-4 py-3 hidden md:table-cell">Sexe</th>
                <th className="text-left text-ss-text-muted font-medium px-4 py-3 hidden lg:table-cell">Matricule</th>
                <th className="text-left text-ss-text-muted font-medium px-4 py-3">Statut</th>
              </tr>
            </thead>
            <tbody>
              {filtered.length === 0 ? (
                <tr>
                  <td colSpan={6} className="text-center text-ss-text-muted py-12">
                    Aucun eleve trouve
                  </td>
                </tr>
              ) : (
                filtered.map(eleve => (
                  <tr key={eleve.id} className="border-b border-ss-border/50 hover:bg-ss-bg-card/50 transition-colors">
                    <td className="px-4 py-3 text-ss-text font-medium">{eleve.nom}</td>
                    <td className="px-4 py-3 text-ss-text">{eleve.prenom}</td>
                    <td className="px-4 py-3 text-ss-text-secondary hidden sm:table-cell">{eleve.classe_nom}</td>
                    <td className="px-4 py-3 hidden md:table-cell">
                      <span className={`text-xs font-medium px-2 py-1 rounded-md ${
                        eleve.sexe === 'M'
                          ? 'text-ss-cyan bg-ss-cyan/10'
                          : 'text-pink-400 bg-pink-400/10'
                      }`}>
                        {eleve.sexe === 'M' ? 'Masculin' : 'Feminin'}
                      </span>
                    </td>
                    <td className="px-4 py-3 text-ss-text-muted text-xs font-mono hidden lg:table-cell">{eleve.matricule}</td>
                    <td className="px-4 py-3">
                      <span className={`text-xs font-medium px-2 py-1 rounded-md ${
                        eleve.actif
                          ? 'text-ss-green bg-ss-green/10'
                          : 'text-ss-red bg-ss-red/10'
                      }`}>
                        {eleve.actif ? 'Actif' : 'Inactif'}
                      </span>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  )
}

'use client'

import { useEffect, useState, useCallback } from 'react'
import { createClient } from '@/lib/supabase/client'
import { useUser } from '@/hooks/useUser'
import {
  isDemoMode,
  DEMO_CLASSES,
  DEMO_MATIERES,
  DEMO_PROFESSEURS,
  DEMO_EMPLOIS_TEMPS,
} from '@/lib/demo-data'

interface Creneau {
  id: string
  classe_id: string
  matiere_id: string
  prof_id: string
  jour_semaine: number
  heure_debut: string
  heure_fin: string
  salle: string
  matiere_nom?: string
  matiere_couleur?: string
  prof_nom?: string
}

interface Classe {
  id: string
  nom: string
  niveau: string
}

interface Matiere {
  id: string
  nom: string
  couleur?: string
}

interface Prof {
  id: string
  nom: string
  prenom: string
}

const JOURS = [
  { idx: 1, label: 'Lundi' },
  { idx: 2, label: 'Mardi' },
  { idx: 3, label: 'Mercredi' },
  { idx: 4, label: 'Jeudi' },
  { idx: 5, label: 'Vendredi' },
  { idx: 6, label: 'Samedi' },
]

const CRENEAUX_HORAIRES = [
  { debut: '07:00', fin: '08:00' },
  { debut: '08:00', fin: '10:00' },
  { debut: '10:00', fin: '12:00' },
  { debut: '14:00', fin: '16:00' },
  { debut: '16:00', fin: '18:00' },
]

// Heures disponibles par pas de 30 min
function genHeures() {
  const heures: string[] = []
  for (let h = 7; h <= 18; h++) {
    heures.push(`${String(h).padStart(2, '0')}:00`)
    if (h < 18) heures.push(`${String(h).padStart(2, '0')}:30`)
  }
  return heures
}
const HEURES = genHeures()

// 6 couleurs pour les matières
const COULEURS_MATIERES = [
  'bg-blue-500/20 text-blue-300 border-blue-500/30',
  'bg-purple-500/20 text-purple-300 border-purple-500/30',
  'bg-green-500/20 text-green-300 border-green-500/30',
  'bg-orange-500/20 text-orange-300 border-orange-500/30',
  'bg-pink-500/20 text-pink-300 border-pink-500/30',
  'bg-yellow-500/20 text-yellow-300 border-yellow-500/30',
]

function getMatiereCouleur(matiereId: string, matieres: Matiere[]): string {
  const idx = matieres.findIndex(m => m.id === matiereId)
  return COULEURS_MATIERES[idx % COULEURS_MATIERES.length] ?? COULEURS_MATIERES[0]
}

function creneauOverlaps(
  debut1: string,
  fin1: string,
  debut2: string,
  fin2: string
): boolean {
  return debut1 < fin2 && fin1 > debut2
}

export default function EmploisTempsPage() {
  const { user, loading: userLoading } = useUser()
  const [classes, setClasses] = useState<Classe[]>([])
  const [matieres, setMatieres] = useState<Matiere[]>([])
  const [profs, setProfs] = useState<Prof[]>([])
  const [emploiDuTemps, setEmploiDuTemps] = useState<Creneau[]>([])
  const [selectedClasse, setSelectedClasse] = useState('')
  const [loading, setLoading] = useState(true)
  const [showModal, setShowModal] = useState(false)
  const [editCreneau, setEditCreneau] = useState<Creneau | null>(null)
  const [selectedJour, setSelectedJour] = useState(1)
  const [saving, setSaving] = useState(false)
  const [deleting, setDeleting] = useState(false)
  const [error, setError] = useState('')

  // Champs formulaire
  const [formMatiere, setFormMatiere] = useState('')
  const [formProf, setFormProf] = useState('')
  const [formDebut, setFormDebut] = useState('08:00')
  const [formFin, setFormFin] = useState('10:00')
  const [formSalle, setFormSalle] = useState('')

  const ecoleId = user?.ecole_id

  // Charger les métadonnées une seule fois
  const loadMeta = useCallback(async () => {
    if (!ecoleId) return

    if (isDemoMode()) {
      setClasses(DEMO_CLASSES.map(c => ({ id: c.id, nom: c.nom, niveau: c.niveau })))
      setMatieres(DEMO_MATIERES.map(m => ({ id: m.id, nom: m.nom })))
      setProfs(DEMO_PROFESSEURS.map(p => ({ id: p.id, nom: p.nom, prenom: p.prenom })))
      setLoading(false)
      return
    }

    const supabase = createClient()
    const [classesRes, matieresRes, profsRes] = await Promise.all([
      supabase
        .from('classes')
        .select('id, nom, niveau')
        .eq('ecole_id', ecoleId)
        .order('niveau', { ascending: true }),
      (supabase.from('matieres') as any)
        .select('id, nom, couleur')
        .eq('ecole_id', ecoleId)
        .order('nom', { ascending: true }),
      supabase
        .from('utilisateurs')
        .select('id, nom, prenom')
        .eq('ecole_id', ecoleId)
        .eq('role', 'professeur')
        .order('nom', { ascending: true }),
    ])

    setClasses((classesRes.data || []) as Classe[])
    setMatieres((matieresRes.data || []) as Matiere[])
    setProfs((profsRes.data || []) as Prof[])
    setLoading(false)
  }, [ecoleId])

  useEffect(() => {
    loadMeta()
  }, [loadMeta])

  // Charger l'emploi du temps quand la classe change
  const loadEDT = useCallback(async () => {
    if (!ecoleId || !selectedClasse) {
      setEmploiDuTemps([])
      return
    }

    if (isDemoMode()) {
      const filtered = DEMO_EMPLOIS_TEMPS.filter(e => e.classe_id === selectedClasse)
      setEmploiDuTemps(
        filtered.map(e => {
          const m = DEMO_MATIERES.find(m => m.id === e.matiere_id)
          const p = DEMO_PROFESSEURS.find(p => p.id === e.prof_id)
          return {
            id: e.id,
            classe_id: e.classe_id,
            matiere_id: e.matiere_id,
            prof_id: e.prof_id,
            jour_semaine: e.jour_semaine,
            heure_debut: e.heure_debut,
            heure_fin: e.heure_fin,
            salle: e.salle,
            matiere_nom: m?.nom,
            prof_nom: p ? `${p.prenom} ${p.nom}` : undefined,
          }
        })
      )
      return
    }

    const supabase = createClient()
    const { data } = await (supabase.from('emplois_temps') as any)
      .select('*, matieres(nom, couleur), utilisateurs(nom, prenom)')
      .eq('ecole_id', ecoleId)
      .eq('classe_id', selectedClasse)

    const raw = (data || []) as any[]
    setEmploiDuTemps(
      raw.map((e: any) => ({
        id: e.id,
        classe_id: e.classe_id,
        matiere_id: e.matiere_id,
        prof_id: e.prof_id,
        jour_semaine: e.jour_semaine,
        heure_debut: e.heure_debut,
        heure_fin: e.heure_fin,
        salle: e.salle,
        matiere_nom: e.matieres?.nom,
        matiere_couleur: e.matieres?.couleur,
        prof_nom: e.utilisateurs
          ? `${e.utilisateurs.prenom} ${e.utilisateurs.nom}`
          : undefined,
      }))
    )
  }, [ecoleId, selectedClasse])

  useEffect(() => {
    loadEDT()
  }, [loadEDT])

  // Sélectionner la 1ère classe par défaut
  useEffect(() => {
    if (classes.length > 0 && !selectedClasse) {
      setSelectedClasse(classes[0].id)
    }
  }, [classes, selectedClasse])

  const resetForm = () => {
    setFormMatiere('')
    setFormProf('')
    setFormDebut('08:00')
    setFormFin('10:00')
    setFormSalle('')
    setError('')
    setEditCreneau(null)
  }

  const openAddModal = (jour: number) => {
    resetForm()
    setSelectedJour(jour)
    setShowModal(true)
  }

  const openEditModal = (c: Creneau) => {
    setEditCreneau(c)
    setSelectedJour(c.jour_semaine)
    setFormMatiere(c.matiere_id)
    setFormProf(c.prof_id)
    setFormDebut(c.heure_debut)
    setFormFin(c.heure_fin)
    setFormSalle(c.salle)
    setError('')
    setShowModal(true)
  }

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!ecoleId || !selectedClasse) return
    if (!formMatiere || !formProf) {
      setError('Matiere et Professeur sont obligatoires.')
      return
    }
    if (formDebut >= formFin) {
      setError("L'heure de fin doit etre apres l'heure de debut.")
      return
    }

    setSaving(true)
    setError('')

    if (isDemoMode()) {
      const matObj = DEMO_MATIERES.find(m => m.id === formMatiere)
      const profObj = DEMO_PROFESSEURS.find(p => p.id === formProf)
      if (editCreneau) {
        setEmploiDuTemps(prev =>
          prev.map(c =>
            c.id === editCreneau.id
              ? {
                  ...c,
                  matiere_id: formMatiere,
                  prof_id: formProf,
                  heure_debut: formDebut,
                  heure_fin: formFin,
                  salle: formSalle,
                  matiere_nom: matObj?.nom,
                  prof_nom: profObj ? `${profObj.prenom} ${profObj.nom}` : undefined,
                }
              : c
          )
        )
      } else {
        const newC: Creneau = {
          id: `edt-demo-${Date.now()}`,
          classe_id: selectedClasse,
          matiere_id: formMatiere,
          prof_id: formProf,
          jour_semaine: selectedJour,
          heure_debut: formDebut,
          heure_fin: formFin,
          salle: formSalle,
          matiere_nom: matObj?.nom,
          prof_nom: profObj ? `${profObj.prenom} ${profObj.nom}` : undefined,
        }
        setEmploiDuTemps(prev => [...prev, newC])
      }
      setShowModal(false)
      setSaving(false)
      return
    }

    try {
      const supabase = createClient()
      const payload = {
        ecole_id: ecoleId,
        classe_id: selectedClasse,
        matiere_id: formMatiere,
        prof_id: formProf,
        jour_semaine: selectedJour,
        heure_debut: formDebut,
        heure_fin: formFin,
        salle: formSalle,
      }

      if (editCreneau) {
        await (supabase.from('emplois_temps') as any).update(payload).eq('id', editCreneau.id)
      } else {
        await (supabase.from('emplois_temps') as any).insert(payload)
      }

      await loadEDT()
      setShowModal(false)
    } catch {
      setError('Une erreur inattendue est survenue.')
    } finally {
      setSaving(false)
    }
  }

  const handleDelete = async () => {
    if (!editCreneau) return
    setDeleting(true)

    if (isDemoMode()) {
      setEmploiDuTemps(prev => prev.filter(c => c.id !== editCreneau.id))
      setShowModal(false)
      setDeleting(false)
      return
    }

    try {
      const supabase = createClient()
      await (supabase.from('emplois_temps') as any).delete().eq('id', editCreneau.id)
      await loadEDT()
      setShowModal(false)
    } catch {
      setError('Erreur lors de la suppression.')
    } finally {
      setDeleting(false)
    }
  }

  // Trouver les cours pour un créneau horaire et un jour donnés
  const getCoursForCell = (jour: number, debutCreneau: string, finCreneau: string): Creneau[] => {
    return emploiDuTemps.filter(
      c =>
        c.jour_semaine === jour &&
        creneauOverlaps(c.heure_debut, c.heure_fin, debutCreneau, finCreneau)
    )
  }

  if (userLoading || loading) {
    return (
      <div>
        <div className="h-8 w-64 bg-ss-bg-secondary rounded-lg ss-shimmer mb-6" />
        <div className="h-12 w-full bg-ss-bg-secondary rounded-xl ss-shimmer mb-6" />
        <div className="h-[400px] bg-ss-bg-secondary rounded-xl ss-shimmer" />
      </div>
    )
  }

  if (!ecoleId) return null

  return (
    <div className="space-y-6">
      {/* En-tête */}
      <div className="flex items-center justify-between flex-wrap gap-3">
        <h1 className="text-2xl font-bold text-ss-text">Emplois du Temps</h1>
        <select
          value={selectedClasse}
          onChange={e => setSelectedClasse(e.target.value)}
          className="bg-ss-bg-secondary border border-ss-border text-ss-text rounded-xl px-4 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-ss-cyan/40"
        >
          {classes.length === 0 && (
            <option value="">Aucune classe disponible</option>
          )}
          {classes.map(c => (
            <option key={c.id} value={c.id}>
              {c.niveau} {c.nom}
            </option>
          ))}
        </select>
      </div>

      {/* Légende couleurs */}
      <div className="flex flex-wrap gap-2">
        {matieres.map((m, i) => (
          <span
            key={m.id}
            className={`text-xs font-medium px-2 py-1 rounded-md border ${COULEURS_MATIERES[i % COULEURS_MATIERES.length]}`}
          >
            {m.nom}
          </span>
        ))}
      </div>

      {/* Grille emploi du temps */}
      {selectedClasse ? (
        <div className="overflow-x-auto rounded-xl border border-ss-border">
          <table className="w-full text-xs min-w-[700px]">
            <thead>
              <tr className="bg-ss-bg-secondary">
                <th className="text-left text-ss-text-muted font-medium px-3 py-3 w-24 border-r border-ss-border">
                  Horaire
                </th>
                {JOURS.map(j => (
                  <th
                    key={j.idx}
                    className="text-center text-ss-text-muted font-medium uppercase px-3 py-3 border-r border-ss-border last:border-r-0"
                  >
                    {j.label}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {CRENEAUX_HORAIRES.map((cr, rowIdx) => (
                <tr
                  key={cr.debut}
                  className={`border-t border-ss-border ${rowIdx % 2 === 0 ? 'bg-ss-bg-secondary/30' : ''}`}
                >
