'use client'

import { useEffect, useState, useCallback } from 'react'
import { createClient } from '@/lib/supabase/client'
import { useUser } from '@/hooks/useUser'
import { StatCard } from '@/components/dashboard/StatCard'
import { FinanceCharts } from '@/components/finance/FinanceCharts'
import { TableauImpayes } from '@/components/finance/TableauImpayes'
import { formatFCFA } from '@/lib/utils'
import { isDemoMode, DEMO_FACTURES, DEMO_PAIEMENTS, DEMO_ELEVES } from '@/lib/demo-data'

interface KPIs {
  encaisseMois: number
  attenduMois: number
  tauxRecouvrement: number
  impayesRetard: number
  projectionFin: number
}

interface FactureImpayee {
  id: string
  eleve_id: string
  type_frais: string
  montant_total: number
  montant_verse: number
  solde_restant: number
  date_limite: string
  nb_relances: number
  statut: string
  eleve_nom: string
  eleve_prenom: string
  classe_nom: string
  parent_id: string | null
  parent_telephone: string | null
}

interface PaiementMois {
  mois: string
  encaisse: number
  attendu: number
}

interface RepartitionStatut {
  statut: string
  count: number
}

export default function FinancesPage() {
  const { user, loading: userLoading } = useUser()
  const supabase = createClient()

  const [kpis, setKpis] = useState<KPIs | null>(null)
  const [repartition, setRepartition] = useState<RepartitionStatut[]>([])
  const [evolution, setEvolution] = useState<PaiementMois[]>([])
  const [impayes, setImpayes] = useState<FactureImpayee[]>([])
  const [loading, setLoading] = useState(true)

  const ecoleId = user?.ecole_id

  const loadData = useCallback(async () => {
    if (!ecoleId) return
    setLoading(true)

    // Demo mode fallback
    if (isDemoMode()) {
      const now = new Date()
      const firstDayOfMonth = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0]

      const paiementsMois = DEMO_PAIEMENTS.filter(p => p.created_at >= firstDayOfMonth && p.statut_confirmation === 'confirmed')
      const encaisseMois = paiementsMois.reduce((sum, p) => sum + p.montant, 0)
      const attenduMois = DEMO_FACTURES.reduce((sum, f) => sum + f.montant_total, 0)
      const totalVerse = DEMO_FACTURES.reduce((sum, f) => sum + f.montant_verse, 0)
      const tauxRecouvrement = attenduMois > 0 ? Math.round((totalVerse / attenduMois) * 100) : 0
      const impayesRetard = DEMO_FACTURES.filter(f => f.statut === 'en_retard').length
      const joursDuMois = new Date(now.getFullYear(), now.getMonth() + 1, 0).getDate()
      const joursEcoules = now.getDate()
      const projectionFin = joursEcoules > 0 ? Math.round((encaisseMois / joursEcoules) * joursDuMois) : 0

      setKpis({ encaisseMois, attenduMois, tauxRecouvrement, impayesRetard, projectionFin })

      // Répartition
      const statutMap = new Map<string, number>()
      for (const f of DEMO_FACTURES) {
        statutMap.set(f.statut, (statutMap.get(f.statut) || 0) + 1)
      }
      setRepartition(Array.from(statutMap, ([statut, count]) => ({ statut, count })))

      // Évolution (simple: mois courant)
      const moisKey = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`
      setEvolution([{ mois: new Date(moisKey + '-01').toLocaleDateString('fr-SN', { month: 'short' }), encaisse: encaisseMois, attendu: attenduMois }])

      // Impayés
      const impayesFacts = DEMO_FACTURES.filter(f => ['en_attente', 'en_retard', 'partiellement_paye'].includes(f.statut))
      setImpayes(impayesFacts.map(f => {
        const eleve = DEMO_ELEVES.find(e => e.id === f.eleve_id)
        return {
          id: f.id, eleve_id: f.eleve_id, type_frais: f.type_frais, montant_total: f.montant_total,
          montant_verse: f.montant_verse, solde_restant: f.solde_restant, date_limite: f.date_limite,
          nb_relances: f.nb_relances, statut: f.statut,
          eleve_nom: eleve?.nom || '', eleve_prenom: eleve?.prenom || '',
          classe_nom: '', parent_id: eleve?.parent_principal_id || null, parent_telephone: null,
        }
      }))

      setLoading(false)
      return
    }

    const now = new Date()
    const firstDayOfMonth = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0]
    const twelveMonthsAgo = new Date(now.getFullYear() - 1, now.getMonth(), 1).toISOString()

    // Requêtes en parallèle
    const [paiementsRes, facturesRes, impayesRes, allPaiementsRes, allFacturesRes] = await Promise.all([
      // Paiements confirmés ce mois
      supabase
        .from('paiements')
        .select('montant')
        .eq('ecole_id', ecoleId)
        .eq('statut_confirmation', 'confirmed')
        .gte('created_at', firstDayOfMonth),

      // Factures ce mois par statut
      supabase
        .from('factures')
        .select('statut, montant_total, solde_restant')
        .eq('ecole_id', ecoleId),

      // Top impayés
      (supabase.from('factures') as any)
        .select('*, eleves(nom, prenom, classe_id, classes(nom), parent_principal_id)')
        .eq('ecole_id', ecoleId)
        .in('statut', ['en_attente', 'en_retard', 'partiellement_paye'])
        .order('date_limite', { ascending: true })
        .limit(20),

      // Paiements 12 mois
      supabase
        .from('paiements')
        .select('created_at, montant')
        .eq('ecole_id', ecoleId)
        .eq('statut_confirmation', 'confirmed')
        .gte('created_at', twelveMonthsAgo),

      // Toutes factures 12 mois
      supabase
        .from('factures')
        .select('date_emission, montant_total')
        .eq('ecole_id', ecoleId)
        .gte('date_emission', twelveMonthsAgo.split('T')[0]),
    ])

    // KPIs
    const paiementsMois = (paiementsRes.data || []) as { montant: number }[]
    const encaisseMois = paiementsMois.reduce((sum, p) => sum + p.montant, 0)

    const factures = (facturesRes.data || []) as { statut: string; montant_total: number; solde_restant: number }[]
    const attenduMois = factures.reduce((sum, f) => sum + f.montant_total, 0)
    const totalVerse = factures.reduce((sum, f) => sum + (f.montant_total - f.solde_restant), 0)
    const tauxRecouvrement = attenduMois > 0 ? Math.round((totalVerse / attenduMois) * 100) : 0

    const impayesRetard = factures.filter(f => f.statut === 'en_retard').length

    // Projection: on double la tendance des jours écoulés
    const joursDuMois = new Date(now.getFullYear(), now.getMonth() + 1, 0).getDate()
    const joursEcoules = now.getDate()
    const projectionFin = joursEcoules > 0 ? Math.round((encaisseMois / joursEcoules) * joursDuMois) : 0

    setKpis({ encaisseMois, attenduMois, tauxRecouvrement, impayesRetard, projectionFin })

    // Répartition par statut
    const statutMap = new Map<string, number>()
    for (const f of factures) {
      statutMap.set(f.statut, (statutMap.get(f.statut) || 0) + 1)
    }
    setRepartition(Array.from(statutMap, ([statut, count]) => ({ statut, count })))

    // Évolution 12 mois
    const moisMap = new Map<string, { encaisse: number; attendu: number }>()
    for (let i = 11; i >= 0; i--) {
      const d = new Date(now.getFullYear(), now.getMonth() - i, 1)
      const key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`
      moisMap.set(key, { encaisse: 0, attendu: 0 })
    }

    for (const p of (allPaiementsRes.data || []) as { created_at: string; montant: number }[]) {
      const d = new Date(p.created_at)
      const key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`
      const entry = moisMap.get(key)
      if (entry) entry.encaisse += p.montant
    }

    for (const f of (allFacturesRes.data || []) as { date_emission: string; montant_total: number }[]) {
      const d = new Date(f.date_emission)
      const key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`
      const entry = moisMap.get(key)
      if (entry) entry.attendu += f.montant_total
    }

    setEvolution(Array.from(moisMap, ([mois, data]) => ({
      mois: new Date(mois + '-01').toLocaleDateString('fr-SN', { month: 'short' }),
      ...data,
    })))

    // Impayés
    const rawImpayes = (impayesRes.data || []) as any[]
    setImpayes(rawImpayes.map(f => ({
      id: f.id,
      eleve_id: f.eleve_id,
      type_frais: f.type_frais,
      montant_total: f.montant_total,
      montant_verse: f.montant_verse,
      solde_restant: f.solde_restant,
      date_limite: f.date_limite,
      nb_relances: f.nb_relances,
      statut: f.statut,
      eleve_nom: f.eleves?.nom || '',
      eleve_prenom: f.eleves?.prenom || '',
      classe_nom: f.eleves?.classes?.nom || '',
      parent_id: f.eleves?.parent_principal_id || null,
      parent_telephone: null,
    })))

    setLoading(false)
  }, [ecoleId, supabase])

  useEffect(() => {
    loadData()
  }, [loadData])

  // Real-time: refresh on new payments
  useEffect(() => {
    if (isDemoMode() || !ecoleId) return
    const channel = supabase.channel('admin-finances-live')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'paiements', filter: `ecole_id=eq.${ecoleId}` }, () => {
        loadData()
      })
      .on('postgres_changes', { event: '*', schema: 'public', table: 'factures', filter: `ecole_id=eq.${ecoleId}` }, () => {
        loadData()
      })
      .subscribe()
    return () => { supabase.removeChannel(channel) }
  }, [ecoleId, supabase, loadData])

  if (userLoading || loading) {
    return (
      <div>
        <div className="h-8 w-56 bg-ss-bg-secondary rounded-lg ss-shimmer mb-6" />
        <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-4 gap-4 mb-6">
          {[...Array(4)].map((_, i) => (
            <StatCard key={i} title="" value="" icon="" loading />
          ))}
        </div>
        <div className="h-64 bg-ss-bg-secondary rounded-xl ss-shimmer" />
      </div>
    )
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between flex-wrap gap-3">
        <h1 className="text-2xl font-bold text-ss-text">Gestion Financière</h1>
        <ExportButton ecoleId={ecoleId!} />
      </div>

      {/* KPI Cards */}
      {kpis && (
        <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-4 gap-4">
          <StatCard
            title="Encaissé ce mois"
            value={formatFCFA(kpis.encaisseMois)}
            subtitle={`Projection: ${formatFCFA(kpis.projectionFin)}`}
            icon="💰"
            color="green"
          />
          <StatCard
            title="Taux recouvrement"
            value={`${kpis.tauxRecouvrement}%`}
            subtitle={`${formatFCFA(kpis.attenduMois)} attendu`}
            icon="📊"
            color="cyan"
            trend={kpis.tauxRecouvrement >= 70 ? 'up' : 'down'}
            trendValue={`${kpis.tauxRecouvrement}%`}
          />
          <StatCard
            title="Impayés en retard"
            value={kpis.impayesRetard.toString()}
            subtitle="Nécessitent une relance"
            icon="⚠️"
            color="red"
          />
          <StatCard
            title="Projection fin mois"
            value={formatFCFA(kpis.projectionFin)}
            subtitle="Basé sur la tendance actuelle"
            icon="📈"
            color="gold"
          />
        </div>
      )}

      {/* Graphiques */}
      <FinanceCharts
        repartition={repartition}
        evolution={evolution}
        tauxRecouvrement={kpis?.tauxRecouvrement || 0}
      />

      {/* Tableau impayés */}
      <TableauImpayes impayes={impayes} onRefresh={loadData} />
    </div>
  )
}

// Bouton export Excel
function ExportButton({ ecoleId }: { ecoleId: string }) {
  const [exporting, setExporting] = useState(false)

  const handleExport = async () => {
    setExporting(true)
    try {
      const XLSX = await import('xlsx')
      const supabase = createClient()

      // Récupérer données
      const [facturesRes, paiementsRes] = await Promise.all([
        (supabase.from('factures') as any)
          .select('*, eleves(nom, prenom, classe_id, classes(nom))')
          .eq('ecole_id', ecoleId)
          .order('date_emission', { ascending: false }),
        supabase
          .from('paiements')
          .select('*')
          .eq('ecole_id', ecoleId)
          .eq('statut_confirmation', 'confirmed')
          .order('created_at', { ascending: false }),
      ])

      const factures = (facturesRes.data || []) as any[]
      const paiements = (paiementsRes.data || []) as any[]

      // Feuille 1: Récapitulatif
      const recapData = factures.map((f: any) => ({
        'Nom': f.eleves?.nom || '',
        'Prénom': f.eleves?.prenom || '',
        'Classe': f.eleves?.classes?.nom || '',
        'Type frais': f.type_frais,
        'Montant total': f.montant_total,
        'Montant versé': f.montant_verse,
        'Solde restant': f.solde_restant,
        'Statut': f.statut,
        'Date émission': f.date_emission,
        'Date limite': f.date_limite,
        'Nb relances': f.nb_relances,
      }))

      // Feuille 2: Paiements détaillés
      const paiementsData = paiements.map((p: any) => ({
        'Référence': p.reference_transaction || '',
        'Montant': p.montant,
        'Méthode': p.methode,
        'Téléphone': p.telephone_payeur || '',
        'Date': p.created_at?.split('T')[0] || '',
        'Statut': p.statut_confirmation,
      }))

      // Feuille 3: Impayés
      const impayesData = factures
        .filter((f: any) => ['en_attente', 'en_retard', 'partiellement_paye'].includes(f.statut))
        .map((f: any) => ({
          'Nom': f.eleves?.nom || '',
          'Prénom': f.eleves?.prenom || '',
          'Classe': f.eleves?.classes?.nom || '',
          'Type frais': f.type_frais,
          'Montant dû': f.solde_restant,
          'Date limite': f.date_limite,
          'Statut': f.statut,
          'Nb relances': f.nb_relances,
        }))

      const wb = XLSX.utils.book_new()
      XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet(recapData), 'Récapitulatif')
      XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet(paiementsData), 'Paiements')
      XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet(impayesData), 'Impayés')

      const dateStr = new Date().toISOString().split('T')[0]
      XLSX.writeFile(wb, `SmartSchool_Finances_${dateStr}.xlsx`)
    } catch (err) {
      console.error('Erreur export:', err)
    }
    setExporting(false)
  }

  return (
    <button
      onClick={handleExport}
      disabled={exporting}
      className="bg-ss-bg-secondary border border-ss-border text-ss-text px-4 py-2.5 rounded-xl text-sm font-medium hover:bg-ss-bg-card transition-colors disabled:opacity-50 min-h-[44px]"
    >
      {exporting ? 'Export...' : '📥 Export Excel'}
    </button>
  )
}

'use client'

import { useEffect, useState, useCallback } from 'react'
import { createClient } from '@/lib/supabase/client'
import { useUser } from '@/hooks/useUser'
import { StatCard } from '@/components/dashboard/StatCard'
import { formatFCFA } from '@/lib/utils'

interface DashboardData {
  totalEleves: number
  totalProfs: number
  absencesAujourdhui: number
  absencesNonJustifiees: number
  totalImpayes: number
  facturesEnAttente: number
  activiteRecente: { text: string; time: string; color: string }[]
  alertes: { text: string; type: string; color: string }[]
}

export default function AdminDashboard() {
  const { user, loading: userLoading } = useUser()
  const [data, setData] = useState<DashboardData | null>(null)
  const [loading, setLoading] = useState(true)
  const [feedItems, setFeedItems] = useState<{id: string; text: string; time: string; color: string; icon: string}[]>([])
  const [profsPointes, setProfsPointes] = useState(0)

  const ecoleId = user?.ecole_id

  const addFeedItem = useCallback((item: {text: string; color: string; icon: string}) => {
    const newItem = {
      id: Date.now().toString(),
      text: item.text,
      time: new Date().toLocaleTimeString('fr-SN', { hour: '2-digit', minute: '2-digit' }),
      color: item.color,
      icon: item.icon,
    }
    setFeedItems(prev => [newItem, ...prev].slice(0, 20))
  }, [])

  const loadData = useCallback(async () => {
    if (!ecoleId) return
    setLoading(true)
    const supabase = createClient()
    const today = new Date().toISOString().split('T')[0]

    const [elevesRes, profsRes, absencesRes, facturesRes, paiementsRes, notifsRes, pointagesRes] = await Promise.all([
      supabase.from('eleves').select('id', { count: 'exact', head: true }).eq('ecole_id', ecoleId).eq('actif', true),
      supabase.from('utilisateurs').select('id', { count: 'exact', head: true }).eq('ecole_id', ecoleId).eq('role', 'professeur').eq('actif', true),
      (supabase.from('absences_eleves') as any).select('id, justifiee').eq('ecole_id', ecoleId).eq('date_absence', today),
      (supabase.from('factures') as any).select('id, montant_total, montant_verse, solde_restant, statut, date_limite').eq('ecole_id', ecoleId).in('statut', ['en_attente', 'en_retard', 'partiellement_paye']),
      (supabase.from('paiements') as any).select('id, montant, created_at, methode').eq('ecole_id', ecoleId).eq('statut_confirmation', 'confirmed').order('created_at', { ascending: false }).limit(5),
      (supabase.from('notifications') as any).select('id, titre, created_at, type_notif').eq('ecole_id', ecoleId).order('created_at', { ascending: false }).limit(5),
      supabase.from('pointages_profs').select('id', { count: 'exact', head: true }).eq('ecole_id', ecoleId!).eq('date_pointage', today),
    ])

    const absences = (absencesRes.data || []) as any[]
    const factures = (facturesRes.data || []) as any[]
    const paiements = (paiementsRes.data || []) as any[]
    const notifs = (notifsRes.data || []) as any[]

    const totalImpayes = factures.reduce((sum: number, f: any) => sum + (f.solde_restant || 0), 0)
    const facturesEnRetard = factures.filter((f: any) => f.statut === 'en_retard')

    const alertes: any[] = []
    if (facturesEnRetard.length > 0) alertes.push({ text: `${facturesEnRetard.length} facture(s) en retard de paiement`, type: 'Finance', color: 'red' })
    if (absences.length > 0) alertes.push({ text: `${absences.length} absence(s) signalée(s) aujourd'hui`, type: 'Absences', color: 'gold' })
    if (alertes.length === 0) alertes.push({ text: "Aucune alerte — tout est en ordre !", type: 'Info', color: 'green' })

    setData({
      totalEleves: elevesRes.count || 0,
      totalProfs: profsRes.count || 0,
      absencesAujourdhui: absences.length,
      absencesNonJustifiees: absences.filter((a: any) => !a.justifiee).length,
      totalImpayes,
      facturesEnAttente: factures.length,
      activiteRecente: [
        ...paiements.map((p: any) => ({ text: `Paiement ${formatFCFA(p.montant)} (${p.methode})`, time: formatTimeAgo(p.created_at), color: 'green' })),
        ...notifs.slice(0, 3).map((n: any) => ({ text: n.titre, time: formatTimeAgo(n.created_at), color: n.type_notif === 'absence' ? 'gold' : 'cyan' })),
      ].slice(0, 6),
      alertes,
    })
    setProfsPointes(pointagesRes.count || 0)
    setLoading(false)
  }, [ecoleId])

  useEffect(() => { loadData() }, [loadData])

  useEffect(() => {
    if (!ecoleId) return
    const supabase = createClient()
    const channel = supabase.channel('admin_feed')
      .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'pointages_profs', filter: `ecole_id=eq.${ecoleId}` }, (payload: any) => {
        const statut = payload.new.statut
        addFeedItem({
          text: statut === 'a_heure' ? "Professeur pointé à l'heure" : `Retard de ${payload.new.minutes_retard || 0} min`,
          color: statut === 'a_heure' ? 'green' : statut === 'retard_leger' ? 'gold' : 'red',
          icon: statut === 'a_heure' ? '✓' : '⚠',
        })
        setProfsPointes(prev => prev + 1)
      })
      .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'paiements', filter: `ecole_id=eq.${ecoleId}` }, (payload: any) => {
        addFeedItem({ text: `Paiement ${formatFCFA(payload.new.montant)} (${payload.new.methode})`, color: 'green', icon: '💰' })
      })
      .subscribe()
    return () => { supabase.removeChannel(channel) }
  }, [ecoleId, addFeedItem])

  const alertColors: Record<string, { bg: string; color: string; border: string }> = {
    red:   { bg: 'rgba(255,23,68,0.1)',   color: '#FF1744', border: 'rgba(255,23,68,0.2)'   },
    gold:  { bg: 'rgba(255,214,0,0.1)',   color: '#FFD600', border: 'rgba(255,214,0,0.2)'   },
    green: { bg: 'rgba(0,230,118,0.1)',   color: '#00E676', border: 'rgba(0,230,118,0.2)'   },
    cyan:  { bg: 'rgba(0,229,255,0.1)',   color: '#00E5FF', border: 'rgba(0,229,255,0.2)'   },
  }

  if (userLoading || loading) {
    return (
      <div className="space-y-6 animate-fade-in">
        <div className="h-32 rounded-2xl ss-shimmer" style={{ background: 'rgba(255,255,255,0.03)' }} />
        <div className="grid grid-cols-2 xl:grid-cols-4 gap-4">
          {[...Array(4)].map((_, i) => <div key={i} className="h-32 rounded-2xl ss-shimmer" style={{ background: 'rgba(255,255,255,0.03)' }} />)}
        </div>
      </div>
    )
  }

  if (!data) return null

  const presencePct = data.totalProfs ? Math.min(100, Math.round((profsPointes / data.totalProfs) * 100)) : 0

  return (
    <div className="space-y-6 animate-fade-in pb-6">

      {/* ── Bannière Hero ── */}
      <div className="relative rounded-2xl overflow-hidden min-h-[140px]">
        <img
          src="https://images.unsplash.com/photo-1509062522246-3755977927d7?auto=format&fit=crop&w=1200&q=80"
          alt="Tableau de bord"
          className="absolute inset-0 w-full h-full object-cover object-center"
        />
        <div className="absolute inset-0" style={{ background: 'linear-gradient(135deg, rgba(2,6,23,0.95) 0%, rgba(2,6,23,0.6) 100%)' }} />
        <div className="absolute inset-0 flex items-center px-6 py-5">
          <div>
            <div className="flex items-center gap-2 mb-2">
              <div className="w-2 h-2 rounded-full bg-[#00E676] animate-pulse" />
              <span className="text-[#94A3B8] text-xs font-semibold tracking-wider uppercase">Tableau de bord</span>
            </div>
            <h1 className="text-2xl sm:text-3xl font-black text-white leading-tight">
              Bonjour, {user?.prenom} 👋
            </h1>
            <p className="text-[#94A3B8] text-sm mt-1">
              {new Date().toLocaleDateString('fr-SN', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' })}
            </p>
          </div>
        </div>
      </div>

      {/* ── KPI Cards ── */}
      <div className="grid grid-cols-2 xl:grid-cols-4 gap-4">
        <StatCard title="Élèves inscrits" value={data.totalEleves.toLocaleString('fr-FR')} subtitle="actifs" icon="👥" trend="up" trendValue="+12" color="cyan" />
        <StatCard title="Professeurs" value={data.totalProfs} subtitle={`${profsPointes} pointés auj.`} icon="👨‍🏫" color="green" />
        <StatCard title="Absences auj." value={data.absencesAujourdhui} subtitle={`${data.absencesNonJustifiees} non justifiées`} icon="⚠️" color={data.absencesAujourdhui > 5 ? 'red' : 'gold'} />
        <StatCard title="Impayés" value={formatFCFA(data.totalImpayes)} subtitle={`${data.facturesEnAttente} facture(s)`} icon="💰" color="red" />
      </div>

      {/* ── Présence profs + Feed ── */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">

        {/* Présence */}
        <div className="rounded-2xl p-5"
          style={{ background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.07)' }}>
          <h3 className="text-sm font-bold text-[#94A3B8] uppercase tracking-wider mb-4">Présence profs</h3>
          <div className="flex items-end gap-3 mb-3">
            <span className="text-5xl font-black text-white">{profsPointes}</span>
            <span className="text-2xl text-[#475569] mb-1">/ {data.totalProfs}</span>
          </div>
          <div className="w-full h-2 rounded-full mb-2" style={{ background: 'rgba(255,255,255,0.05)' }}>
            <div className="h-2 rounded-full transition-all duration-700"
              style={{ width: `${presencePct}%`, background: 'linear-gradient(90deg, #00853F, #00E676)', boxShadow: '0 0 10px rgba(0,230,118,0.5)' }} />
          </div>
          <p className="text-xs text-[#475569]">{presencePct}% présents aujourd'hui</p>

          {/* Mini légende */}
          <div className="mt-4 pt-4 grid grid-cols-3 gap-2" style={{ borderTop: '1px solid rgba(255,255,255,0.05)' }}>
            {[
              { label: 'À l\'heure', value: profsPointes, color: '#FFFFFF' },
              { label: 'Absents', value: data.totalProfs - profsPointes, color: '#FFFFFF' },
              { label: 'Total', value: data.totalProfs, color: '#FFFFFF' },
            ].map(s => (
              <div key={s.label} className="text-center">
                <p className="text-lg font-black" style={{ color: s.color }}>{s.value}</p>
                <p className="text-[10px] text-[#475569]">{s.label}</p>
              </div>
            ))}
          </div>
        </div>

        {/* Feed temps réel */}
        <div className="lg:col-span-2 rounded-2xl p-5"
          style={{ background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.07)' }}>
          <div className="flex items-center justify-between mb-4">
            <h3 className="text-sm font-bold text-[#94A3B8] uppercase tracking-wider">Activité en direct</h3>
            <span className="flex items-center gap-1.5 text-xs font-semibold" style={{ color: '#00E676' }}>
              <span className="w-1.5 h-1.5 rounded-full bg-[#00E676] animate-pulse" />
              LIVE
            </span>
          </div>
          <div className="space-y-2 max-h-48 overflow-y-auto scrollbar-hide">
            {feedItems.length === 0 ? (
              <div className="flex flex-col items-center justify-center py-8 text-center">
                <div className="w-10 h-10 rounded-xl flex items-center justify-center mb-3"
                  style={{ background: 'rgba(0,229,255,0.1)', border: '1px solid rgba(0,229,255,0.2)' }}>
                  <span className="text-xl">📡</span>
                </div>
                <p className="text-sm text-[#475569]">En attente d'activité...</p>
              </div>
            ) : feedItems.map(item => {
              const c = alertColors[item.color] || alertColors.cyan
              return (
                <div key={item.id} className="flex items-center gap-3 p-3 rounded-xl transition-all duration-200"
                  style={{ background: c.bg, border: `1px solid ${c.border}` }}>
                  <span className="text-base shrink-0">{item.icon}</span>
                  <span className="text-sm text-white flex-1 min-w-0 truncate">{item.text}</span>
                  <span className="text-xs shrink-0" style={{ color: '#475569' }}>{item.time}</span>
                </div>
              )
            })}
          </div>
        </div>
      </div>

      {/* ── Activité + Alertes ── */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">

        {/* Activité récente */}
        <div className="rounded-2xl p-5"
          style={{ background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.07)' }}>
          <h2 className="text-sm font-bold text-[#94A3B8] uppercase tracking-wider mb-4">Activité récente</h2>
          {data.activiteRecente.length === 0 ? (
            <p className="text-sm text-[#475569] text-center py-6">Aucune activité récente</p>
          ) : (
            <div className="space-y-3">
              {data.activiteRecente.map((item, i) => {
                const c = alertColors[item.color] || alertColors.cyan
                return (
                  <div key={i} className="flex items-start gap-3">
                    <div className="w-2 h-2 rounded-full mt-2 shrink-0" style={{ background: c.color, boxShadow: `0 0 6px ${c.color}` }} />
