    prenom: p.prenom,
    telephone: p.telephone,
    role: 'professeur' as Role,
    actif: p.actif,
  })),
  surveillant: [
    {
      id: DEMO_USERS.surveillant.id,
      nom: DEMO_USERS.surveillant.nom,
      prenom: DEMO_USERS.surveillant.prenom,
      telephone: DEMO_USERS.surveillant.telephone,
      role: 'surveillant' as Role,
      actif: DEMO_USERS.surveillant.actif,
    },
  ],
  parent: [
    {
      id: DEMO_USERS.parent.id,
      nom: DEMO_USERS.parent.nom,
      prenom: DEMO_USERS.parent.prenom,
      telephone: DEMO_USERS.parent.telephone,
      role: 'parent' as Role,
      actif: DEMO_USERS.parent.actif,
    },
  ],
  eleve: DEMO_ELEVES.slice(0, 10).map(e => ({
    id: e.id,
    nom: e.nom,
    prenom: e.prenom,
    telephone: '',
    role: 'eleve' as Role,
    actif: e.actif,
  })),
}

export default function UtilisateursPage() {
  const { user, loading: userLoading } = useUser()
  const [onglet, setOnglet] = useState<Role>('professeur')
  const [utilisateurs, setUtilisateurs] = useState<Utilisateur[]>([])
  const [classes, setClasses] = useState<Classe[]>([])
  const [eleves, setEleves] = useState<EleveSimple[]>([])
  const [loading, setLoading] = useState(true)
  const [showModal, setShowModal] = useState(false)
  const [saving, setSaving] = useState(false)
  const [error, setError] = useState('')

  // Champs du formulaire
  const [formPrenom, setFormPrenom] = useState('')
  const [formNom, setFormNom] = useState('')
  const [formEmail, setFormEmail] = useState('')
  const [formTelephone, setFormTelephone] = useState('')
  const [formClasse, setFormClasse] = useState('')
  const [formMatricule, setFormMatricule] = useState('')
  const [formEnfants, setFormEnfants] = useState<string[]>([])

  const ecoleId = user?.ecole_id

  const loadData = useCallback(async () => {
    if (!ecoleId) return
    setLoading(true)

    if (isDemoMode()) {
      setUtilisateurs(DEMO_UTILISATEURS[onglet])
      setClasses(DEMO_CLASSES.map(c => ({ id: c.id, nom: c.nom, niveau: c.niveau })))
      setEleves(DEMO_ELEVES.slice(0, 20).map(e => ({ id: e.id, nom: e.nom, prenom: e.prenom })))
      setLoading(false)
      return
    }

    const supabase = createClient()
    const [usersRes, classesRes, elevesRes] = await Promise.all([
      supabase
        .from('utilisateurs')
        .select('id, nom, prenom, telephone, role, actif')
        .eq('ecole_id', ecoleId)
        .eq('role', onglet)
        .order('nom', { ascending: true }),
      supabase
        .from('classes')
        .select('id, nom, niveau')
        .eq('ecole_id', ecoleId)
        .order('niveau', { ascending: true }),
      (supabase.from('eleves') as any)
        .select('id, nom, prenom')
        .eq('ecole_id', ecoleId)
        .order('nom', { ascending: true }),
    ])

    setUtilisateurs((usersRes.data || []) as Utilisateur[])
    setClasses((classesRes.data || []) as Classe[])
    setEleves((elevesRes.data || []) as EleveSimple[])
    setLoading(false)
  }, [ecoleId, onglet])

  useEffect(() => {
    loadData()
  }, [loadData])

  const resetForm = () => {
    setFormPrenom('')
    setFormNom('')
    setFormEmail('')
    setFormTelephone('')
    setFormClasse('')
    setFormMatricule('')
    setFormEnfants([])
    setError('')
  }

  const openModal = () => {
    resetForm()
    setShowModal(true)
  }

  const handleToggle = async (userId: string, currentActif: boolean) => {
    if (isDemoMode()) {
      setUtilisateurs(prev =>
        prev.map(u => (u.id === userId ? { ...u, actif: !currentActif } : u))
      )
      return
    }
    const supabase = createClient()
    await (supabase.from('utilisateurs') as any)
      .update({ actif: !currentActif })
      .eq('id', userId)
    setUtilisateurs(prev =>
      prev.map(u => (u.id === userId ? { ...u, actif: !currentActif } : u))
    )
  }

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!ecoleId || !user) return
    if (!formPrenom.trim() || !formNom.trim() || !formEmail.trim()) {
      setError('Prénom, Nom et Email sont obligatoires.')
      return
    }

    setSaving(true)
    setError('')

    if (isDemoMode()) {
      const newUser: Utilisateur = {
        id: `demo-${Date.now()}`,
        nom: formNom.trim(),
        prenom: formPrenom.trim(),
        telephone: formTelephone.trim(),
        role: onglet,
        actif: true,
      }
      setUtilisateurs(prev => [...prev, newUser])
      setShowModal(false)
      setSaving(false)
      return
    }

    try {
      const supabase = createClient()
      const tempPwd = generateTempPassword()

      // 1. Créer compte auth
      const { data: authData, error: authError } = await supabase.auth.signUp({
        email: formEmail.trim(),
        password: tempPwd,
      })

      if (authError || !authData.user) {
        setError(authError?.message || 'Erreur lors de la création du compte.')
        setSaving(false)
        return
      }

      const userId = authData.user.id

      // 2. Créer profil utilisateur
      await (supabase.from('utilisateurs') as any).insert({
        id: userId,
        ecole_id: ecoleId,
        nom: formNom.trim(),
        prenom: formPrenom.trim(),
        telephone: formTelephone.trim(),
        role: onglet,
        actif: true,
      })

      // 3. Si élève: créer dans eleves
      if (onglet === 'eleve' && formClasse) {
        await (supabase.from('eleves') as any).insert({
          id: userId,
          ecole_id: ecoleId,
          classe_id: formClasse,
          nom: formNom.trim(),
          prenom: formPrenom.trim(),
          matricule: formMatricule.trim() || `MAT-${Date.now()}`,
          sexe: 'M',
          actif: true,
        })
      }

      // 4. Si parent + enfants: lier les élèves
      if (onglet === 'parent' && formEnfants.length > 0) {
        for (const eleveId of formEnfants) {
          await (supabase.from('eleves') as any)
            .update({ parent_principal_id: userId })
            .eq('id', eleveId)
        }
      }

      await loadData()
      setShowModal(false)
    } catch {
      setError('Une erreur inattendue est survenue.')
    } finally {
      setSaving(false)
    }
  }

  const roleLabel = ONGLETS.find(o => o.key === onglet)?.label ?? ''

  if (userLoading) {
    return (
      <div>
        <div className="h-8 w-56 bg-ss-bg-secondary rounded-lg ss-shimmer mb-6" />
        <div className="h-12 w-full bg-ss-bg-secondary rounded-xl ss-shimmer mb-4" />
        <div className="space-y-3">
          {[...Array(6)].map((_, i) => (
            <div key={i} className="h-14 bg-ss-bg-secondary rounded-xl ss-shimmer" />
          ))}
        </div>
      </div>
    )
  }

  if (!ecoleId) return null

  return (
    <div className="space-y-6">
      {/* En-tête */}
      <div className="flex items-center justify-between flex-wrap gap-3">
        <h1 className="text-2xl font-bold text-ss-text">Gestion des Acces</h1>
        <button
          onClick={openModal}
          className="flex items-center gap-2 bg-ss-cyan text-white font-medium text-sm px-4 py-2.5 rounded-xl hover:opacity-90 transition-opacity"
        >
          <span className="text-lg leading-none">+</span>
          Ajouter {roleLabel.slice(0, -1)}
        </button>
      </div>

      {/* Onglets */}
      <div className="flex gap-1 border-b border-ss-border">
        {ONGLETS.map(o => (
          <button
            key={o.key}
            onClick={() => setOnglet(o.key)}
            className={`px-4 py-2.5 text-sm font-medium transition-all rounded-t-lg ${
              onglet === o.key
                ? 'bg-ss-cyan/10 text-ss-cyan border-b-2 border-ss-cyan'
                : 'text-ss-text-muted hover:text-ss-text'
            }`}
          >
            {o.label}
          </button>
        ))}
      </div>

      {/* Tableau */}
      {loading ? (
        <div className="space-y-3">
          {[...Array(5)].map((_, i) => (
            <div key={i} className="h-14 bg-ss-bg-secondary rounded-xl ss-shimmer" />
          ))}
        </div>
      ) : (
        <div className="bg-ss-bg-secondary rounded-xl border border-ss-border overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead>
                <tr className="border-b border-ss-border">
                  <th className="text-left text-ss-text-muted font-medium px-4 py-3">Nom / Prenom</th>
                  <th className="text-left text-ss-text-muted font-medium px-4 py-3 hidden sm:table-cell">Telephone</th>
                  <th className="text-left text-ss-text-muted font-medium px-4 py-3">Statut</th>
                  <th className="text-left text-ss-text-muted font-medium px-4 py-3">Actions</th>
                </tr>
              </thead>
              <tbody>
                {utilisateurs.length === 0 ? (
                  <tr>
                    <td colSpan={4} className="text-center text-ss-text-muted py-12">
                      Aucun {roleLabel.toLowerCase().slice(0, -1)} trouve
                    </td>
                  </tr>
                ) : (
                  utilisateurs.map((u, i) => (
                    <tr
                      key={u.id}
                      className={`border-b border-ss-border/50 hover:bg-ss-bg-card/50 transition-colors ${
                        i % 2 === 0 ? 'bg-ss-bg-secondary' : 'bg-transparent'
                      }`}
                    >
                      <td className="px-4 py-3">
                        <span className="text-ss-text font-medium">{u.nom}</span>
                        <span className="text-ss-text-muted ml-2">{u.prenom}</span>
                      </td>
                      <td className="px-4 py-3 text-ss-text-muted hidden sm:table-cell">
                        {u.telephone || '—'}
                      </td>
                      <td className="px-4 py-3">
                        <span
                          className={`text-xs font-medium px-2 py-1 rounded-md ${
                            u.actif
                              ? 'bg-green-500/10 text-green-400'
                              : 'bg-red-500/10 text-red-400'
                          }`}
                        >
                          {u.actif ? 'Actif' : 'Inactif'}
                        </span>
                      </td>
                      <td className="px-4 py-3">
                        <button
                          onClick={() => handleToggle(u.id, u.actif)}
                          className={`text-xs font-medium px-3 py-1.5 rounded-lg border transition-colors ${
                            u.actif
                              ? 'border-red-500/30 text-red-400 hover:bg-red-500/10'
                              : 'border-green-500/30 text-green-400 hover:bg-green-500/10'
                          }`}
                        >
                          {u.actif ? 'Desactiver' : 'Activer'}
                        </button>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Modal Ajouter */}
      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 px-4">
          <div className="bg-[#141833] rounded-2xl p-6 max-w-md w-full max-h-[90vh] overflow-y-auto shadow-2xl">
            <div className="flex items-center justify-between mb-5">
              <h2 className="text-lg font-bold text-ss-text">
                Ajouter un {roleLabel.slice(0, -1).toLowerCase()}
              </h2>
              <button
                onClick={() => setShowModal(false)}
                className="text-ss-text-muted hover:text-ss-text text-xl leading-none"
              >
                x
              </button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-4">
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="block text-xs text-ss-text-muted mb-1">Prenom *</label>
                  <input
                    type="text"
                    value={formPrenom}
                    onChange={e => setFormPrenom(e.target.value)}
                    placeholder="Mamadou"
                    className="w-full bg-ss-bg-secondary border border-ss-border text-ss-text rounded-xl px-3 py-2.5 text-sm placeholder:text-ss-text-muted focus:outline-none focus:ring-2 focus:ring-ss-cyan/40"
                    required
                  />
                </div>
                <div>
                  <label className="block text-xs text-ss-text-muted mb-1">Nom *</label>
                  <input
                    type="text"
                    value={formNom}
                    onChange={e => setFormNom(e.target.value)}
                    placeholder="Diallo"
                    className="w-full bg-ss-bg-secondary border border-ss-border text-ss-text rounded-xl px-3 py-2.5 text-sm placeholder:text-ss-text-muted focus:outline-none focus:ring-2 focus:ring-ss-cyan/40"
                    required
                  />
                </div>
              </div>

              <div>
                <label className="block text-xs text-ss-text-muted mb-1">Email *</label>
                <input
                  type="email"
                  value={formEmail}
                  onChange={e => setFormEmail(e.target.value)}
                  placeholder="exemple@email.com"
                  className="w-full bg-ss-bg-secondary border border-ss-border text-ss-text rounded-xl px-3 py-2.5 text-sm placeholder:text-ss-text-muted focus:outline-none focus:ring-2 focus:ring-ss-cyan/40"
                  required
                />
              </div>

              <div>
                <label className="block text-xs text-ss-text-muted mb-1">Telephone</label>
                <input
                  type="tel"
                  value={formTelephone}
                  onChange={e => setFormTelephone(e.target.value)}
                  placeholder="77 123 45 67"
                  className="w-full bg-ss-bg-secondary border border-ss-border text-ss-text rounded-xl px-3 py-2.5 text-sm placeholder:text-ss-text-muted focus:outline-none focus:ring-2 focus:ring-ss-cyan/40"
                />
              </div>

              <div>
                <label className="block text-xs text-ss-text-muted mb-1">Role</label>
                <input
                  type="text"
                  value={roleLabel.slice(0, -1)}
                  readOnly
                  className="w-full bg-ss-bg-secondary/50 border border-ss-border text-ss-text-muted rounded-xl px-3 py-2.5 text-sm cursor-not-allowed"
                />
              </div>

              {/* Champs spécifiques élèves */}
              {onglet === 'eleve' && (
                <>
                  <div>
                    <label className="block text-xs text-ss-text-muted mb-1">Classe</label>
                    <select
                      value={formClasse}
                      onChange={e => setFormClasse(e.target.value)}
                      className="w-full bg-ss-bg-secondary border border-ss-border text-ss-text rounded-xl px-3 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-ss-cyan/40"
                    >
                      <option value="">Selectionner une classe</option>
                      {classes.map(c => (
                        <option key={c.id} value={c.id}>
                          {c.niveau} {c.nom}
                        </option>
                      ))}
                    </select>
                  </div>
                  <div>
                    <label className="block text-xs text-ss-text-muted mb-1">Matricule</label>
                    <input
                      type="text"
                      value={formMatricule}
                      onChange={e => setFormMatricule(e.target.value)}
                      placeholder="MAT-001"
                      className="w-full bg-ss-bg-secondary border border-ss-border text-ss-text rounded-xl px-3 py-2.5 text-sm placeholder:text-ss-text-muted focus:outline-none focus:ring-2 focus:ring-ss-cyan/40"
                    />
                  </div>
                </>
              )}

              {/* Champs spécifiques parents */}
              {onglet === 'parent' && eleves.length > 0 && (
                <div>
                  <label className="block text-xs text-ss-text-muted mb-1">
                    Lier a un eleve (optionnel)
                  </label>
                  <select
                    multiple
                    value={formEnfants}
                    onChange={e =>
                      setFormEnfants(Array.from(e.target.selectedOptions, o => o.value))
                    }
                    className="w-full bg-ss-bg-secondary border border-ss-border text-ss-text rounded-xl px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-ss-cyan/40 min-h-[80px]"
                  >
                    {eleves.map(el => (
                      <option key={el.id} value={el.id}>
                        {el.nom} {el.prenom}
                      </option>
                    ))}
                  </select>
                  <p className="text-xs text-ss-text-muted mt-1">
                    Maintenez Ctrl pour selectionner plusieurs eleves
                  </p>
                </div>
              )}

              {error && (
                <div className="bg-red-500/10 border border-red-500/30 text-red-400 text-sm rounded-xl px-4 py-3">
                  {error}
                </div>
              )}

              <div className="flex gap-3 pt-2">
                <button
                  type="button"
                  onClick={() => setShowModal(false)}
                  className="flex-1 bg-ss-bg-secondary border border-ss-border text-ss-text-muted font-medium text-sm py-2.5 rounded-xl hover:text-ss-text transition-colors"
                >
                  Annuler
                </button>
                <button
                  type="submit"
                  disabled={saving}
                  className="flex-1 bg-ss-cyan text-white font-medium text-sm py-2.5 rounded-xl hover:opacity-90 transition-opacity disabled:opacity-50"
                >
                  {saving ? 'Enregistrement...' : 'Ajouter'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  )
}

'use client'

import { useEffect, useState, useMemo } from 'react'
import { createClient } from '@/lib/supabase/client'
import { useUser } from '@/hooks/useUser'
import {
  isDemoMode, DEMO_ELEVES, DEMO_CLASSES, DEMO_MATIERES,
  DEMO_MOYENNES_TRIMESTRE, DEMO_MOYENNE_GENERALE
} from '@/lib/demo-data'

interface MoyenneMatiere {
  matiere_nom: string
  coeff: number
  moyenne: number
}

function getMention(moy: number): { label: string; color: string } {
  if (moy >= 16) return { label: 'Tres Bien', color: '#00E676' }
  if (moy >= 14) return { label: 'Bien', color: '#00E676' }
  if (moy >= 12) return { label: 'Assez Bien', color: '#00E5FF' }
  if (moy >= 10) return { label: 'Passable', color: '#FFD600' }
  return { label: 'Insuffisant', color: '#FF1744' }
}

function getAppreciation(moy: number): string {
  if (moy >= 16) return 'Excellent travail'
  if (moy >= 14) return 'Bon travail'
  if (moy >= 12) return 'Travail satisfaisant'
  if (moy >= 10) return 'Peut mieux faire'
  if (moy >= 8) return 'Travail insuffisant'
  return 'En grande difficulte'
}

function getCurrentTrimestre() {
  const month = new Date().getMonth() + 1
  if (month >= 10) return 1
  if (month <= 3) return 2
  return 3
}

export default function EleveBulletinsPage() {
  const { user, loading: userLoading } = useUser()
  const supabase = createClient()

  const [trimestre, setTrimestre] = useState(getCurrentTrimestre())
  const [moyennes, setMoyennes] = useState<MoyenneMatiere[]>([])
  const [moyenneGenerale, setMoyenneGenerale] = useState<number | null>(null)
  const [rang, setRang] = useState<number | null>(null)
  const [classeNom, setClasseNom] = useState('')
  const [eleveNom, setEleveNom] = useState('')
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    if (!user) return
    setLoading(true)

    if (isDemoMode()) {
      const demoEleve = DEMO_ELEVES[0]
      const classe = DEMO_CLASSES.find(c => c.id === demoEleve.classe_id)
      setClasseNom(classe ? `${classe.niveau} ${classe.nom}` : '')
      setEleveNom(`${demoEleve.prenom} ${demoEleve.nom}`)

      const moys = DEMO_MOYENNES_TRIMESTRE.filter(m => m.trimestre === trimestre)
      setMoyennes(moys.map(m => ({
        matiere_nom: m.matiere_nom,
        coeff: m.coeff_matiere,
        moyenne: m.moyenne_matiere,
      })))
      setMoyenneGenerale(DEMO_MOYENNE_GENERALE.moyenne_generale)
      setRang(DEMO_MOYENNE_GENERALE.rang)
      setLoading(false)
      return
    }

    async function loadBulletin() {
      const { data: eleveData } = await (supabase.from('eleves') as any)
        .select('id, nom, prenom, classe_id, classes(nom, niveau)')
        .eq('user_id', user!.id).limit(1).maybeSingle()
      if (!eleveData) { setLoading(false); return }

      setEleveNom(`${eleveData.prenom} ${eleveData.nom}`)
      setClasseNom(eleveData.classes ? `${eleveData.classes.niveau} ${eleveData.classes.nom}` : '')

      const [moyRes, genRes] = await Promise.all([
        (supabase.from('v_moyennes_trimestre') as any)
          .select('matiere_nom, coeff_matiere, moyenne_matiere')
          .eq('eleve_id', eleveData.id).eq('trimestre', trimestre),
        (supabase.from('v_moyennes_generales') as any)
          .select('moyenne_generale, rang')
          .eq('eleve_id', eleveData.id).eq('trimestre', trimestre).maybeSingle(),
      ])

      if (moyRes.data) setMoyennes((moyRes.data as any[]).map((m: any) => ({
        matiere_nom: m.matiere_nom, coeff: m.coeff_matiere, moyenne: m.moyenne_matiere,
      })))
      if (genRes.data) { setMoyenneGenerale(genRes.data.moyenne_generale); setRang(genRes.data.rang) }
      setLoading(false)
    }
    loadBulletin()
  }, [user, trimestre, supabase])

  const mention = useMemo(() => moyenneGenerale !== null ? getMention(moyenneGenerale) : null, [moyenneGenerale])

  if (userLoading) {
    return <div className="space-y-4">{[...Array(4)].map((_, i) => <div key={i} className="h-28 rounded-2xl ss-shimmer" style={{ background: 'rgba(255,255,255,0.03)' }} />)}</div>
  }

  return (
    <div className="space-y-5 pb-6 animate-fade-in">
      {/* Header */}
      <div className="flex items-center justify-between flex-wrap gap-3">
        <div>
          <h1 className="text-2xl font-black text-white">Mes Bulletins</h1>
          <p className="text-sm mt-1" style={{ color: '#94A3B8' }}>{eleveNom} — {classeNom}</p>
        </div>
        <div className="flex items-center gap-1 p-1 rounded-xl" style={{ background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.08)' }}>
          {[1, 2, 3].map(t => (
            <button key={t} onClick={() => setTrimestre(t)}
              className="px-4 py-2 rounded-lg text-sm font-bold transition-all"
              style={{
                background: trimestre === t ? 'rgba(213,0,249,0.15)' : 'transparent',
                color: trimestre === t ? '#D500F9' : '#94A3B8',
                border: trimestre === t ? '1px solid rgba(213,0,249,0.3)' : '1px solid transparent',
              }}>
              T{t}
            </button>
          ))}
        </div>
      </div>

      {/* Bulletin */}
      {loading ? (
        <div className="space-y-3">{[...Array(8)].map((_, i) => <div key={i} className="h-14 rounded-xl ss-shimmer" style={{ background: 'rgba(255,255,255,0.03)' }} />)}</div>
      ) : moyennes.length === 0 ? (
        <div className="rounded-2xl p-10 text-center" style={{ background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.07)' }}>
          <div className="w-14 h-14 rounded-2xl flex items-center justify-center mx-auto mb-4 text-3xl" style={{ background: 'rgba(255,255,255,0.04)', border: '1px solid rgba(255,255,255,0.08)' }}>📭</div>
          <p className="text-white font-semibold">Aucun bulletin disponible</p>
          <p className="text-sm mt-1" style={{ color: '#94A3B8' }}>Le bulletin du trimestre {trimestre} n&apos;est pas encore disponible</p>
        </div>
      ) : (
        <>
          {/* Table */}
          <div className="rounded-2xl overflow-hidden" style={{ background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.07)' }}>
            {/* Table header */}
            <div className="grid grid-cols-12 gap-2 px-5 py-3" style={{ background: 'rgba(255,255,255,0.03)', borderBottom: '1px solid rgba(255,255,255,0.07)' }}>
              <div className="col-span-5 text-xs font-bold uppercase tracking-wider" style={{ color: '#475569' }}>Matiere</div>
              <div className="col-span-2 text-xs font-bold uppercase tracking-wider text-center" style={{ color: '#475569' }}>Coeff</div>
              <div className="col-span-2 text-xs font-bold uppercase tracking-wider text-center" style={{ color: '#475569' }}>Moyenne</div>
              <div className="col-span-3 text-xs font-bold uppercase tracking-wider text-right" style={{ color: '#475569' }}>Appreciation</div>
            </div>

            {/* Rows */}
            {moyennes.map((m, idx) => {
              const noteColor = m.moyenne >= 14 ? '#00E676' : m.moyenne >= 10 ? '#FFD600' : '#FF1744'
              return (
                <div key={idx} className="grid grid-cols-12 gap-2 px-5 py-3 items-center"
                  style={{ borderBottom: '1px solid rgba(255,255,255,0.04)' }}>
                  <div className="col-span-5 text-sm font-semibold text-white truncate">{m.matiere_nom}</div>
                  <div className="col-span-2 text-sm text-center" style={{ color: '#94A3B8' }}>{m.coeff}</div>
                  <div className="col-span-2 text-center">
                    <span className="text-sm font-black px-2 py-0.5 rounded-md"
                      style={{ background: `${noteColor}15`, color: noteColor }}>
                      {m.moyenne.toFixed(1)}
                    </span>
                  </div>
                  <div className="col-span-3 text-xs text-right" style={{ color: '#94A3B8' }}>{getAppreciation(m.moyenne)}</div>
                </div>
              )
            })}
          </div>

          {/* Summary card */}
          <div className="rounded-2xl p-6" style={{
            background: mention ? `${mention.color}08` : 'rgba(255,255,255,0.03)',
            border: `1px solid ${mention ? `${mention.color}20` : 'rgba(255,255,255,0.07)'}`,
          }}>
            <div className="flex items-center justify-between flex-wrap gap-4">
              <div className="flex items-center gap-5">
                {/* Moyenne */}
                <div className="text-center">
                  <p className="text-xs uppercase tracking-wider mb-1" style={{ color: '#94A3B8' }}>Moyenne Generale</p>
                  <p className="text-4xl font-black" style={{ color: mention?.color || '#fff' }}>
                    {moyenneGenerale !== null ? moyenneGenerale.toFixed(2) : '--'}
                    <span className="text-lg font-bold" style={{ color: '#475569' }}>/20</span>
                  </p>
                </div>
                {/* Divider */}
                <div className="w-px h-16" style={{ background: 'rgba(255,255,255,0.1)' }} />
                {/* Rang */}
                <div className="text-center">
                  <p className="text-xs uppercase tracking-wider mb-1" style={{ color: '#94A3B8' }}>Rang</p>
                  <p className="text-3xl font-black text-white">
                    {rang !== null ? rang : '--'}
                    <span className="text-sm font-bold" style={{ color: '#475569' }}>{rang === 1 ? 'er' : 'e'}</span>
                  </p>
                </div>
              </div>
              {/* Mention */}
              {mention && (
                <div className="px-5 py-2.5 rounded-xl" style={{ background: `${mention.color}15`, border: `1px solid ${mention.color}30` }}>
                  <p className="text-xs uppercase tracking-wider mb-0.5" style={{ color: '#94A3B8' }}>Mention</p>
                  <p className="text-lg font-black" style={{ color: mention.color }}>{mention.label}</p>
                </div>
              )}
            </div>
          </div>
        </>
      )}
    </div>
  )
}

'use client'

import { useEffect, useState, useMemo } from 'react'
import { createClient } from '@/lib/supabase/client'
import { useUser } from '@/hooks/useUser'
import { isDemoMode, DEMO_ELEVES, DEMO_CLASSES } from '@/lib/demo-data'

interface CahierItem {
  id: string
  contenu: string
  date_cours: string
  type: 'cours' | 'devoir'
  matiere_nom: string
}

const DEMO_CAHIER: CahierItem[] = [
  { id: 'ct-001', contenu: 'Resolution d\'equations du second degre. Discriminant et solutions.', date_cours: '2026-03-25', type: 'cours', matiere_nom: 'Mathematiques' },
  { id: 'ct-002', contenu: 'Devoir a rendre : exercices 12 a 18 page 145.', date_cours: '2026-03-25', type: 'devoir', matiere_nom: 'Mathematiques' },
  { id: 'ct-003', contenu: 'Lecture et commentaire du texte de Senghor : Nuit de Sine.', date_cours: '2026-03-24', type: 'cours', matiere_nom: 'Francais' },
  { id: 'ct-004', contenu: 'Vocabulaire chapitre 8. Revisions pour le controle de jeudi.', date_cours: '2026-03-24', type: 'devoir', matiere_nom: 'Anglais' },
  { id: 'ct-005', contenu: 'Les lois de Newton : principe d\'inertie et lois fondamentales de la dynamique.', date_cours: '2026-03-21', type: 'cours', matiere_nom: 'Sciences Physiques' },
  { id: 'ct-006', contenu: 'La photosynthese : chloroplastes, reactions lumineuses et sombres.', date_cours: '2026-03-20', type: 'cours', matiere_nom: 'SVT' },
  { id: 'ct-007', contenu: 'Rediger une dissertation sur la liberte. A remettre lundi.', date_cours: '2026-03-20', type: 'devoir', matiere_nom: 'Philosophie' },
  { id: 'ct-008', contenu: 'La decolonisation en Afrique de l\'Ouest : causes et consequences.', date_cours: '2026-03-19', type: 'cours', matiere_nom: 'Histoire-Geo' },
  { id: 'ct-009', contenu: 'Exercices de conjugaison : le subjonctif present.', date_cours: '2026-03-18', type: 'devoir', matiere_nom: 'Francais' },
  { id: 'ct-010', contenu: 'Introduction aux fonctions derivees. Tangente a une courbe.', date_cours: '2026-03-17', type: 'cours', matiere_nom: 'Mathematiques' },
]

export default function EleveCahierTextePage() {
  const { user, loading: userLoading } = useUser()
  const supabase = createClient()

  const [items, setItems] = useState<CahierItem[]>([])
  const [loading, setLoading] = useState(true)
  const [filtre, setFiltre] = useState<'tous' | 'cours' | 'devoir'>('tous')

  useEffect(() => {
    if (!user) return
    setLoading(true)

    if (isDemoMode()) {
      const demoEleve = DEMO_ELEVES[0]
      // Try real table first, fallback to demo
      ;(async () => {
        try {
          const { data } = await (supabase.from('cahier_texte') as any)
            .select('id, contenu_cours, devoirs, date_seance, matieres(nom)')
            .eq('classe_id', demoEleve.classe_id)
            .order('date_seance', { ascending: false }).limit(20)
          if (data && data.length > 0) {
            const parsed: CahierItem[] = []
            for (const c of data as any[]) {
              if (c.contenu_cours) parsed.push({ id: c.id + '-c', contenu: c.contenu_cours, date_cours: c.date_seance, type: 'cours', matiere_nom: c.matieres?.nom || '' })
              if (c.devoirs) parsed.push({ id: c.id + '-d', contenu: c.devoirs, date_cours: c.date_seance, type: 'devoir', matiere_nom: c.matieres?.nom || '' })
            }
            setItems(parsed.length > 0 ? parsed : DEMO_CAHIER)
          } else {
            setItems(DEMO_CAHIER)
          }
        } catch {
          setItems(DEMO_CAHIER)
        }
        setLoading(false)
      })()
      return
    }

    async function load() {
      const { data: eleveData } = await (supabase.from('eleves') as any)
        .select('id, classe_id').eq('user_id', user!.id).limit(1).maybeSingle()
      if (!eleveData) { setLoading(false); return }
      const { data } = await (supabase.from('cahier_texte') as any)
        .select('id, contenu_cours, devoirs, date_seance, matieres(nom)')
        .eq('classe_id', eleveData.classe_id)
        .order('date_seance', { ascending: false }).limit(30)
      if (data) {
        const parsed: CahierItem[] = []
        for (const c of data as any[]) {
          if (c.contenu_cours) parsed.push({ id: c.id + '-c', contenu: c.contenu_cours, date_cours: c.date_seance, type: 'cours', matiere_nom: c.matieres?.nom || '' })
          if (c.devoirs) parsed.push({ id: c.id + '-d', contenu: c.devoirs, date_cours: c.date_seance, type: 'devoir', matiere_nom: c.matieres?.nom || '' })
        }
        setItems(parsed)
      }
      setLoading(false)
    }
    load()
  }, [user, supabase])

  const filtered = useMemo(() => {
    if (filtre === 'tous') return items
    return items.filter(i => i.type === filtre)
  }, [items, filtre])

  const grouped = useMemo(() => {
    const groups: Record<string, CahierItem[]> = {}
    for (const item of filtered) {
      if (!groups[item.date_cours]) groups[item.date_cours] = []
      groups[item.date_cours].push(item)
    }
    return groups
  }, [filtered])

  const nbCours = items.filter(i => i.type === 'cours').length
  const nbDevoirs = items.filter(i => i.type === 'devoir').length

  if (userLoading) {
    return <div className="space-y-4">{[...Array(5)].map((_, i) => <div key={i} className="h-20 rounded-2xl ss-shimmer" style={{ background: 'rgba(255,255,255,0.03)' }} />)}</div>
  }

  return (
    <div className="space-y-5 pb-6 animate-fade-in">
      {/* Header */}
      <div>
        <h1 className="text-2xl font-black text-white">Cahier de Texte</h1>
        <p className="text-sm mt-1" style={{ color: '#94A3B8' }}>{items.length} entrees</p>
      </div>

      {/* Filter pills */}
      <div className="flex gap-2">
        {([
          { key: 'tous' as const, label: 'Tous', count: items.length },
          { key: 'cours' as const, label: 'Cours', count: nbCours },
          { key: 'devoir' as const, label: 'Devoirs', count: nbDevoirs },
        ]).map(f => (
          <button key={f.key} onClick={() => setFiltre(f.key)}
            className="flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-bold transition-all"
            style={{
              background: filtre === f.key ? 'rgba(213,0,249,0.12)' : 'rgba(255,255,255,0.04)',
              color: filtre === f.key ? '#D500F9' : '#94A3B8',
              border: `1px solid ${filtre === f.key ? 'rgba(213,0,249,0.3)' : 'rgba(255,255,255,0.08)'}`,
            }}>
            {f.label}
            <span className="text-[10px] px-1.5 py-0.5 rounded-full" style={{
              background: filtre === f.key ? 'rgba(213,0,249,0.2)' : 'rgba(255,255,255,0.06)',
              color: filtre === f.key ? '#D500F9' : '#475569',
            }}>{f.count}</span>
          </button>
        ))}
      </div>

      {/* Content */}
      {loading ? (
        <div className="space-y-3">{[...Array(6)].map((_, i) => <div key={i} className="h-20 rounded-xl ss-shimmer" style={{ background: 'rgba(255,255,255,0.03)' }} />)}</div>
      ) : filtered.length === 0 ? (
        <div className="rounded-2xl p-10 text-center" style={{ background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.07)' }}>
          <div className="w-14 h-14 rounded-2xl flex items-center justify-center mx-auto mb-4 text-3xl" style={{ background: 'rgba(255,255,255,0.04)', border: '1px solid rgba(255,255,255,0.08)' }}>📭</div>
          <p className="text-white font-semibold">Aucune entree</p>
          <p className="text-sm mt-1" style={{ color: '#94A3B8' }}>Le cahier de texte est vide</p>
        </div>
      ) : (
        <div className="space-y-6">
          {Object.keys(grouped).sort((a, b) => b.localeCompare(a)).map(date => (
            <div key={date}>
              {/* Date header */}
              <div className="flex items-center gap-3 mb-3">
                <span className="text-xs font-bold uppercase tracking-wider" style={{ color: '#94A3B8' }}>
                  {new Date(date).toLocaleDateString('fr-SN', { weekday: 'long', day: 'numeric', month: 'long' })}
                </span>
                <div className="flex-1 h-px" style={{ background: 'rgba(255,255,255,0.06)' }} />
              </div>

              {/* Entries */}
              <div className="space-y-2">
                {grouped[date].map(item => {
                  const isDevoir = item.type === 'devoir'
                  const color = isDevoir ? '#FF1744' : '#00853F'
                  return (
                    <div key={item.id} className="p-4 rounded-xl" style={{ background: `${color}06`, border: `1px solid ${color}15` }}>
                      <div className="flex items-center gap-2 mb-2">
                        <span className="text-[10px] font-bold px-2 py-0.5 rounded-full" style={{ background: `${color}15`, color }}>
                          {isDevoir ? 'Devoir' : 'Cours'}
                        </span>
                        <span className="text-sm font-semibold text-white">{item.matiere_nom}</span>
                      </div>
                      <p className="text-sm leading-relaxed" style={{ color: '#94A3B8' }}>{item.contenu}</p>
                    </div>
                  )
                })}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  )
}

'use client'

import { useState, useEffect } from 'react'
import { createBrowserClient } from '@supabase/ssr'

interface Cours {
  id: string
  titre: string
  description: string
  type: string
  contenu: string | null
  fichier_url: string | null
  fichier_type: string | null
  created_at: string
  matieres: { nom: string } | null
}

interface Devoir {
  id: string
  titre: string
  description: string
  date_limite: string
  points_max: number
  fichier_url: string | null
  matieres: { nom: string } | null
  soumission?: { id: string; note: number | null; soumis_at: string; commentaire_prof: string | null } | null
}

interface ClasseVirtuelle {
  id: string
  titre: string
  description: string | null
  date_heure: string
  duree_minutes: number
  lien_reunion: string | null
  statut: string
  matieres: { nom: string } | null
  utilisateurs: { nom: string; prenom: string } | null
}

export default function EleveElearningPage() {
  const [tab, setTab] = useState<'cours' | 'devoirs' | 'classes'>('cours')
  const [cours, setCours] = useState<Cours[]>([])
  const [devoirs, setDevoirs] = useState<Devoir[]>([])
  const [classesVirt, setClassesVirt] = useState<ClasseVirtuelle[]>([])
  const [loading, setLoading] = useState(true)
  const [selectedCours, setSelectedCours] = useState<Cours | null>(null)
  const [showSoumission, setShowSoumission] = useState<string | null>(null)
  const [soumissionTexte, setSoumissionTexte] = useState('')
  const [submitting, setSubmitting] = useState(false)

  const supabase = createBrowserClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!
  )

  useEffect(() => { loadData() }, [])

  async function loadData() {
    setLoading(true)
    const { data: { user } } = await supabase.auth.getUser()
    if (!user) { setLoading(false); return }

    // Trouver le profil élève
    const { data: profil } = await (supabase.from('utilisateurs') as any)
      .select('id, ecole_id').eq('id', user.id).single()
    if (!profil) { setLoading(false); return }

    const { data: eleve } = await (supabase.from('eleves') as any)
      .select('id, classe_id').eq('ecole_id', profil.ecole_id).limit(1).single()
    if (!eleve) { setLoading(false); return }

    // Cours de ma classe
    const { data: coursData } = await (supabase.from('cours') as any)
      .select('id, titre, description, type, contenu, fichier_url, fichier_type, created_at, matieres(nom)')
      .eq('classe_id', eleve.classe_id).eq('visible', true)
      .order('created_at', { ascending: false })
    if (coursData) setCours(coursData)

    // Devoirs avec mes soumissions
    const { data: devoirsData } = await (supabase.from('devoirs') as any)
      .select('id, titre, description, date_limite, points_max, fichier_url, matieres(nom)')
      .eq('classe_id', eleve.classe_id).eq('actif', true)
      .order('date_limite', { ascending: true })

    if (devoirsData) {
      const devoirsAvecSoumissions = await Promise.all(
        devoirsData.map(async (d: any) => {
          const { data: soum } = await (supabase.from('soumissions_devoirs') as any)
            .select('id, note, soumis_at, commentaire_prof')
            .eq('devoir_id', d.id).eq('eleve_id', eleve.id).limit(1).single()
          return { ...d, soumission: soum }
        })
      )
      setDevoirs(devoirsAvecSoumissions)
    }

    // Classes virtuelles
    const { data: cvData } = await (supabase.from('classes_virtuelles') as any)
      .select('id, titre, description, date_heure, duree_minutes, lien_reunion, statut, matieres(nom), utilisateurs:prof_id(nom, prenom)')
      .eq('classe_id', eleve.classe_id)
      .gte('date_heure', new Date(Date.now() - 86400000).toISOString())
      .order('date_heure', { ascending: true })
    if (cvData) setClassesVirt(cvData)

    setLoading(false)
  }

  async function soumettre(devoirId: string) {
    if (!soumissionTexte.trim()) return
    setSubmitting(true)
    const { data: { user } } = await supabase.auth.getUser()
    if (!user) { setSubmitting(false); return }
    const { data: profil } = await (supabase.from('utilisateurs') as any)
      .select('ecole_id').eq('id', user.id).single()
    const { data: eleve } = await (supabase.from('eleves') as any)
      .select('id').eq('ecole_id', profil.ecole_id).limit(1).single()

    await (supabase.from('soumissions_devoirs') as any).upsert({
      ecole_id: profil.ecole_id,
      devoir_id: devoirId,
      eleve_id: eleve.id,
      contenu: soumissionTexte,
    }, { onConflict: 'devoir_id,eleve_id' })

    setSoumissionTexte('')
    setShowSoumission(null)
    setSubmitting(false)
    loadData()
  }

  function tempsRestant(dateLimite: string): { texte: string; urgent: boolean } {
    const diff = new Date(dateLimite).getTime() - Date.now()
    if (diff < 0) return { texte: 'Expiré', urgent: true }
    const heures = Math.floor(diff / 3600000)
    const jours = Math.floor(heures / 24)
    if (jours > 3) return { texte: `${jours} jours`, urgent: false }
    if (jours > 0) return { texte: `${jours}j ${heures % 24}h`, urgent: true }
    return { texte: `${heures}h`, urgent: true }
  }

  const tabs = [
    { key: 'cours' as const, label: '📚 Cours', count: cours.length },
    { key: 'devoirs' as const, label: '📝 Devoirs', count: devoirs.length },
    { key: 'classes' as const, label: '🎥 Classes virtuelles', count: classesVirt.length },
  ]

  if (loading) {
    return (
      <div className="p-6 space-y-4">
        <h1 className="text-2xl font-bold text-ss-text">💻 E-Learning</h1>
        {[1, 2, 3].map(i => <div key={i} className="bg-ss-bg-secondary rounded-xl h-32 ss-shimmer" />)}
      </div>
    )
  }

  return (
    <div className="p-6 space-y-6">
      <div>
        <h1 className="text-2xl font-bold text-ss-text">💻 E-Learning</h1>
        <p className="text-ss-text-secondary text-sm">Cours, devoirs et classes virtuelles</p>
        <div className="flex h-1 rounded-full overflow-hidden mt-3 max-w-xs">
          <div className="flex-1 bg-[#00853F]" /><div className="flex-1 bg-[#FDEF42]" /><div className="flex-1 bg-[#E31B23]" />
        </div>
      </div>

      {/* Tabs */}
      <div className="flex gap-1 bg-ss-bg-secondary rounded-lg p-1">
        {tabs.map(t => (
          <button key={t.key} onClick={() => setTab(t.key)}
            className={`flex-1 px-4 py-2 rounded-md text-sm font-medium transition-colors ${tab === t.key ? 'bg-[#00853F] text-white' : 'text-ss-text-secondary hover:text-ss-text'}`}>
            {t.label} ({t.count})
          </button>
        ))}
      </div>

      {/* === COURS === */}
      {tab === 'cours' && (
        <div className="space-y-4">
          {selectedCours ? (
            <div className="bg-ss-bg-secondary rounded-xl p-6">
              <button onClick={() => setSelectedCours(null)} className="text-sm text-[#00853F] mb-4">← Retour aux cours</button>
              <div className="flex items-center gap-2 mb-2">
                <span className="px-2 py-1 rounded text-xs bg-blue-500/20 text-blue-400">{selectedCours.matieres?.nom}</span>
                <span className="px-2 py-1 rounded text-xs bg-ss-bg-card text-ss-text-muted">{selectedCours.type}</span>
              </div>
              <h2 className="text-xl font-bold text-ss-text mb-4">{selectedCours.titre}</h2>
              <p className="text-ss-text-secondary mb-4">{selectedCours.description}</p>
              {selectedCours.contenu && (
                <div className="bg-ss-bg-card rounded-lg p-4 text-ss-text whitespace-pre-wrap">{selectedCours.contenu}</div>
              )}
              {selectedCours.fichier_url && (
                <a href={selectedCours.fichier_url} target="_blank" className="mt-4 inline-block px-4 py-2 bg-[#00853F] text-white rounded-lg">
                  📥 Télécharger le fichier ({selectedCours.fichier_type})
                </a>
              )}
            </div>
          ) : (
            <>
              {cours.length === 0 ? (
                <div className="text-center py-12 text-ss-text-muted">
                  <p className="text-4xl mb-3">📚</p><p>Aucun cours disponible pour le moment</p>
                </div>
              ) : cours.map(c => (
                <div key={c.id} onClick={() => setSelectedCours(c)}
                  className="bg-ss-bg-secondary rounded-xl p-4 cursor-pointer hover:bg-ss-bg-card transition-colors">
                  <div className="flex items-center justify-between">
                    <div>
                      <div className="flex items-center gap-2 mb-1">
                        <span className="text-lg">{c.type === 'cours' ? '📖' : c.type === 'exercice' ? '✏️' : '📎'}</span>
                        <span className="px-2 py-0.5 rounded text-xs bg-blue-500/20 text-blue-400">{c.matieres?.nom}</span>
