                  </a>
                )}
              </div>
            )
          })}
        </div>
      )}
    </div>
  )
}

'use client'

import { useEffect, useState, useMemo } from 'react'
import { createClient } from '@/lib/supabase/client'
import { useUser } from '@/hooks/useUser'
import { isDemoMode, DEMO_ELEVES, DEMO_EMPLOIS_TEMPS, DEMO_MATIERES, DEMO_CLASSES } from '@/lib/demo-data'

interface CoursItem {
  id: string
  jour: number
  heure_debut: string
  heure_fin: string
  matiere_nom: string
  salle: string
}

const JOUR_LABELS: Record<number, string> = { 1: 'Lundi', 2: 'Mardi', 3: 'Mercredi', 4: 'Jeudi', 5: 'Vendredi', 6: 'Samedi' }
const JOUR_SHORT: Record<number, string> = { 0: 'Sem', 1: 'Lun', 2: 'Mar', 3: 'Mer', 4: 'Jeu', 5: 'Ven', 6: 'Sam' }
const MATIERE_COLORS = ['#00E676', '#00E5FF', '#FFD600', '#D500F9', '#FF6D00', '#FF1744', '#448AFF']

export default function EleveEmploiTempsPage() {
  const { user, loading: userLoading } = useUser()
  const supabase = createClient()

  const [emploi, setEmploi] = useState<CoursItem[]>([])
  const [loading, setLoading] = useState(true)
  const [selectedJour, setSelectedJour] = useState(0) // 0 = Semaine entiere

  const today = new Date()
  const jourSemaine = today.getDay() === 0 ? 7 : today.getDay()
  const now = today.toLocaleTimeString('fr-SN', { hour: '2-digit', minute: '2-digit' })

  useEffect(() => {
    if (!user) return
    setLoading(true)

    if (isDemoMode()) {
      const demoEleve = DEMO_ELEVES[0]
      const items = DEMO_EMPLOIS_TEMPS
        .filter(e => e.classe_id === demoEleve.classe_id)
        .map(e => ({
          id: e.id,
          jour: e.jour_semaine,
          heure_debut: e.heure_debut,
          heure_fin: e.heure_fin,
          matiere_nom: DEMO_MATIERES.find(m => m.id === e.matiere_id)?.nom || '',
          salle: e.salle,
        }))
      setEmploi(items)
      setLoading(false)
      return
    }

    async function load() {
      const { data: eleveData } = await (supabase.from('eleves') as any)
        .select('id, classe_id').eq('user_id', user!.id).limit(1).maybeSingle()
      if (!eleveData) { setLoading(false); return }
      const { data } = await (supabase.from('emplois_temps') as any)
        .select('id, jour, heure_debut, heure_fin, salle, matieres(nom)')
        .eq('classe_id', eleveData.classe_id).order('jour').order('heure_debut')
      if (data) setEmploi((data as any[]).map((e: any) => ({
        id: e.id, jour: e.jour, heure_debut: e.heure_debut, heure_fin: e.heure_fin,
        matiere_nom: e.matieres?.nom || '', salle: e.salle || '',
      })))
      setLoading(false)
    }
    load()
  }, [user, supabase])

  const matiereColorMap = useMemo(() => {
    const map: Record<string, string> = {}
    let idx = 0
    for (const item of emploi) {
      if (!map[item.matiere_nom]) { map[item.matiere_nom] = MATIERE_COLORS[idx % MATIERE_COLORS.length]; idx++ }
    }
    return map
  }, [emploi])

  const filteredEmploi = useMemo(() => {
    if (selectedJour === 0) return emploi
    return emploi.filter(e => e.jour === selectedJour)
  }, [emploi, selectedJour])

  const groupedByJour = useMemo(() => {
    const groups: Record<number, CoursItem[]> = {}
    for (const item of filteredEmploi) {
      if (!groups[item.jour]) groups[item.jour] = []
      groups[item.jour].push(item)
    }
    for (const key in groups) {
      groups[key].sort((a, b) => a.heure_debut.localeCompare(b.heure_debut))
    }
    return groups
  }, [filteredEmploi])

  if (userLoading) {
    return <div className="space-y-4">{[...Array(5)].map((_, i) => <div key={i} className="h-20 rounded-2xl ss-shimmer" style={{ background: 'rgba(255,255,255,0.03)' }} />)}</div>
  }

  return (
    <div className="space-y-5 pb-6 animate-fade-in">
      {/* Header */}
      <div>
        <h1 className="text-2xl font-black text-white">Mon Emploi du Temps</h1>
        <p className="text-sm mt-1" style={{ color: '#94A3B8' }}>{JOUR_LABELS[jourSemaine]} — {today.toLocaleDateString('fr-SN', { day: 'numeric', month: 'long', year: 'numeric' })}</p>
      </div>

      {/* Day filter */}
      <div className="flex gap-1.5 overflow-x-auto scrollbar-hide pb-1">
        {[0, 1, 2, 3, 4, 5, 6].map(j => {
          const isActive = selectedJour === j
          const isToday = j === jourSemaine
          return (
            <button key={j} onClick={() => setSelectedJour(j)}
              className="px-3.5 py-2 rounded-xl text-xs font-bold whitespace-nowrap transition-all"
              style={{
                background: isActive ? 'rgba(213,0,249,0.15)' : 'rgba(255,255,255,0.04)',
                color: isActive ? '#D500F9' : isToday ? '#D500F9' : '#94A3B8',
                border: `1px solid ${isActive ? 'rgba(213,0,249,0.3)' : isToday ? 'rgba(213,0,249,0.15)' : 'rgba(255,255,255,0.08)'}`,
              }}>
              {JOUR_SHORT[j]}
              {isToday && j !== 0 && <span className="ml-1 w-1.5 h-1.5 rounded-full bg-[#D500F9] inline-block" />}
            </button>
          )
        })}
      </div>

      {/* Content */}
      {loading ? (
        <div className="space-y-3">{[...Array(6)].map((_, i) => <div key={i} className="h-20 rounded-xl ss-shimmer" style={{ background: 'rgba(255,255,255,0.03)' }} />)}</div>
      ) : filteredEmploi.length === 0 ? (
        <div className="rounded-2xl p-10 text-center" style={{ background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.07)' }}>
          <div className="w-14 h-14 rounded-2xl flex items-center justify-center mx-auto mb-4 text-3xl" style={{ background: 'rgba(255,255,255,0.04)', border: '1px solid rgba(255,255,255,0.08)' }}>📭</div>
          <p className="text-white font-semibold">Aucun cours</p>
          <p className="text-sm mt-1" style={{ color: '#94A3B8' }}>
            {selectedJour === 0 ? 'Emploi du temps non disponible' : `Pas de cours ${JOUR_LABELS[selectedJour] || 'ce jour'}`}
          </p>
        </div>
      ) : (
        <div className="space-y-6">
          {Object.keys(groupedByJour).sort((a, b) => Number(a) - Number(b)).map(jourKey => {
            const jour = Number(jourKey)
            const cours = groupedByJour[jour]
            const isToday = jour === jourSemaine
            return (
              <div key={jour}>
                {/* Day header */}
                {selectedJour === 0 && (
                  <div className="flex items-center gap-3 mb-3">
                    <div className="flex items-center gap-2">
                      {isToday && <span className="w-2 h-2 rounded-full bg-[#D500F9] animate-pulse" />}
                      <h2 className="text-sm font-bold uppercase tracking-wider" style={{ color: isToday ? '#D500F9' : '#94A3B8' }}>
                        {JOUR_LABELS[jour]}
                      </h2>
                    </div>
                    <div className="flex-1 h-px" style={{ background: 'rgba(255,255,255,0.06)' }} />
                    <span className="text-xs" style={{ color: '#475569' }}>{cours.length} cours</span>
                  </div>
                )}

                {/* Course cards */}
                <div className="space-y-2">
                  {cours.map(c => {
                    const color = matiereColorMap[c.matiere_nom] || '#00E676'
                    const isCurrent = isToday && c.heure_debut <= now && c.heure_fin > now
                    const isPast = isToday && c.heure_fin < now

                    return (
                      <div key={c.id}
                        className="flex items-center gap-4 p-4 rounded-xl transition-all"
                        style={{
                          background: isCurrent ? `${color}12` : 'rgba(255,255,255,0.03)',
                          border: `1px solid ${isCurrent ? color + '40' : 'rgba(255,255,255,0.07)'}`,
                          opacity: isPast ? 0.5 : 1,
                        }}>
                        <div className="w-1 h-12 rounded-full shrink-0" style={{ background: color }} />
                        <div className="w-16 shrink-0 text-center">
                          <p className="text-sm font-black text-white">{c.heure_debut}</p>
                          <p className="text-xs" style={{ color: '#475569' }}>{c.heure_fin}</p>
                        </div>
                        <div className="flex-1 min-w-0">
                          <p className="text-sm font-bold text-white truncate">{c.matiere_nom}</p>
                          <p className="text-xs mt-0.5" style={{ color: '#94A3B8' }}>{c.salle}</p>
                        </div>
                        {isCurrent && (
                          <span className="text-[10px] font-bold px-2 py-1 rounded-full shrink-0 flex items-center gap-1"
                            style={{ background: `${color}20`, color, border: `1px solid ${color}40` }}>
                            <span className="w-1.5 h-1.5 rounded-full animate-pulse" style={{ background: color }} />
                            EN COURS
                          </span>
                        )}
                      </div>
                    )
                  })}
                </div>
              </div>
            )
          })}
        </div>
      )}
    </div>
  )
}

'use client'

import { useEffect, useState, useCallback, useMemo } from 'react'
import { createClient } from '@/lib/supabase/client'
import { useUser } from '@/hooks/useUser'
import { StatCard } from '@/components/dashboard/StatCard'
import Link from 'next/link'
import {
  isDemoMode, DEMO_ELEVES, DEMO_NOTES, DEMO_ABSENCES,
  DEMO_EMPLOIS_TEMPS, DEMO_MATIERES, DEMO_EVALUATIONS, DEMO_CLASSES
} from '@/lib/demo-data'

interface EleveProfile { id: string; nom: string; prenom: string; classe_id: string; classe_nom: string; matricule: string | null }
interface NoteRecente { id: string; valeur: number; matiere_nom: string; type: string; date_eval: string }
interface AbsenceItem { id: string; date_absence: string; matiere_nom: string; type: string; justifiee: boolean }
interface EmploiTempsItem { id: string; jour: number; heure_debut: string; heure_fin: string; matiere_nom: string; salle: string }
interface CahierTexteItem { id: string; contenu: string; date_cours: string; type: string; matiere_nom: string }

// Fallback demo data used only when no real cahier_texte entries exist
const DEMO_CAHIER_TEXTE_FALLBACK: CahierTexteItem[] = [
  { id: 'ct-001', contenu: 'Résolution d\'équations du second degré. Discriminant et solutions.', date_cours: '2026-03-25', type: 'cours', matiere_nom: 'Mathématiques' },
  { id: 'ct-002', contenu: 'Devoir à rendre : exercices 12 à 18 page 145.', date_cours: '2026-03-25', type: 'devoir', matiere_nom: 'Mathématiques' },
  { id: 'ct-003', contenu: 'Lecture et commentaire du texte de Senghor : «Nuit de Sine».', date_cours: '2026-03-24', type: 'cours', matiere_nom: 'Français' },
  { id: 'ct-004', contenu: 'Vocabulaire chapitre 8. Révisions pour le contrôle de jeudi.', date_cours: '2026-03-24', type: 'devoir', matiere_nom: 'Anglais' },
  { id: 'ct-005', contenu: 'Les lois de Newton : principe d\'inertie et lois fondamentales.', date_cours: '2026-03-21', type: 'cours', matiere_nom: 'Sciences Physiques' },
  { id: 'ct-006', contenu: 'La photosynthèse : chloroplastes, réactions lumineuses et sombres.', date_cours: '2026-03-20', type: 'cours', matiere_nom: 'SVT' },
]

const JOUR_LABELS: Record<number, string> = { 1: 'Lundi', 2: 'Mardi', 3: 'Mercredi', 4: 'Jeudi', 5: 'Vendredi', 6: 'Samedi' }
const HEURES_SLOTS = ['08:00','09:00','10:00','11:00','12:00','14:00','15:00','16:00','17:00']
const MATIERE_COLORS = ['#00E676','#00E5FF','#FFD600','#D500F9','#FF6D00','#FF1744','#448AFF']

function getCurrentTrimestre() {
  const month = new Date().getMonth() + 1
  if (month >= 10) return 1
  if (month <= 3) return 2
  return 3
}


export default function EleveDashboard() {
  const { user, loading: userLoading } = useUser()
  const supabase = createClient()

  const [eleve, setEleve] = useState<EleveProfile | null>(null)
  const [moyenneGenerale, setMoyenneGenerale] = useState<number | null>(null)
  const [rang, setRang] = useState<number | null>(null)
  const [nbAbsences, setNbAbsences] = useState(0)
  const [nbMatieres, setNbMatieres] = useState(0)
  const [notesRecentes, setNotesRecentes] = useState<NoteRecente[]>([])
  const [absences, setAbsences] = useState<AbsenceItem[]>([])
  const [emploiTemps, setEmploiTemps] = useState<EmploiTempsItem[]>([])
  const [cahierTexte, setCahierTexte] = useState<CahierTexteItem[]>([])
  const [loading, setLoading] = useState(true)

  // ── Mode démo ──
  useEffect(() => {
    if (!isDemoMode() || !user) return
    const demoEleve = DEMO_ELEVES[0] // Awa Diallo, 6ème A
    const classe = DEMO_CLASSES.find(c => c.id === demoEleve.classe_id)
    setEleve({
      id: demoEleve.id,
      nom: demoEleve.nom,
      prenom: demoEleve.prenom,
      classe_id: demoEleve.classe_id,
      classe_nom: classe ? `${classe.niveau} ${classe.nom}` : '6ème A',
      matricule: demoEleve.matricule,
    })

    // Notes
    const myNotes = DEMO_NOTES.filter(n => n.eleve_id === demoEleve.id)
    const notesFormatted: NoteRecente[] = myNotes.slice(0, 8).map((n, i) => {
      const eval_ = DEMO_EVALUATIONS.find(e => e.id === n.evaluation_id)
      const matiere = DEMO_MATIERES.find(m => m.id === eval_?.matiere_id)
      return {
        id: `note-${i}`,
        valeur: n.note,
        matiere_nom: matiere?.nom || 'Matière',
        type: eval_?.type_eval || 'devoir',
        date_eval: eval_?.date_eval || '',
      }
    })
    setNotesRecentes(notesFormatted)

    // Moyenne (calcul simple)
    if (notesFormatted.length > 0) {
      const avg = notesFormatted.reduce((s, n) => s + n.valeur, 0) / notesFormatted.length
      setMoyenneGenerale(Math.round(avg * 10) / 10)
      setRang(7)
    }

    // Absences
    const myAbs = DEMO_ABSENCES.filter(a => a.eleve_id === demoEleve.id).slice(0, 6)
    setNbAbsences(myAbs.length)
    setAbsences(myAbs.map(a => ({
      id: a.id,
      date_absence: a.date_absence,
      matiere_nom: 'Cours',
      type: a.type,
      justifiee: a.justifiee,
    })))

    // Emploi du temps
    const myEmploi = DEMO_EMPLOIS_TEMPS.filter(e => e.classe_id === demoEleve.classe_id)
    setEmploiTemps(myEmploi.map(e => ({
      id: e.id,
      jour: e.jour_semaine,
      heure_debut: e.heure_debut,
      heure_fin: e.heure_fin,
      matiere_nom: DEMO_MATIERES.find(m => m.id === e.matiere_id)?.nom || '',
      salle: e.salle,
    })))
    setNbMatieres(new Set(myEmploi.map(e => e.matiere_id)).size)

    // Cahier de texte — try real table first, fallback to demo data
    ;(async () => {
      try {
        const { data: cahierData } = await (supabase.from('cahier_texte') as any)
          .select('id, contenu_cours, devoirs, date_seance, matieres(nom)')
          .eq('classe_id', demoEleve.classe_id)
          .order('date_seance', { ascending: false })
          .limit(8)
        if (cahierData && cahierData.length > 0) {
          const items: CahierTexteItem[] = []
          for (const c of cahierData as any[]) {
            if (c.contenu_cours) {
              items.push({ id: c.id + '-cours', contenu: c.contenu_cours, date_cours: c.date_seance, type: 'cours', matiere_nom: c.matieres?.nom || '' })
            }
            if (c.devoirs) {
              items.push({ id: c.id + '-devoir', contenu: c.devoirs, date_cours: c.date_seance, type: 'devoir', matiere_nom: c.matieres?.nom || '' })
            }
          }
          setCahierTexte(items.length > 0 ? items : DEMO_CAHIER_TEXTE_FALLBACK)
        } else {
          setCahierTexte(DEMO_CAHIER_TEXTE_FALLBACK)
        }
      } catch {
        setCahierTexte(DEMO_CAHIER_TEXTE_FALLBACK)
      }
      setLoading(false)
    })()
  }, [user, supabase])

  // ── Mode réel ──
  useEffect(() => {
    if (isDemoMode() || !user) return
    async function loadEleve() {
      const { data } = await (supabase.from('eleves') as any).select('id, nom, prenom, classe_id, matricule, classes(nom, niveau)').eq('ecole_id', user!.ecole_id).eq('user_id', user!.id).limit(1).maybeSingle()
      if (data) setEleve({ id: data.id, nom: data.nom, prenom: data.prenom, classe_id: data.classe_id, classe_nom: data.classes ? `${data.classes.niveau} ${data.classes.nom}` : '', matricule: data.matricule })
      else setLoading(false)
    }
    loadEleve()
  }, [user, supabase])

  const loadDashboard = useCallback(async () => {
    if (isDemoMode() || !eleve) return
    setLoading(true)
    const trimestre = getCurrentTrimestre()
    const [moyenneRes, notesRes, absencesRes, emploiRes, cahierRes, matieresRes] = await Promise.all([
      (supabase.from('v_moyennes_generales') as any).select('moyenne_generale, rang').eq('eleve_id', eleve.id).eq('trimestre', trimestre).maybeSingle(),
      (supabase.from('notes') as any).select('id, valeur, evaluations(type, date_eval, matieres(nom))').eq('eleve_id', eleve.id).order('created_at', { ascending: false }).limit(10),
      (supabase.from('absences_eleves') as any).select('id, date_absence, type, justifiee, matieres(nom)').eq('eleve_id', eleve.id).order('date_absence', { ascending: false }).limit(10),
      (supabase.from('emplois_temps') as any).select('id, jour, heure_debut, heure_fin, salle, matieres(nom)').eq('classe_id', eleve.classe_id).order('jour').order('heure_debut'),
      (supabase.from('cahier_texte') as any).select('id, contenu_cours, devoirs, date_seance, matieres(nom)').eq('classe_id', eleve.classe_id).order('date_seance', { ascending: false }).limit(8),
      (supabase.from('emplois_temps') as any).select('matiere_id').eq('classe_id', eleve.classe_id),
    ])
    if (moyenneRes.data) { setMoyenneGenerale(moyenneRes.data.moyenne_generale ?? null); setRang(moyenneRes.data.rang ?? null) }
    if (notesRes.data) setNotesRecentes((notesRes.data as any[]).map((n: any) => ({ id: n.id, valeur: n.valeur, matiere_nom: n.evaluations?.matieres?.nom || 'Matière', type: n.evaluations?.type || 'Devoir', date_eval: n.evaluations?.date_eval || '' })))
    if (absencesRes.data) { setNbAbsences((absencesRes.data as any[]).length); setAbsences((absencesRes.data as any[]).map((a: any) => ({ id: a.id, date_absence: a.date_absence, matiere_nom: a.matieres?.nom || 'Non précisé', type: a.type || 'absence', justifiee: a.justifiee ?? false }))) }
    if (emploiRes.data) setEmploiTemps((emploiRes.data as any[]).map((e: any) => ({ id: e.id, jour: e.jour, heure_debut: e.heure_debut, heure_fin: e.heure_fin, matiere_nom: e.matieres?.nom || '', salle: e.salle || '' })))
    if (cahierRes.data) {
      const cahierItems: CahierTexteItem[] = []
      for (const c of cahierRes.data as any[]) {
        if (c.contenu_cours) {
          cahierItems.push({ id: c.id + '-cours', contenu: c.contenu_cours, date_cours: c.date_seance, type: 'cours', matiere_nom: c.matieres?.nom || '' })
        }
        if (c.devoirs) {
          cahierItems.push({ id: c.id + '-devoir', contenu: c.devoirs, date_cours: c.date_seance, type: 'devoir', matiere_nom: c.matieres?.nom || '' })
        }
        if (!c.contenu_cours && !c.devoirs) {
          cahierItems.push({ id: c.id, contenu: '', date_cours: c.date_seance, type: 'cours', matiere_nom: c.matieres?.nom || '' })
        }
      }
      setCahierTexte(cahierItems)
    }
    if (matieresRes.data) setNbMatieres(new Set((matieresRes.data as any[]).map((m: any) => m.matiere_id)).size)
    setLoading(false)
  }, [eleve, supabase])

  useEffect(() => { if (!isDemoMode() && eleve) loadDashboard() }, [eleve, loadDashboard])

  const emploiParJour = useMemo(() => {
    const grouped: Record<number, EmploiTempsItem[]> = {}
    for (let j = 1; j <= 6; j++) grouped[j] = []
    for (const item of emploiTemps) { if (grouped[item.jour]) grouped[item.jour].push(item) }
    return grouped
  }, [emploiTemps])

  const today = new Date()
  const jourSemaine = today.getDay() === 0 ? 7 : today.getDay()
  const matiereColorMap = useMemo(() => {
    const map: Record<string, string> = {}
    let idx = 0
    for (const item of emploiTemps) { if (!map[item.matiere_nom]) { map[item.matiere_nom] = MATIERE_COLORS[idx % MATIERE_COLORS.length]; idx++ } }
    return map
  }, [emploiTemps])

  if (userLoading) {
    return <div className="space-y-4">{[...Array(5)].map((_, i) => <div key={i} className="h-28 rounded-2xl ss-shimmer" style={{ background: 'rgba(255,255,255,0.03)' }} />)}</div>
  }

  const moyColor = moyenneGenerale !== null ? (moyenneGenerale >= 14 ? '#00E676' : moyenneGenerale >= 10 ? '#FFD600' : '#FF1744') : '#00E5FF'

  return (
    <div className="space-y-5 pb-6 animate-fade-in">

      {/* ── Bannière élève ── */}
      <div className="relative rounded-2xl overflow-hidden min-h-[140px]">
        <img src="https://images.unsplash.com/photo-1503676260728-1c00da094a0b?auto=format&fit=crop&w=1200&q=80" alt="Élève" className="absolute inset-0 w-full h-full object-cover" />
        <div className="absolute inset-0" style={{ background: 'linear-gradient(135deg, rgba(2,6,23,0.95) 0%, rgba(2,6,23,0.55) 100%)' }} />
        <div className="relative px-6 py-5 flex items-end gap-4">
          {/* Avatar */}
          <div className="w-14 h-14 rounded-2xl flex items-center justify-center text-xl font-black shrink-0"
            style={{ background: 'linear-gradient(135deg, rgba(213,0,249,0.3), rgba(213,0,249,0.1))', border: '2px solid rgba(213,0,249,0.4)', color: '#D500F9' }}>
            {eleve?.prenom?.[0]}{eleve?.nom?.[0]}
          </div>
          <div>
            <span className="text-xs font-semibold tracking-wider uppercase text-[#94A3B8]">Mon Espace</span>
            <h1 className="text-2xl font-black text-white">{eleve?.prenom} {eleve?.nom}</h1>
            <p className="text-sm mt-0.5" style={{ color: '#94A3B8' }}>{eleve?.classe_nom}{eleve?.matricule && <> · <span style={{ color: '#475569' }}>{eleve.matricule}</span></>}</p>
          </div>
        </div>
      </div>

      {/* ── Stats ── */}
      {loading ? (
        <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">{[...Array(4)].map((_, i) => <div key={i} className="h-28 rounded-2xl ss-shimmer" style={{ background: 'rgba(255,255,255,0.03)' }} />)}</div>
      ) : (
        <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
          <StatCard title="Moyenne générale" value={moyenneGenerale !== null ? `${moyenneGenerale.toFixed(1)}/20` : '--'} subtitle={`Trimestre ${getCurrentTrimestre()}`} icon="📊" color={moyenneGenerale !== null ? (moyenneGenerale >= 10 ? 'green' : 'red') : 'cyan'} />
          <StatCard title="Absences" value={nbAbsences} subtitle="Ce trimestre" icon="📅" color={nbAbsences > 5 ? 'red' : nbAbsences > 0 ? 'gold' : 'green'} />
          <StatCard title="Rang" value={rang !== null ? `${rang}${rang === 1 ? 'er' : 'e'}` : '--'} subtitle="Dans la classe" icon="🏆" color="gold" />
          <StatCard title="Matières" value={nbMatieres} subtitle={eleve?.classe_nom || ''} icon="📚" color="purple" />
        </div>
      )}

      {/* ── Actions rapides ── */}
      <div className="rounded-2xl p-5" style={{ background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.07)' }}>
        <h2 className="text-sm font-bold text-[#94A3B8] uppercase tracking-wider mb-4">Actions rapides</h2>
        <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
          {[
            { href: '/eleve/bulletins',    icon: '📊', label: 'Mes Bulletins',     color: '#D500F9' },
            { href: '/eleve/emploi-temps', icon: '📅', label: 'Emploi du temps',   color: '#00E5FF' },
            { href: '/eleve/cahier-texte', icon: '📚', label: 'Cahier de texte',   color: '#FFD600' },
            { href: '/eleve/elearning',    icon: '💻', label: 'E-Learning',        color: '#00E676' },
          ].map(a => (
            <Link key={a.href} href={a.href}
              className="flex flex-col items-center gap-2 p-4 rounded-xl text-center transition-all duration-200 hover:scale-105 active:scale-95"
              style={{ background: `${a.color}12`, border: `1px solid ${a.color}30` }}>
              <span className="text-2xl">{a.icon}</span>
              <span className="text-xs font-semibold leading-tight text-white">{a.label}</span>
            </Link>
          ))}
        </div>
      </div>

      {/* ── Notes récentes ── */}
      <div className="rounded-2xl p-5" style={{ background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.07)' }}>
        <h2 className="text-sm font-bold text-[#94A3B8] uppercase tracking-wider mb-4">Notes récentes</h2>
        {loading ? (
          <div className="space-y-2">{[...Array(4)].map((_, i) => <div key={i} className="h-10 rounded-xl ss-shimmer" style={{ background: 'rgba(255,255,255,0.03)' }} />)}</div>
        ) : notesRecentes.length === 0 ? (
          <div className="flex flex-col items-center py-8 text-center">
            <div className="w-12 h-12 rounded-2xl flex items-center justify-center mb-3 text-2xl" style={{ background: 'rgba(255,255,255,0.04)', border: '1px solid rgba(255,255,255,0.08)' }}>📭</div>
            <p className="text-sm" style={{ color: '#94A3B8' }}>Aucune note enregistrée</p>
          </div>
        ) : (
          <div className="space-y-2">
            {notesRecentes.map(n => {
              const noteColor = n.valeur >= 14 ? '#00E676' : n.valeur >= 10 ? '#FFD600' : '#FF1744'
              const typeColor = n.type === 'composition' ? '#FF1744' : '#00853F'
              return (
                <div key={n.id} className="flex items-center gap-3 p-3 rounded-xl"
                  style={{ background: 'rgba(255,255,255,0.02)', border: '1px solid rgba(255,255,255,0.05)' }}>
                  <div className="w-10 h-10 rounded-xl flex items-center justify-center font-black text-lg shrink-0"
                    style={{ background: `${noteColor}15`, border: `1px solid ${noteColor}30`, color: noteColor }}>
                    {n.valeur}
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-semibold text-white truncate">{n.matiere_nom}</p>
                    <span className="text-[10px] font-bold px-1.5 py-0.5 rounded-full" style={{ background: `${typeColor}15`, color: typeColor }}>{n.type}</span>
                  </div>
                  <div className="text-right shrink-0">
                    <p className="text-sm font-black text-white">{n.valeur}/20</p>
                    <p className="text-[10px]" style={{ color: '#475569' }}>{n.date_eval ? new Date(n.date_eval).toLocaleDateString('fr-SN', { day: 'numeric', month: 'short' }) : '--'}</p>
                  </div>
                </div>
              )
            })}
          </div>
        )}
      </div>

      {/* ── Emploi du temps ── */}
      <div className="rounded-2xl p-5" style={{ background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.07)' }}>
        <h2 className="text-sm font-bold text-[#94A3B8] uppercase tracking-wider mb-4">Emploi du temps</h2>
        {loading ? <div className="h-64 rounded-xl ss-shimmer" style={{ background: 'rgba(255,255,255,0.03)' }} />
        : emploiTemps.length === 0 ? (
          <div className="flex flex-col items-center py-8 text-center">
            <div className="w-12 h-12 rounded-2xl flex items-center justify-center mb-3 text-2xl" style={{ background: 'rgba(255,255,255,0.04)', border: '1px solid rgba(255,255,255,0.08)' }}>📭</div>
            <p className="text-sm" style={{ color: '#94A3B8' }}>Emploi du temps non disponible</p>
          </div>
        ) : (
          <div className="overflow-x-auto scrollbar-hide">
            <table className="w-full text-xs border-collapse min-w-[400px]">
              <thead>
                <tr>
                  <th className="py-2 px-1 text-left font-medium w-12" style={{ color: '#475569' }}>Heure</th>
                  {[1,2,3,4,5,6].map(j => (
                    <th key={j} className="py-2 px-1 font-bold text-center"
                      style={{ color: j === jourSemaine ? '#D500F9' : '#475569', background: j === jourSemaine ? 'rgba(213,0,249,0.05)' : 'transparent' }}>
                      {JOUR_LABELS[j].slice(0, 3)}
                    </th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {HEURES_SLOTS.map(h => (
                  <tr key={h} style={{ borderTop: '1px solid rgba(255,255,255,0.04)' }}>
                    <td className="py-1.5 px-1 font-mono text-[10px]" style={{ color: '#475569' }}>{h}</td>
                    {[1,2,3,4,5,6].map(j => {
                      const cours = emploiParJour[j]?.find(c => c.heure_debut <= h && c.heure_fin > h)
                      const isStart = cours?.heure_debut === h
                      const color = cours ? (matiereColorMap[cours.matiere_nom] || '#00E676') : 'transparent'
                      return (
                        <td key={j} className="py-0.5 px-0.5" style={{ background: j === jourSemaine ? 'rgba(213,0,249,0.04)' : 'transparent' }}>
                          {cours && isStart && (
                            <div className="rounded-md px-1 py-1 text-center" style={{ background: `${color}12`, border: `1px solid ${color}25` }}>
                              <p className="font-bold truncate text-[9px] leading-tight" style={{ color }}>{cours.matiere_nom}</p>
                              {cours.salle && <p className="text-[8px] leading-tight" style={{ color: '#475569' }}>{cours.salle}</p>}
                            </div>
                          )}
                        </td>
                      )
                    })}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {/* ── Absences + Cahier ── */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
        {/* Absences */}
        <div className="rounded-2xl p-5" style={{ background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.07)' }}>
          <h2 className="text-sm font-bold text-[#94A3B8] uppercase tracking-wider mb-4">Absences récentes</h2>
          {loading ? <div className="space-y-2">{[...Array(3)].map((_, i) => <div key={i} className="h-12 rounded-xl ss-shimmer" style={{ background: 'rgba(255,255,255,0.03)' }} />)}</div>
          : absences.length === 0 ? (
            <div className="flex flex-col items-center py-8 text-center">
              <div className="w-10 h-10 rounded-xl flex items-center justify-center mb-2 text-xl" style={{ background: 'rgba(0,230,118,0.1)', border: '1px solid rgba(0,230,118,0.2)' }}>✅</div>
              <p className="text-sm" style={{ color: '#94A3B8' }}>Aucune absence</p>
            </div>
          ) : (
            <div className="space-y-2">
              {absences.map(a => (
                <div key={a.id} className="flex items-center gap-3 p-3 rounded-xl"
                  style={{ background: a.justifiee ? 'rgba(0,230,118,0.05)' : 'rgba(255,23,68,0.05)', border: `1px solid ${a.justifiee ? 'rgba(0,230,118,0.15)' : 'rgba(255,23,68,0.15)'}` }}>
                  <div className="w-2 h-2 rounded-full shrink-0" style={{ background: a.justifiee ? '#00E676' : '#FF1744', boxShadow: `0 0 6px ${a.justifiee ? '#00E676' : '#FF1744'}` }} />
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-semibold text-white truncate">{a.matiere_nom}</p>
                    <p className="text-xs" style={{ color: '#94A3B8' }}>{new Date(a.date_absence).toLocaleDateString('fr-SN', { day: 'numeric', month: 'short', year: 'numeric' })}</p>
                  </div>
                  <span className="text-[10px] font-bold px-2 py-0.5 rounded-full" style={{ background: a.justifiee ? 'rgba(0,230,118,0.15)' : 'rgba(255,23,68,0.15)', color: a.justifiee ? '#00E676' : '#FF1744' }}>
                    {a.justifiee ? 'Justifiée' : 'Non justifiée'}
                  </span>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Cahier de texte */}
        <div className="rounded-2xl p-5" style={{ background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.07)' }}>
          <h2 className="text-sm font-bold text-[#94A3B8] uppercase tracking-wider mb-4">Cahier de texte</h2>
          {loading ? <div className="space-y-2">{[...Array(3)].map((_, i) => <div key={i} className="h-16 rounded-xl ss-shimmer" style={{ background: 'rgba(255,255,255,0.03)' }} />)}</div>
          : cahierTexte.length === 0 ? (
            <div className="flex flex-col items-center py-8 text-center">
              <div className="w-10 h-10 rounded-xl flex items-center justify-center mb-2 text-xl" style={{ background: 'rgba(255,255,255,0.04)', border: '1px solid rgba(255,255,255,0.08)' }}>📭</div>
              <p className="text-sm" style={{ color: '#94A3B8' }}>Aucune entrée</p>
            </div>
          ) : (
            <div className="space-y-2">
              {cahierTexte.map(c => {
                const isDevoir = c.type === 'devoir'
                const color = isDevoir ? '#FF1744' : '#00853F'
                return (
                  <div key={c.id} className="p-3 rounded-xl" style={{ background: `${color}06`, border: `1px solid ${color}15` }}>
                    <div className="flex items-center justify-between mb-1">
                      <div className="flex items-center gap-2">
                        <span className="text-[10px] font-bold px-1.5 py-0.5 rounded-full" style={{ background: `${color}15`, color }}>{isDevoir ? 'Devoir' : 'Cours'}</span>
                        <span className="text-xs font-semibold text-white">{c.matiere_nom}</span>
                      </div>
                      <span className="text-[10px]" style={{ color: '#475569' }}>{new Date(c.date_cours).toLocaleDateString('fr-SN', { day: 'numeric', month: 'short' })}</span>
                    </div>
                    <p className="text-xs leading-relaxed line-clamp-2" style={{ color: '#94A3B8' }}>{c.contenu}</p>
                  </div>
                )
              })}
            </div>
          )}
        </div>
      </div>
    </div>
  )
}

'use client'

import { useEffect, useState, useCallback, useMemo } from 'react'
import { createClient } from '@/lib/supabase/client'
import { useUser } from '@/hooks/useUser'
import { isDemoMode, DEMO_ABSENCES, DEMO_ELEVES } from '@/lib/demo-data'

interface Enfant {
  id: string
  nom: string
  prenom: string
}

interface Absence {
  id: string
  date_absence: string
  type: string
  motif: string | null
  justifiee: boolean
  valide_par: string | null
}

export default function AbsencesPage() {
  const { user, loading: userLoading } = useUser()
  const supabase = createClient()

  const [enfants, setEnfants] = useState<Enfant[]>([])
  const [selectedEnfant, setSelectedEnfant] = useState('')
  const [absences, setAbsences] = useState<Absence[]>([])
  const [moisOffset, setMoisOffset] = useState(0)
  const [loading, setLoading] = useState(true)
  const [justifModal, setJustifModal] = useState<Absence | null>(null)
  const [motif, setMotif] = useState('')
  const [saving, setSaving] = useState(false)

  // Charger enfants
  useEffect(() => {
    if (!user) return
    if (isDemoMode()) {
      const demoEnfants = DEMO_ELEVES
        .filter(e => e.parent_principal_id === user.id && e.actif)
        .slice(0, 3)
        .map(e => ({ id: e.id, nom: e.nom, prenom: e.prenom }))
      setEnfants(demoEnfants)
      if (demoEnfants.length > 0 && !selectedEnfant) setSelectedEnfant(demoEnfants[0].id)
      return
    }
    async function load() {
      const { data } = await (supabase
        .from('eleves') as any)
        .select('id, nom, prenom')
        .eq('parent_principal_id', user!.id)
        .eq('actif', true)
        .order('nom')

      if (data) {
        const mapped = (data as any[]).map(e => ({ id: e.id, nom: e.nom, prenom: e.prenom }))
        setEnfants(mapped)
        if (mapped.length > 0 && !selectedEnfant) setSelectedEnfant(mapped[0].id)
      }
    }
    load()
  }, [user, supabase, selectedEnfant])

  // Mois affiché
  const moisDate = useMemo(() => {
    const d = new Date()
    d.setMonth(d.getMonth() + moisOffset)
    return d
  }, [moisOffset])

  // Charger absences du mois
  const loadAbsences = useCallback(async () => {
    if (!selectedEnfant) return
    setLoading(true)

    const debut = new Date(moisDate.getFullYear(), moisDate.getMonth(), 1).toISOString().split('T')[0]
    const fin = new Date(moisDate.getFullYear(), moisDate.getMonth() + 1, 0).toISOString().split('T')[0]

    if (isDemoMode()) {
      const filtered = DEMO_ABSENCES
        .filter((a: any) => a.eleve_id === selectedEnfant && a.date_absence >= debut && a.date_absence <= fin)
        .map((a: any) => ({ id: a.id, date_absence: a.date_absence, type: a.type, motif: a.motif, justifiee: a.justifiee, valide_par: a.valide_par }))
      setAbsences(filtered)
      setLoading(false)
      return
    }

    const { data } = await (supabase
      .from('absences_eleves') as any)
      .select('id, date_absence, type, motif, justifiee, valide_par')
      .eq('eleve_id', selectedEnfant)
      .gte('date_absence', debut)
      .lte('date_absence', fin)
      .order('date_absence')

    setAbsences((data as Absence[]) || [])
    setLoading(false)
  }, [selectedEnfant, moisDate, supabase])

  useEffect(() => {
    loadAbsences()
  }, [loadAbsences])

  // Real-time subscription on absences_eleves for selected child
  useEffect(() => {
    if (isDemoMode() || !selectedEnfant) return

    const channel = supabase.channel('parent-absences-live')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'absences_eleves', filter: `eleve_id=eq.${selectedEnfant}` }, () => {
        loadAbsences()
      })
      .subscribe()

    return () => {
      supabase.removeChannel(channel)
    }
  }, [selectedEnfant, supabase, loadAbsences])

  // Calendrier
  const calendar = useMemo(() => {
    const year = moisDate.getFullYear()
    const month = moisDate.getMonth()
    const firstDay = new Date(year, month, 1).getDay()
    const daysInMonth = new Date(year, month + 1, 0).getDate()
    const offset = firstDay === 0 ? 6 : firstDay - 1 // Lundi = 0

    const absenceMap = new Map<string, Absence>()
    for (const a of absences) {
      absenceMap.set(a.date_absence, a)
    }

    const days: { day: number; date: string; isWeekend: boolean; absence: Absence | null }[] = []

    // Padding
    for (let i = 0; i < offset; i++) {
      days.push({ day: 0, date: '', isWeekend: false, absence: null })
    }

    for (let d = 1; d <= daysInMonth; d++) {
      const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(d).padStart(2, '0')}`
      const dow = new Date(year, month, d).getDay()
      const isWeekend = dow === 0 || dow === 6
      days.push({ day: d, date: dateStr, isWeekend, absence: absenceMap.get(dateStr) || null })
    }

    return days
  }, [moisDate, absences])

  // Justifier absence
  const handleJustifier = async () => {
    if (!justifModal || !motif.trim()) return
    setSaving(true)

    await (supabase.from('absences_eleves') as any)
      .update({ motif: motif.trim(), justifiee: true })
      .eq('id', justifModal.id)

    setSaving(false)
    setJustifModal(null)
    setMotif('')
    loadAbsences()
  }

  const absencesNonJustifiees = absences.filter(a => !a.justifiee)
  const moisLabel = moisDate.toLocaleDateString('fr-SN', { month: 'long', year: 'numeric' })

  if (userLoading) {
    return (
      <div>
        <div className="h-8 w-48 bg-ss-bg-secondary rounded-lg ss-shimmer mb-6" />
        <div className="h-64 bg-ss-bg-secondary rounded-xl ss-shimmer" />
      </div>
    )
  }

  return (
    <div className="max-w-lg mx-auto space-y-4">
      <h1 className="text-2xl font-bold text-ss-text">Absences</h1>

      {/* Sélecteur enfant */}
      {enfants.length > 1 && (
        <div className="flex gap-2 overflow-x-auto pb-1">
          {enfants.map(e => (
            <button
              key={e.id}
              onClick={() => setSelectedEnfant(e.id)}
              className={`px-4 py-2 rounded-xl text-sm font-medium whitespace-nowrap min-h-[40px] transition-all ${
                selectedEnfant === e.id
                  ? 'bg-ss-cyan/15 border border-ss-cyan text-ss-text'
                  : 'bg-ss-bg-secondary border border-ss-border text-ss-text-secondary'
              }`}
            >
              {e.prenom}
            </button>
          ))}
        </div>
      )}

      {/* Navigation mois */}
      <div className="flex items-center justify-between bg-ss-bg-secondary rounded-xl border border-ss-border p-3">
        <button
          onClick={() => setMoisOffset(o => o - 1)}
          className="w-10 h-10 rounded-lg bg-ss-bg-card flex items-center justify-center text-ss-text hover:bg-ss-bg-card/80"
        >
          ◀
        </button>
        <span className="text-sm font-semibold text-ss-text capitalize">{moisLabel}</span>
        <button
          onClick={() => setMoisOffset(o => Math.min(o + 1, 0))}
          disabled={moisOffset >= 0}
          className="w-10 h-10 rounded-lg bg-ss-bg-card flex items-center justify-center text-ss-text hover:bg-ss-bg-card/80 disabled:opacity-30"
        >
          ▶
        </button>
      </div>

      {/* Calendrier */}
      <div className="bg-ss-bg-secondary rounded-xl border border-ss-border p-4">
        <div className="grid grid-cols-7 gap-1 mb-2">
          {['Lu', 'Ma', 'Me', 'Je', 'Ve', 'Sa', 'Di'].map(j => (
            <div key={j} className="text-center text-xs font-medium text-ss-text-muted py-1">{j}</div>
          ))}
        </div>
        <div className="grid grid-cols-7 gap-1">
          {calendar.map((cell, idx) => {
            if (cell.day === 0) return <div key={idx} />

            let bg = 'bg-ss-bg-card'
            let textColor = 'text-ss-text'

            if (cell.isWeekend) {
              bg = 'bg-ss-bg-card/40'
              textColor = 'text-ss-text-muted'
            } else if (cell.absence) {
              if (cell.absence.type === 'retard') {
                bg = 'bg-ss-gold/20'
                textColor = 'text-ss-gold'
              } else {
                bg = cell.absence.justifiee ? 'bg-ss-red/10' : 'bg-ss-red/25'
                textColor = 'text-ss-red'
              }
            } else if (!cell.isWeekend) {
              // Passé = présent (vert subtil)
              const today = new Date().toISOString().split('T')[0]
              if (cell.date <= today) {
                bg = 'bg-ss-green/8'
                textColor = 'text-ss-text'
              }
            }

            return (
              <button
                key={idx}
                onClick={() => cell.absence && !cell.absence.justifiee ? setJustifModal(cell.absence) : undefined}
                className={`aspect-square rounded-lg flex items-center justify-center text-xs font-medium ${bg} ${textColor} ${
                  cell.absence && !cell.absence.justifiee ? 'ring-1 ring-ss-red/50 cursor-pointer' : ''
                }`}
              >
                {cell.day}
              </button>
            )
          })}
        </div>

        {/* Légende */}
        <div className="flex flex-wrap gap-3 mt-3 pt-3 border-t border-ss-border">
          {[
            { color: 'bg-ss-green/20', label: 'Présent' },
            { color: 'bg-ss-red/25', label: 'Absent' },
            { color: 'bg-ss-gold/20', label: 'Retard' },
            { color: 'bg-ss-bg-card/40', label: 'Weekend' },
          ].map(l => (
            <div key={l.label} className="flex items-center gap-1.5">
              <div className={`w-3 h-3 rounded ${l.color}`} />
              <span className="text-xs text-ss-text-muted">{l.label}</span>
            </div>
          ))}
        </div>
      </div>

      {/* Absences non justifiées */}
      {absencesNonJustifiees.length > 0 && (
        <div className="bg-ss-red/5 border border-ss-red/20 rounded-xl p-4">
          <h3 className="text-sm font-semibold text-ss-red mb-3">
            Absences non justifiées ({absencesNonJustifiees.length})
          </h3>
          <div className="space-y-2">
            {absencesNonJustifiees.map(a => (
              <div key={a.id} className="flex items-center justify-between bg-ss-bg-card rounded-lg p-3">
                <div>
                  <p className="text-sm font-medium text-ss-text">
                    {new Date(a.date_absence).toLocaleDateString('fr-SN', { weekday: 'short', day: 'numeric', month: 'short' })}
                  </p>
                  <p className="text-xs text-ss-text-muted capitalize">{a.type || 'absence'}</p>
                </div>
                <button
                  onClick={() => { setJustifModal(a); setMotif('') }}
                  className="text-xs bg-ss-cyan/10 text-ss-cyan px-3 py-1.5 rounded-lg font-medium min-h-[32px] hover:bg-ss-cyan/20 transition-colors"
                >
                  Justifier
                </button>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Modal justification */}
      {justifModal && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-end sm:items-center justify-center z-50 p-0 sm:p-4">
          <div className="bg-ss-bg-secondary rounded-t-2xl sm:rounded-2xl w-full sm:max-w-sm border border-ss-border p-5 space-y-4">
            <div className="flex items-center justify-between">
              <h3 className="text-lg font-bold text-ss-text">Justifier l&apos;absence</h3>
              <button onClick={() => setJustifModal(null)} className="text-ss-text-muted hover:text-ss-text text-xl">✕</button>
            </div>
            <p className="text-sm text-ss-text-secondary">
              {new Date(justifModal.date_absence).toLocaleDateString('fr-SN', { weekday: 'long', day: 'numeric', month: 'long' })}
            </p>
            <div>
              <label className="block text-sm font-medium text-ss-text-secondary mb-1.5">Motif</label>
              <textarea
                value={motif}
                onChange={e => setMotif(e.target.value)}
                placeholder="Ex: Rendez-vous médical, maladie..."
                rows={3}
                className="w-full bg-ss-bg border border-ss-border text-ss-text rounded-lg px-3 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-ss-cyan resize-none"
              />
            </div>
            <button
              onClick={handleJustifier}
              disabled={saving || !motif.trim()}
              className="w-full bg-ss-green text-white py-3 rounded-xl font-bold text-sm min-h-[48px] hover:bg-ss-green/80 disabled:opacity-50 transition-colors"
            >
              {saving ? 'Envoi...' : 'Envoyer la justification'}
            </button>
          </div>
        </div>
      )}
    </div>
  )
}

'use client'

import { useEffect, useState, useCallback, useMemo } from 'react'
import { createClient } from '@/lib/supabase/client'
import { useUser } from '@/hooks/useUser'
import { useOffline } from '@/hooks/useOffline'
import {
  RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis,
  Radar, ResponsiveContainer, Tooltip,
} from 'recharts'
import { isDemoMode, DEMO_MOYENNES_TRIMESTRE, DEMO_MOYENNE_GENERALE, DEMO_ELEVES, DEMO_CLASSES } from '@/lib/demo-data'

interface Enfant {
  id: string
  nom: string
  prenom: string
  classe_id: string
  classe_nom: string
}

interface MoyenneMatiere {
  matiere_id: string
  matiere_nom: string
  coeff_matiere: number
  moyenne_matiere: number
}

interface MoyenneGenerale {
  moyenne_generale: number
  rang: number
}

function getCurrentTrimestre(): number {
  const month = new Date().getMonth() + 1
  if (month >= 10 || month <= 12) return 1
  if (month >= 1 && month <= 3) return 2
  return 3
}

export default function BulletinsPage() {
  const { user, loading: userLoading } = useUser()
  const { isOffline, cacheData, getCachedData } = useOffline()
  const supabase = createClient()

  const [enfants, setEnfants] = useState<Enfant[]>([])
  const [selectedEnfant, setSelectedEnfant] = useState('')
  const [trimestre, setTrimestre] = useState(getCurrentTrimestre())
  const [moyennes, setMoyennes] = useState<MoyenneMatiere[]>([])
  const [generale, setGenerale] = useState<MoyenneGenerale | null>(null)
  const [totalEleves, setTotalEleves] = useState(0)
  const [loading, setLoading] = useState(true)
  const [downloading, setDownloading] = useState(false)

  // Charger enfants
  useEffect(() => {
    if (!user) return
    if (isDemoMode()) {
      const demoEnfants = DEMO_ELEVES
        .filter(e => e.parent_principal_id === user.id && e.actif)
        .slice(0, 3)
        .map(e => {
          const cls = DEMO_CLASSES.find(c => c.id === e.classe_id)
          return { id: e.id, nom: e.nom, prenom: e.prenom, classe_id: e.classe_id, classe_nom: cls ? `${cls.niveau} ${cls.nom}` : '' }
        })
      setEnfants(demoEnfants)
      if (demoEnfants.length > 0 && !selectedEnfant) setSelectedEnfant(demoEnfants[0].id)
      return
    }
    async function load() {
      const { data } = await (supabase
        .from('eleves') as any)
        .select('id, nom, prenom, classe_id, classes(nom)')
        .eq('parent_principal_id', user!.id)
        .eq('actif', true)
        .order('nom')

      if (data) {
        const mapped = (data as any[]).map(e => ({
          id: e.id,
          nom: e.nom,
          prenom: e.prenom,
          classe_id: e.classe_id,
          classe_nom: e.classes?.nom || '',
        }))
        setEnfants(mapped)
        if (mapped.length > 0 && !selectedEnfant) {
          setSelectedEnfant(mapped[0].id)
        }
      }
    }
    load()
  }, [user, supabase, selectedEnfant])

  // Charger moyennes
  const loadMoyennes = useCallback(async () => {
    if (!selectedEnfant) return
    setLoading(true)

    // Demo mode fallback
    if (isDemoMode()) {
      const moy = DEMO_MOYENNES_TRIMESTRE
        .filter(m => m.eleve_id === selectedEnfant && m.trimestre === trimestre)
        .map(m => ({ matiere_id: m.matiere_id, matiere_nom: m.matiere_nom, coeff_matiere: m.coeff_matiere, moyenne_matiere: m.moyenne_matiere }))
      setMoyennes(moy)

      const gen = DEMO_MOYENNE_GENERALE.eleve_id === selectedEnfant && DEMO_MOYENNE_GENERALE.trimestre === trimestre
        ? { moyenne_generale: DEMO_MOYENNE_GENERALE.moyenne_generale, rang: DEMO_MOYENNE_GENERALE.rang }
        : null
      setGenerale(gen)

      const enfant = enfants.find(e => e.id === selectedEnfant)
      if (enfant) {
        setTotalEleves(DEMO_ELEVES.filter(e => e.classe_id === enfant.classe_id && e.actif).length)
      }
      setLoading(false)
      return
    }

    const cacheKey = `bulletins_${selectedEnfant}_t${trimestre}`
    if (isOffline) {
      const cached = getCachedData<{ moyennes: MoyenneMatiere[]; generale: MoyenneGenerale | null }>(cacheKey)
      if (cached) {
        setMoyennes(cached.moyennes)
        setGenerale(cached.generale)
      }
      setLoading(false)
      return
    }

    const enfant = enfants.find(e => e.id === selectedEnfant)

    const [moyRes, genRes, countRes] = await Promise.all([
      supabase
        .from('v_moyennes_trimestre')
        .select('*')
        .eq('eleve_id', selectedEnfant)
        .eq('trimestre', trimestre)
        .order('matiere_nom'),

      supabase
        .from('v_moyennes_generales')
        .select('*')
        .eq('eleve_id', selectedEnfant)
        .eq('trimestre', trimestre)
        .maybeSingle(),

      enfant ? supabase
        .from('eleves')
        .select('id', { count: 'exact' })
        .eq('classe_id', enfant.classe_id)
        .eq('actif', true) : Promise.resolve({ count: 0 }),
    ])

    const moy = (moyRes.data || []) as unknown as MoyenneMatiere[]
    const gen = genRes.data as unknown as MoyenneGenerale | null

    setMoyennes(moy)
    setGenerale(gen)
    setTotalEleves(countRes.count || 0)

    cacheData(cacheKey, { moyennes: moy, generale: gen })
    setLoading(false)
  }, [selectedEnfant, trimestre, enfants, isOffline, supabase, cacheData, getCachedData])

  useEffect(() => {
    loadMoyennes()
  }, [loadMoyennes])

  // Données radar
  const radarData = useMemo(() =>
    moyennes.map(m => ({
      matiere: m.matiere_nom.length > 8 ? m.matiere_nom.slice(0, 8) + '.' : m.matiere_nom,
      note: m.moyenne_matiere,
      fullMark: 20,
    })),
  [moyennes])

  const handleDownloadBulletin = async () => {
    if (!selectedEnfant) return
    setDownloading(true)
    try {
      const res = await fetch('/api/bulletins/generate', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ eleveId: selectedEnfant, trimestre }),
      })

      if (!res.ok) throw new Error('Erreur génération')

      const blob = await res.blob()
      const url = URL.createObjectURL(blob)
      const a = document.createElement('a')
      a.href = url
      a.download = `Bulletin_T${trimestre}_${enfants.find(e => e.id === selectedEnfant)?.prenom || 'eleve'}.pdf`
      document.body.appendChild(a)
      a.click()
      document.body.removeChild(a)
      URL.revokeObjectURL(url)
    } catch (err) {
      console.error('Erreur téléchargement bulletin:', err)
    }
    setDownloading(false)
  }

  const enfantActuel = enfants.find(e => e.id === selectedEnfant)

  if (userLoading) {
    return (
      <div>
        <div className="h-8 w-48 bg-ss-bg-secondary rounded-lg ss-shimmer mb-6" />
        <div className="h-64 bg-ss-bg-secondary rounded-xl ss-shimmer" />
      </div>
    )
  }

  return (
    <div className="max-w-lg mx-auto space-y-4">
      <h1 className="text-2xl font-bold text-ss-text">Bulletins</h1>

      {/* Sélecteur enfant */}
      {enfants.length > 1 && (
        <div className="flex gap-2 overflow-x-auto pb-1">
          {enfants.map(e => (
            <button
              key={e.id}
              onClick={() => setSelectedEnfant(e.id)}
              className={`px-4 py-2 rounded-xl text-sm font-medium whitespace-nowrap min-h-[40px] transition-all ${
                selectedEnfant === e.id
                  ? 'bg-ss-cyan/15 border border-ss-cyan text-ss-text'
                  : 'bg-ss-bg-secondary border border-ss-border text-ss-text-secondary'
              }`}
            >
              {e.prenom}
            </button>
          ))}
        </div>
      )}

      {/* Sélecteur trimestre */}
      <div className="flex gap-2">
        {[1, 2, 3].map(t => (
          <button
            key={t}
            onClick={() => setTrimestre(t)}
            className={`flex-1 py-2.5 rounded-xl text-sm font-semibold min-h-[44px] transition-colors ${
              trimestre === t
                ? 'bg-ss-cyan text-white'
                : 'bg-ss-bg-secondary text-ss-text-secondary border border-ss-border'
            }`}
          >
            T{t}
          </button>
        ))}
      </div>

      {loading ? (
        <div className="space-y-3">
          {[...Array(5)].map((_, i) => (
            <div key={i} className="h-12 bg-ss-bg-secondary rounded-xl ss-shimmer" />
          ))}
        </div>
      ) : moyennes.length === 0 ? (
        <div className="bg-ss-bg-secondary rounded-xl border border-ss-border p-8 text-center">
          <span className="text-3xl block mb-2">📚</span>
          <p className="text-ss-text font-semibold">Aucune note pour le Trimestre {trimestre}</p>
          <p className="text-ss-text-muted text-sm mt-1">Les notes apparaîtront ici une fois saisies.</p>
        </div>
      ) : (
        <>
          {/* Moyenne générale */}
          {generale && (
            <div className="bg-ss-bg-secondary rounded-xl border border-ss-border p-5 text-center">
              <p className={`text-4xl font-bold ${generale.moyenne_generale >= 10 ? 'text-ss-green' : 'text-ss-red'}`}>
                {generale.moyenne_generale.toFixed(2)}/20
              </p>
              <p className="text-sm text-ss-text-secondary mt-1">Moyenne générale</p>
              {generale.rang > 0 && totalEleves > 0 && (
                <p className="text-sm font-medium text-ss-cyan mt-2">
                  {generale.rang}{generale.rang === 1 ? 'er' : 'ème'} sur {totalEleves} élèves
                </p>
              )}
            </div>
          )}

          {/* Tableau des matières */}
          <div className="bg-ss-bg-secondary rounded-xl border border-ss-border overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead>
                  <tr className="border-b border-ss-border bg-ss-bg-card">
                    <th className="px-4 py-3 text-left text-xs font-semibold text-ss-text-secondary">Matière</th>
                    <th className="px-3 py-3 text-center text-xs font-semibold text-ss-text-secondary">Coeff.</th>
                    <th className="px-3 py-3 text-center text-xs font-semibold text-ss-text-secondary">Moyenne</th>
                  </tr>
                </thead>
                <tbody>
                  {moyennes.map((m, idx) => (
                    <tr
                      key={m.matiere_id}
                      className={`border-b border-ss-border/50 ${
                        m.moyenne_matiere < 10 ? 'bg-ss-red/5' : ''
                      } ${idx % 2 === 0 ? '' : 'bg-ss-bg-card/30'}`}
                    >
                      <td className="px-4 py-3 text-sm font-medium text-ss-text">{m.matiere_nom}</td>
                      <td className="px-3 py-3 text-center text-sm text-ss-text-muted">{m.coeff_matiere}</td>
                      <td className="px-3 py-3 text-center">
                        <span className={`text-sm font-bold ${m.moyenne_matiere >= 10 ? 'text-ss-green' : 'text-ss-red'}`}>
                          {m.moyenne_matiere.toFixed(1)}
                        </span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          {/* Graphique Radar */}
          {radarData.length >= 3 && (
            <div className="bg-ss-bg-secondary rounded-xl border border-ss-border p-5">
              <h3 className="text-sm font-semibold text-ss-text mb-4">Profil par matière</h3>
              <div style={{ height: 280 }}>
                <ResponsiveContainer width="100%" height="100%">
                  <RadarChart data={radarData}>
                    <PolarGrid stroke="#2A3166" />
                    <PolarAngleAxis
                      dataKey="matiere"
                      tick={{ fill: '#9FA8DA', fontSize: 10 }}
                    />
                    <PolarRadiusAxis
                      angle={90}
                      domain={[0, 20]}
                      tick={{ fill: '#666', fontSize: 9 }}
                    />
                    <Radar
                      name={enfantActuel?.prenom || 'Élève'}
                      dataKey="note"
                      stroke="#00BCD4"
                      fill="#00BCD4"
                      fillOpacity={0.25}
                      strokeWidth={2}
                    />
                    <Tooltip
                      contentStyle={{
                        backgroundColor: '#1E2547',
                        border: '1px solid #2A3166',
                        borderRadius: '8px',
                        color: '#E0E0E0',
                        fontSize: '12px',
                      }}
                      formatter={(value) => [`${value}/20`, 'Moyenne']}
                    />
                  </RadarChart>
                </ResponsiveContainer>
              </div>
            </div>
          )}

          {/* Bouton téléchargement bulletin PDF */}
          <div className="mt-6">
            <button
              onClick={handleDownloadBulletin}
              disabled={downloading || !selectedEnfant}
              className="w-full sm:w-auto flex items-center justify-center gap-2 px-6 py-3 bg-[#00853F] text-white rounded-xl font-semibold hover:bg-[#00853F]/90 disabled:opacity-50 transition text-sm min-h-[48px]"
            >
              {downloading ? (
                <>
                  <span className="animate-spin">&#9203;</span>
                  Génération en cours...
                </>
              ) : (
                <>
                  &#128229; Télécharger le bulletin PDF
                </>
              )}
            </button>
          </div>
        </>
      )}
    </div>
  )
}

'use client'

import { useEffect, useState, useCallback } from 'react'
import { createClient } from '@/lib/supabase/client'
import { useUser } from '@/hooks/useUser'

interface Enfant {
  id: string
  nom: string
  prenom: string
}

interface MenuCantine {
  id: string
  semaine_debut: string
  jour: string
  entree: string
  plat_principal: string
  dessert: string
  prix: number
}

interface AbonnementCantine {
  id: string
  eleve_id: string
  actif: boolean
  montant_mensuel: number
  regime_special: string | null
}

interface RepasPris {
  id: string
  eleve_id: string
  date: string
  present: boolean
}

const JOURS_SEMAINE = ['Lundi', 'Mardi', 'Mercredi', 'Jeudi', 'Vendredi']

function getMonday(d: Date): Date {
  const date = new Date(d)
  const day = date.getDay()
  const diff = date.getDate() - day + (day === 0 ? -6 : 1)
  date.setDate(diff)
  date.setHours(0, 0, 0, 0)
  return date
}

function formatDate(dateStr: string): string {
  return new Date(dateStr).toLocaleDateString('fr-SN', {
    day: 'numeric',
    month: 'short',
  })
}

function getTodayJour(): string {
  const days = ['Dimanche', 'Lundi', 'Mardi', 'Mercredi', 'Jeudi', 'Vendredi', 'Samedi']
  return days[new Date().getDay()]
}

export default function ParentCantinePage() {
  const { user, loading: userLoading } = useUser()
  const supabase = createClient()

  const [enfants, setEnfants] = useState<Enfant[]>([])
  const [selectedEnfant, setSelectedEnfant] = useState<string>('')
  const [menus, setMenus] = useState<MenuCantine[]>([])
  const [abonnement, setAbonnement] = useState<AbonnementCantine | null>(null)
  const [repasPris, setRepasPris] = useState<RepasPris[]>([])
  const [loading, setLoading] = useState(true)
  const [noSubscription, setNoSubscription] = useState(false)

  const todayJour = getTodayJour()

  // Charger les enfants
  useEffect(() => {
    if (!user) return

    async function loadEnfants() {
      const { data } = await (supabase
        .from('eleves') as any)
        .select('id, nom, prenom')
        .eq('parent_principal_id', user!.id)
        .eq('actif', true)
        .order('nom')

      if (data && data.length > 0) {
        setEnfants(data)
        if (!selectedEnfant) setSelectedEnfant(data[0].id)
      }
    }

    loadEnfants()
  }, [user, supabase, selectedEnfant])

  // Charger les donnees cantine
  const loadCantineData = useCallback(async (eleveId: string) => {
    if (!eleveId) return
    setLoading(true)
    setNoSubscription(false)

    const monday = getMonday(new Date())
    const mondayStr = monday.toISOString().split('T')[0]

    // 1. Menus de la semaine
    const { data: menusData } = await (supabase
      .from('menus_cantine') as any)
      .select('*')
      .eq('semaine_debut', mondayStr)
      .order('jour')

    setMenus(menusData || [])

    // 2. Abonnement cantine
    const { data: aboData } = await (supabase
      .from('abonnements_cantine') as any)
      .select('*')
      .eq('eleve_id', eleveId)
      .eq('actif', true)
      .maybeSingle()

    if (!aboData) {
      setNoSubscription(true)
      setAbonnement(null)
    } else {
      setAbonnement(aboData)
    }

    // 3. Repas pris du mois en cours
    const now = new Date()
    const debutMois = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0]
    const finMois = new Date(now.getFullYear(), now.getMonth() + 1, 0).toISOString().split('T')[0]

    const { data: repasData } = await (supabase
      .from('repas_pris') as any)
      .select('*')
      .eq('eleve_id', eleveId)
      .gte('date', debutMois)
      .lte('date', finMois)
      .order('date', { ascending: false })

    setRepasPris(repasData || [])
    setLoading(false)
