'use client'

import { useEffect, useState, useCallback } from 'react'
import { createClient } from '@/lib/supabase/client'
import { useUser } from '@/hooks/useUser'
import { useOffline } from '@/hooks/useOffline'
import { formatFCFA } from '@/lib/utils'
import { PaiementModal } from '@/components/finance/PaiementModal'
import { isDemoMode, DEMO_FACTURES, DEMO_ELEVES } from '@/lib/demo-data'

interface Facture {
  id: string
  eleve_id: string
  ecole_id: string
  type_frais: string
  montant_total: number
  montant_verse: number
  solde_restant: number
  statut: string
  date_emission: string
  date_limite: string
  eleve_nom: string
}

const STATUT_STYLES: Record<string, string> = {
  paye: 'bg-ss-green/15 text-ss-green',
  partiellement_paye: 'bg-ss-cyan/15 text-ss-cyan',
  en_attente: 'bg-ss-gold/15 text-ss-gold',
  en_retard: 'bg-ss-red/15 text-ss-red',
}

const STATUT_LABELS: Record<string, string> = {
  paye: 'Payé',
  partiellement_paye: 'Partiel',
  en_attente: 'En attente',
  en_retard: 'En retard',
}

export default function PaiementPage() {
  const { user, loading: userLoading } = useUser()
  const { isOffline } = useOffline()
  const supabase = createClient()

  const [factures, setFactures] = useState<Facture[]>([])
  const [loading, setLoading] = useState(true)
  const [selectedFacture, setSelectedFacture] = useState<Facture | null>(null)
  const [filter, setFilter] = useState<'all' | 'unpaid'>('unpaid')

  // Vérifier status query param
  useEffect(() => {
    const params = new URLSearchParams(window.location.search)
    const status = params.get('status')
    if (status === 'success') {
      // Nettoyer URL
      window.history.replaceState({}, '', '/parent/paiement')
    }
  }, [])

  const loadFactures = useCallback(async () => {
    if (!user) return
    setLoading(true)

    // Demo mode fallback
    if (isDemoMode()) {
      const demoEleves = DEMO_ELEVES.filter(e => e.parent_principal_id === user.id && e.actif)
      const eleveIds = demoEleves.map(e => e.id)
      const eleveMap = new Map(demoEleves.map(e => [e.id, `${e.prenom} ${e.nom}`]))

      let facts = DEMO_FACTURES.filter(f => eleveIds.includes(f.eleve_id))
      if (filter === 'unpaid') {
        facts = facts.filter(f => ['en_attente', 'en_retard', 'partiellement_paye'].includes(f.statut))
      }

      setFactures(facts.map(f => ({
        id: f.id, eleve_id: f.eleve_id, ecole_id: f.ecole_id, type_frais: f.type_frais,
        montant_total: f.montant_total, montant_verse: f.montant_verse, solde_restant: f.solde_restant,
        statut: f.statut, date_emission: f.date_emission, date_limite: f.date_limite,
        eleve_nom: eleveMap.get(f.eleve_id) || '',
      })))
      setLoading(false)
      return
    }

    // Récupérer les élèves du parent
    const { data: eleves } = await (supabase
      .from('eleves') as any)
      .select('id, nom, prenom')
      .eq('parent_principal_id', user.id)
      .eq('actif', true)

    if (!eleves || eleves.length === 0) {
      setLoading(false)
      return
    }

    const eleveIds = (eleves as any[]).map(e => e.id)
    const eleveMap = new Map((eleves as any[]).map(e => [e.id, `${e.prenom} ${e.nom}`]))

    let query = supabase
      .from('factures')
      .select('*')
      .in('eleve_id', eleveIds)
      .order('date_emission', { ascending: false })

    if (filter === 'unpaid') {
      query = query.in('statut', ['en_attente', 'en_retard', 'partiellement_paye'])
    }

    const { data } = await query

    if (data) {
      setFactures((data as any[]).map(f => ({
        ...f,
        eleve_nom: eleveMap.get(f.eleve_id) || '',
      })))
    }

    setLoading(false)
  }, [user, supabase, filter])

  useEffect(() => {
    loadFactures()
  }, [loadFactures])

  const totalDu = factures
    .filter(f => f.statut !== 'paye')
    .reduce((sum, f) => sum + f.solde_restant, 0)

  if (userLoading) {
    return (
      <div>
        <div className="h-8 w-48 bg-ss-bg-secondary rounded-lg ss-shimmer mb-6" />
        <div className="space-y-3">
          {[...Array(3)].map((_, i) => (
            <div key={i} className="h-20 bg-ss-bg-secondary rounded-xl ss-shimmer" />
          ))}
        </div>
      </div>
    )
  }

  return (
    <div className="max-w-lg mx-auto space-y-4">
      <h1 className="text-2xl font-bold text-ss-text">Paiements</h1>

      {/* Offline warning */}
      {isOffline && (
        <div className="bg-ss-gold/10 border border-ss-gold/30 rounded-xl px-4 py-3">
          <p className="text-ss-gold text-sm font-medium">📵 Paiement impossible hors-ligne</p>
          <p className="text-ss-text-muted text-xs mt-0.5">Connectez-vous à Internet pour effectuer un paiement.</p>
        </div>
      )}

      {/* Résumé */}
      {totalDu > 0 && (
        <div className="bg-ss-bg-secondary rounded-xl border border-ss-border p-5 text-center">
          <p className="text-xs text-ss-text-muted mb-1">Total à payer</p>
          <p className="text-3xl font-bold text-ss-red">{formatFCFA(totalDu)}</p>
        </div>
      )}

      {/* Filtres */}
      <div className="flex gap-2">
        <button
          onClick={() => setFilter('unpaid')}
          className={`px-4 py-2 rounded-lg text-sm font-medium min-h-[40px] transition-colors ${
            filter === 'unpaid' ? 'bg-ss-cyan text-white' : 'bg-ss-bg-secondary text-ss-text-secondary border border-ss-border'
          }`}
        >
          Impayés
        </button>
        <button
          onClick={() => setFilter('all')}
          className={`px-4 py-2 rounded-lg text-sm font-medium min-h-[40px] transition-colors ${
            filter === 'all' ? 'bg-ss-cyan text-white' : 'bg-ss-bg-secondary text-ss-text-secondary border border-ss-border'
          }`}
        >
          Toutes
        </button>
      </div>

      {/* Liste factures */}
      {loading ? (
        <div className="space-y-3">
          {[...Array(3)].map((_, i) => (
            <div key={i} className="h-24 bg-ss-bg-secondary rounded-xl ss-shimmer" />
          ))}
        </div>
      ) : factures.length === 0 ? (
        <div className="bg-ss-bg-secondary rounded-xl border border-ss-border p-8 text-center">
          <span className="text-3xl block mb-2">🎉</span>
          <p className="text-ss-text font-semibold">Aucune facture {filter === 'unpaid' ? 'impayée' : ''}</p>
        </div>
      ) : (
        <div className="space-y-3">
          {factures.map(f => (
            <div
              key={f.id}
              className={`bg-ss-bg-secondary rounded-xl border p-4 transition-colors ${
                f.statut === 'en_retard' ? 'border-ss-red/40' : 'border-ss-border'
              }`}
            >
              <div className="flex items-start justify-between mb-2">
                <div className="min-w-0">
                  <p className="text-sm font-semibold text-ss-text truncate">{f.type_frais}</p>
                  <p className="text-xs text-ss-text-muted">{f.eleve_nom}</p>
                </div>
                <span className={`text-xs font-medium px-2 py-1 rounded-md shrink-0 ${STATUT_STYLES[f.statut] || 'bg-ss-bg-card text-ss-text-muted'}`}>
                  {STATUT_LABELS[f.statut] || f.statut}
                </span>
              </div>

              <div className="flex items-end justify-between">
                <div>
                  <p className="text-lg font-bold text-ss-text">{formatFCFA(f.solde_restant)}</p>
                  {f.montant_verse > 0 && (
                    <p className="text-xs text-ss-text-muted">
                      Versé: {formatFCFA(f.montant_verse)} / {formatFCFA(f.montant_total)}
                    </p>
                  )}
                </div>
                {f.statut !== 'paye' && !isOffline && (
                  <button
                    onClick={() => setSelectedFacture(f)}
                    className="bg-ss-green text-white px-4 py-2.5 rounded-xl text-sm font-semibold min-h-[44px] hover:bg-ss-green/80 transition-colors"
                  >
                    Payer
                  </button>
                )}
              </div>

              <p className="text-xs text-ss-text-muted mt-2">
                Émise le {new Date(f.date_emission).toLocaleDateString('fr-SN')}
                {f.date_limite && ` · Échéance: ${new Date(f.date_limite).toLocaleDateString('fr-SN')}`}
              </p>
            </div>
          ))}
        </div>
      )}

      {/* Modal paiement */}
      {selectedFacture && (
        <PaiementModal
          facture={{
            ...selectedFacture,
            eleve_nom: selectedFacture.eleve_nom,
          }}
          onClose={() => setSelectedFacture(null)}
          onSuccess={() => {
            setSelectedFacture(null)
            loadFactures()
          }}
        />
      )}
    </div>
  )
}

'use client'

import { useEffect, useState, useCallback } from 'react'
import { createClient } from '@/lib/supabase/client'
import { useUser } from '@/hooks/useUser'

interface Enfant {
  id: string
  nom: string
  prenom: string
}

interface Abonnement {
  id: string
  eleve_id: string
  trajet_id: string
  arret_id: string
  actif: boolean
}

interface Trajet {
  id: string
  nom: string
  type: 'aller' | 'retour'
  vehicule_id: string
}

interface Arret {
  id: string
  nom: string
  adresse: string
  heure_passage: string
  ordre: number
  trajet_id: string
}

interface Vehicule {
  id: string
  immatriculation: string
  chauffeur_nom: string
  chauffeur_telephone: string
  latitude: number | null
  longitude: number | null
  vitesse: number | null
  derniere_position_at: string | null
}

interface NotificationTransport {
  id: string
  type: 'depart' | 'approche' | 'arrivee' | 'retard'
  message: string
  created_at: string
}

export default function ParentTransportPage() {
  const { user, loading: userLoading } = useUser()
  const supabase = createClient()

  const [enfants, setEnfants] = useState<Enfant[]>([])
  const [selectedEnfant, setSelectedEnfant] = useState<string>('')
  const [abonnement, setAbonnement] = useState<Abonnement | null>(null)
  const [trajets, setTrajets] = useState<Trajet[]>([])
  const [arrets, setArrets] = useState<Arret[]>([])
  const [arretEnfant, setArretEnfant] = useState<Arret | null>(null)
  const [vehicule, setVehicule] = useState<Vehicule | null>(null)
  const [notifications, setNotifications] = useState<NotificationTransport[]>([])
  const [loading, setLoading] = useState(true)
  const [noSubscription, setNoSubscription] = useState(false)

  // Charger les enfants
  useEffect(() => {
    if (!user) return

    async function loadEnfants() {
      const { data } = await (supabase
        .from('eleves') as any)
        .select('id, nom, prenom')
        .eq('parent_principal_id', user!.id)
        .eq('actif', true)
        .order('nom')

      if (data && data.length > 0) {
        setEnfants(data)
        if (!selectedEnfant) setSelectedEnfant(data[0].id)
      }
    }

    loadEnfants()
  }, [user, supabase, selectedEnfant])

  // Charger les donnees transport
  const loadTransportData = useCallback(async (eleveId: string) => {
    if (!eleveId) return
    setLoading(true)
    setNoSubscription(false)

    // 1. Abonnement transport
    const { data: aboData } = await (supabase
      .from('abonnements_transport') as any)
      .select('*')
      .eq('eleve_id', eleveId)
      .eq('actif', true)
      .maybeSingle()

    if (!aboData) {
      setNoSubscription(true)
      setAbonnement(null)
      setTrajets([])
      setArrets([])
      setArretEnfant(null)
      setVehicule(null)
      setNotifications([])
      setLoading(false)
      return
    }

    setAbonnement(aboData)

    // 2. Trajets lies a cet abonnement
    const { data: trajetData } = await (supabase
      .from('trajets') as any)
      .select('*')
      .eq('id', aboData.trajet_id)

    const loadedTrajets = trajetData || []
    setTrajets(loadedTrajets)

    // 3. Arrets du trajet
    const { data: arretsData } = await (supabase
      .from('arrets') as any)
      .select('*')
      .eq('trajet_id', aboData.trajet_id)
      .order('ordre', { ascending: true })

    const loadedArrets = arretsData || []
    setArrets(loadedArrets)

    // Arret de l'enfant
    const enfantArret = loadedArrets.find((a: Arret) => a.id === aboData.arret_id) || null
    setArretEnfant(enfantArret)

    // 4. Vehicule
    if (loadedTrajets.length > 0 && loadedTrajets[0].vehicule_id) {
      const { data: vehData } = await (supabase
        .from('vehicules') as any)
        .select('*')
        .eq('id', loadedTrajets[0].vehicule_id)
        .maybeSingle()

      setVehicule(vehData || null)
    }

    // 5. Notifications recentes
    const { data: notifData } = await (supabase
      .from('notifications_transport') as any)
      .select('*')
      .eq('eleve_id', eleveId)
      .order('created_at', { ascending: false })
      .limit(10)

    setNotifications(notifData || [])
    setLoading(false)
  }, [supabase])

  useEffect(() => {
    if (selectedEnfant) loadTransportData(selectedEnfant)
  }, [selectedEnfant, loadTransportData])

  // Supabase Realtime: subscribe to vehicule updates
  useEffect(() => {
    if (!vehicule?.id) return

    const channel = supabase
      .channel(`vehicule-${vehicule.id}`)
      .on(
        'postgres_changes' as any,
        {
          event: 'UPDATE',
          schema: 'public',
          table: 'vehicules',
          filter: `id=eq.${vehicule.id}`,
        },
        (payload: any) => {
          setVehicule((prev) => prev ? { ...prev, ...payload.new } : prev)
        }
      )
      .subscribe()

    return () => {
      supabase.removeChannel(channel)
    }
  }, [vehicule?.id, supabase])

  // Helpers
  function getMinutesAgo(dateStr: string | null): number | null {
    if (!dateStr) return null
    const diff = Date.now() - new Date(dateStr).getTime()
    return Math.floor(diff / 60000)
  }

  function isBusActive(): boolean {
    if (!vehicule?.derniere_position_at) return false
    const mins = getMinutesAgo(vehicule.derniere_position_at)
    return mins !== null && mins < 10
  }

  function getNotifIcon(type: string): string {
    switch (type) {
      case 'depart': return '🟢'
      case 'approche': return '🟡'
      case 'arrivee': return '🏁'
      case 'retard': return '🔴'
      default: return '🔔'
    }
  }

  function formatTimeAgo(dateStr: string): string {
    const mins = getMinutesAgo(dateStr)
    if (mins === null) return ''
    if (mins < 1) return "A l'instant"
    if (mins < 60) return `Il y a ${mins} min`
    const hours = Math.floor(mins / 60)
    if (hours < 24) return `Il y a ${hours}h`
    return new Date(dateStr).toLocaleDateString('fr-SN', { day: 'numeric', month: 'short', hour: '2-digit', minute: '2-digit' })
  }

  const enfantActuel = enfants.find(e => e.id === selectedEnfant)

  // Loading state
  if (userLoading) {
    return (
      <div className="max-w-lg mx-auto p-4">
        <div className="h-8 w-56 bg-ss-bg-secondary rounded-lg ss-shimmer mb-6" />
        <div className="space-y-4">
          {[...Array(3)].map((_, i) => (
            <div key={i} className="h-32 bg-ss-bg-secondary rounded-xl ss-shimmer" />
          ))}
        </div>
      </div>
    )
  }

  return (
    <div className="max-w-lg mx-auto space-y-4">
      {/* Header */}
      <div>
        <h1 className="text-xl font-bold text-ss-text flex items-center gap-2">
          <span className="text-2xl">🚌</span> Transport scolaire
        </h1>
        {enfantActuel && (
          <p className="text-sm text-ss-text-secondary mt-1">
            {enfantActuel.prenom} {enfantActuel.nom}
            {trajets.length > 0 && <span className="ml-1">— Ligne : {trajets[0].nom}</span>}
          </p>
        )}
      </div>

      {/* Selecteur enfant */}
      {enfants.length > 1 && (
        <div className="flex gap-2 overflow-x-auto pb-1 scrollbar-hide">
          {enfants.map(e => (
            <button
              key={e.id}
              onClick={() => setSelectedEnfant(e.id)}
              className={`flex items-center gap-2 px-4 py-2.5 rounded-xl text-sm font-medium whitespace-nowrap transition-all min-h-[44px] ${
                selectedEnfant === e.id
                  ? 'bg-[#00853F]/15 border border-[#00853F] text-ss-text'
                  : 'bg-ss-bg-secondary border border-ss-border text-ss-text-secondary'
              }`}
            >
              <div className="w-7 h-7 rounded-full bg-ss-bg-card flex items-center justify-center text-xs font-bold text-[#00853F] shrink-0">
                {e.prenom[0]}
              </div>
              {e.prenom}
            </button>
          ))}
        </div>
      )}

      {/* No subscription */}
      {noSubscription && !loading && (
        <div className="bg-ss-bg-secondary rounded-xl border border-ss-border p-6 text-center">
          <span className="text-4xl block mb-3">🚫</span>
          <p className="text-ss-text font-medium mb-1">Pas d'abonnement transport</p>
          <p className="text-sm text-ss-text-muted">
            Votre enfant n'est pas inscrit au transport scolaire. Contactez l'administration.
          </p>
        </div>
      )}

      {/* Loading shimmer */}
      {loading && !noSubscription && (
        <div className="space-y-4">
          <div className="h-40 bg-ss-bg-secondary rounded-xl ss-shimmer" />
          <div className="h-48 bg-ss-bg-secondary rounded-xl ss-shimmer" />
          <div className="h-24 bg-ss-bg-secondary rounded-xl ss-shimmer" />
        </div>
      )}

      {/* Main content */}
      {!loading && !noSubscription && abonnement && (
        <>
          {/* Bus Status Card */}
          <div className={`rounded-xl border p-5 ${
            isBusActive()
              ? 'bg-[#00853F]/5 border-[#00853F]/30'
              : 'bg-ss-bg-secondary border-ss-border'
          }`}>
            <div className="flex items-center gap-3 mb-4">
              {isBusActive() ? (
                <span className="relative flex h-4 w-4">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-[#00853F] opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-4 w-4 bg-[#00853F]"></span>
                </span>
              ) : (
                <span className="inline-flex rounded-full h-4 w-4 bg-gray-400"></span>
              )}
              <span className={`text-lg font-bold ${isBusActive() ? 'text-[#00853F]' : 'text-ss-text-muted'}`}>
                {isBusActive() ? 'En route' : 'En attente'}
              </span>
            </div>

            {vehicule && (
              <div className="space-y-3">
                <div className="grid grid-cols-2 gap-3">
                  <div>
                    <p className="text-xs text-ss-text-muted">Immatriculation</p>
                    <p className="text-sm font-semibold text-ss-text">{vehicule.immatriculation}</p>
                  </div>
                  <div>
                    <p className="text-xs text-ss-text-muted">Vitesse</p>
                    <p className="text-sm font-semibold text-ss-text">
                      {isBusActive() && vehicule.vitesse !== null ? `${Math.round(vehicule.vitesse)} km/h` : '—'}
                    </p>
                  </div>
                </div>

                <div>
                  <p className="text-xs text-ss-text-muted">Chauffeur</p>
                  <div className="flex items-center gap-2 mt-0.5">
                    <p className="text-sm font-semibold text-ss-text">{vehicule.chauffeur_nom}</p>
                    <a
                      href={`tel:${vehicule.chauffeur_telephone}`}
                      className="text-[#00853F] text-sm underline"
                    >
                      {vehicule.chauffeur_telephone}
                    </a>
                  </div>
                </div>

                {vehicule.derniere_position_at && (
                  <p className="text-xs text-ss-text-muted">
                    Derniere mise a jour : {formatTimeAgo(vehicule.derniere_position_at)}
                  </p>
                )}
              </div>
            )}
          </div>

          {/* Trajet Info - Arrets */}
          {arrets.length > 0 && (
            <div className="bg-ss-bg-secondary rounded-xl border border-ss-border p-5">
              <h3 className="text-sm font-semibold text-ss-text mb-4">
                Trajet : {trajets[0]?.nom || 'Ligne'}
              </h3>
              <div className="space-y-0">
                {arrets.map((arret, index) => {
                  const isChildStop = arret.id === arretEnfant?.id
                  const isLast = index === arrets.length - 1
                  // Determine if stop has been passed (simple heuristic: if bus is active and has position)
                  const passed = isBusActive() && vehicule?.derniere_position_at
                    ? false // Without actual GPS comparison, we can't determine this
                    : false

                  return (
                    <div key={arret.id} className="flex items-start gap-3 relative">
                      {/* Progress line */}
                      <div className="flex flex-col items-center">
                        <div className={`w-4 h-4 rounded-full border-2 shrink-0 z-10 ${
                          isChildStop
                            ? 'bg-[#00853F] border-[#00853F]'
                            : passed
                              ? 'bg-[#00853F]/50 border-[#00853F]/50'
                              : 'bg-ss-bg-card border-ss-border'
                        }`}>
                          {isChildStop && (
                            <div className="w-full h-full rounded-full flex items-center justify-center">
                              <div className="w-1.5 h-1.5 rounded-full bg-white"></div>
                            </div>
                          )}
                        </div>
                        {!isLast && (
                          <div className={`w-0.5 h-8 ${passed ? 'bg-[#00853F]/50' : 'bg-ss-border'}`} />
                        )}
                      </div>

                      {/* Stop info */}
                      <div className={`pb-4 flex-1 min-w-0 -mt-0.5 ${isChildStop ? 'font-semibold' : ''}`}>
                        <div className="flex items-center gap-2">
                          <p className={`text-sm ${isChildStop ? 'text-[#00853F]' : 'text-ss-text'}`}>
                            {arret.nom}
                            {isChildStop && <span className="ml-1 text-xs">★</span>}
                          </p>
                          <span className="text-xs text-ss-text-muted ml-auto shrink-0">
                            {arret.heure_passage}
                          </span>
                        </div>
                      </div>
                    </div>
                  )
                })}
              </div>
            </div>
          )}

          {/* Arret de l'enfant */}
          {arretEnfant && (
            <div className="bg-[#00853F]/5 rounded-xl border border-[#00853F]/30 p-5">
              <h3 className="text-sm font-semibold text-[#00853F] mb-2">
                Arret habituel
              </h3>
              <p className="text-base font-bold text-ss-text">{arretEnfant.nom}</p>
              <p className="text-sm text-ss-text-secondary mt-1">{arretEnfant.adresse}</p>
              <div className="mt-3 flex items-center gap-2">
                <span className="text-sm">🕐</span>
                <p className="text-sm font-medium text-ss-text">
                  Heure de passage prevue : <span className="text-[#00853F]">{arretEnfant.heure_passage}</span>
                </p>
              </div>
            </div>
          )}

          {/* Notifications recentes */}
          {notifications.length > 0 && (
            <div className="bg-ss-bg-secondary rounded-xl border border-ss-border p-5">
              <h3 className="text-sm font-semibold text-ss-text mb-4">Notifications recentes</h3>
              <div className="space-y-3">
                {notifications.map(n => (
                  <div key={n.id} className="flex items-start gap-3">
                    <span className="text-lg mt-0.5">{getNotifIcon(n.type)}</span>
                    <div className="flex-1 min-w-0">
                      <p className="text-sm text-ss-text">{n.message}</p>
                    </div>
                    <span className="text-xs text-ss-text-muted shrink-0">
                      {formatTimeAgo(n.created_at)}
                    </span>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* Contact chauffeur */}
          {vehicule && (
            <div className="flex gap-3">
              <a
                href={`tel:${vehicule.chauffeur_telephone}`}
                className="flex-1 flex items-center justify-center gap-2 px-4 py-3 rounded-xl text-sm font-semibold bg-[#00853F] text-white hover:bg-[#00853F]/90 transition-colors min-h-[48px] active:scale-[0.98]"
              >
                <span>📞</span> Appeler le chauffeur
              </a>
              <a
                href={`https://wa.me/${vehicule.chauffeur_telephone.replace(/[^0-9]/g, '')}`}
                target="_blank"
                rel="noopener noreferrer"
                className="flex items-center justify-center gap-2 px-4 py-3 rounded-xl text-sm font-semibold bg-[#25D366] text-white hover:bg-[#25D366]/90 transition-colors min-h-[48px] active:scale-[0.98]"
              >
                <span>📱</span> WhatsApp
              </a>
            </div>
          )}
        </>
      )}
    </div>
  )
}

'use client'

import { useEffect, useState, useCallback } from 'react'
import { createClient } from '@/lib/supabase/client'
import { useUser } from '@/hooks/useUser'
import { isDemoMode, DEMO_ELEVES, DEMO_CLASSES } from '@/lib/demo-data'

type PresenceStatut = 'present' | 'absent' | 'retard'

interface ElevePresence {
  id: string
  nom: string
  prenom: string
  matricule: string
  statut: PresenceStatut
}

const JOURS: Record<number, string> = {
  0: 'Dimanche', 1: 'Lundi', 2: 'Mardi', 3: 'Mercredi',
  4: 'Jeudi', 5: 'Vendredi', 6: 'Samedi',
}

const MOIS: Record<number, string> = {
  0: 'janvier', 1: 'février', 2: 'mars', 3: 'avril', 4: 'mai', 5: 'juin',
  6: 'juillet', 7: 'août', 8: 'septembre', 9: 'octobre', 10: 'novembre', 11: 'décembre',
}

export default function AppelPage() {
  const { user, loading: userLoading } = useUser()

  const [selectedClasse, setSelectedClasse] = useState('')
  const [selectedClasseNom, setSelectedClasseNom] = useState('')
  const [classes, setClasses] = useState<{ id: string; nom: string; niveau: string }[]>([])
  const [eleves, setEleves] = useState<ElevePresence[]>([])
  const [loadingEleves, setLoadingEleves] = useState(false)
  const [submitting, setSubmitting] = useState(false)
  const [appelValide, setAppelValide] = useState(false)
  const [appelResultat, setAppelResultat] = useState({ absents: 0, retards: 0 })

  const ecoleId = user?.ecole_id
  const today = new Date()
  const dateLabel = `${JOURS[today.getDay()]} ${today.getDate()} ${MOIS[today.getMonth()]} ${today.getFullYear()}`

  // Charger les classes
  const loadClasses = useCallback(async () => {
    if (!ecoleId) return

    if (isDemoMode()) {
      setClasses(DEMO_CLASSES.map(c => ({ id: c.id, nom: c.nom, niveau: c.niveau })))
      return
    }

    const supabase = createClient()
    const { data } = await (supabase.from('classes') as any)
      .select('id, nom, niveau')
      .eq('ecole_id', ecoleId)
      .order('niveau')
    setClasses(data || [])
  }, [ecoleId])

  // Charger les élèves de la classe sélectionnée
  const loadEleves = useCallback(async (classeId: string) => {
    if (!classeId) { setEleves([]); return }
    setLoadingEleves(true)

    if (isDemoMode()) {
      const demoEleves = DEMO_ELEVES
        .filter(e => e.classe_id === classeId)
        .map(e => ({
          id: e.id,
          nom: e.nom,
          prenom: e.prenom,
          matricule: e.matricule,
          statut: 'present' as PresenceStatut,
        }))
      setEleves(demoEleves)
      setLoadingEleves(false)
      return
    }

    const supabase = createClient()
    const { data } = await (supabase.from('eleves') as any)
      .select('id, nom, prenom, matricule')
      .eq('classe_id', classeId)
      .eq('actif', true)
      .order('nom')
    const elevesAvecStatut = (data || []).map((e: any) => ({ ...e, statut: 'present' as PresenceStatut }))
    setEleves(elevesAvecStatut)
    setLoadingEleves(false)
  }, [])

  useEffect(() => { loadClasses() }, [loadClasses])

  const handleClasseChange = (classeId: string) => {
    const classe = classes.find(c => c.id === classeId)
    setSelectedClasse(classeId)
    setSelectedClasseNom(classe ? `${classe.niveau} ${classe.nom}` : '')
    setAppelValide(false)
    loadEleves(classeId)
  }

  const toggleStatut = (eleveId: string, statut: PresenceStatut) => {
    setEleves(prev => prev.map(e => e.id === eleveId ? { ...e, statut } : e))
  }

  const stats = {
    presents: eleves.filter(e => e.statut === 'present').length,
    absents: eleves.filter(e => e.statut === 'absent').length,
    retards: eleves.filter(e => e.statut === 'retard').length,
  }

  const validerAppel = async () => {
    if (!ecoleId || !selectedClasse) return
    setSubmitting(true)
    const todayStr = new Date().toISOString().split('T')[0]

    if (isDemoMode()) {
      const absents = eleves.filter(e => e.statut === 'absent').length
      const retards = eleves.filter(e => e.statut === 'retard').length
      setAppelResultat({ absents, retards })
      setAppelValide(true)
      setSubmitting(false)
      return
    }

    const supabase = createClient()

    // Supprimer les anciennes absences du jour pour cette classe (pour éviter doublons)
    const elevesIds = eleves.map(e => e.id)
    await (supabase.from('absences_eleves') as any)
      .delete()
      .in('eleve_id', elevesIds)
      .eq('date_absence', todayStr)

    // Insérer les nouvelles absences/retards
    const absentsEtRetards = eleves.filter(e => e.statut !== 'present')
    if (absentsEtRetards.length > 0) {
      await (supabase.from('absences_eleves') as any).insert(
        absentsEtRetards.map(e => ({
          eleve_id: e.id,
          ecole_id: ecoleId,
          date_absence: todayStr,
          type: e.statut === 'retard' ? 'retard' : 'absence',
          justifiee: false,
          session: 'journee',
        }))
      )
    }

    // Notifier le surveillant
    await (supabase.from('notifications') as any).insert({
      ecole_id: ecoleId,
      user_id: user!.id,
      type_notif: 'appel_valide',
      titre: `Appel validé — ${selectedClasseNom}`,
      contenu: `${absentsEtRetards.filter(e => e.statut === 'absent').length} absent(s), ${absentsEtRetards.filter(e => e.statut === 'retard').length} retard(s)`,
      priorite: 2,
    })

    const absents = eleves.filter(e => e.statut === 'absent').length
    const retards = eleves.filter(e => e.statut === 'retard').length
    setAppelResultat({ absents, retards })
    setAppelValide(true)
    setSubmitting(false)
  }

  if (userLoading) {
    return (
      <div className="space-y-4">
        <div className="h-8 w-64 bg-ss-bg-secondary rounded-lg ss-shimmer" />
        <div className="h-12 w-full bg-ss-bg-secondary rounded-xl ss-shimmer" />
      </div>
    )
  }

  // Ecran de confirmation après validation
  if (appelValide) {
    return (
      <div className="space-y-6">
        <div className="bg-[#00853F]/10 border border-[#00853F]/30 rounded-2xl p-8 text-center">
          <div className="text-5xl mb-4">✅</div>
          <h1 className="text-2xl font-bold text-[#00853F] mb-2">Appel validé !</h1>
          <p className="text-ss-text font-medium text-lg">{selectedClasseNom}</p>
          <p className="text-ss-text-muted text-sm mt-1">{dateLabel}</p>

          <div className="grid grid-cols-3 gap-4 mt-6">
            <div className="bg-[#00853F]/10 rounded-xl p-4">
              <p className="text-2xl font-bold text-[#00853F]">{stats.presents}</p>
              <p className="text-xs text-ss-text-muted mt-1">Présents</p>
            </div>
            <div className="bg-ss-red/10 rounded-xl p-4">
              <p className="text-2xl font-bold text-ss-red">{appelResultat.absents}</p>
              <p className="text-xs text-ss-text-muted mt-1">Absents</p>
            </div>
            <div className="bg-ss-gold/10 rounded-xl p-4">
              <p className="text-2xl font-bold text-ss-gold">{appelResultat.retards}</p>
              <p className="text-xs text-ss-text-muted mt-1">Retards</p>
            </div>
          </div>

          <button
            onClick={() => {
              setAppelValide(false)
              setSelectedClasse('')
              setSelectedClasseNom('')
              setEleves([])
            }}
            className="mt-6 text-sm text-ss-text-muted underline"
          >
            Faire un nouvel appel
          </button>
        </div>
      </div>
    )
  }

  return (
    <div className="space-y-4 pb-28">
      {/* En-tête */}
      <div>
        <h1 className="text-2xl font-bold text-ss-text">Appel de classe</h1>
        <p className="text-sm text-ss-text-muted mt-0.5">{dateLabel}</p>
      </div>

      {/* Sélecteur de classe */}
      <div className="bg-ss-bg-secondary rounded-xl border border-ss-border p-4">
        <label className="block text-sm font-medium text-ss-text mb-2">Sélectionner une classe</label>
        <select
          value={selectedClasse}
          onChange={e => handleClasseChange(e.target.value)}
          className="w-full bg-ss-bg-card border border-ss-border rounded-lg px-3 py-2.5 text-sm text-ss-text focus:outline-none focus:border-ss-cyan"
        >
          <option value="">-- Choisir une classe --</option>
          {classes.map(c => (
            <option key={c.id} value={c.id}>{c.niveau} {c.nom}</option>
          ))}
        </select>
      </div>

      {/* Stats rapides */}
      {eleves.length > 0 && (
        <div className="grid grid-cols-3 gap-3">
          <div className="bg-[#00853F]/10 border border-[#00853F]/20 rounded-xl p-3 text-center">
            <p className="text-xl font-bold text-[#00853F]">{stats.presents}</p>
            <p className="text-xs text-ss-text-muted mt-0.5">Présents</p>
          </div>
          <div className="bg-ss-red/10 border border-ss-red/20 rounded-xl p-3 text-center">
            <p className="text-xl font-bold text-ss-red">{stats.absents}</p>
            <p className="text-xs text-ss-text-muted mt-0.5">Absents</p>
          </div>
          <div className="bg-ss-gold/10 border border-ss-gold/20 rounded-xl p-3 text-center">
            <p className="text-xl font-bold text-ss-gold">{stats.retards}</p>
            <p className="text-xs text-ss-text-muted mt-0.5">Retards</p>
          </div>
        </div>
      )}

      {/* Liste des élèves */}
      {loadingEleves ? (
        <div className="space-y-2">
          {[...Array(5)].map((_, i) => (
            <div key={i} className="h-20 bg-ss-bg-secondary rounded-xl ss-shimmer" />
          ))}
        </div>
      ) : eleves.length > 0 ? (
        <div className="space-y-2">
          {eleves.map(eleve => {
            const initiales = `${eleve.prenom[0]}${eleve.nom[0]}`.toUpperCase()
            const cercleColor =
              eleve.statut === 'present' ? 'bg-[#00853F]/20 text-[#00853F]' :
              eleve.statut === 'absent'  ? 'bg-ss-red/20 text-ss-red' :
                                           'bg-ss-gold/20 text-ss-gold'

            return (
              <div
                key={eleve.id}
                className="bg-ss-bg-secondary border border-ss-border rounded-xl p-3 flex items-center gap-3"
              >
                {/* Initiales */}
                <div className={`w-10 h-10 rounded-full flex items-center justify-center shrink-0 text-sm font-bold ${cercleColor}`}>
                  {initiales}
                </div>

                {/* Info */}
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-medium text-ss-text truncate">
                    {eleve.prenom} {eleve.nom}
                  </p>
                  <p className="text-xs text-ss-text-muted">{eleve.matricule}</p>
                </div>

                {/* Boutons de statut */}
                <div className="flex gap-1 shrink-0">
                  <button
                    onClick={() => toggleStatut(eleve.id, 'present')}
                    className={`text-xs px-2 py-1.5 rounded-lg font-medium transition ${
                      eleve.statut === 'present'
                        ? 'bg-[#00853F] text-white'
                        : 'bg-ss-bg-card text-ss-text-muted hover:bg-[#00853F]/10'
                    }`}
                  >
                    ✓ Présent
                  </button>
                  <button
                    onClick={() => toggleStatut(eleve.id, 'absent')}
                    className={`text-xs px-2 py-1.5 rounded-lg font-medium transition ${
                      eleve.statut === 'absent'
                        ? 'bg-ss-red text-white'
                        : 'bg-ss-bg-card text-ss-text-muted hover:bg-ss-red/10'
                    }`}
                  >
                    ✗ Absent
                  </button>
                  <button
                    onClick={() => toggleStatut(eleve.id, 'retard')}
                    className={`text-xs px-2 py-1.5 rounded-lg font-medium transition ${
                      eleve.statut === 'retard'
                        ? 'bg-ss-gold text-white'
                        : 'bg-ss-bg-card text-ss-text-muted hover:bg-ss-gold/10'
                    }`}
                  >
                    ⏰ Retard
                  </button>
                </div>
              </div>
            )
          })}
        </div>
      ) : selectedClasse ? (
        <div className="text-center py-12">
          <span className="text-3xl block mb-2">📭</span>
          <p className="text-ss-text-muted text-sm">Aucun élève dans cette classe</p>
        </div>
      ) : null}

      {/* Bouton sticky de validation */}
      {eleves.length > 0 && (
        <div className="fixed bottom-0 left-0 right-0 p-4 bg-ss-bg border-t border-ss-border">
          <button
            onClick={validerAppel}
            disabled={submitting || eleves.length === 0}
            className="w-full bg-[#00853F] text-white font-semibold py-4 rounded-xl text-base hover:bg-[#00853F]/90 transition disabled:opacity-50 disabled:cursor-not-allowed"
          >
            {submitting
              ? 'Validation en cours...'
              : `Valider l'appel (${stats.absents} absent${stats.absents > 1 ? 's' : ''}, ${stats.retards} retard${stats.retards > 1 ? 's' : ''})`
            }
          </button>
        </div>
      )}
    </div>
  )
}

'use client'

import { useState, useMemo } from 'react'
import { useUser } from '@/hooks/useUser'
import { isDemoMode, DEMO_EMPLOIS_TEMPS, DEMO_MATIERES, DEMO_CLASSES } from '@/lib/demo-data'
import { createClient } from '@/lib/supabase/client'

interface CahierEntry {
  id: string
  classe_id: string
  matiere_id: string
  prof_id: string
  titre: string
  contenu: string
  date: string
  created_at: string
}

export default function CahierPage() {
  const { user, loading: userLoading } = useUser()
  const supabase = createClient()

  const profId = user?.id || ''

  // Selections
  const [selectedClasse, setSelectedClasse] = useState('')
  const [selectedMatiere, setSelectedMatiere] = useState('')

  // Entries (demo: local state)
  const [entries, setEntries] = useState<CahierEntry[]>([])
  const [loadingEntries, setLoadingEntries] = useState(false)

  // Form
  const [showForm, setShowForm] = useState(false)
  const [titre, setTitre] = useState('')
  const [contenu, setContenu] = useState('')
  const [date, setDate] = useState(new Date().toISOString().split('T')[0])
  const [saving, setSaving] = useState(false)

  // Classes du prof (from emploi du temps)
  const classesDuProf = useMemo(() => {
    if (!profId) return []
    const classeIds = [...new Set(DEMO_EMPLOIS_TEMPS.filter(e => e.prof_id === profId).map(e => e.classe_id))]
    return classeIds
      .map(id => DEMO_CLASSES.find(c => c.id === id))
      .filter(Boolean) as typeof DEMO_CLASSES
  }, [profId])

  // Matieres du prof pour la classe selectionnee
  const matieresDuProf = useMemo(() => {
    if (!profId || !selectedClasse) return []
    const matiereIds = [...new Set(
      DEMO_EMPLOIS_TEMPS
        .filter(e => e.prof_id === profId && e.classe_id === selectedClasse)
        .map(e => e.matiere_id)
    )]
    return matiereIds
      .map(id => DEMO_MATIERES.find(m => m.id === id))
      .filter(Boolean) as typeof DEMO_MATIERES
  }, [profId, selectedClasse])

  // Load entries when class+subject change (real mode)
  const loadEntries = async (classeId: string, matiereId: string) => {
    if (!classeId || !matiereId) {
      setEntries([])
      return
    }

    if (isDemoMode()) {
      // In demo mode, entries are already in local state; just filter
      return
    }

    setLoadingEntries(true)
    const { data: rawData } = await (supabase.from('cahier_texte') as any)
      .select('id, classe_id, matiere_id, prof_id, contenu_cours, devoirs, date_seance, created_at')
      .eq('classe_id', classeId)
      .eq('matiere_id', matiereId)
      .eq('prof_id', profId)
      .order('date_seance', { ascending: false })
    // Map DB columns to CahierEntry interface
    const data = rawData ? (rawData as any[]).map((r: any) => ({
      id: r.id,
      classe_id: r.classe_id,
      matiere_id: r.matiere_id,
      prof_id: r.prof_id,
      titre: '',
      contenu: [r.contenu_cours, r.devoirs].filter(Boolean).join('\n---\n'),
      date: r.date_seance,
      created_at: r.created_at,
    })) : null

    if (data) {
      setEntries(data as CahierEntry[])
    }
    setLoadingEntries(false)
  }

  const handleClasseChange = (val: string) => {
    setSelectedClasse(val)
    setSelectedMatiere('')
    setEntries([])
    setShowForm(false)
  }

  const handleMatiereChange = (val: string) => {
    setSelectedMatiere(val)
    setShowForm(false)
    loadEntries(selectedClasse, val)
  }

  // Filtered entries for demo
  const displayedEntries = useMemo(() => {
    if (!selectedClasse || !selectedMatiere) return []
    return entries
      .filter(e => e.classe_id === selectedClasse && e.matiere_id === selectedMatiere)
      .sort((a, b) => b.date.localeCompare(a.date))
  }, [entries, selectedClasse, selectedMatiere])

  // Add entry
  const handleSubmit = async () => {
    if (!titre.trim() || !contenu.trim() || !selectedClasse || !selectedMatiere || !profId) return
    setSaving(true)

    const newEntry: CahierEntry = {
      id: `cahier-${Date.now()}`,
      classe_id: selectedClasse,
      matiere_id: selectedMatiere,
      prof_id: profId,
      titre: titre.trim(),
      contenu: contenu.trim(),
      date,
      created_at: new Date().toISOString(),
    }

    if (isDemoMode()) {
      setEntries(prev => [newEntry, ...prev])
    } else {
      const { data, error } = await (supabase.from('cahier_texte') as any)
        .insert({
          classe_id: newEntry.classe_id,
          matiere_id: newEntry.matiere_id,
          prof_id: newEntry.prof_id,
          contenu_cours: newEntry.titre ? `${newEntry.titre}\n${newEntry.contenu}` : newEntry.contenu,
          date_seance: newEntry.date,
        })
        .select()
        .single()

      if (!error && data) {
        setEntries(prev => [data as CahierEntry, ...prev])
      }
    }

    setTitre('')
    setContenu('')
    setDate(new Date().toISOString().split('T')[0])
    setShowForm(false)
    setSaving(false)
  }

  const classeLabel = (c: typeof DEMO_CLASSES[0]) => `${c.niveau} ${c.nom}`

  if (userLoading) {
    return (
      <div>
        <div className="h-8 w-48 bg-ss-bg-secondary rounded-lg ss-shimmer mb-6" />
        <div className="space-y-3">
          {[...Array(3)].map((_, i) => (
            <div key={i} className="h-12 bg-ss-bg-secondary rounded-xl ss-shimmer" />
          ))}
        </div>
      </div>
    )
  }

  return (
    <div className="max-w-3xl mx-auto space-y-4">
      <h1 className="text-2xl font-bold text-ss-text">Cahier de Textes</h1>

      {/* Selecteurs */}
      <div className="bg-ss-bg-secondary rounded-xl border border-ss-border p-4 space-y-3">
        {/* Classe */}
        <div>
          <label className="block text-sm font-medium text-ss-text-secondary mb-1.5">Classe</label>
          <select
            value={selectedClasse}
            onChange={e => handleClasseChange(e.target.value)}
            className="w-full bg-ss-bg border border-ss-border text-ss-text rounded-xl px-4 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-ss-cyan min-h-[48px]"
          >
            <option value="">Selectionner une classe</option>
            {classesDuProf.map(c => (
              <option key={c.id} value={c.id}>{classeLabel(c)}</option>
            ))}
          </select>
        </div>

        {/* Matiere */}
        {selectedClasse && (
          <div>
            <label className="block text-sm font-medium text-ss-text-secondary mb-1.5">Matiere</label>
            <select
              value={selectedMatiere}
              onChange={e => handleMatiereChange(e.target.value)}
              className="w-full bg-ss-bg border border-ss-border text-ss-text rounded-xl px-4 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-ss-cyan min-h-[48px]"
            >
              <option value="">Selectionner une matiere</option>
              {matieresDuProf.map(m => (
                <option key={m.id} value={m.id}>{m.nom}</option>
              ))}
            </select>
          </div>
        )}
      </div>

      {/* Button to add new entry */}
      {selectedClasse && selectedMatiere && (
        <button
          onClick={() => setShowForm(!showForm)}
          className="w-full bg-ss-cyan text-white py-3 rounded-xl font-bold text-sm min-h-[48px] hover:bg-ss-cyan/80 transition-colors"
        >
          {showForm ? 'Annuler' : '+ Nouvelle entree'}
        </button>
      )}

      {/* Form to add entry */}
      {showForm && (
        <div className="bg-ss-bg-secondary rounded-xl border border-ss-border p-4 space-y-3">
          <p className="text-sm font-semibold text-ss-text">Nouvelle entree</p>

          <div>
            <label className="block text-xs text-ss-text-muted mb-1">Date</label>
            <input
              type="date"
              value={date}
              onChange={e => setDate(e.target.value)}
              className="w-full bg-ss-bg border border-ss-border text-ss-text rounded-lg px-3 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-ss-cyan"
            />
          </div>

          <div>
            <label className="block text-xs text-ss-text-muted mb-1">Titre</label>
            <input
              type="text"
              value={titre}
              onChange={e => setTitre(e.target.value)}
              placeholder="Ex: Chapitre 5 — Les equations du 2nd degre"
              className="w-full bg-ss-bg border border-ss-border text-ss-text rounded-lg px-3 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-ss-cyan"
            />
          </div>

          <div>
            <label className="block text-xs text-ss-text-muted mb-1">Contenu</label>
            <textarea
              value={contenu}
              onChange={e => setContenu(e.target.value)}
              placeholder="Description du cours, exercices donnes, devoirs a faire..."
              rows={4}
              className="w-full bg-ss-bg border border-ss-border text-ss-text rounded-lg px-3 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-ss-cyan resize-none"
            />
          </div>

          <button
            onClick={handleSubmit}
            disabled={saving || !titre.trim() || !contenu.trim()}
            className="w-full bg-ss-green text-white py-3 rounded-xl font-bold text-sm min-h-[48px] hover:bg-ss-green/80 disabled:opacity-50 transition-colors"
          >
            {saving ? 'Enregistrement...' : 'Enregistrer'}
          </button>
        </div>
      )}

      {/* Entries list */}
      {selectedClasse && selectedMatiere && (
        <div className="space-y-3">
          {loadingEntries ? (
            <div className="space-y-3">
              {[...Array(3)].map((_, i) => (
                <div key={i} className="h-24 bg-ss-bg-secondary rounded-xl ss-shimmer" />
              ))}
            </div>
          ) : displayedEntries.length === 0 ? (
            <div className="bg-ss-bg-secondary rounded-xl border border-ss-border p-8 text-center">
              <span className="text-3xl mb-2 block">📓</span>
              <p className="text-ss-text-secondary text-sm">Aucune entree dans le cahier de textes</p>
              <p className="text-ss-text-muted text-xs mt-1">Cliquez sur &laquo; Nouvelle entree &raquo; pour commencer</p>
            </div>
          ) : (
            displayedEntries.map((entry) => (
              <div
                key={entry.id}
                className="bg-ss-bg-secondary rounded-xl border border-ss-border p-4"
              >
                <div className="flex items-start justify-between gap-3">
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-semibold text-ss-text">{entry.titre}</p>
                    <p className="text-xs text-ss-text-muted mt-0.5">
                      {new Date(entry.date).toLocaleDateString('fr-SN', { weekday: 'short', day: 'numeric', month: 'long', year: 'numeric' })}
                    </p>
                  </div>
                </div>
                <p className="text-sm text-ss-text-secondary mt-2 whitespace-pre-wrap">{entry.contenu}</p>
              </div>
            ))
          )}
        </div>
      )}

      {/* Indication pour commencer */}
      {!selectedClasse && (
        <div className="bg-ss-bg-secondary rounded-xl border border-ss-border p-8 text-center">
          <span className="text-3xl mb-2 block">📓</span>
          <p className="text-ss-text-secondary text-sm">Selectionnez une classe pour consulter le cahier de textes</p>
        </div>
      )}
    </div>
  )
}

