export default function ProfesseurMessagesPage() {
  const { user, loading: userLoading } = useUser()
  const supabase = createClient()

  const [conversations, setConversations] = useState<Conversation[]>([])
  const [selectedConv, setSelectedConv] = useState<string | null>(null)
  const [messages, setMessages] = useState<Message[]>([])
  const [newMessage, setNewMessage] = useState('')
  const [loading, setLoading] = useState(true)
  const messagesEndRef = useRef<HTMLDivElement>(null)

  // Load conversations
  useEffect(() => {
    if (!user) return
    if (isDemoMode()) {
      setConversations(DEMO_CONVERSATIONS)
      setLoading(false)
      return
    }
    const userId = user.id
    async function loadConversations() {
      const { data } = await (supabase.from('messages') as any)
        .select('id, contenu, created_at, expediteur_id, destinataire_id, eleve_id, lu, eleves(nom, prenom, classe_id, classes(nom, niveau)), utilisateurs!messages_destinataire_id_fkey(nom, prenom)')
        .or(`expediteur_id.eq.${userId},destinataire_id.eq.${userId}`)
        .order('created_at', { ascending: false })
        .limit(50)
      if (data) {
        const convMap: Record<string, Conversation> = {}
        for (const msg of data as any[]) {
          const partnerId = msg.expediteur_id === userId ? msg.destinataire_id : msg.expediteur_id
          if (!convMap[partnerId]) {
            convMap[partnerId] = {
              id: partnerId,
              parent_nom: msg.utilisateurs?.prenom + ' ' + msg.utilisateurs?.nom || 'Parent',
              eleve_nom: msg.eleves ? `${msg.eleves.prenom} ${msg.eleves.nom}` : '',
              classe: msg.eleves?.classes ? `${msg.eleves.classes.niveau} ${msg.eleves.classes.nom}` : '',
              dernierMessage: msg.contenu,
              date: msg.created_at?.split('T')[0] || '',
              nonLu: 0,
            }
          }
          if (!msg.lu && msg.destinataire_id === userId) convMap[partnerId].nonLu++
        }
        setConversations(Object.values(convMap))
      }
      setLoading(false)
    }
    loadConversations()
  }, [user, supabase])

  // Load messages for selected conversation
  useEffect(() => {
    if (!selectedConv) return
    if (isDemoMode()) {
      setMessages(DEMO_MESSAGES[selectedConv] || [])
      setConversations(prev => prev.map(c => c.id === selectedConv ? { ...c, nonLu: 0 } : c))
      return
    }
    async function loadMessages() {
      const { data } = await (supabase.from('messages') as any)
        .select('id, contenu, created_at, expediteur_id')
        .or(`and(expediteur_id.eq.${user!.id},destinataire_id.eq.${selectedConv}),and(expediteur_id.eq.${selectedConv},destinataire_id.eq.${user!.id})`)
        .order('created_at', { ascending: true })
      if (data) {
        setMessages((data as any[]).map(m => ({
          id: m.id,
          envoyeur: m.expediteur_id === user!.id ? 'prof' as const : 'parent' as const,
          contenu: m.contenu,
          date: m.created_at,
        })))
      }
      // Mark as read
      await (supabase.from('messages') as any).update({ lu: true, lu_le: new Date().toISOString() })
        .eq('destinataire_id', user!.id).eq('expediteur_id', selectedConv)
    }
    loadMessages()
  }, [selectedConv, user, supabase])

  // Real-time subscription on messages
  useEffect(() => {
    if (isDemoMode() || !user) return
    const channel = supabase.channel('prof-messages-live')
      .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'messages', filter: `destinataire_id=eq.${user.id}` }, (payload: any) => {
        const newMsg = payload.new
        if (selectedConv && newMsg.expediteur_id === selectedConv) {
          setMessages(prev => [...prev, {
            id: newMsg.id,
            envoyeur: 'parent' as const,
            contenu: newMsg.contenu,
            date: newMsg.created_at,
          }])
        }
        // Update conversation list
        setConversations(prev => prev.map(c =>
          c.id === newMsg.expediteur_id
            ? { ...c, dernierMessage: newMsg.contenu, nonLu: selectedConv === c.id ? 0 : c.nonLu + 1 }
            : c
        ))
      })
      .subscribe()
    return () => { supabase.removeChannel(channel) }
  }, [user, selectedConv, supabase])

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' })
  }, [messages])

  async function handleSend() {
    if (!newMessage.trim() || !selectedConv || !user) return
    const contenu = newMessage.trim()
    setNewMessage('')

    if (isDemoMode()) {
      const msg: Message = { id: `m-new-${Date.now()}`, envoyeur: 'prof', contenu, date: new Date().toISOString() }
      setMessages(prev => [...prev, msg])
      setConversations(prev => prev.map(c => c.id === selectedConv ? { ...c, dernierMessage: contenu, date: new Date().toISOString().split('T')[0] } : c))
      return
    }

    // Real mode: insert into messages table
    const { data, error } = await (supabase.from('messages') as any).insert({
      ecole_id: user.ecole_id,
      expediteur_id: user.id,
      destinataire_id: selectedConv,
      contenu,
    }).select().single()

    if (!error && data) {
      setMessages(prev => [...prev, { id: data.id, envoyeur: 'prof', contenu: data.contenu, date: data.created_at }])
      setConversations(prev => prev.map(c => c.id === selectedConv ? { ...c, dernierMessage: contenu, date: new Date().toISOString().split('T')[0] } : c))
    }
  }

  const selectedConvData = conversations.find(c => c.id === selectedConv)

  if (userLoading) {
    return <div className="space-y-4">{[...Array(3)].map((_, i) => <div key={i} className="h-20 rounded-2xl ss-shimmer" style={{ background: 'rgba(255,255,255,0.03)' }} />)}</div>
  }

  return (
    <div className="animate-fade-in" style={{ height: 'calc(100vh - 120px)' }}>
      {/* Header */}
      <div className="mb-4">
        <h1 className="text-2xl font-black text-white">Messagerie</h1>
        <p className="text-sm mt-1" style={{ color: '#94A3B8' }}>
          {conversations.reduce((sum, c) => sum + c.nonLu, 0)} message(s) non lu(s)
        </p>
      </div>

      <div className="flex gap-4 h-[calc(100%-80px)]">
        {/* Conversation list */}
        <div className={`${selectedConv ? 'hidden lg:block' : ''} w-full lg:w-80 shrink-0 rounded-2xl overflow-hidden flex flex-col`}
          style={{ background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.07)' }}>
          <div className="p-3" style={{ borderBottom: '1px solid rgba(255,255,255,0.07)' }}>
            <p className="text-xs font-bold uppercase tracking-wider" style={{ color: '#94A3B8' }}>Conversations</p>
          </div>
          <div className="flex-1 overflow-y-auto">
            {conversations.length === 0 ? (
              <div className="flex flex-col items-center py-10 text-center px-4">
                <div className="text-3xl mb-3">💬</div>
                <p className="text-sm" style={{ color: '#94A3B8' }}>Aucune conversation</p>
              </div>
            ) : conversations.map(conv => (
              <button key={conv.id} onClick={() => setSelectedConv(conv.id)}
                className="w-full text-left p-4 transition-all"
                style={{
                  background: selectedConv === conv.id ? 'rgba(0,230,118,0.08)' : 'transparent',
                  borderBottom: '1px solid rgba(255,255,255,0.04)',
                }}>
                <div className="flex items-start gap-3">
                  <div className="w-10 h-10 rounded-xl flex items-center justify-center text-xs font-bold shrink-0"
                    style={{ background: 'rgba(0,230,118,0.1)', border: '1px solid rgba(0,230,118,0.2)', color: '#00E676' }}>
                    {conv.parent_nom.split(' ').map(n => n[0]).join('')}
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center justify-between">
                      <p className="text-sm font-bold text-white truncate">{conv.parent_nom}</p>
                      {conv.nonLu > 0 && (
                        <span className="w-5 h-5 rounded-full text-[9px] font-black flex items-center justify-center shrink-0"
                          style={{ background: '#00E676', color: '#020617' }}>{conv.nonLu}</span>
                      )}
                    </div>
                    <p className="text-[10px] mt-0.5" style={{ color: '#475569' }}>{conv.eleve_nom} · {conv.classe}</p>
                    <p className="text-xs mt-1 truncate" style={{ color: '#94A3B8' }}>{conv.dernierMessage}</p>
                  </div>
                </div>
              </button>
            ))}
          </div>
        </div>

        {/* Message thread */}
        <div className={`${!selectedConv ? 'hidden lg:flex' : 'flex'} flex-1 flex-col rounded-2xl overflow-hidden`}
          style={{ background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.07)' }}>

          {!selectedConv ? (
            <div className="flex-1 flex flex-col items-center justify-center text-center px-6">
              <div className="text-4xl mb-4">💬</div>
              <p className="text-white font-semibold">Selectionnez une conversation</p>
              <p className="text-sm mt-1" style={{ color: '#94A3B8' }}>Choisissez un parent dans la liste</p>
            </div>
          ) : (
            <>
              {/* Thread header */}
              <div className="flex items-center gap-3 px-4 py-3" style={{ borderBottom: '1px solid rgba(255,255,255,0.07)', background: 'rgba(255,255,255,0.02)' }}>
                <button onClick={() => setSelectedConv(null)} className="lg:hidden text-white text-lg mr-1">&larr;</button>
                <div className="w-9 h-9 rounded-xl flex items-center justify-center text-xs font-bold shrink-0"
                  style={{ background: 'rgba(0,230,118,0.1)', border: '1px solid rgba(0,230,118,0.2)', color: '#00E676' }}>
                  {selectedConvData?.parent_nom.split(' ').map(n => n[0]).join('')}
                </div>
                <div>
                  <p className="text-sm font-bold text-white">{selectedConvData?.parent_nom}</p>
                  <p className="text-[10px]" style={{ color: '#475569' }}>Parent de {selectedConvData?.eleve_nom} · {selectedConvData?.classe}</p>
                </div>
              </div>

              {/* Messages */}
              <div className="flex-1 overflow-y-auto p-4 space-y-3">
                {messages.map(msg => {
                  const isProf = msg.envoyeur === 'prof'
                  return (
                    <div key={msg.id} className={`flex ${isProf ? 'justify-end' : 'justify-start'}`}>
                      <div className="max-w-[80%] px-4 py-2.5 rounded-2xl"
                        style={{
                          background: isProf ? 'rgba(0,230,118,0.12)' : 'rgba(255,255,255,0.06)',
                          border: `1px solid ${isProf ? 'rgba(0,230,118,0.25)' : 'rgba(255,255,255,0.1)'}`,
                          borderBottomRightRadius: isProf ? '4px' : '16px',
                          borderBottomLeftRadius: isProf ? '16px' : '4px',
                        }}>
                        <p className="text-sm text-white leading-relaxed">{msg.contenu}</p>
                        <p className="text-[10px] mt-1" style={{ color: '#475569' }}>
                          {new Date(msg.date).toLocaleTimeString('fr-SN', { hour: '2-digit', minute: '2-digit' })}
                        </p>
                      </div>
                    </div>
                  )
                })}
                <div ref={messagesEndRef} />
              </div>

              {/* Compose */}
              <div className="px-4 py-3 flex gap-2" style={{ borderTop: '1px solid rgba(255,255,255,0.07)', background: 'rgba(255,255,255,0.02)' }}>
                <input
                  type="text"
                  value={newMessage}
                  onChange={e => setNewMessage(e.target.value)}
                  onKeyDown={e => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSend() } }}
                  placeholder="Ecrire un message..."
                  className="flex-1 px-4 py-2.5 rounded-xl text-sm text-white outline-none placeholder:text-[#475569]"
                  style={{ background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.1)' }}
                />
                <button onClick={handleSend} disabled={!newMessage.trim()}
                  className="px-4 py-2.5 rounded-xl text-sm font-bold transition-all hover:opacity-90 disabled:opacity-40 shrink-0"
                  style={{ background: '#00E676', color: '#020617' }}>
                  Envoyer
                </button>
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  )
}

'use client'

import { useEffect, useState, useCallback } from 'react'
import { createClient } from '@/lib/supabase/client'
import { useUser } from '@/hooks/useUser'
import { GrilleNotes } from '@/components/notes/GrilleNotes'
import { isDemoMode, DEMO_CLASSES, DEMO_MATIERES, DEMO_EVALUATIONS, DEMO_ELEVES } from '@/lib/demo-data'

interface Classe {
  id: string
  nom: string
  niveau: string
}

interface Matiere {
  id: string
  nom: string
  coefficient: number
}

interface Evaluation {
  id: string
  titre: string | null
  type_eval: string
  date_eval: string
  trimestre: number
  coefficient_eval: number
}

interface Eleve {
  id: string
  nom: string
  prenom: string
}

// Trimestre courant basé sur la date
function getCurrentTrimestre(): number {
  const month = new Date().getMonth() + 1
  if (month >= 10 || month <= 12) return 1
  if (month >= 1 && month <= 3) return 2
  return 3
}

export default function NotesPage() {
  const { user, loading: userLoading } = useUser()
  const supabase = createClient()

  // Sélections
  const [classes, setClasses] = useState<Classe[]>([])
  const [matieres, setMatieres] = useState<Matiere[]>([])
  const [evaluations, setEvaluations] = useState<Evaluation[]>([])
  const [eleves, setEleves] = useState<Eleve[]>([])

  const [selectedClasse, setSelectedClasse] = useState('')
  const [selectedMatiere, setSelectedMatiere] = useState('')
  const [selectedEval, setSelectedEval] = useState('')

  // Nouvelle évaluation
  const [showNewEval, setShowNewEval] = useState(false)
  const [newEvalTitre, setNewEvalTitre] = useState('')
  const [newEvalType, setNewEvalType] = useState('devoir')
  const [newEvalCoeff, setNewEvalCoeff] = useState(1)
  const [creatingEval, setCreatingEval] = useState(false)

  const ecoleId = user?.ecole_id
  const trimestre = getCurrentTrimestre()

  // Charger les classes du prof
  useEffect(() => {
    if (!ecoleId) return
    if (isDemoMode()) {
      setClasses(DEMO_CLASSES.map(c => ({ id: c.id, nom: c.nom, niveau: c.niveau })))
      return
    }
    async function load() {
      // Classes où le prof enseigne (via emplois_temps) ou toutes les classes si admin/démo
      const { data } = await supabase
        .from('classes')
        .select('id, nom, niveau')
        .eq('ecole_id', ecoleId!)
        .order('niveau')
      setClasses((data as unknown as Classe[]) || [])
    }
    load()
  }, [ecoleId, supabase])

  // Charger les matières quand classe sélectionnée
  useEffect(() => {
    if (!ecoleId || !selectedClasse) { setMatieres([]); return }
    if (isDemoMode()) {
      setMatieres(DEMO_MATIERES.map(m => ({ id: m.id, nom: m.nom, coefficient: m.coefficient })))
      return
    }
    async function load() {
      const { data } = await supabase
        .from('matieres')
        .select('id, nom, coefficient')
        .eq('ecole_id', ecoleId!)
        .order('nom')
      setMatieres((data as unknown as Matiere[]) || [])
    }
    load()
  }, [ecoleId, selectedClasse, supabase])

  // Charger les évaluations quand matière sélectionnée
  useEffect(() => {
    if (!selectedClasse || !selectedMatiere) { setEvaluations([]); return }
    if (isDemoMode()) {
      setEvaluations(
        DEMO_EVALUATIONS
          .filter(e => e.classe_id === selectedClasse && e.matiere_id === selectedMatiere && e.trimestre === trimestre)
          .map(e => ({ id: e.id, titre: e.titre, type_eval: e.type_eval, date_eval: e.date_eval, trimestre: e.trimestre, coefficient_eval: e.coefficient_eval }))
      )
      return
    }
    async function load() {
      const { data } = await supabase
        .from('evaluations')
        .select('id, titre, type_eval, date_eval, trimestre, coefficient_eval')
        .eq('classe_id', selectedClasse)
        .eq('matiere_id', selectedMatiere)
        .eq('trimestre', trimestre)
        .order('date_eval', { ascending: false })
      setEvaluations((data as unknown as Evaluation[]) || [])
    }
    load()
  }, [selectedClasse, selectedMatiere, trimestre, supabase])

  // Charger les élèves quand classe sélectionnée
  useEffect(() => {
    if (!selectedClasse) { setEleves([]); return }
    if (isDemoMode()) {
      setEleves(
        DEMO_ELEVES
          .filter(e => e.classe_id === selectedClasse && e.actif)
          .map(e => ({ id: e.id, nom: e.nom, prenom: e.prenom }))
          .sort((a, b) => a.nom.localeCompare(b.nom))
      )
      return
    }
    async function load() {
      const { data } = await supabase
        .from('eleves')
        .select('id, nom, prenom')
        .eq('classe_id', selectedClasse)
        .eq('actif', true)
        .order('nom')
      setEleves((data as unknown as Eleve[]) || [])
    }
    load()
  }, [selectedClasse, supabase])

  // Reset en cascade
  const handleClasseChange = (val: string) => {
    setSelectedClasse(val)
    setSelectedMatiere('')
    setSelectedEval('')
    setShowNewEval(false)
  }

  const handleMatiereChange = (val: string) => {
    setSelectedMatiere(val)
    setSelectedEval('')
    setShowNewEval(false)
  }

  // Créer nouvelle évaluation
  const handleCreateEval = useCallback(async () => {
    if (!selectedClasse || !selectedMatiere || !user) return
    setCreatingEval(true)

    const { data, error } = await (supabase.from('evaluations') as any).insert({
      classe_id: selectedClasse,
      matiere_id: selectedMatiere,
      prof_id: user.id,
      type_eval: newEvalType,
      titre: newEvalTitre || `${newEvalType} — ${new Date().toLocaleDateString('fr-SN')}`,
      date_eval: new Date().toISOString().split('T')[0],
      trimestre,
      coefficient_eval: newEvalCoeff,
    }).select().single()

    if (!error && data) {
      const created = data as unknown as Evaluation
      setEvaluations(prev => [created, ...prev])
      setSelectedEval(created.id)
      setShowNewEval(false)
      setNewEvalTitre('')
      setNewEvalType('devoir')
      setNewEvalCoeff(1)
    }

    setCreatingEval(false)
  }, [selectedClasse, selectedMatiere, user, newEvalType, newEvalTitre, newEvalCoeff, trimestre, supabase])

  if (userLoading) {
    return (
      <div>
        <div className="h-8 w-48 bg-ss-bg-secondary rounded-lg ss-shimmer mb-6" />
        <div className="space-y-3">
          {[...Array(3)].map((_, i) => (
            <div key={i} className="h-12 bg-ss-bg-secondary rounded-xl ss-shimmer" />
          ))}
        </div>
      </div>
    )
  }

  return (
    <div className="max-w-3xl mx-auto space-y-4">
      <h1 className="text-2xl font-bold text-ss-text">Saisie des Notes</h1>

      {/* Sélecteurs */}
      <div className="bg-ss-bg-secondary rounded-xl border border-ss-border p-4 space-y-3">
        <p className="text-xs text-ss-text-muted font-medium">Trimestre {trimestre}</p>

        {/* Classe */}
        <div>
          <label className="block text-sm font-medium text-ss-text-secondary mb-1.5">Classe</label>
          <select
            value={selectedClasse}
            onChange={e => handleClasseChange(e.target.value)}
            className="w-full bg-ss-bg border border-ss-border text-ss-text rounded-xl px-4 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-ss-cyan min-h-[48px]"
          >
            <option value="">Sélectionner une classe</option>
            {classes.map(c => (
              <option key={c.id} value={c.id}>{c.niveau} — {c.nom}</option>
            ))}
          </select>
        </div>

        {/* Matière */}
        {selectedClasse && (
          <div>
            <label className="block text-sm font-medium text-ss-text-secondary mb-1.5">Matière</label>
            <select
              value={selectedMatiere}
              onChange={e => handleMatiereChange(e.target.value)}
              className="w-full bg-ss-bg border border-ss-border text-ss-text rounded-xl px-4 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-ss-cyan min-h-[48px]"
            >
              <option value="">Sélectionner une matière</option>
              {matieres.map(m => (
                <option key={m.id} value={m.id}>{m.nom} (coeff. {m.coefficient})</option>
              ))}
            </select>
          </div>
        )}

        {/* Évaluation */}
        {selectedMatiere && (
          <div>
            <label className="block text-sm font-medium text-ss-text-secondary mb-1.5">Évaluation</label>
            <div className="flex gap-2">
              <select
                value={selectedEval}
                onChange={e => { setSelectedEval(e.target.value); setShowNewEval(false) }}
                className="flex-1 bg-ss-bg border border-ss-border text-ss-text rounded-xl px-4 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-ss-cyan min-h-[48px]"
              >
                <option value="">Sélectionner</option>
                {evaluations.map(ev => (
                  <option key={ev.id} value={ev.id}>
                    {ev.titre || ev.type_eval} — {new Date(ev.date_eval).toLocaleDateString('fr-SN')}
                  </option>
                ))}
              </select>
              <button
                onClick={() => { setShowNewEval(!showNewEval); setSelectedEval('') }}
                className="shrink-0 bg-ss-cyan text-white px-4 py-3 rounded-xl text-sm font-medium min-h-[48px] hover:bg-ss-cyan/80 transition-colors"
              >
                + Nouvelle
              </button>
            </div>
          </div>
        )}

        {/* Formulaire nouvelle évaluation */}
        {showNewEval && (
          <div className="bg-ss-bg-card rounded-xl p-4 space-y-3 border border-ss-border">
            <p className="text-sm font-semibold text-ss-text">Nouvelle évaluation</p>
            <input
              type="text"
              placeholder="Titre (ex: Devoir n°3)"
              value={newEvalTitre}
              onChange={e => setNewEvalTitre(e.target.value)}
              className="w-full bg-ss-bg border border-ss-border text-ss-text rounded-lg px-3 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-ss-cyan"
            />
            <div className="grid grid-cols-2 gap-3">
              <div>
                <label className="block text-xs text-ss-text-muted mb-1">Type</label>
                <select
                  value={newEvalType}
                  onChange={e => setNewEvalType(e.target.value)}
                  className="w-full bg-ss-bg border border-ss-border text-ss-text rounded-lg px-3 py-2.5 text-sm"
                >
                  <option value="devoir">Devoir</option>
                  <option value="composition">Composition</option>
                  <option value="interrogation">Interrogation</option>
                  <option value="tp">TP</option>
                </select>
              </div>
              <div>
                <label className="block text-xs text-ss-text-muted mb-1">Coefficient</label>
                <input
                  type="number"
                  min={1}
                  max={5}
                  value={newEvalCoeff}
                  onChange={e => setNewEvalCoeff(parseInt(e.target.value) || 1)}
                  className="w-full bg-ss-bg border border-ss-border text-ss-text rounded-lg px-3 py-2.5 text-sm"
                />
              </div>
            </div>
            <button
              onClick={handleCreateEval}
              disabled={creatingEval}
              className="w-full bg-ss-green text-white py-2.5 rounded-lg text-sm font-semibold hover:bg-ss-green/80 disabled:opacity-50 transition-colors min-h-[44px]"
            >
              {creatingEval ? 'Création...' : 'Créer et saisir les notes'}
            </button>
          </div>
        )}
      </div>

      {/* Grille de notes */}
      {selectedEval && eleves.length > 0 && (
        <GrilleNotes
          classeId={selectedClasse}
          matiereId={selectedMatiere}
          evaluationId={selectedEval}
          eleves={eleves}
          userId={user?.id ?? 'demo'}
          trimestre={trimestre}
        />
      )}

      {/* Message si pas d'élèves */}
      {selectedEval && eleves.length === 0 && (
        <div className="bg-ss-bg-secondary rounded-xl border border-ss-border p-8 text-center">
          <span className="text-3xl mb-2 block">📭</span>
          <p className="text-ss-text-secondary text-sm">Aucun élève dans cette classe</p>
        </div>
      )}

      {/* Indication pour commencer */}
      {!selectedClasse && (
        <div className="bg-ss-bg-secondary rounded-xl border border-ss-border p-8 text-center">
          <span className="text-3xl mb-2 block">📝</span>
          <p className="text-ss-text-secondary text-sm">Sélectionnez une classe pour commencer la saisie</p>
        </div>
      )}
    </div>
  )
}

'use client'

import { useMemo } from 'react'
import { useUser } from '@/hooks/useUser'
import { StatCard } from '@/components/dashboard/StatCard'
import { isDemoMode, DEMO_EMPLOIS_TEMPS, DEMO_MATIERES, DEMO_CLASSES, DEMO_POINTAGES } from '@/lib/demo-data'
import Link from 'next/link'

const JOUR_LABELS: Record<number, string> = {
  1: 'Lundi', 2: 'Mardi', 3: 'Mercredi', 4: 'Jeudi', 5: 'Vendredi', 6: 'Samedi',
}

const MATIERE_COLORS = [
  '#00E676', '#00E5FF', '#FFD600', '#D500F9', '#FF1744', '#448AFF', '#FF6D00',
]

export default function ProfesseurDashboard() {
  const { user, loading: userLoading } = useUser()

  const today = new Date()
  const jsDay = today.getDay()
  const jourSemaine = jsDay === 0 ? 7 : jsDay
  const profId = user?.id || ''

  const coursAujourdhui = useMemo(() => {
    if (!isDemoMode() || !profId) return []
    return DEMO_EMPLOIS_TEMPS
      .filter(e => e.prof_id === profId && e.jour_semaine === jourSemaine)
      .sort((a, b) => a.heure_debut.localeCompare(b.heure_debut))
      .map(e => ({
        ...e,
        matiere_nom: DEMO_MATIERES.find(m => m.id === e.matiere_id)?.nom || 'Matière',
        classe_nom: (() => { const c = DEMO_CLASSES.find(c => c.id === e.classe_id); return c ? `${c.niveau} ${c.nom}` : 'Classe' })(),
      }))
  }, [profId, jourSemaine])

  const classesEnseignees = useMemo(() => {
    if (!isDemoMode() || !profId) return []
    const classeIds = [...new Set(DEMO_EMPLOIS_TEMPS.filter(e => e.prof_id === profId).map(e => e.classe_id))]
    return classeIds.map(id => DEMO_CLASSES.find(c => c.id === id)).filter(Boolean)
  }, [profId])

  const pointageDuJour = useMemo(() => {
    if (!isDemoMode() || !profId) return null
    const todayStr = today.toISOString().split('T')[0]
    return DEMO_POINTAGES.find(p => p.prof_id === profId && p.date_pointage === todayStr) || null
  }, [profId, today])

  const pointageColor = pointageDuJour
    ? pointageDuJour.statut === 'a_heure' ? 'green' : pointageDuJour.statut === 'retard_leger' ? 'gold' : 'red'
    : 'cyan' as const

  const pointageLabel = pointageDuJour
    ? pointageDuJour.statut === 'a_heure' ? "À l'heure ✓"
      : `Retard +${pointageDuJour.minutes_retard}min`
    : 'Non pointé'

  if (userLoading) {
    return (
      <div className="space-y-4">
        {[...Array(4)].map((_, i) => <div key={i} className="h-28 rounded-2xl ss-shimmer" style={{ background: 'rgba(255,255,255,0.03)' }} />)}
      </div>
    )
  }

  return (
    <div className="space-y-5 pb-6 animate-fade-in">

      {/* ── Bannière prof ── */}
      <div className="relative rounded-2xl overflow-hidden min-h-[130px]">
        <img
          src="https://images.unsplash.com/photo-1524178232363-1fb2b075b655?auto=format&fit=crop&w=1200&q=80"
          alt="Professeur"
          className="absolute inset-0 w-full h-full object-cover"
        />
        <div className="absolute inset-0" style={{ background: 'linear-gradient(135deg, rgba(2,6,23,0.95) 0%, rgba(2,6,23,0.6) 100%)' }} />
        <div className="relative px-6 py-5">
          <div className="flex items-center gap-2 mb-1">
            <div className="w-2 h-2 rounded-full bg-[#00E676] animate-pulse" />
            <span className="text-[#94A3B8] text-xs font-semibold tracking-wider uppercase">Espace Professeur</span>
          </div>
          <h1 className="text-2xl font-black text-white">Bonjour, {user?.prenom} {user?.nom}</h1>
          <p className="text-sm mt-1" style={{ color: '#94A3B8' }}>
            {JOUR_LABELS[jourSemaine] || 'Aujourd\'hui'} — {today.toLocaleDateString('fr-SN', { day: 'numeric', month: 'long', year: 'numeric' })}
          </p>
        </div>
      </div>

      {/* ── Stats ── */}
      <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
        <StatCard title="Classes enseignées" value={classesEnseignees.length}
          subtitle={classesEnseignees.map(c => c ? `${c.niveau} ${c.nom}` : '').slice(0, 2).join(', ')}
          icon="🏫" color="cyan" />
        <StatCard title="Cours aujourd'hui" value={coursAujourdhui.length}
          subtitle={JOUR_LABELS[jourSemaine] || 'Dimanche'} icon="📚" color="green" />
        <StatCard title="Mon pointage" value={pointageLabel}
