                      EN COURS
                    </span>
                  )}
                </div>
              )
            })}
          </div>
        )}
      </div>
    </div>
  )
}

'use client'

import { useState, useMemo, useCallback, useEffect } from 'react'
import { useUser } from '@/hooks/useUser'
import { isDemoMode, DEMO_CLASSES, DEMO_ELEVES, DEMO_ABSENCES } from '@/lib/demo-data'
import { createClient } from '@/lib/supabase/client'

type StatutPresence = 'present' | 'absent' | 'retard'

interface ElevePresence {
  eleve_id: string
  nom: string
  prenom: string
  statut: StatutPresence
}

export default function AbsencesPage() {
  const { user, loading: userLoading } = useUser()
  const supabase = createClient()

  const [selectedDate, setSelectedDate] = useState(new Date().toISOString().split('T')[0])
  const [selectedClasse, setSelectedClasse] = useState('')
  const [presences, setPresences] = useState<ElevePresence[]>([])
  const [loading, setLoading] = useState(false)
  const [saving, setSaving] = useState(false)
  const [saved, setSaved] = useState(false)

  // Load student presence data when class or date changes
  const loadPresences = useCallback(async (classeId: string, date: string) => {
    if (!classeId || !date) {
      setPresences([])
      return
    }

    setLoading(true)
    setSaved(false)

    if (isDemoMode()) {
      // Get students for this class
      const eleves = DEMO_ELEVES.filter(e => e.classe_id === classeId)

      // Get absences for this date
      const absencesDuJour = DEMO_ABSENCES.filter(a => a.date_absence === date)

      const presenceList: ElevePresence[] = eleves.map(e => {
        const absence = absencesDuJour.find(a => a.eleve_id === e.id)
        let statut: StatutPresence = 'present'
        if (absence) {
          statut = absence.type === 'retard' ? 'retard' : 'absent'
        }
        return {
          eleve_id: e.id,
          nom: e.nom,
          prenom: e.prenom,
          statut,
        }
      })

      setPresences(presenceList.sort((a, b) => a.nom.localeCompare(b.nom)))
      setLoading(false)
      return
    }

    // Real mode: load from supabase
    const { data: eleves } = await (supabase.from('eleves') as any)
      .select('id, nom, prenom')
      .eq('classe_id', classeId)
      .eq('actif', true)
      .order('nom')

    const { data: absences } = await (supabase.from('absences_eleves') as any)
      .select('eleve_id, type')
      .eq('date_absence', date)
      .in('eleve_id', (eleves || []).map((e: any) => e.id))

    const absMap = new Map((absences || []).map((a: any) => [a.eleve_id, a.type]))

    const presenceList: ElevePresence[] = (eleves || []).map((e: any) => {
      const absType = absMap.get(e.id)
      let statut: StatutPresence = 'present'
      if (absType === 'retard') statut = 'retard'
      else if (absType) statut = 'absent'
      return {
        eleve_id: e.id,
        nom: e.nom,
        prenom: e.prenom,
        statut,
      }
    })

    setPresences(presenceList)
    setLoading(false)
  }, [supabase])

  useEffect(() => {
    if (selectedClasse && selectedDate) {
      loadPresences(selectedClasse, selectedDate)
    }
  }, [selectedClasse, selectedDate, loadPresences])

  // Real-time subscription on absences_eleves
  useEffect(() => {
    if (isDemoMode() || !user?.ecole_id || !selectedClasse || !selectedDate) return

    const channel = supabase.channel('surv-absences-live')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'absences_eleves', filter: `ecole_id=eq.${user.ecole_id}` }, () => {
        loadPresences(selectedClasse, selectedDate)
      })
      .subscribe()

    return () => {
      supabase.removeChannel(channel)
    }
  }, [user?.ecole_id, selectedClasse, selectedDate, supabase, loadPresences])

  // Toggle presence status
  const toggleStatut = (eleveId: string) => {
    setPresences(prev =>
      prev.map(p => {
        if (p.eleve_id !== eleveId) return p
        const cycle: StatutPresence[] = ['present', 'absent', 'retard']
        const nextIdx = (cycle.indexOf(p.statut) + 1) % cycle.length
        return { ...p, statut: cycle[nextIdx] }
      })
    )
    setSaved(false)
  }

  // Save absences
  const handleSave = async () => {
    if (!selectedClasse || !selectedDate || !user) return
    setSaving(true)

    if (isDemoMode()) {
      // In demo mode, just mark as saved
      setTimeout(() => {
        setSaving(false)
        setSaved(true)
      }, 500)
      return
    }

    // Real mode: upsert to supabase
    // First delete existing absences for this date and these students
    const eleveIds = presences.map(p => p.eleve_id)
    await (supabase.from('absences_eleves') as any)
      .delete()
      .eq('date_absence', selectedDate)
      .in('eleve_id', eleveIds)

    // Insert absences and retards
    const toInsert = presences
      .filter(p => p.statut !== 'present')
      .map(p => ({
        eleve_id: p.eleve_id,
        ecole_id: user.ecole_id,
        date_absence: selectedDate,
        type: p.statut === 'retard' ? 'retard' : 'absence',
        motif: null,
        justifiee: false,
        valide_par: user.id,
        valide_le: new Date().toISOString(),
      }))

    if (toInsert.length > 0) {
      await (supabase.from('absences_eleves') as any).insert(toInsert)
    }

    setSaving(false)
    setSaved(true)
  }

  // Stats
  const stats = useMemo(() => {
    const presents = presences.filter(p => p.statut === 'present').length
    const absents = presences.filter(p => p.statut === 'absent').length
    const retards = presences.filter(p => p.statut === 'retard').length
    return { presents, absents, retards, total: presences.length }
  }, [presences])

  const classeLabel = (c: typeof DEMO_CLASSES[0]) => `${c.niveau} ${c.nom}`

  const statutConfig: Record<StatutPresence, { label: string; bg: string; text: string; icon: string }> = {
    present: { label: 'Present', bg: 'bg-ss-green/15', text: 'text-ss-green', icon: '🟢' },
    absent: { label: 'Absent', bg: 'bg-ss-red/15', text: 'text-ss-red', icon: '🔴' },
    retard: { label: 'Retard', bg: 'bg-ss-gold/15', text: 'text-ss-gold', icon: '🟡' },
  }

  if (userLoading) {
    return (
      <div>
        <div className="h-8 w-48 bg-ss-bg-secondary rounded-lg ss-shimmer mb-6" />
        <div className="space-y-3">
          {[...Array(3)].map((_, i) => (
            <div key={i} className="h-12 bg-ss-bg-secondary rounded-xl ss-shimmer" />
          ))}
        </div>
      </div>
    )
  }

  return (
    <div className="max-w-3xl mx-auto space-y-4">
      <h1 className="text-2xl font-bold text-ss-text">Gestion des Absences</h1>

      {/* Filtres: date + classe */}
      <div className="bg-ss-bg-secondary rounded-xl border border-ss-border p-4 space-y-3">
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
          <div>
            <label className="block text-sm font-medium text-ss-text-secondary mb-1.5">Date</label>
            <input
              type="date"
              value={selectedDate}
              onChange={e => setSelectedDate(e.target.value)}
              className="w-full bg-ss-bg border border-ss-border text-ss-text rounded-xl px-4 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-ss-cyan min-h-[48px]"
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-ss-text-secondary mb-1.5">Classe</label>
            <select
              value={selectedClasse}
              onChange={e => setSelectedClasse(e.target.value)}
              className="w-full bg-ss-bg border border-ss-border text-ss-text rounded-xl px-4 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-ss-cyan min-h-[48px]"
            >
              <option value="">Selectionner une classe</option>
              {DEMO_CLASSES.map(c => (
                <option key={c.id} value={c.id}>{classeLabel(c)}</option>
              ))}
            </select>
          </div>
        </div>
      </div>

      {/* Stats banner */}
      {presences.length > 0 && (
        <div className="grid grid-cols-3 gap-3">
          <div className="bg-ss-green/10 border border-ss-green/20 rounded-xl p-3 text-center">
            <p className="text-xl font-bold text-ss-green">{stats.presents}</p>
            <p className="text-xs text-ss-text-muted">Presents</p>
          </div>
          <div className="bg-ss-red/10 border border-ss-red/20 rounded-xl p-3 text-center">
            <p className="text-xl font-bold text-ss-red">{stats.absents}</p>
            <p className="text-xs text-ss-text-muted">Absents</p>
          </div>
          <div className="bg-ss-gold/10 border border-ss-gold/20 rounded-xl p-3 text-center">
            <p className="text-xl font-bold text-ss-gold">{stats.retards}</p>
            <p className="text-xs text-ss-text-muted">Retards</p>
          </div>
        </div>
      )}

      {/* Student list */}
      {selectedClasse && (
        <div className="bg-ss-bg-secondary rounded-xl border border-ss-border">
          {loading ? (
            <div className="p-4 space-y-3">
              {[...Array(8)].map((_, i) => (
                <div key={i} className="h-14 bg-ss-bg-card rounded-xl ss-shimmer" />
              ))}
            </div>
          ) : presences.length === 0 ? (
            <div className="p-8 text-center">
              <span className="text-3xl mb-2 block">📋</span>
              <p className="text-ss-text-secondary text-sm">Aucun eleve dans cette classe</p>
            </div>
          ) : (
            <>
              <div className="p-4 border-b border-ss-border flex items-center justify-between">
                <p className="text-sm font-semibold text-ss-text">
                  {stats.total} eleve{stats.total > 1 ? 's' : ''}
                </p>
                <p className="text-xs text-ss-text-muted">
                  Cliquez pour changer le statut
                </p>
              </div>

              <div className="divide-y divide-ss-border">
                {presences.map((eleve) => {
                  const cfg = statutConfig[eleve.statut]
                  return (
                    <div
                      key={eleve.eleve_id}
                      className="flex items-center gap-3 px-4 py-3 hover:bg-ss-bg-card transition-colors"
                    >
                      {/* Avatar */}
                      <div className="w-9 h-9 rounded-full bg-ss-bg-card flex items-center justify-center shrink-0">
                        <span className="text-xs font-medium text-ss-text-muted">
                          {eleve.prenom[0]}{eleve.nom[0]}
                        </span>
                      </div>

                      {/* Nom */}
                      <div className="flex-1 min-w-0">
                        <p className="text-sm font-medium text-ss-text truncate">
                          {eleve.nom} {eleve.prenom}
                        </p>
                      </div>

                      {/* Toggle button */}
                      <button
                        onClick={() => toggleStatut(eleve.eleve_id)}
                        className={`shrink-0 flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-medium min-h-[36px] transition-colors ${cfg.bg} ${cfg.text}`}
                      >
                        <span>{cfg.icon}</span>
                        {cfg.label}
                      </button>
                    </div>
                  )
                })}
              </div>

              {/* Save button */}
              <div className="p-4 border-t border-ss-border">
                <button
                  onClick={handleSave}
                  disabled={saving || saved}
                  className={`w-full py-3 rounded-xl font-bold text-sm min-h-[48px] transition-colors ${
                    saved
                      ? 'bg-ss-green/20 text-ss-green'
                      : 'bg-ss-green text-white hover:bg-ss-green/80 disabled:opacity-50'
                  }`}
                >
                  {saving ? 'Enregistrement...' : saved ? 'Enregistre !' : 'Enregistrer les presences'}
                </button>
              </div>
            </>
          )}
        </div>
      )}

      {/* Indication pour commencer */}
      {!selectedClasse && (
        <div className="bg-ss-bg-secondary rounded-xl border border-ss-border p-8 text-center">
          <span className="text-3xl mb-2 block">📋</span>
          <p className="text-ss-text-secondary text-sm">Selectionnez une classe pour commencer l&apos;appel</p>
        </div>
      )}
    </div>
  )
}

'use client'

import { useState, useMemo } from 'react'
import { useUser } from '@/hooks/useUser'
import {
  isDemoMode, DEMO_ABSENCES, DEMO_ELEVES, DEMO_CLASSES,
  DEMO_POINTAGES, DEMO_PROFESSEURS
} from '@/lib/demo-data'

type ExportType = 'absences' | 'pointages'

function downloadCSV(headers: string[], rows: string[][], filename: string) {
  const BOM = '\uFEFF'
  const csv = BOM + [headers.join(';'), ...rows.map(r => r.join(';'))].join('\n')
  const blob = new Blob([csv], { type: 'text/csv;charset=utf-8' })
  const url = URL.createObjectURL(blob)
  const a = document.createElement('a')
  a.href = url; a.download = filename; a.click()
  URL.revokeObjectURL(url)
}

export default function SurveillantExportPage() {
  const { user, loading: userLoading } = useUser()

  const [exportType, setExportType] = useState<ExportType>('absences')
  const [dateDebut, setDateDebut] = useState(() => {
    const d = new Date(); d.setDate(1); return d.toISOString().split('T')[0]
  })
  const [dateFin, setDateFin] = useState(() => new Date().toISOString().split('T')[0])
  const [classeFilter, setClasseFilter] = useState('all')
  const [exported, setExported] = useState(false)

  // Absences data
  const absencesData = useMemo(() => {
    if (!isDemoMode()) return []
    return (DEMO_ABSENCES as any[])
      .filter(a => a.date_absence >= dateDebut && a.date_absence <= dateFin)
      .filter(a => {
        if (classeFilter === 'all') return true
        const eleve = DEMO_ELEVES.find(e => e.id === a.eleve_id)
        return eleve?.classe_id === classeFilter
      })
      .map(a => {
        const eleve = DEMO_ELEVES.find(e => e.id === a.eleve_id)
        const classe = eleve ? DEMO_CLASSES.find(c => c.id === eleve.classe_id) : null
        return {
          date: a.date_absence,
          eleve: eleve ? `${eleve.prenom} ${eleve.nom}` : 'Inconnu',
          classe: classe ? `${classe.niveau} ${classe.nom}` : '',
          type: a.type === 'retard' ? 'Retard' : 'Absence',
          motif: a.motif || '-',
          justifiee: a.justifiee ? 'Oui' : 'Non',
        }
      })
      .sort((a: any, b: any) => b.date.localeCompare(a.date))
  }, [dateDebut, dateFin, classeFilter])

  // Pointages data
  const pointagesData = useMemo(() => {
    if (!isDemoMode()) return []
    return DEMO_POINTAGES
      .filter((p: any) => p.date_pointage >= dateDebut && p.date_pointage <= dateFin)
      .map((p: any) => {
        const prof = DEMO_PROFESSEURS.find(pr => pr.id === p.prof_id)
        const statutLabels: Record<string, string> = { a_heure: 'A l\'heure', retard_leger: 'Retard leger', retard_grave: 'Retard grave' }
        return {
          date: p.date_pointage,
          professeur: prof ? `${prof.prenom} ${prof.nom}` : 'Inconnu',
          heure: new Date(p.heure_arrivee).toLocaleTimeString('fr-SN', { hour: '2-digit', minute: '2-digit' }),
          statut: statutLabels[p.statut] || p.statut,
          minutes: String(p.minutes_retard),
        }
      })
      .sort((a: any, b: any) => b.date.localeCompare(a.date))
  }, [dateDebut, dateFin])

  const currentData = exportType === 'absences' ? absencesData : pointagesData
  const previewData = currentData.slice(0, 20)

  function handleExport() {
    if (exportType === 'absences') {
      const headers = ['Date', 'Eleve', 'Classe', 'Type', 'Motif', 'Justifiee']
      const rows = absencesData.map(a => [a.date, a.eleve, a.classe, a.type, a.motif, a.justifiee])
      downloadCSV(headers, rows, `absences_${dateDebut}_${dateFin}.csv`)
    } else {
      const headers = ['Date', 'Professeur', 'Heure arrivee', 'Statut', 'Minutes retard']
      const rows = pointagesData.map(p => [p.date, p.professeur, p.heure, p.statut, p.minutes])
      downloadCSV(headers, rows, `pointages_${dateDebut}_${dateFin}.csv`)
    }
    setExported(true)
    setTimeout(() => setExported(false), 3000)
  }

  if (userLoading) {
    return <div className="space-y-4">{[...Array(3)].map((_, i) => <div key={i} className="h-28 rounded-2xl ss-shimmer" style={{ background: 'rgba(255,255,255,0.03)' }} />)}</div>
  }

  return (
    <div className="space-y-5 pb-6 animate-fade-in">
      {/* Header */}
      <h1 className="text-2xl font-black text-white">Export Rapports</h1>

      {/* Controls */}
      <div className="rounded-2xl p-5 space-y-4" style={{ background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.07)' }}>
        {/* Type toggle */}
        <div>
          <label className="text-xs font-bold uppercase tracking-wider block mb-2" style={{ color: '#94A3B8' }}>Type de rapport</label>
          <div className="flex gap-2">
            {([
              { key: 'absences' as const, label: 'Absences eleves', icon: '📅' },
              { key: 'pointages' as const, label: 'Pointages profs', icon: '🕐' },
            ]).map(t => (
              <button key={t.key} onClick={() => setExportType(t.key)}
                className="flex items-center gap-2 px-4 py-2.5 rounded-xl text-sm font-bold transition-all"
                style={{
                  background: exportType === t.key ? 'rgba(255,214,0,0.12)' : 'rgba(255,255,255,0.04)',
                  color: exportType === t.key ? '#FFD600' : '#94A3B8',
                  border: `1px solid ${exportType === t.key ? 'rgba(255,214,0,0.3)' : 'rgba(255,255,255,0.08)'}`,
                }}>
                <span>{t.icon}</span> {t.label}
              </button>
            ))}
          </div>
        </div>

        {/* Date range */}
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
          <div>
            <label className="text-xs font-bold uppercase tracking-wider block mb-1.5" style={{ color: '#94A3B8' }}>Date debut</label>
            <input type="date" value={dateDebut} onChange={e => setDateDebut(e.target.value)}
              className="w-full px-3 py-2.5 rounded-xl text-sm font-medium text-white outline-none transition-all"
              style={{ background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.1)' }} />
          </div>
          <div>
            <label className="text-xs font-bold uppercase tracking-wider block mb-1.5" style={{ color: '#94A3B8' }}>Date fin</label>
            <input type="date" value={dateFin} onChange={e => setDateFin(e.target.value)}
              className="w-full px-3 py-2.5 rounded-xl text-sm font-medium text-white outline-none transition-all"
              style={{ background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.1)' }} />
          </div>
        </div>

        {/* Classe filter (absences only) */}
        {exportType === 'absences' && (
          <div>
            <label className="text-xs font-bold uppercase tracking-wider block mb-1.5" style={{ color: '#94A3B8' }}>Classe</label>
            <select value={classeFilter} onChange={e => setClasseFilter(e.target.value)}
              className="w-full px-3 py-2.5 rounded-xl text-sm font-medium text-white outline-none"
              style={{ background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.1)' }}>
              <option value="all">Toutes les classes</option>
              {DEMO_CLASSES.map(c => (
                <option key={c.id} value={c.id}>{c.niveau} {c.nom}</option>
              ))}
            </select>
          </div>
        )}
      </div>

      {/* Preview */}
      <div className="rounded-2xl p-5" style={{ background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.07)' }}>
        <div className="flex items-center justify-between mb-4">
          <h2 className="text-sm font-bold text-[#94A3B8] uppercase tracking-wider">Apercu</h2>
          <span className="text-xs px-2 py-1 rounded-full" style={{ background: 'rgba(255,214,0,0.1)', color: '#FFD600', border: '1px solid rgba(255,214,0,0.2)' }}>
            {currentData.length} enregistrement(s)
          </span>
        </div>

        {currentData.length === 0 ? (
          <p className="text-sm text-center py-6" style={{ color: '#475569' }}>Aucune donnee pour cette periode</p>
        ) : (
          <div className="overflow-x-auto scrollbar-hide">
            <table className="w-full text-xs min-w-[500px]">
              <thead>
                <tr style={{ borderBottom: '1px solid rgba(255,255,255,0.07)' }}>
                  {exportType === 'absences' ? (
                    <>
                      <th className="py-2 px-2 text-left font-bold" style={{ color: '#475569' }}>Date</th>
                      <th className="py-2 px-2 text-left font-bold" style={{ color: '#475569' }}>Eleve</th>
                      <th className="py-2 px-2 text-left font-bold" style={{ color: '#475569' }}>Classe</th>
                      <th className="py-2 px-2 text-left font-bold" style={{ color: '#475569' }}>Type</th>
                      <th className="py-2 px-2 text-left font-bold" style={{ color: '#475569' }}>Justifiee</th>
                    </>
                  ) : (
                    <>
                      <th className="py-2 px-2 text-left font-bold" style={{ color: '#475569' }}>Date</th>
                      <th className="py-2 px-2 text-left font-bold" style={{ color: '#475569' }}>Professeur</th>
                      <th className="py-2 px-2 text-left font-bold" style={{ color: '#475569' }}>Heure</th>
                      <th className="py-2 px-2 text-left font-bold" style={{ color: '#475569' }}>Statut</th>
                      <th className="py-2 px-2 text-right font-bold" style={{ color: '#475569' }}>Min retard</th>
                    </>
                  )}
                </tr>
              </thead>
              <tbody>
                {previewData.map((row: any, idx: number) => (
                  <tr key={idx} style={{ borderBottom: '1px solid rgba(255,255,255,0.04)' }}>
                    {exportType === 'absences' ? (
                      <>
                        <td className="py-2 px-2 text-white">{row.date}</td>
                        <td className="py-2 px-2 text-white">{row.eleve}</td>
                        <td className="py-2 px-2" style={{ color: '#94A3B8' }}>{row.classe}</td>
                        <td className="py-2 px-2" style={{ color: '#94A3B8' }}>{row.type}</td>
                        <td className="py-2 px-2">
                          <span className="px-1.5 py-0.5 rounded-full text-[10px] font-bold"
                            style={{ background: row.justifiee === 'Oui' ? 'rgba(0,230,118,0.15)' : 'rgba(255,23,68,0.15)', color: row.justifiee === 'Oui' ? '#00E676' : '#FF1744' }}>
                            {row.justifiee}
                          </span>
                        </td>
                      </>
                    ) : (
                      <>
                        <td className="py-2 px-2 text-white">{row.date}</td>
                        <td className="py-2 px-2 text-white">{row.professeur}</td>
                        <td className="py-2 px-2" style={{ color: '#94A3B8' }}>{row.heure}</td>
                        <td className="py-2 px-2" style={{ color: '#94A3B8' }}>{row.statut}</td>
                        <td className="py-2 px-2 text-right text-white">{row.minutes}</td>
                      </>
                    )}
                  </tr>
                ))}
              </tbody>
            </table>
            {currentData.length > 20 && (
              <p className="text-[10px] text-center mt-2" style={{ color: '#475569' }}>
                ... et {currentData.length - 20} autre(s) enregistrement(s)
              </p>
            )}
          </div>
        )}
      </div>

      {/* Export button */}
      <div className="flex items-center gap-3">
        <button onClick={handleExport} disabled={currentData.length === 0}
          className="px-6 py-3 rounded-xl text-sm font-bold transition-all hover:opacity-90 disabled:opacity-40"
          style={{ background: '#FFD600', color: '#020617' }}>
          Exporter en CSV ({currentData.length})
        </button>
        {exported && (
          <span className="text-sm font-semibold animate-fade-in" style={{ color: '#00E676' }}>
            Fichier telecharge !
          </span>
        )}
      </div>
    </div>
  )
}

'use client'

import { useEffect, useState, useCallback, useRef } from 'react'
import { createClient } from '@/lib/supabase/client'
import { useUser } from '@/hooks/useUser'
import { StatCard } from '@/components/dashboard/StatCard'
import { envoyerAlerteRetard } from '@/app/actions/alertes'
import Link from 'next/link'
import { isDemoMode, DEMO_POINTAGES, DEMO_ABSENCES, DEMO_PROFESSEURS, DEMO_ELEVES, DEMO_CLASSES } from '@/lib/demo-data'

interface PointageRow { id: string; prof_id: string; statut: string; minutes_retard: number; heure_arrivee: string; alerte_envoyee: boolean; date_pointage: string }
interface ProfInfo { id: string; nom: string; prenom: string; photo_url: string | null }
interface RetardGrave extends PointageRow { prof?: ProfInfo }
interface AbsenceEleve { id: string; eleve_id: string; date_absence: string; session: string; motif: string | null; valide_par: string | null; valide_le: string | null; eleve?: { nom: string; prenom: string; photo_url: string | null; classe?: { nom: string } } }
interface HeatmapCell { prof_id: string; prof_nom: string; jour: string; statut: string | null }

const STATUT_PALETTE: Record<string, { bg: string; color: string }> = {
  a_heure:     { bg: 'rgba(0,230,118,0.25)',  color: '#00E676' },
  retard_leger:{ bg: 'rgba(255,214,0,0.25)',  color: '#FFD600' },
  retard_grave:{ bg: 'rgba(255,23,68,0.25)',  color: '#FF1744' },
  absent:      { bg: 'rgba(100,116,139,0.25)', color: '#64748B' },
}
const JOUR_LABELS = ['Lun', 'Mar', 'Mer', 'Jeu', 'Ven', 'Sam']

export default function SurveillantDashboard() {
  const { user, loading: userLoading } = useUser()
  const supabase = createClient()

  const [stats, setStats] = useState({ presents: 0, retards: 0, graves: 0, absents: 0, total: 0 })
  const [statsLoading, setStatsLoading] = useState(true)
  const [retardsGraves, setRetardsGraves] = useState<RetardGrave[]>([])
  const [absences, setAbsences] = useState<AbsenceEleve[]>([])
  const [heatmap, setHeatmap] = useState<HeatmapCell[]>([])
  const [profs, setProfs] = useState<ProfInfo[]>([])
  const [appelsRecents, setAppelsRecents] = useState<{ id: string; titre: string; contenu: string; created_at: string; lu_le: string | null }[]>([])
  const audioCtxRef = useRef<AudioContext | null>(null)
  const ecoleId = user?.ecole_id

  const playAlertSound = useCallback(() => {
    try {
      if (!audioCtxRef.current) audioCtxRef.current = new AudioContext()
      const ctx = audioCtxRef.current
      const osc = ctx.createOscillator(); const gain = ctx.createGain()
      osc.connect(gain); gain.connect(ctx.destination)
      osc.frequency.value = 880; osc.type = 'square'; gain.gain.value = 0.15
      osc.start(); osc.stop(ctx.currentTime + 0.3)
    } catch {}
  }, [])

  const loadStats = useCallback(async () => {
    if (!ecoleId) return
    const today = new Date().toISOString().split('T')[0]
    const { data } = await supabase.from('pointages_profs').select('*').eq('ecole_id', ecoleId).eq('date_pointage', today)
    const rows = (data || []) as unknown as PointageRow[]
    const { count: totalProfs } = await supabase.from('utilisateurs').select('*', { count: 'exact', head: true }).eq('ecole_id', ecoleId).eq('role', 'professeur').eq('actif', true)
    setStats({ presents: rows.filter(r => r.statut === 'a_heure').length, retards: rows.filter(r => r.statut === 'retard_leger').length, graves: rows.filter(r => r.statut === 'retard_grave').length, absents: Math.max(0, (totalProfs || 0) - rows.length), total: totalProfs || 0 })
    setStatsLoading(false)
  }, [ecoleId, supabase])

  const loadAppels = useCallback(async () => {
    if (!ecoleId) return
    if (isDemoMode()) { setAppelsRecents([{ id: '1', titre: 'Appel validé — 6ème A', contenu: '2 absent(s), 1 retard(s)', created_at: new Date().toISOString(), lu_le: null }, { id: '2', titre: 'Appel validé — 5ème A', contenu: '0 absent(s)', created_at: new Date().toISOString(), lu_le: null }]); return }
    const { data } = await (supabase.from('notifications') as any).select('id, titre, contenu, created_at, lu_le').eq('ecole_id', ecoleId).eq('type_notif', 'appel_valide').order('created_at', { ascending: false }).limit(10)
    setAppelsRecents(data || [])
  }, [ecoleId, supabase])

  useEffect(() => {
    if (!ecoleId) return
    if (isDemoMode()) {
      const today = new Date().toISOString().split('T')[0]
      const todayP = DEMO_POINTAGES.filter(p => p.date_pointage === today)
      const total = DEMO_PROFESSEURS.length
      setStats({ presents: todayP.filter(r => r.statut === 'a_heure').length, retards: todayP.filter(r => r.statut === 'retard_leger').length, graves: todayP.filter(r => r.statut === 'retard_grave').length, absents: Math.max(0, total - todayP.length), total })
      setStatsLoading(false)
      setRetardsGraves(todayP.filter(p => p.statut === 'retard_grave').map(p => { const prof = DEMO_PROFESSEURS.find(pr => pr.id === p.prof_id); return { ...p, prof: prof ? { id: prof.id, nom: prof.nom, prenom: prof.prenom, photo_url: prof.photo_url } : undefined } as RetardGrave }))
      setAbsences(DEMO_ABSENCES.filter((a: any) => !a.justifiee && !a.valide_par).slice(0, 20).map((a: any) => { const eleve = DEMO_ELEVES.find(e => e.id === a.eleve_id); const classe = eleve ? DEMO_CLASSES.find(c => c.id === eleve.classe_id) : null; return { id: a.id, eleve_id: a.eleve_id, date_absence: a.date_absence, session: 'journee', motif: a.motif, valide_par: a.valide_par, valide_le: null, eleve: eleve ? { nom: eleve.nom, prenom: eleve.prenom, photo_url: null, classe: classe ? { nom: `${classe.niveau} ${classe.nom}` } : undefined } : undefined } as AbsenceEleve }))
      const profsList = DEMO_PROFESSEURS.map(p => ({ id: p.id, nom: p.nom, prenom: p.prenom, photo_url: p.photo_url })); setProfs(profsList)
      const dates: string[] = []; for (let i = 6; i >= 0; i--) { const d = new Date(); d.setDate(d.getDate() - i); if (d.getDay() !== 0) dates.push(d.toISOString().split('T')[0]) }
      setHeatmap(profsList.flatMap(prof => dates.map(date => { const match = DEMO_POINTAGES.find(r => r.prof_id === prof.id && r.date_pointage === date); return { prof_id: prof.id, prof_nom: `${prof.prenom} ${prof.nom}`, jour: date, statut: match?.statut || null } })))
      loadAppels(); return
    }
    loadStats(); loadAppels()
    const channel = supabase.channel('retards-live').on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'pointages_profs', filter: `ecole_id=eq.${ecoleId}` }, async (payload) => {
      const newRow = payload.new as unknown as PointageRow; loadStats()
      if (newRow.statut === 'retard_grave' && !newRow.alerte_envoyee) { playAlertSound(); const { data: profData } = await supabase.from('utilisateurs').select('id, nom, prenom, photo_url').eq('id', newRow.prof_id).single(); setRetardsGraves(prev => [{ ...newRow, prof: profData as unknown as ProfInfo }, ...prev]); envoyerAlerteRetard(newRow.id) }
    }).subscribe()
    return () => { supabase.removeChannel(channel) }
  }, [ecoleId, supabase, loadStats, loadAppels, playAlertSound])

  const heatmapDates = [...new Set(heatmap.map(c => c.jour))].sort()
  const formatH = (iso: string) => { try { return new Date(iso).toLocaleTimeString('fr-SN', { hour: '2-digit', minute: '2-digit' }) } catch { return iso } }

  if (userLoading) return <div className="space-y-4">{[...Array(4)].map((_, i) => <div key={i} className="h-28 rounded-2xl ss-shimmer" style={{ background: 'rgba(255,255,255,0.03)' }} />)}</div>

  return (
    <div className="space-y-5 pb-6 animate-fade-in">

      {/* Bannière */}
      <div className="relative rounded-2xl overflow-hidden min-h-[120px]">
        <img src="https://images.unsplash.com/photo-1568992687947-868a62a9f521?auto=format&fit=crop&w=1200&q=80" alt="Surveillance" className="absolute inset-0 w-full h-full object-cover" />
        <div className="absolute inset-0" style={{ background: 'linear-gradient(135deg, rgba(2,6,23,0.95) 0%, rgba(2,6,23,0.6) 100%)' }} />
        <div className="relative px-6 py-5">
          <div className="flex items-center gap-2 mb-1">
            <span className="w-2 h-2 rounded-full bg-[#FFD600] animate-pulse" />
            <span className="text-xs font-semibold tracking-wider uppercase text-[#94A3B8]">Espace Surveillant</span>
          </div>
          <h1 className="text-2xl font-black text-white">Surveillance & Discipline</h1>
        </div>
      </div>

      {/* Appels reçus */}
      <div className="rounded-2xl p-5" style={{ background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.07)' }}>
        <div className="flex items-center justify-between mb-4">
          <h2 className="text-sm font-bold text-[#94A3B8] uppercase tracking-wider">Appels reçus</h2>
          <span className="text-xs font-bold px-2 py-1 rounded-full" style={{ background: 'rgba(0,229,255,0.12)', color: '#00E5FF', border: '1px solid rgba(0,229,255,0.2)' }}>
            {appelsRecents.filter(a => !a.lu_le).length} nouveau(x)
          </span>
        </div>
        <div className="space-y-2">
          {appelsRecents.length === 0
            ? <p className="text-sm text-center py-4" style={{ color: '#475569' }}>Aucun appel reçu aujourd'hui</p>
            : appelsRecents.map(a => (
              <div key={a.id} className="flex items-center justify-between p-3 rounded-xl"
                style={{ background: !a.lu_le ? 'rgba(0,229,255,0.06)' : 'rgba(255,255,255,0.03)', border: `1px solid ${!a.lu_le ? 'rgba(0,229,255,0.2)' : 'rgba(255,255,255,0.07)'}` }}>
                <div>
                  <p className="text-sm font-semibold text-white">{a.titre}</p>
                  <p className="text-xs mt-0.5" style={{ color: '#94A3B8' }}>{a.contenu}</p>
                </div>
                {!a.lu_le && (
                  <button onClick={() => {
                    if (isDemoMode()) { setAppelsRecents(prev => prev.map(x => x.id === a.id ? { ...x, lu_le: new Date().toISOString() } : x)); return }
                    ;(supabase.from('notifications') as any).update({ lu_le: new Date().toISOString() }).eq('id', a.id)
                  }}
                    className="text-xs font-bold px-3 py-1.5 rounded-lg shrink-0 ml-3 transition-all"
                    style={{ background: '#00853F', color: '#fff' }}>
                    ✓ Valider
                  </button>
                )}
              </div>
            ))}
        </div>
      </div>

      {/* Actions rapides */}
      <div className="grid grid-cols-3 gap-3">
        {[
          { href: '/surveillant/absences',      icon: '📋', label: 'Gerer absences',  color: '#FFD600' },
          { href: '/surveillant/statistiques',  icon: '📊', label: 'Statistiques',    color: '#00E5FF' },
          { href: '/surveillant/export',        icon: '📥', label: 'Export rapports',  color: '#00E676' },
        ].map(a => (
          <Link key={a.href} href={a.href}
            className="flex flex-col items-center gap-2 p-4 rounded-xl text-center transition-all duration-200 hover:scale-105 active:scale-95"
            style={{ background: `${a.color}12`, border: `1px solid ${a.color}30` }}>
            <span className="text-2xl">{a.icon}</span>
            <span className="text-xs font-semibold leading-tight text-white">{a.label}</span>
          </Link>
        ))}
      </div>

      {/* KPI */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        <StatCard title="Présents" value={stats.presents} subtitle={`sur ${stats.total}`} icon="🟢" color="green" loading={statsLoading} />
        <StatCard title="Retards légers" value={stats.retards} subtitle="< 20 min" icon="🟡" color="gold" loading={statsLoading} />
        <StatCard title="Retards graves" value={stats.graves} subtitle="≥ 20 min" icon="🔴" color="red" loading={statsLoading} />
        <StatCard title="Non pointés" value={stats.absents} subtitle="Absence probable" icon="⚫" color="cyan" loading={statsLoading} />
      </div>

      {/* Retards graves live */}
      <div className="rounded-2xl p-5" style={{ background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.07)' }}>
        <div className="flex items-center justify-between mb-4">
          <h2 className="text-sm font-bold text-[#94A3B8] uppercase tracking-wider flex items-center gap-2">
            <span className="w-2 h-2 rounded-full bg-[#FF1744] animate-pulse" />
            Retards graves — Temps réel
          </h2>
          <span className="text-xs" style={{ color: '#475569' }}>{retardsGraves.length} alerte(s)</span>
        </div>
        {retardsGraves.length === 0 ? (
          <div className="flex flex-col items-center py-8 text-center">
            <div className="w-12 h-12 rounded-2xl flex items-center justify-center mb-3 text-2xl" style={{ background: 'rgba(0,230,118,0.1)', border: '1px solid rgba(0,230,118,0.2)' }}>✅</div>
            <p className="text-sm" style={{ color: '#94A3B8' }}>Aucun retard grave aujourd'hui</p>
          </div>
        ) : (
          <div className="space-y-3">
            {retardsGraves.map(r => (
              <div key={r.id} className="flex items-center gap-3 p-3 rounded-xl" style={{ background: 'rgba(255,23,68,0.07)', border: '1px solid rgba(255,23,68,0.2)' }}>
                <div className="w-10 h-10 rounded-xl flex items-center justify-center font-bold text-sm shrink-0 overflow-hidden"
                  style={{ background: 'rgba(255,23,68,0.2)', color: '#FF1744', border: '1px solid rgba(255,23,68,0.3)' }}>
                  {r.prof?.photo_url ? <img src={r.prof.photo_url} alt="" className="w-full h-full object-cover" /> : r.prof ? `${r.prof.prenom[0]}${r.prof.nom[0]}` : '?'}
                </div>
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-bold text-white truncate">{r.prof ? `${r.prof.prenom} ${r.prof.nom}` : 'Professeur'}</p>
                  <p className="text-xs" style={{ color: '#94A3B8' }}>Arrivée {formatH(r.heure_arrivee)}</p>
                </div>
                <div className="text-right shrink-0">
                  <span className="text-sm font-black text-white">+{r.minutes_retard} min</span>
                  {r.alerte_envoyee && <p className="text-[10px]" style={{ color: '#475569' }}>SMS envoyé</p>}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Absences non justifiées */}
      <div className="rounded-2xl p-5" style={{ background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.07)' }}>
        <div className="flex items-center justify-between mb-4">
          <h2 className="text-sm font-bold text-[#94A3B8] uppercase tracking-wider">Absences non justifiées</h2>
          <span className="text-xs" style={{ color: '#475569' }}>{absences.length}</span>
        </div>
        {absences.length === 0 ? (
          <div className="flex flex-col items-center py-8 text-center">
            <div className="w-12 h-12 rounded-2xl flex items-center justify-center mb-3 text-2xl" style={{ background: 'rgba(0,230,118,0.1)', border: '1px solid rgba(0,230,118,0.2)' }}>📋</div>
            <p className="text-sm" style={{ color: '#94A3B8' }}>Toutes les absences sont justifiées</p>
          </div>
        ) : (
          <div className="space-y-2">
            {absences.slice(0, 10).map(a => (
              <div key={a.id} className="flex items-center gap-3 p-3 rounded-xl" style={{ background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.06)' }}>
                <div className="w-9 h-9 rounded-xl flex items-center justify-center text-sm font-bold shrink-0"
                  style={{ background: 'rgba(255,214,0,0.1)', border: '1px solid rgba(255,214,0,0.2)', color: '#FFD600' }}>
                  {a.eleve ? `${a.eleve.prenom[0]}${a.eleve.nom[0]}` : '?'}
                </div>
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-semibold text-white truncate">{a.eleve ? `${a.eleve.prenom} ${a.eleve.nom}` : `Élève #${a.eleve_id.slice(0, 6)}`}</p>
                  <p className="text-xs" style={{ color: '#94A3B8' }}>{new Date(a.date_absence).toLocaleDateString('fr-SN', { day: '2-digit', month: 'short' })}{a.motif && ` · ${a.motif}`}</p>
                </div>
                <button
                  className="text-xs font-bold px-3 py-2 rounded-lg shrink-0 min-h-[36px] transition-all"
                  style={{ background: 'rgba(0,229,255,0.1)', border: '1px solid rgba(0,229,255,0.2)', color: '#00E5FF' }}
                  onClick={async () => {
                    if (!user) return
                    const { validerAbsence } = await import('@/app/actions/alertes')
