                  }}>
                  Valider
                </button>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Heatmap */}
      {profs.length > 0 && heatmapDates.length > 0 && (
        <div className="rounded-2xl p-5" style={{ background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.07)' }}>
          <h2 className="text-sm font-bold text-[#94A3B8] uppercase tracking-wider mb-4">Pointages — 7 derniers jours</h2>
          <div className="overflow-x-auto scrollbar-hide">
            <table className="w-full min-w-[400px]">
              <thead>
                <tr>
                  <th className="text-left text-xs pb-3 pr-3" style={{ color: '#475569' }}>Professeur</th>
                  {heatmapDates.map(d => { const day = new Date(d); const idx = (day.getDay() + 6) % 7; return <th key={d} className="text-center text-xs pb-3 px-1 w-10" style={{ color: '#475569' }}>{JOUR_LABELS[idx] || '?'}<br/><span className="text-[10px]">{day.getDate()}</span></th> })}
                </tr>
              </thead>
              <tbody>
                {profs.map(p => (
                  <tr key={p.id}>
                    <td className="text-xs text-white py-1.5 pr-3 truncate max-w-[120px]">{p.prenom} {p.nom}</td>
                    {heatmapDates.map(d => {
                      const cell = heatmap.find(c => c.prof_id === p.id && c.jour === d)
                      const pal = cell?.statut ? STATUT_PALETTE[cell.statut] : { bg: 'rgba(255,255,255,0.05)', color: 'transparent' }
                      return <td key={d} className="text-center py-1.5 px-0.5"><div className="w-8 h-8 mx-auto rounded-lg transition-opacity hover:opacity-100 opacity-80 cursor-default" style={{ background: pal.bg }} title={`${p.prenom} ${p.nom} — ${cell?.statut?.replace('_', ' ') || 'Non pointé'}`} /></td>
                    })}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
          <div className="flex flex-wrap gap-4 mt-4 pt-4" style={{ borderTop: '1px solid rgba(255,255,255,0.06)' }}>
            {[{ label: "À l'heure", key: 'a_heure' }, { label: 'Retard léger', key: 'retard_leger' }, { label: 'Retard grave', key: 'retard_grave' }].map(l => {
              const pal = STATUT_PALETTE[l.key]
              return <div key={l.key} className="flex items-center gap-1.5"><div className="w-3 h-3 rounded-sm" style={{ background: pal.bg }} /><span className="text-xs" style={{ color: '#475569' }}>{l.label}</span></div>
            })}
          </div>
        </div>
      )}
    </div>
  )
}

'use client'

import { useEffect, useState, useMemo } from 'react'
import { createClient } from '@/lib/supabase/client'
import { useUser } from '@/hooks/useUser'
import { StatCard } from '@/components/dashboard/StatCard'
import {
  isDemoMode, DEMO_ABSENCES, DEMO_POINTAGES, DEMO_PROFESSEURS,
  DEMO_ELEVES, DEMO_CLASSES
} from '@/lib/demo-data'

type Periode = 'mois' | 't1' | 't2' | 't3'

function getPeriodeDates(periode: Periode): { start: string; end: string } {
  const now = new Date()
  const year = now.getFullYear()
  switch (periode) {
    case 'mois': {
      const s = new Date(year, now.getMonth(), 1)
      const e = new Date(year, now.getMonth() + 1, 0)
      return { start: s.toISOString().split('T')[0], end: e.toISOString().split('T')[0] }
    }
    case 't1': return { start: `${year - 1}-10-01`, end: `${year - 1}-12-31` }
    case 't2': return { start: `${year}-01-01`, end: `${year}-03-31` }
    case 't3': return { start: `${year}-04-01`, end: `${year}-06-30` }
  }
}

export default function SurveillantStatistiquesPage() {
  const { user, loading: userLoading } = useUser()
  const supabase = createClient()

  const [periode, setPeriode] = useState<Periode>('mois')
  const [loading, setLoading] = useState(false)

  const dates = useMemo(() => getPeriodeDates(periode), [periode])

  // Calculate stats from demo data
  const stats = useMemo(() => {
    if (!isDemoMode()) return null

    const absences = DEMO_ABSENCES.filter((a: any) => a.date_absence >= dates.start && a.date_absence <= dates.end)
    const totalAbs = absences.length
    const justifiees = absences.filter((a: any) => a.justifiee).length
    const tauxJustif = totalAbs > 0 ? Math.round((justifiees / totalAbs) * 100) : 100

    const pointages = DEMO_POINTAGES.filter((p: any) => p.date_pointage >= dates.start && p.date_pointage <= dates.end)
    const retardsTotal = pointages.filter((p: any) => p.statut !== 'a_heure').length
    const retardsGraves = pointages.filter((p: any) => p.statut === 'retard_grave').length

    return { totalAbs, tauxJustif, retardsTotal, retardsGraves }
  }, [dates])

  // Absences par classe
  const absencesParClasse = useMemo(() => {
    if (!isDemoMode()) return []
    const absences = DEMO_ABSENCES.filter((a: any) => a.date_absence >= dates.start && a.date_absence <= dates.end)
    const classeCount: Record<string, { nom: string; count: number }> = {}
    for (const a of absences as any[]) {
      const eleve = DEMO_ELEVES.find(e => e.id === a.eleve_id)
      if (!eleve) continue
      const classe = DEMO_CLASSES.find(c => c.id === eleve.classe_id)
      if (!classe) continue
      const key = classe.id
      if (!classeCount[key]) classeCount[key] = { nom: `${classe.niveau} ${classe.nom}`, count: 0 }
      classeCount[key].count++
    }
    return Object.values(classeCount).sort((a, b) => b.count - a.count)
  }, [dates])

  const maxAbsClasse = useMemo(() => Math.max(...absencesParClasse.map(c => c.count), 1), [absencesParClasse])

  // Ponctualite profs
  const profPonctualite = useMemo(() => {
    if (!isDemoMode()) return []
    const pointages = DEMO_POINTAGES.filter((p: any) => p.date_pointage >= dates.start && p.date_pointage <= dates.end)
    return DEMO_PROFESSEURS.map(prof => {
      const profP = pointages.filter((p: any) => p.prof_id === prof.id)
      const aHeure = profP.filter((p: any) => p.statut === 'a_heure').length
      const total = profP.length
      return {
        nom: `${prof.prenom} ${prof.nom}`,
        aHeure,
        total,
        taux: total > 0 ? Math.round((aHeure / total) * 100) : 0,
      }
    }).sort((a, b) => b.taux - a.taux)
  }, [dates])

  // Top eleves absents
  const topAbsents = useMemo(() => {
    if (!isDemoMode()) return []
    const absences = DEMO_ABSENCES.filter((a: any) => a.date_absence >= dates.start && a.date_absence <= dates.end)
    const eleveCount: Record<string, { nom: string; classe: string; count: number }> = {}
    for (const a of absences as any[]) {
      const eleve = DEMO_ELEVES.find(e => e.id === a.eleve_id)
      if (!eleve) continue
      const classe = DEMO_CLASSES.find(c => c.id === eleve.classe_id)
      if (!eleveCount[a.eleve_id]) eleveCount[a.eleve_id] = {
        nom: `${eleve.prenom} ${eleve.nom}`,
        classe: classe ? `${classe.niveau} ${classe.nom}` : '',
        count: 0,
      }
      eleveCount[a.eleve_id].count++
    }
    return Object.values(eleveCount).sort((a, b) => b.count - a.count).slice(0, 10)
  }, [dates])

  if (userLoading) {
    return <div className="space-y-4">{[...Array(4)].map((_, i) => <div key={i} className="h-28 rounded-2xl ss-shimmer" style={{ background: 'rgba(255,255,255,0.03)' }} />)}</div>
  }

  return (
    <div className="space-y-5 pb-6 animate-fade-in">
      {/* Header */}
      <div className="flex items-center justify-between flex-wrap gap-3">
        <h1 className="text-2xl font-black text-white">Statistiques</h1>
        <div className="flex gap-1 p-1 rounded-xl" style={{ background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.08)' }}>
          {([
            { key: 'mois' as const, label: 'Ce mois' },
            { key: 't1' as const, label: 'T1' },
            { key: 't2' as const, label: 'T2' },
            { key: 't3' as const, label: 'T3' },
          ]).map(p => (
            <button key={p.key} onClick={() => setPeriode(p.key)}
              className="px-3 py-1.5 rounded-lg text-xs font-bold transition-all"
              style={{
                background: periode === p.key ? 'rgba(255,214,0,0.15)' : 'transparent',
                color: periode === p.key ? '#FFD600' : '#94A3B8',
                border: periode === p.key ? '1px solid rgba(255,214,0,0.3)' : '1px solid transparent',
              }}>
              {p.label}
            </button>
          ))}
        </div>
      </div>

      {/* KPI */}
      {stats && (
        <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
          <StatCard title="Total absences" value={stats.totalAbs} subtitle="Eleves" icon="📅" color={stats.totalAbs > 20 ? 'red' : 'gold'} />
          <StatCard title="Taux justification" value={`${stats.tauxJustif}%`} subtitle="Des absences" icon="📋" color={stats.tauxJustif >= 80 ? 'green' : stats.tauxJustif >= 50 ? 'gold' : 'red'} />
          <StatCard title="Retards profs" value={stats.retardsTotal} subtitle="Total" icon="🕐" color="gold" />
          <StatCard title="Retards graves" value={stats.retardsGraves} subtitle=">= 20 min" icon="🔴" color="red" />
        </div>
      )}

      {/* Absences par classe - Bar chart */}
      <div className="rounded-2xl p-5" style={{ background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.07)' }}>
        <h2 className="text-sm font-bold text-[#94A3B8] uppercase tracking-wider mb-4">Absences par classe</h2>
        {absencesParClasse.length === 0 ? (
          <p className="text-sm text-center py-6" style={{ color: '#475569' }}>Aucune donnee</p>
        ) : (
          <div className="space-y-3">
            {absencesParClasse.map((c, idx) => (
              <div key={idx} className="flex items-center gap-3">
                <span className="text-xs font-semibold text-white w-20 shrink-0 truncate">{c.nom}</span>
                <div className="flex-1 h-7 rounded-lg overflow-hidden" style={{ background: 'rgba(255,255,255,0.04)' }}>
                  <div className="h-full rounded-lg flex items-center px-2 transition-all duration-500"
                    style={{
                      width: `${Math.max((c.count / maxAbsClasse) * 100, 8)}%`,
                      background: c.count > 10 ? 'rgba(255,23,68,0.3)' : c.count > 5 ? 'rgba(255,214,0,0.3)' : 'rgba(0,230,118,0.3)',
                    }}>
                    <span className="text-[10px] font-bold text-white">{c.count}</span>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Two columns: Prof ranking + Top absent students */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
        {/* Ponctualite profs */}
        <div className="rounded-2xl p-5" style={{ background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.07)' }}>
          <h2 className="text-sm font-bold text-[#94A3B8] uppercase tracking-wider mb-4">Ponctualite professeurs</h2>
          <div className="space-y-2">
            {profPonctualite.map((p, idx) => {
              const color = p.taux >= 90 ? '#00E676' : p.taux >= 70 ? '#FFD600' : '#FF1744'
              return (
                <div key={idx} className="flex items-center gap-3 p-3 rounded-xl"
                  style={{ background: 'rgba(255,255,255,0.02)', border: '1px solid rgba(255,255,255,0.05)' }}>
                  <span className="text-xs font-bold w-6 text-center" style={{ color: '#475569' }}>{idx + 1}</span>
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-semibold text-white truncate">{p.nom}</p>
                    <p className="text-[10px]" style={{ color: '#475569' }}>{p.aHeure}/{p.total} jours</p>
                  </div>
                  <span className="text-sm font-black px-2 py-0.5 rounded-md"
                    style={{ background: `${color}15`, color }}>{p.taux}%</span>
                </div>
              )
            })}
          </div>
        </div>

        {/* Top eleves absents */}
        <div className="rounded-2xl p-5" style={{ background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.07)' }}>
          <h2 className="text-sm font-bold text-[#94A3B8] uppercase tracking-wider mb-4">Eleves les plus absents</h2>
          {topAbsents.length === 0 ? (
            <p className="text-sm text-center py-6" style={{ color: '#475569' }}>Aucune absence</p>
          ) : (
            <div className="space-y-2">
              {topAbsents.map((e, idx) => (
                <div key={idx} className="flex items-center gap-3 p-3 rounded-xl"
                  style={{ background: 'rgba(255,255,255,0.02)', border: '1px solid rgba(255,255,255,0.05)' }}>
                  <div className="w-8 h-8 rounded-lg flex items-center justify-center text-xs font-bold shrink-0"
                    style={{ background: 'rgba(255,23,68,0.1)', border: '1px solid rgba(255,23,68,0.2)', color: '#FF1744' }}>
                    {e.count}
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-semibold text-white truncate">{e.nom}</p>
                    <p className="text-xs" style={{ color: '#94A3B8' }}>{e.classe}</p>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  )
}

'use server'

import { createClient } from '@/lib/supabase/server'

export async function envoyerAlerteRetard(pointageId: string) {
  const supabase = await createClient()

  // Récupérer les infos du pointage avec le profil prof et l'école
  const { data: pointage, error: fetchErr } = await supabase
    .from('pointages_profs')
    .select('*')
    .eq('id', pointageId)
    .single()

  if (fetchErr || !pointage) {
    return { success: false, error: 'Pointage introuvable' }
  }

  const p = pointage as any

  // Récupérer le profil du professeur
  const { data: prof } = await supabase
    .from('utilisateurs')
    .select('*')
    .eq('id', p.prof_id)
    .single()

  // Récupérer l'école
  const { data: ecole } = await supabase
    .from('ecoles')
    .select('*')
    .eq('id', p.ecole_id)
    .single()

  const profData = prof as any
  const ecoleData = ecole as any

  if (!profData || !ecoleData) {
    return { success: false, error: 'Données incomplètes' }
  }

  const message = `⚠️ SmartSchool SN — ${profData.prenom} ${profData.nom} est en retard de ${p.minutes_retard} min à ${ecoleData.nom}. Cours non démarré.`

  // Envoi SMS via Africa's Talking (si les clés sont configurées)
  if (process.env.AFRICASTALKING_API_KEY && profData.telephone) {
    try {
      const AT = require('africastalking')({
        apiKey: process.env.AFRICASTALKING_API_KEY,
        username: process.env.AFRICASTALKING_USERNAME || 'smartschool',
      })

      let phone = profData.telephone.replace(/\s/g, '')
      if (!phone.startsWith('+')) {
        phone = '+221' + phone
      }

      await AT.SMS.send({
        to: [phone],
        message: `Bonjour ${profData.prenom}, votre retard de ${p.minutes_retard} min est enregistré. — SmartSchool SN`,
        from: 'SmartSchool',
      })
    } catch (smsErr) {
      console.error('Erreur SMS Africa\'s Talking:', smsErr)
    }
  }

  // Notification in-app pour les admin_global de l'école
  const { data: admins } = await supabase
    .from('utilisateurs')
    .select('id')
    .eq('ecole_id', p.ecole_id)
    .eq('role', 'admin_global')
    .eq('actif', true)

  if (admins && admins.length > 0) {
    const notifs = (admins as any[]).map((admin) => ({
      user_id: admin.id,
      ecole_id: p.ecole_id,
      type_notif: 'retard_grave',
      priorite: 1,
      titre: '⚠️ Retard grave professeur',
      contenu: message,
    }))

    await supabase.from('notifications').insert(notifs as any)
  }

  // Marquer alerte comme envoyée
  await (supabase
    .from('pointages_profs') as any)
    .update({ alerte_envoyee: true })
    .eq('id', pointageId)

  return { success: true }
}

export async function validerAbsence(absenceId: string, valideurId: string) {
  const supabase = await createClient()

  const { error } = await (supabase
    .from('absences_eleves') as any)
    .update({
      valide_par: valideurId,
      valide_le: new Date().toISOString(),
    })
    .eq('id', absenceId)

  if (error) {
    return { success: false, error: error.message }
  }

  return { success: true }
}

'use server'

import { createClient } from '@/lib/supabase/server'

export async function envoyerRelanceSMS(factureId: string) {
  const supabase = await createClient()

  // Récupérer facture + élève + parent
  const { data: facture, error: fetchErr } = await (supabase
    .from('factures') as any)
    .select('*, eleves(nom, prenom, parent_principal_id, classe_id, classes(nom))')
    .eq('id', factureId)
    .single()

  if (fetchErr || !facture) {
    return { success: false, error: 'Facture introuvable' }
  }

  const parentId = facture.eleves?.parent_principal_id
  if (!parentId) {
    return { success: false, error: 'Parent non renseigné' }
  }

  // Récupérer le téléphone du parent
  const { data: parent } = await supabase
    .from('utilisateurs')
    .select('telephone, nom, prenom')
    .eq('id', parentId)
    .single()

  const parentData = parent as { telephone: string | null; nom: string; prenom: string } | null
  if (!parentData?.telephone) {
    return { success: false, error: 'Téléphone parent non disponible' }
  }

  const eleveNom = `${facture.eleves.prenom} ${facture.eleves.nom}`
  const solde = new Intl.NumberFormat('fr-SN').format(facture.solde_restant)
  const message = `SmartSchool: Rappel frais scolarité ${eleveNom}. Montant dû: ${solde} FCFA. Merci de régulariser rapidement.`

  // Envoi SMS via Africa's Talking
  if (process.env.AFRICASTALKING_API_KEY) {
    try {
      const AT = require('africastalking')({
        apiKey: process.env.AFRICASTALKING_API_KEY,
        username: process.env.AFRICASTALKING_USERNAME || 'smartschool',
      })

      let phone = parentData.telephone.replace(/\s/g, '')
      if (!phone.startsWith('+')) {
        phone = '+221' + phone
      }

      await AT.SMS.send({
        to: [phone],
        message,
        from: 'SmartSchool',
      })
    } catch (smsErr) {
      console.error('Erreur SMS relance:', smsErr)
    }
  }

  // Incrémenter nb_relances
  await (supabase.from('factures') as any)
    .update({ nb_relances: (facture.nb_relances || 0) + 1 })
    .eq('id', factureId)

  // Notification in-app au parent
  await (supabase.from('notifications') as any).insert({
    user_id: parentId,
    ecole_id: facture.ecole_id,
    type_notif: 'relance_paiement',
    priorite: 2,
    titre: 'Rappel de paiement',
    contenu: `Rappel: frais de scolarité de ${eleveNom} — ${solde} FCFA restant.`,
  })

  return { success: true }
}

export async function envoyerRelanceWhatsApp(factureId: string) {
  const supabase = await createClient()

  // Récupérer les infos
  const { data: facture } = await (supabase.from('factures') as any)
    .select('*, eleves(nom, prenom, utilisateurs!eleves_parent_principal_id_fkey(nom, telephone))')
    .eq('id', factureId)
    .single() as { data: any }

  if (!facture) return { success: false, error: 'Facture introuvable' }

  const parent = facture.eleves?.utilisateurs
  const telephone = parent?.telephone

  if (!telephone) return { success: false, error: 'Téléphone parent non renseigné' }

  const { sendWhatsApp } = await import('@/lib/whatsapp')

  const result = await sendWhatsApp({
    to: telephone,
    template: 'relance',
    data: {
      parentNom: parent?.nom || 'Parent',
      montant: new Intl.NumberFormat('fr-SN').format(facture.solde_restant || facture.montant_total),
      elevePrenom: facture.eleves?.prenom || 'votre enfant',
      typeFrags: facture.type_frais,
      dateLimite: new Date(facture.date_limite).toLocaleDateString('fr-SN'),
      ecoleNom: 'SmartSchool SN',
    }
  })

  if (result.success) {
    // Incrémenter nb_relances
    await (supabase.from('factures') as any)
      .update({ nb_relances: (facture.nb_relances || 0) + 1 })
      .eq('id', factureId)
  }

  return result
}

export async function marquerPayeEspeces(factureId: string, montant: number, reference: string) {
  const supabase = await createClient()

  const { data: facture } = await (supabase
    .from('factures') as any)
    .select('ecole_id, solde_restant, montant_total, montant_verse, type_frais, eleves(nom, prenom, parent_principal_id)')
    .eq('id', factureId)
    .single()

  if (!facture) {
    return { success: false, error: 'Facture introuvable' }
  }

  const f = facture as { ecole_id: string; solde_restant: number; montant_total: number; montant_verse: number; type_frais: string; eleves: { nom: string; prenom: string; parent_principal_id: string | null } | null }
  const montantFinal = Math.min(montant, f.solde_restant)

  const { error } = await (supabase.from('paiements') as any).insert({
    facture_id: factureId,
    ecole_id: f.ecole_id,
    montant: montantFinal,
    methode: 'especes',
    reference_transaction: reference || `ESP-${Date.now()}`,
    statut_confirmation: 'confirmed',
  })

  if (error) {
    return { success: false, error: error.message }
  }

  // Notify parent about the payment confirmation
  const parentId = f.eleves?.parent_principal_id
  if (parentId) {
    const eleveNom = f.eleves ? `${f.eleves.prenom} ${f.eleves.nom}` : ''
    const montantFormate = new Intl.NumberFormat('fr-SN').format(montantFinal)
    const nouveauSolde = f.solde_restant - montantFinal
    const soldeFormate = new Intl.NumberFormat('fr-SN').format(nouveauSolde)

    await (supabase.from('notifications') as any).insert({
      user_id: parentId,
      ecole_id: f.ecole_id,
      type_notif: 'paiement_confirme',
      priorite: 1,
      titre: 'Paiement enregistré',
      contenu: nouveauSolde <= 0
        ? `Paiement de ${montantFormate} FCFA reçu pour ${eleveNom} (${f.type_frais}). Facture entièrement réglée.`
        : `Paiement de ${montantFormate} FCFA reçu pour ${eleveNom} (${f.type_frais}). Solde restant: ${soldeFormate} FCFA.`,
    })
  }

  return { success: true }
}

