// Utilitaire : vérifier si le message contient un des mots-clés
function matches(text: string, keywords: string[]): boolean {
  return keywords.some(kw => text.includes(kw))
}

// Cron job : relances automatiques des factures impayées
// Appelé par Vercel Cron chaque lundi à 8h (heure Dakar)
// vercel.json: { "crons": [{ "path": "/api/cron/relances", "schedule": "0 8 * * 1" }] }

import { NextResponse } from 'next/server'
import { createClient } from '@supabase/supabase-js'

const CRON_SECRET = process.env.CRON_SECRET || ''

export async function GET(request: Request) {
  // Vérifier l'authentification du cron
  const authHeader = request.headers.get('authorization')
  if (CRON_SECRET && authHeader !== `Bearer ${CRON_SECRET}`) {
    return NextResponse.json({ error: 'Non autorisé' }, { status: 401 })
  }

  const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL
  const serviceRoleKey = process.env.SUPABASE_SERVICE_ROLE_KEY

  if (!supabaseUrl || !serviceRoleKey || serviceRoleKey.includes('placeholder')) {
    return NextResponse.json({
      message: 'Mode test — relances non envoyées (Supabase service role non configuré)',
      sent: 0
    })
  }

  // Client admin (bypass RLS)
  const supabase = createClient(supabaseUrl, serviceRoleKey)

  try {
    // 1. Récupérer les factures impayées avec date_limite dépassée
    const today = new Date().toISOString().split('T')[0]

    const { data: facturesImpayees, error: fetchErr } = await supabase
      .from('factures')
      .select(`
        id,
        montant_total,
        montant_paye,
        type_frais,
        echeance,
        nb_relances,
        ecole_id,
        eleve_id,
        eleves (
          id,
          nom,
          prenom,
          parent_principal_id
        )
      `)
      .neq('statut', 'payee')
      .lte('echeance', today)
      .order('echeance', { ascending: true })

    if (fetchErr) {
      console.error('[Cron Relances] Erreur requête factures:', fetchErr)
      return NextResponse.json({ error: fetchErr.message }, { status: 500 })
    }

    if (!facturesImpayees || facturesImpayees.length === 0) {
      return NextResponse.json({ message: 'Aucune facture en retard', sent: 0 })
    }

    // 2. Grouper par parent pour éviter le spam
    const parentsMap = new Map<string, {
      parentId: string
      factures: typeof facturesImpayees
    }>()

    for (const facture of facturesImpayees) {
      const eleve = facture.eleves as any
      const parentId = eleve?.parent_principal_id
      if (!parentId) continue

      if (!parentsMap.has(parentId)) {
        parentsMap.set(parentId, { parentId, factures: [] })
      }
      parentsMap.get(parentId)!.factures.push(facture)
    }

    // 3. Envoyer les relances
    let sent = 0
    let errors = 0
    const results: Array<{ parent: string; status: string }> = []

    for (const [parentId, { factures }] of parentsMap) {
      // Récupérer les infos du parent
      const { data: parent } = await supabase
        .from('utilisateurs')
        .select('nom, prenom, telephone, ecole_id')
        .eq('id', parentId)
        .single()

      if (!parent || !parent.telephone) {
        results.push({ parent: parentId, status: 'pas de téléphone' })
        continue
      }

      // Récupérer le nom de l'école
      const { data: ecole } = await supabase
        .from('ecoles')
        .select('nom')
        .eq('id', parent.ecole_id)
        .single()

      // Calculer le solde total dû
      const soldeTotalDu = factures.reduce((sum, f) => {
        return sum + ((f.montant_total || 0) - (f.montant_paye || 0))
      }, 0)

      // Lister les enfants concernés
      const enfants = [...new Set(factures.map(f => {
        const e = f.eleves as any
        return e ? `${e.prenom} ${e.nom}` : 'Élève'
      }))]

      // Déterminer le niveau de relance
      const maxRelances = Math.max(...factures.map(f => f.nb_relances || 0))
      const isUrgent = maxRelances >= 2

      // Construire le message
      const montantFormate = new Intl.NumberFormat('fr-SN').format(soldeTotalDu)

      let message: string
      if (isUrgent) {
        message = `🔴 *URGENT — SmartSchool SN*\n\n` +
          `Bonjour ${parent.prenom} ${parent.nom},\n\n` +
          `Malgré nos rappels précédents, un montant de *${montantFormate} FCFA* reste impayé pour ${enfants.join(', ')}.\n\n` +
          `⚠️ Merci de régulariser dans les plus brefs délais pour éviter toute suspension.\n\n` +
          `💳 Payez via Wave ou Orange Money dans l'application SmartSchool.\n\n` +
          `_${ecole?.nom || 'Votre école'}_`
      } else {
        message = `⚠️ *Rappel paiement — SmartSchool SN*\n\n` +
          `Bonjour ${parent.prenom} ${parent.nom},\n\n` +
          `Un montant de *${montantFormate} FCFA* est dû pour ${enfants.join(', ')}.\n\n` +
          `📅 La date limite est dépassée.\n\n` +
          `💳 Payez facilement via Wave ou Orange Money dans l'application SmartSchool.\n\n` +
          `_${ecole?.nom || 'Votre école'}_`
      }

      // Envoyer via WhatsApp
      try {
        const { sendWhatsApp } = await import('@/lib/whatsapp')
        const result = await sendWhatsApp({
          to: parent.telephone,
          template: 'relance',
          data: {
            parentNom: `${parent.prenom} ${parent.nom}`,
            montant: montantFormate,
            elevePrenom: enfants.join(', '),
            typeFrags: 'frais de scolarité',
            dateLimite: 'dépassée',
            ecoleNom: ecole?.nom || 'SmartSchool SN',
          }
        })

        if (result.success) {
          sent++
          results.push({ parent: `${parent.prenom} ${parent.nom}`, status: 'envoyé' })
        } else {
          errors++
          results.push({ parent: `${parent.prenom} ${parent.nom}`, status: `erreur: ${result.error}` })
        }
      } catch (err: any) {
        errors++
        results.push({ parent: `${parent.prenom} ${parent.nom}`, status: `exception: ${err.message}` })
      }

      // Incrémenter nb_relances pour toutes les factures de ce parent
      for (const facture of factures) {
        await supabase
          .from('factures')
          .update({ nb_relances: (facture.nb_relances || 0) + 1 })
          .eq('id', facture.id)
      }

      // Créer une notification in-app
      await supabase.from('notifications').insert({
        user_id: parentId,
        ecole_id: parent.ecole_id,
        type_notif: 'relance_auto',
        priorite: isUrgent ? 3 : 2,
        titre: isUrgent ? '🔴 Rappel urgent de paiement' : '⚠️ Rappel de paiement',
        contenu: `Montant dû: ${montantFormate} FCFA pour ${enfants.join(', ')}`,
      })
    }

    // 4. Log dans les logs_audit
    await supabase.from('logs_audit').insert({
      action: 'relances_auto',
      table_cible: 'factures',
      details: { sent, errors, total_factures: facturesImpayees.length, total_parents: parentsMap.size },
    })

    return NextResponse.json({
      message: `Relances automatiques terminées`,
      sent,
      errors,
      total_factures: facturesImpayees.length,
      total_parents: parentsMap.size,
      details: results,
    })

  } catch (err: any) {
    console.error('[Cron Relances] Erreur:', err)
    return NextResponse.json({ error: err.message }, { status: 500 })
  }
}

// API Export — Format Ministère de l'Éducation Nationale du Sénégal
// Compatible PLANETE 3
// GET /api/export/ministere?type=eleves|profs|resultats|absences|financier&format=json|csv

import { NextResponse } from 'next/server'
import { createClient } from '@supabase/supabase-js'

function getSupabase() {
  const url = process.env.NEXT_PUBLIC_SUPABASE_URL!
  const key = process.env.SUPABASE_SERVICE_ROLE_KEY!
  if (!key || key.includes('placeholder')) return null
  return createClient(url, key)
}

function toCSV(headers: string[], rows: string[][]): string {
  const BOM = '\uFEFF' // Pour Excel
  const headerLine = headers.map(h => `"${h}"`).join(';')
  const dataLines = rows.map(row => row.map(cell => `"${String(cell || '').replace(/"/g, '""')}"`).join(';'))
  return BOM + [headerLine, ...dataLines].join('\n')
}

export async function GET(request: Request) {
  const { searchParams } = new URL(request.url)
  const type = searchParams.get('type') || 'eleves'
  const format = searchParams.get('format') || 'json'
  const ecoleId = searchParams.get('ecole_id')

  const supabase = getSupabase()
  if (!supabase) {
    return NextResponse.json({ error: 'Service non configuré' }, { status: 503 })
  }

  // Déterminer l'école
  let targetEcoleId = ecoleId
  if (!targetEcoleId) {
    // Utiliser la première école active
    const { data: ecole } = await supabase.from('ecoles').select('id').eq('actif', true).limit(1).single()
    targetEcoleId = ecole?.id
  }

  if (!targetEcoleId) {
    return NextResponse.json({ error: 'École non trouvée' }, { status: 404 })
  }

  // Info école
  const { data: ecole } = await supabase.from('ecoles').select('*').eq('id', targetEcoleId).single()

  const metadata = {
    ecole: ecole?.nom || 'Inconnue',
    ville: ecole?.ville || '',
    region: ecole?.region || '',
    date_export: new Date().toISOString(),
    annee_scolaire: '2025-2026',
    format_version: '1.0',
    plateforme: 'SmartSchool SN v2.0',
  }

  try {
    switch (type) {
      case 'eleves': {
        const { data: eleves } = await supabase
          .from('eleves')
          .select('matricule, nom, prenom, date_naissance, sexe, classe_id, actif, classes(nom, niveau)')
          .eq('ecole_id', targetEcoleId)
          .eq('actif', true)
          .order('nom')

        const rows = (eleves || []).map((e: any) => ({
          matricule: e.matricule || '',
          nom: e.nom,
          prenom: e.prenom,
          date_naissance: e.date_naissance || '',
          sexe: e.sexe || '',
          classe: e.classes?.nom || '',
          niveau: e.classes?.niveau || '',
          statut: e.actif ? 'Actif' : 'Inactif',
        }))

        if (format === 'csv') {
          const csv = toCSV(
            ['Matricule', 'Nom', 'Prénom', 'Date naissance', 'Sexe', 'Classe', 'Niveau', 'Statut'],
            rows.map(r => [r.matricule, r.nom, r.prenom, r.date_naissance, r.sexe, r.classe, r.niveau, r.statut])
          )
          return new Response(csv, {
            headers: {
              'Content-Type': 'text/csv; charset=utf-8',
              'Content-Disposition': `attachment; filename="eleves_${metadata.annee_scolaire}.csv"`,
            },
          })
        }
        return NextResponse.json({ metadata, type: 'eleves', total: rows.length, data: rows })
      }

      case 'profs': {
        const { data: profs } = await supabase
          .from('utilisateurs')
          .select('nom, prenom, telephone, actif')
          .eq('ecole_id', targetEcoleId)
          .eq('role', 'professeur')
          .order('nom')

        const rows = (profs || []).map((p: any) => ({
          nom: p.nom,
          prenom: p.prenom,
          telephone: p.telephone || '',
          statut: p.actif ? 'Actif' : 'Inactif',
        }))

        if (format === 'csv') {
          const csv = toCSV(
            ['Nom', 'Prénom', 'Téléphone', 'Statut'],
            rows.map(r => [r.nom, r.prenom, r.telephone, r.statut])
          )
          return new Response(csv, {
            headers: {
              'Content-Type': 'text/csv; charset=utf-8',
              'Content-Disposition': `attachment; filename="enseignants_${metadata.annee_scolaire}.csv"`,
            },
          })
        }
        return NextResponse.json({ metadata, type: 'enseignants', total: rows.length, data: rows })
      }

      case 'resultats': {
        const { data: moyennes } = await supabase
          .from('v_moyennes_generales')
          .select('eleve_id, trimestre, moyenne_generale, rang')

        const { data: eleves } = await supabase
          .from('eleves')
          .select('id, matricule, nom, prenom, classes(nom)')
          .eq('ecole_id', targetEcoleId)

        const elevesMap = new Map((eleves || []).map((e: any) => [e.id, e]))

        const rows = (moyennes || []).map((m: any) => {
          const eleve = elevesMap.get(m.eleve_id) as any
          return {
            matricule: eleve?.matricule || '',
            nom: eleve?.nom || '',
            prenom: eleve?.prenom || '',
            classe: eleve?.classes?.nom || '',
            trimestre: m.trimestre,
            moyenne_generale: Number(m.moyenne_generale || 0).toFixed(2),
            rang: m.rang || '',
            decision: Number(m.moyenne_generale) >= 10 ? 'Admis' : 'En difficulté',
          }
        })

        if (format === 'csv') {
          const csv = toCSV(
            ['Matricule', 'Nom', 'Prénom', 'Classe', 'Trimestre', 'Moyenne', 'Rang', 'Décision'],
            rows.map(r => [r.matricule, r.nom, r.prenom, r.classe, String(r.trimestre), r.moyenne_generale, String(r.rang), r.decision])
          )
          return new Response(csv, {
            headers: {
              'Content-Type': 'text/csv; charset=utf-8',
              'Content-Disposition': `attachment; filename="resultats_${metadata.annee_scolaire}.csv"`,
            },
          })
        }
        return NextResponse.json({ metadata, type: 'resultats', total: rows.length, data: rows })
      }

      case 'absences': {
        const { data: eleves } = await supabase
          .from('eleves')
          .select('id, matricule, nom, prenom, classes(nom)')
          .eq('ecole_id', targetEcoleId)

        const { data: absences } = await supabase
          .from('absences_eleves')
          .select('eleve_id, justifiee')
          .eq('ecole_id', targetEcoleId)

        const absMap = new Map<string, { total: number; justifiees: number }>()
        for (const a of (absences || []) as any[]) {
          const cur = absMap.get(a.eleve_id) || { total: 0, justifiees: 0 }
          cur.total++
          if (a.justifiee) cur.justifiees++
          absMap.set(a.eleve_id, cur)
        }

        const rows = (eleves || []).map((e: any) => {
          const abs = absMap.get(e.id) || { total: 0, justifiees: 0 }
          return {
            matricule: e.matricule || '',
            nom: e.nom,
            prenom: e.prenom,
            classe: e.classes?.nom || '',
            nb_absences: abs.total,
            nb_justifiees: abs.justifiees,
            nb_non_justifiees: abs.total - abs.justifiees,
            taux_presence: abs.total > 0 ? `${((1 - abs.total / 180) * 100).toFixed(1)}%` : '100%',
          }
        })

        if (format === 'csv') {
          const csv = toCSV(
            ['Matricule', 'Nom', 'Prénom', 'Classe', 'Absences', 'Justifiées', 'Non justifiées', 'Taux présence'],
            rows.map(r => [r.matricule, r.nom, r.prenom, r.classe, String(r.nb_absences), String(r.nb_justifiees), String(r.nb_non_justifiees), r.taux_presence])
          )
          return new Response(csv, {
            headers: {
              'Content-Type': 'text/csv; charset=utf-8',
              'Content-Disposition': `attachment; filename="absences_${metadata.annee_scolaire}.csv"`,
            },
          })
        }
        return NextResponse.json({ metadata, type: 'absences', total: rows.length, data: rows })
      }

      case 'financier': {
        const { data: factures } = await supabase
          .from('factures')
          .select('montant_total, montant_paye, statut')
          .eq('ecole_id', targetEcoleId)

        const { data: eleves } = await supabase
          .from('eleves')
          .select('id')
          .eq('ecole_id', targetEcoleId)
          .eq('actif', true)

        const totalFacture = (factures || []).reduce((s: number, f: any) => s + (f.montant_total || 0), 0)
        const totalPaye = (factures || []).reduce((s: number, f: any) => s + (f.montant_paye || 0), 0)
        const totalImpaye = totalFacture - totalPaye
        const tauxRecouvrement = totalFacture > 0 ? ((totalPaye / totalFacture) * 100).toFixed(1) : '0'

        const bilan = {
          total_eleves: (eleves || []).length,
          total_factures: (factures || []).length,
          montant_total_facture: totalFacture,
          montant_total_paye: totalPaye,
          montant_total_impaye: totalImpaye,
          taux_recouvrement: `${tauxRecouvrement}%`,
        }

        if (format === 'csv') {
          const csv = toCSV(
            ['Indicateur', 'Valeur'],
            [
              ['Total élèves', String(bilan.total_eleves)],
              ['Total factures', String(bilan.total_factures)],
              ['Montant total facturé (FCFA)', String(bilan.montant_total_facture)],
              ['Montant total payé (FCFA)', String(bilan.montant_total_paye)],
              ['Montant total impayé (FCFA)', String(bilan.montant_total_impaye)],
              ['Taux de recouvrement', bilan.taux_recouvrement],
            ]
          )
          return new Response(csv, {
            headers: {
              'Content-Type': 'text/csv; charset=utf-8',
              'Content-Disposition': `attachment; filename="bilan_financier_${metadata.annee_scolaire}.csv"`,
            },
          })
        }
        return NextResponse.json({ metadata, type: 'financier', data: bilan })
      }

      default:
        return NextResponse.json({ error: `Type d'export inconnu: ${type}` }, { status: 400 })
    }
  } catch (err: any) {
    return NextResponse.json({ error: err.message }, { status: 500 })
  }
}

import { createClient } from '@/lib/supabase/server'

export async function POST(req: Request) {
  const { facture_id, methode, telephone, montant_verse, reference_recu } = await req.json()
  const supabase = await createClient()

  // Vérifier la facture (doit exister et ne pas être payée)
  const { data: facture } = await (supabase
    .from('factures') as any)
    .select('id, ecole_id, eleve_id, solde_restant, statut, eleves(nom, parent_principal_id)')
    .eq('id', facture_id)
    .neq('statut', 'paye')
    .single()

  if (!facture) {
    return Response.json({ error: 'Facture introuvable ou déjà payée' }, { status: 404 })
  }

  const montant = facture.solde_restant

  // Wave
  if (methode === 'wave') {
    const apiKey = process.env.WAVE_API_KEY
    if (!apiKey) {
      return Response.json({ error: 'Wave non configuré' }, { status: 503 })
    }

    const res = await fetch('https://api.wave.com/v1/checkout/sessions', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${apiKey}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        currency: 'XOF',
        amount: montant,
        error_url: `${process.env.NEXT_PUBLIC_APP_URL}/parent/paiement?status=error`,
        success_url: `${process.env.NEXT_PUBLIC_APP_URL}/parent/paiement?status=success`,
        client_reference: `SS-${facture_id}`,
      }),
    })

    if (!res.ok) {
      const err = await res.text()
      console.error('Wave API error:', err)
      return Response.json({ error: 'Erreur Wave' }, { status: 502 })
    }

    const data = await res.json()
    return Response.json({ checkout_url: data.wave_launch_url, methode: 'wave' })
  }

  // Orange Money via CinetPay
  if (methode === 'orange_money') {
    const apiKey = process.env.CINETPAY_API_KEY
    const siteId = process.env.CINETPAY_SITE_ID
    if (!apiKey || !siteId) {
      return Response.json({ error: 'CinetPay non configuré' }, { status: 503 })
    }

    const transactionId = `SS-OM-${facture_id}-${Date.now()}`
    let phone = (telephone || '').replace(/\s/g, '')
    if (phone && !phone.startsWith('+')) {
      phone = '+221' + phone
    }

    const eleveNom = facture.eleves?.nom || 'Élève'

    const res = await fetch('https://api-checkout.cinetpay.com/v2/payment', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        apikey: apiKey,
        site_id: siteId,
        transaction_id: transactionId,
        amount: montant,
        currency: 'XOF',
        description: `Frais scolarité - ${eleveNom}`,
        customer_phone_number: phone,
        notify_url: `${process.env.NEXT_PUBLIC_APP_URL}/api/webhooks/cinetpay`,
        return_url: `${process.env.NEXT_PUBLIC_APP_URL}/parent/paiement`,
        channels: 'MOBILE_MONEY',
      }),
    })

    if (!res.ok) {
      const err = await res.text()
      console.error('CinetPay API error:', err)
      return Response.json({ error: 'Erreur CinetPay' }, { status: 502 })
    }

    const data = await res.json()
    return Response.json({
      checkout_url: data.data?.payment_url,
      methode: 'orange_money',
      transaction_id: transactionId,
    })
  }

  // Espèces (paiement direct, admin uniquement)
  if (methode === 'especes') {
    const { error } = await (supabase.from('paiements') as any).insert({
      facture_id,
      ecole_id: facture.ecole_id,
      montant: montant_verse || montant,
      methode: 'especes',
      reference_transaction: reference_recu || `ESP-${Date.now()}`,
      statut_confirmation: 'confirmed',
    })

    if (error) {
      console.error('Erreur paiement espèces:', error)
      return Response.json({ error: error.message }, { status: 500 })
    }

    return Response.json({ success: true, methode: 'especes' })
  }

  return Response.json({ error: 'Méthode non supportée' }, { status: 400 })
}

import { createClient } from '@/lib/supabase/server'
import { sendWhatsApp } from '@/lib/whatsapp'

export async function POST(req: Request) {
  const body = await req.json()

  // CinetPay envoie: cpm_trans_id, cpm_site_id, cpm_trans_status, ...
  const transactionId = body.cpm_trans_id || ''
  const siteId = body.cpm_site_id || ''

  // Vérifier que le site_id correspond au nôtre
  if (siteId !== process.env.CINETPAY_SITE_ID) {
    console.error('CinetPay webhook: site_id invalide', siteId)
    return Response.json({ error: 'Unauthorized' }, { status: 401 })
  }

  // Vérification côté serveur du statut de la transaction
  const apiKey = process.env.CINETPAY_API_KEY
  if (!apiKey) {
    return Response.json({ error: 'Server misconfigured' }, { status: 500 })
  }

  const checkRes = await fetch('https://api-checkout.cinetpay.com/v2/payment/check', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      apikey: apiKey,
      site_id: siteId,
      transaction_id: transactionId,
    }),
  })

  const checkData = await checkRes.json()
  const status = checkData.data?.status

  // Seuls les paiements réussis nous intéressent
  if (status !== 'ACCEPTED') {
    console.log('CinetPay webhook: statut non accepté', status, transactionId)
    return Response.json({ ok: true, status })
  }

  // Extraire facture_id depuis transaction_id: SS-OM-{factureId}-{timestamp}
  const match = transactionId.match(/^SS-OM-(.+)-\d+$/)
  if (!match) {
    console.error('CinetPay webhook: format transaction_id invalide', transactionId)
    return Response.json({ error: 'Format invalide' }, { status: 400 })
  }
  const factureId = match[1]

  const supabase = await createClient()

  // Récupérer la facture
  const { data: facture } = await (supabase
    .from('factures') as any)
    .select('ecole_id, eleve_id, eleves(nom, prenom, parent_principal_id, utilisateurs!eleves_parent_principal_id_fkey(nom, telephone))')
    .eq('id', factureId)
    .single()

  if (!facture) {
    console.error('CinetPay webhook: facture introuvable', factureId)
    return Response.json({ error: 'Facture introuvable' }, { status: 404 })
  }

  // Vérifier doublon (même transaction_id)
  const { data: existing } = await supabase
    .from('paiements')
    .select('id')
    .eq('reference_transaction', transactionId)
    .maybeSingle()

  if (existing) {
    return Response.json({ ok: true, message: 'Déjà traité' })
  }

  // Enregistrer le paiement
  const montant = checkData.data?.amount || 0
  const { error: insertErr } = await (supabase.from('paiements') as any).insert({
    facture_id: factureId,
    ecole_id: facture.ecole_id,
    montant,
    methode: 'orange_money',
    reference_transaction: transactionId,
    telephone_payeur: checkData.data?.phone_number || null,
    statut_confirmation: 'confirmed',
    webhook_payload: checkData,
  })

  if (insertErr) {
    console.error('CinetPay webhook: erreur insertion', insertErr)
    return Response.json({ error: 'Erreur serveur' }, { status: 500 })
  }

  // Notifier le parent
  const parentId = facture.eleves?.parent_principal_id
  const parentTelephone = facture.eleves?.utilisateurs?.telephone
  const parentNom = facture.eleves?.utilisateurs?.nom
  const elevePrenom = facture.eleves?.prenom
  if (parentId) {
    const montantFmt = new Intl.NumberFormat('fr-SN').format(montant)
    await (supabase.from('notifications') as any).insert({
      user_id: parentId,
      ecole_id: facture.ecole_id,
      type_notif: 'paiement_confirme',
      priorite: 1,
      titre: 'Paiement confirmé',
      contenu: `Votre paiement Orange Money de ${montantFmt} FCFA pour ${facture.eleves?.nom || 'votre enfant'} a été reçu.`,
    })

    // Envoi WhatsApp au parent
    if (parentTelephone) {
      await sendWhatsApp({
        to: parentTelephone,
        template: 'paiement_confirme',
        data: {
          parentNom: parentNom || 'Parent',
          montant: new Intl.NumberFormat('fr-SN').format(montant),
          elevePrenom: elevePrenom || 'votre enfant',
          ecoleNom: 'SmartSchool SN',
        }
      })
    }
  }

  return Response.json({ received: true }, { status: 200 })
}

import crypto from 'crypto'
import { createClient } from '@/lib/supabase/server'
import { sendWhatsApp } from '@/lib/whatsapp'

export async function POST(req: Request) {
  const body = await req.text()
  const signature = req.headers.get('wave-signature') || ''

  // Vérification HMAC-SHA256
  const secret = process.env.WAVE_WEBHOOK_SECRET
  if (!secret) {
    console.error('WAVE_WEBHOOK_SECRET non configuré')
    return Response.json({ error: 'Server misconfigured' }, { status: 500 })
  }

  const expectedSig = crypto
    .createHmac('sha256', secret)
    .update(body)
    .digest('hex')

  if (signature !== expectedSig) {
    console.error('Wave webhook: signature invalide')
    return Response.json({ error: 'Unauthorized' }, { status: 401 })
  }

  const event = JSON.parse(body)

  // Ignorer les événements non pertinents
  if (event.type !== 'checkout.session.completed') {
    return Response.json({ ok: true })
  }

  const clientRef = event.data?.client_reference || ''
  const factureId = clientRef.replace('SS-', '')
  if (!factureId) {
    return Response.json({ error: 'Référence manquante' }, { status: 400 })
  }

  const supabase = await createClient()

  // Récupérer ecole_id depuis la facture
  const { data: facture } = await (supabase
    .from('factures') as any)
    .select('ecole_id, eleve_id, eleves(nom, prenom, parent_principal_id, utilisateurs!eleves_parent_principal_id_fkey(nom, telephone))')
    .eq('id', factureId)
    .single()

  if (!facture) {
    console.error('Wave webhook: facture introuvable', factureId)
    return Response.json({ error: 'Facture introuvable' }, { status: 404 })
  }

  // Enregistrer le paiement
  const { error: insertErr } = await (supabase.from('paiements') as any).insert({
    facture_id: factureId,
    ecole_id: facture.ecole_id,
    montant: event.data.amount,
    methode: 'wave',
    reference_transaction: event.data.id,
    telephone_payeur: event.data.client_phone || null,
    statut_confirmation: 'confirmed',
    webhook_payload: event,
  })

  if (insertErr) {
    console.error('Wave webhook: erreur insertion paiement', insertErr)
    return Response.json({ error: 'Erreur serveur' }, { status: 500 })
  }
  // Le trigger PostgreSQL fn_update_facture_statut() met à jour factures.statut automatiquement

  // Notifier le parent
  const parentId = facture.eleves?.parent_principal_id
  const parentTelephone = facture.eleves?.utilisateurs?.telephone
  const parentNom = facture.eleves?.utilisateurs?.nom
  const elevePrenom = facture.eleves?.prenom
  const montant = event.data.amount
  if (parentId) {
    const montantFmt = new Intl.NumberFormat('fr-SN').format(montant)
    await (supabase.from('notifications') as any).insert({
      user_id: parentId,
      ecole_id: facture.ecole_id,
      type_notif: 'paiement_confirme',
      priorite: 1,
      titre: 'Paiement confirmé',
      contenu: `Votre paiement Wave de ${montantFmt} FCFA pour ${facture.eleves?.nom || 'votre enfant'} a été reçu.`,
    })

    // Envoi WhatsApp au parent
    if (parentTelephone) {
      await sendWhatsApp({
        to: parentTelephone,
        template: 'paiement_confirme',
        data: {
          parentNom: parentNom || 'Parent',
          montant: new Intl.NumberFormat('fr-SN').format(montant),
          elevePrenom: elevePrenom || 'votre enfant',
          ecoleNom: 'SmartSchool SN',
        }
      })
    }
  }

  return Response.json({ received: true }, { status: 200 })
}

import { NextResponse } from 'next/server'
import { createClient } from '@supabase/supabase-js'
import { chat } from '@/lib/ai/engine'

// Client Supabase avec service role key (pas de RLS) pour les requêtes webhook
function getSupabase() {
  const url = process.env.NEXT_PUBLIC_SUPABASE_URL!
  const serviceKey = process.env.SUPABASE_SERVICE_ROLE_KEY!
  return createClient(url, serviceKey)
}

// Sessions AI WhatsApp en mémoire (en prod, utiliser Redis)
const aiSessions = new Map<string, { role: string; messages: { role: 'user' | 'assistant'; content: string }[] }>()

// Réponse TwiML pour Twilio
function twiml(message: string): Response {
  const xml = `<?xml version="1.0" encoding="UTF-8"?>\n<Response><Message>${escapeXml(message)}</Message></Response>`
  return new Response(xml, {
    status: 200,
    headers: { 'Content-Type': 'text/xml' },
  })
}

function escapeXml(str: string): string {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&apos;')
}

function formatFCFA(montant: number): string {
  return new Intl.NumberFormat('fr-SN').format(montant)
}

const HELP_MESSAGE = `📚 *SmartSchool SN — Commandes disponibles*

Envoyez un mot-clé pour obtenir des informations :

💰 *SOLDE* ou *FACTURE* — Voir le solde dû
📝 *NOTES* — Voir les dernières notes
📋 *ABSENCES* — Voir les absences du mois
🚌 *TRANSPORT* ou *BUS* — Infos bus scolaire
🤖 *AI* ou *CHAT* — Parler à SmartBot (IA)
🔄 *RESET* — Réinitialiser la conversation AI
❓ *AIDE* ou *HELP* — Afficher ce message

_Tapez simplement le mot-clé et envoyez ! 🇸🇳_`

// GET — Vérification webhook Twilio (health check)
export async function GET() {
  return NextResponse.json({ status: 'ok' }, { status: 200 })
}

// POST — Traitement des messages WhatsApp entrants via Twilio
export async function POST(req: Request) {
  try {
    const formData = await req.formData()
    const body = (formData.get('Body') as string || '').trim()
    const from = (formData.get('From') as string || '')

    // Extraire le numéro de téléphone (format: whatsapp:+221XXXXXXXXX)
    const telephone = from.replace('whatsapp:', '').trim()

    if (!telephone) {
      return twiml('Erreur : numéro de téléphone non reconnu.')
    }

    const supabase = getSupabase()

    // Rechercher le parent par numéro de téléphone
    // On cherche avec le numéro tel quel, et aussi sans le +221
    const telSans221 = telephone.replace(/^\+221/, '')
    const { data: parent } = await (supabase
      .from('utilisateurs') as any)
      .select('id, nom, prenom, ecole_id, role')
      .or(`telephone.eq.${telephone},telephone.eq.${telSans221},telephone.eq.+221${telSans221}`)
      .eq('role', 'parent')
      .single()

    if (!parent) {
      return twiml(
        '⚠️ Numéro non enregistré.\n\n' +
        'Ce numéro de téléphone n\'est associé à aucun compte parent SmartSchool SN.\n\n' +
        'Veuillez contacter l\'administration de votre école pour enregistrer votre numéro.'
      )
    }

    // Trouver les enfants liés à ce parent
    const { data: eleves } = await (supabase
      .from('eleves') as any)
      .select('id, nom, prenom, classe_id, classes(nom)')
      .eq('parent_principal_id', parent.id)
      .eq('actif', true)
      .order('nom')

    if (!eleves || eleves.length === 0) {
      return twiml(
        '⚠️ Aucun élève trouvé.\n\n' +
        'Aucun enfant n\'est associé à votre compte. ' +
        'Veuillez contacter l\'administration de votre école.'
      )
    }

    // Analyser la commande
    const commande = body.toUpperCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '')

    if (commande === 'SOLDE' || commande === 'FACTURE') {
      return await handleSolde(supabase, parent, eleves)
    }

    if (commande === 'NOTES') {
      return await handleNotes(supabase, eleves)
    }

    if (commande === 'ABSENCES') {
      return await handleAbsences(supabase, eleves)
    }

    if (commande === 'TRANSPORT' || commande === 'BUS') {
      return await handleTransport(supabase, parent, eleves)
    }

    // Commande RESET — réinitialiser la session AI
    if (commande === 'RESET') {
      aiSessions.delete(telephone)
      return twiml('🔄 Conversation AI réinitialisée !\n\nEnvoyez un message pour démarrer une nouvelle conversation avec SmartBot.')
    }

    // Mode AI — si le message commence par "AI" ou "CHAT" ou si une session AI existe
    if (commande.startsWith('AI ') || commande.startsWith('CHAT ') || commande === 'AI' || commande === 'CHAT' || aiSessions.has(telephone)) {
      // Extraire le message réel (supprimer le préfixe AI/CHAT)
      let aiMessage = body
      if (commande.startsWith('AI ')) aiMessage = body.substring(3).trim()
      else if (commande.startsWith('CHAT ')) aiMessage = body.substring(5).trim()
      else if (commande === 'AI' || commande === 'CHAT') {
        // Activer le mode AI
        aiSessions.set(telephone, { role: parent.role || 'parent', messages: [] })
        return twiml('🤖 *Mode SmartBot activé !*\n\nJe suis SmartBot, votre assistant IA.\nPosez-moi vos questions ! Je peux vous aider avec les notes, les paiements, les cours...\n\nTapez *RESET* pour quitter le mode AI.')
      }

      return await handleAI(telephone, aiMessage, parent)
    }

    // AIDE, HELP, ou message non reconnu
    return twiml(HELP_MESSAGE)
  } catch (error) {
    console.error('[WhatsApp Webhook] Erreur:', error)
    return twiml(
      '❌ Une erreur est survenue. Veuillez réessayer plus tard ou contacter l\'administration.'
    )
  }
}

// --- Handlers de commandes ---

interface Eleve {
  id: string
  nom: string
  prenom: string
  classe_id: string
  classes: { nom: string } | null
}

interface Parent {
  id: string
  nom: string
  prenom: string
  ecole_id: string
  role: string
}

async function handleSolde(
  supabase: any,
  parent: Parent,
  eleves: Eleve[]
): Promise<Response> {
  const eleveIds = eleves.map(e => e.id)

  const { data: factures } = await (supabase
    .from('factures') as any)
    .select('id, eleve_id, type_frais, montant_total, montant_paye, statut, echeance')
    .in('eleve_id', eleveIds)
    .neq('statut', 'payee')
    .order('echeance', { ascending: true })

  if (!factures || factures.length === 0) {
    return twiml(
      `✅ Bonjour ${parent.prenom},\n\n` +
      'Aucune facture en attente ! Toutes vos factures sont réglées. 🎉'
    )
  }

  let message = `💰 *Solde dû — SmartSchool SN*\n\nBonjour ${parent.prenom},\n`
  let totalGeneral = 0

  for (const eleve of eleves) {
    const facturesEleve = factures.filter((f: any) => f.eleve_id === eleve.id)
    if (facturesEleve.length === 0) continue

    const totalEleve = facturesEleve.reduce((sum: number, f: any) => sum + ((f.montant_total || 0) - (f.montant_paye || 0)), 0)
    totalGeneral += totalEleve

    message += `\n📚 *${eleve.prenom} ${eleve.nom}* :\n`
    for (const f of facturesEleve) {
      const solde = (f.montant_total || 0) - (f.montant_paye || 0)
      const enRetard = f.echeance && new Date(f.echeance) < new Date() ? ' ⚠️' : ''
      message += `  - ${f.type_frais || 'scolarité'} : ${formatFCFA(solde)} FCFA${enRetard}\n`
    }
    message += `  _Sous-total : ${formatFCFA(totalEleve)} FCFA_\n`
  }

  message += `\n*Total dû : ${formatFCFA(totalGeneral)} FCFA*`

  return twiml(message)
}

async function handleNotes(
  supabase: any,
  eleves: Eleve[]
): Promise<Response> {
  let message = '📝 *Notes récentes — SmartSchool SN*\n'

  for (const eleve of eleves) {
    const { data: notes } = await (supabase
      .from('notes') as any)
      .select('valeur, created_at, evaluations(type, date_eval, matieres(nom))')
      .eq('eleve_id', eleve.id)
      .not('valeur', 'is', null)
      .order('created_at', { ascending: false })
      .limit(5)

    message += `\n📚 *${eleve.prenom} ${eleve.nom}*`
    if (eleve.classes?.nom) {
      message += ` (${eleve.classes.nom})`
    }
    message += ' :\n'

    if (!notes || notes.length === 0) {
      message += '  _Aucune note récente_\n'
      continue
    }

    for (const n of notes) {
      const matiere = n.evaluations?.matieres?.nom || 'Matière inconnue'
      const type = n.evaluations?.type || ''
      const emoji = (n.valeur || 0) >= 10 ? '✅' : '⚠️'
      const noteVal = n.valeur !== null ? `${n.valeur}/20` : 'Absent'
      message += `  ${emoji} ${matiere} : ${noteVal}${type ? ` (${type})` : ''}\n`
    }
  }

  return twiml(message)
}

async function handleAbsences(
  supabase: any,
  eleves: Eleve[]
): Promise<Response> {
  // Période : mois en cours
  const now = new Date()
  const debutMois = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0]
  const finMois = new Date(now.getFullYear(), now.getMonth() + 1, 0).toISOString().split('T')[0]

  const moisNom = now.toLocaleDateString('fr-FR', { month: 'long', year: 'numeric' })

  let message = `📋 *Absences de ${moisNom} — SmartSchool SN*\n`

  for (const eleve of eleves) {
    const { data: absences } = await (supabase
      .from('absences_eleves') as any)
      .select('id, date_absence, type, motif, justifiee')
      .eq('eleve_id', eleve.id)
      .gte('date_absence', debutMois)
      .lte('date_absence', finMois)
      .order('date_absence', { ascending: true })

    message += `\n📚 *${eleve.prenom} ${eleve.nom}*`
    if (eleve.classes?.nom) {
      message += ` (${eleve.classes.nom})`
    }
    message += ' :\n'

    if (!absences || absences.length === 0) {
      message += '  _Aucune absence ce mois_ ✅\n'
      continue
    }

    for (const a of absences) {
      const date = new Date(a.date_absence).toLocaleDateString('fr-FR', {
        weekday: 'short',
        day: 'numeric',
        month: 'short',
      })
      const justif = a.justifiee ? '✅ justifiée' : '❌ non justifiée'
      message += `  - ${date} : ${a.type || 'absence'}  (${justif})\n`
    }

    const total = absences.length
    const nonJustifiees = absences.filter((a: any) => !a.justifiee).length
    message += `  _Total : ${total} absence${total > 1 ? 's' : ''}`
    if (nonJustifiees > 0) {
      message += ` dont ${nonJustifiees} non justifiée${nonJustifiees > 1 ? 's' : ''}`
    }
    message += '_\n'
  }

  return twiml(message)
}

// === TRANSPORT ===
async function handleTransport(
  supabase: any,
  parent: Parent,
  eleves: Eleve[]
): Promise<Response> {
  const eleveIds = eleves.map(e => e.id)

  const { data: abonnements } = await (supabase
    .from('abonnements_transport') as any)
    .select(`
      id, statut, montant_mensuel, arret_id, eleve_id,
      trajets_aller:trajet_aller_id(nom, heure_depart, heure_arrivee_estimee,
        vehicules:vehicule_id(immatriculation, chauffeur_nom, chauffeur_telephone, derniere_position_at)
      ),
      arrets:arret_id(nom, heure_passage_estimee)
    `)
    .in('eleve_id', eleveIds)
    .eq('statut', 'actif')

  if (!abonnements || abonnements.length === 0) {
    return twiml(
      `🚌 *Transport — SmartSchool SN*\n\n` +
      `Bonjour ${parent.prenom},\n\n` +
      `Aucun de vos enfants n'est inscrit au transport scolaire.\n` +
      `Contactez l'administration pour inscrire votre enfant.`
    )
  }

  let message = `🚌 *Transport scolaire — SmartSchool SN*\n\nBonjour ${parent.prenom},\n`

  for (const abo of abonnements as any[]) {
    const eleve = eleves.find(e => e.id === abo.eleve_id)
    if (!eleve) continue

    const trajet = abo.trajets_aller
    const vehicule = trajet?.vehicules
    const arret = abo.arrets

    message += `\n📌 *${eleve.prenom} ${eleve.nom}*\n`

    if (trajet) {
      message += `  🗺️ Trajet: ${trajet.nom}\n`
      message += `  🕐 ${trajet.heure_depart?.slice(0, 5)} → ${trajet.heure_arrivee_estimee?.slice(0, 5)}\n`
    }
    if (arret) {
      message += `  🚏 Arrêt: ${arret.nom}`
      if (arret.heure_passage_estimee) message += ` (${arret.heure_passage_estimee.slice(0, 5)})`
      message += '\n'
    }
    if (vehicule) {
      message += `  🚌 Bus: ${vehicule.immatriculation}\n`
      message += `  👨‍✈️ ${vehicule.chauffeur_nom} — 📞 ${vehicule.chauffeur_telephone}\n`
      if (vehicule.derniere_position_at) {
        const mins = Math.floor((Date.now() - new Date(vehicule.derniere_position_at).getTime()) / 60000)
        message += mins < 10 ? `  ✅ En route (il y a ${mins} min)\n` : `  ⚪ Hors ligne (${mins} min)\n`
      }
    }
    message += `  💰 ${new Intl.NumberFormat('fr-SN').format(abo.montant_mensuel)} FCFA/mois\n`
  }

  return twiml(message)
}

// === AI CHATBOT ===
async function handleAI(telephone: string, message: string, parent: Parent): Promise<Response> {
  try {
    // Récupérer ou créer la session
    let session = aiSessions.get(telephone)
    if (!session) {
      session = { role: parent.role || 'parent', messages: [] }
      aiSessions.set(telephone, session)
    }

    // Ajouter le message utilisateur
    session.messages.push({ role: 'user', content: message })

    // Garder max 20 messages pour éviter de dépasser la fenêtre de contexte
    if (session.messages.length > 20) {
      session.messages = session.messages.slice(-20)
    }

    // Vérifier si une clé API IA est configurée
    if (!process.env.GOOGLE_GEMINI_API_KEY && !process.env.ANTHROPIC_API_KEY) {
      // Mode démo — réponse simulée
      const demoReply = getAIDemoResponse(message, session.role)
      session.messages.push({ role: 'assistant', content: demoReply })
      return twiml(`🤖 ${demoReply}`)
    }

    // Appel à l'engine AI
    const response = await chat({
      messages: session.messages,
      userRole: session.role,
      userId: `whatsapp:${telephone}`,
    })

    // Tronquer si nécessaire pour WhatsApp
    let content = response.content
    if (content.length > 1500) {
      content = content.substring(0, 1500) + '\n\n_...suite tronquée_'
    }

    // Sauvegarder la réponse
    session.messages.push({ role: 'assistant', content })

    // Ajouter les outils utilisés
    const toolInfo = response.toolsUsed.length > 0
      ? `\n\n_🔧 ${response.toolsUsed.join(', ')}_`
      : ''

    return twiml(`🤖 ${content}${toolInfo}`)
  } catch (error) {
    console.error('[WhatsApp AI Error]', error)
    return twiml('❌ Erreur du service IA. Réessayez ou tapez RESET pour réinitialiser.')
  }
}

function getAIDemoResponse(message: string, role: string): string {
  const msg = message.toLowerCase()

  if (msg.includes('bonjour') || msg.includes('salut')) {
    return 'Bonjour ! 👋 Je suis SmartBot en mode démo. Comment puis-je vous aider ?'
  }
  if (msg.includes('note') || msg.includes('moyenne')) {
    return '📊 En mode démo, les notes simulées sont :\n\n📐 Maths : 12/20\n📖 Français : 14/20\n🔬 Physique : 11/20\n\n📈 Moyenne : 12.3/20'
  }
  if (msg.includes('aide') || msg.includes('help')) {
    return 'Je peux vous aider avec :\n• 📊 Notes et moyennes\n• 💳 Factures et paiements\n• 📅 Absences\n• 📚 Questions scolaires\n\nPosez simplement votre question !'
  }
  return `SmartBot (démo) — Pour une expérience complète, configurez ANTHROPIC_API_KEY.\n\nJe peux quand même vous aider avec les commandes : NOTES, SOLDE, ABSENCES, TRANSPORT.`
}

