'use client'

import { useState, useRef, useEffect, useCallback } from 'react'

interface ChatInputProps {
  onSend: (message: string) => void
  isLoading: boolean
  onStop: () => void
  accentColor: string
  placeholder?: string
}

export default function ChatInput({ onSend, isLoading, onStop, accentColor, placeholder }: ChatInputProps) {
  const [input, setInput] = useState('')
  const [isListening, setIsListening] = useState(false)
  const [speechSupported, setSpeechSupported] = useState(false)
  const textareaRef = useRef<HTMLTextAreaElement>(null)
  const recognitionRef = useRef<SpeechRecognition | null>(null)

  // Vérifier le support de la reconnaissance vocale
  useEffect(() => {
    const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition
    if (SpeechRecognition) {
      setSpeechSupported(true)
      const recognition = new SpeechRecognition()
      recognition.lang = 'fr-FR'
      recognition.continuous = false
      recognition.interimResults = true
      recognition.maxAlternatives = 1

      recognition.onresult = (event: SpeechRecognitionEvent) => {
        let finalTranscript = ''
        let interimTranscript = ''

        for (let i = event.resultIndex; i < event.results.length; i++) {
          const transcript = event.results[i][0].transcript
          if (event.results[i].isFinal) {
            finalTranscript += transcript
          } else {
            interimTranscript += transcript
          }
        }

        if (finalTranscript) {
          setInput(prev => prev + finalTranscript)
        } else if (interimTranscript) {
          // Afficher le texte intérimaire
          setInput(prev => {
            const base = prev.replace(/\s*🎤.*$/, '')
            return base + ' ' + interimTranscript
          })
        }
      }

      recognition.onend = () => {
        setIsListening(false)
        // Nettoyer les marqueurs intérimaires
        setInput(prev => prev.replace(/\s*🎤.*$/, '').trim())
      }

      recognition.onerror = (event: SpeechRecognitionErrorEvent) => {
        console.warn('[Speech]', event.error)
        setIsListening(false)
      }

      recognitionRef.current = recognition
    }
  }, [])

  // Auto-resize textarea
  useEffect(() => {
    const ta = textareaRef.current
    if (ta) {
      ta.style.height = 'auto'
      ta.style.height = `${Math.min(ta.scrollHeight, 120)}px`
    }
  }, [input])

  const handleSubmit = useCallback(() => {
    const cleanInput = input.replace(/\s*🎤.*$/, '').trim()
    if (!cleanInput || isLoading) return
    // Arrêter la reconnaissance si active
    if (isListening && recognitionRef.current) {
      recognitionRef.current.stop()
      setIsListening(false)
    }
    onSend(cleanInput)
    setInput('')
  }, [input, isLoading, isListening, onSend])

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault()
      handleSubmit()
    }
  }

  const toggleVoice = useCallback(() => {
    if (!recognitionRef.current) return

    if (isListening) {
      recognitionRef.current.stop()
      setIsListening(false)
    } else {
      try {
        recognitionRef.current.start()
        setIsListening(true)
      } catch {
        // Peut échouer si déjà en cours
        setIsListening(false)
      }
    }
  }, [isListening])

  return (
    <div className="flex items-end gap-2 p-3 bg-black/30 border-t border-white/10">
      {/* Bouton micro */}
      {speechSupported && !isLoading && (
        <button
          onClick={toggleVoice}
          className={`shrink-0 w-10 h-10 rounded-xl flex items-center justify-center transition-all ${
            isListening
              ? 'animate-pulse'
              : 'hover:bg-white/5'
          }`}
          style={{
            backgroundColor: isListening ? `${accentColor}30` : 'transparent',
            color: isListening ? accentColor : 'rgba(255,255,255,0.4)',
            border: `1px solid ${isListening ? accentColor : 'rgba(255,255,255,0.1)'}`,
            boxShadow: isListening ? `0 0 12px ${accentColor}40` : 'none',
          }}
          title={isListening ? 'Arrêter le micro' : 'Parler'}
        >
          {isListening ? (
            // Micro actif — icône animée
            <svg width="18" height="18" viewBox="0 0 24 24" fill="currentColor">
              <path d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z" />
              <path d="M19 10v2a7 7 0 0 1-14 0v-2" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" />
              <line x1="12" y1="19" x2="12" y2="23" stroke="currentColor" strokeWidth="2" strokeLinecap="round" />
              <line x1="8" y1="23" x2="16" y2="23" stroke="currentColor" strokeWidth="2" strokeLinecap="round" />
            </svg>
          ) : (
            // Micro inactif
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
              <path d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z" />
              <path d="M19 10v2a7 7 0 0 1-14 0v-2" />
              <line x1="12" y1="19" x2="12" y2="23" />
              <line x1="8" y1="23" x2="16" y2="23" />
            </svg>
          )}
        </button>
      )}

      <textarea
        ref={textareaRef}
        value={input}
        onChange={(e) => setInput(e.target.value)}
        onKeyDown={handleKeyDown}
        placeholder={isListening ? '🎤 Parlez maintenant...' : (placeholder || 'Écris ton message...')}
        rows={1}
        className="flex-1 bg-white/5 border border-white/10 rounded-xl px-4 py-2.5 text-sm text-white placeholder-white/30 resize-none focus:outline-none focus:border-white/30 transition-colors"
        style={{
          maxHeight: '120px',
          borderColor: isListening ? accentColor : undefined,
          boxShadow: isListening ? `0 0 8px ${accentColor}20` : undefined,
        }}
        disabled={isLoading}
      />

      {isLoading ? (
        <button
          onClick={onStop}
          className="shrink-0 w-10 h-10 rounded-xl flex items-center justify-center bg-red-500/20 text-red-400 hover:bg-red-500/30 transition-colors"
          title="Arrêter"
        >
          <svg width="16" height="16" viewBox="0 0 16 16" fill="currentColor">
            <rect x="3" y="3" width="10" height="10" rx="1" />
          </svg>
        </button>
      ) : (
        <button
          onClick={handleSubmit}
          disabled={!input.replace(/\s*🎤.*$/, '').trim()}
          className="shrink-0 w-10 h-10 rounded-xl flex items-center justify-center transition-all disabled:opacity-30"
          style={{
            backgroundColor: input.trim() ? `${accentColor}30` : 'transparent',
            color: input.trim() ? accentColor : 'rgba(255,255,255,0.3)',
            border: `1px solid ${input.trim() ? `${accentColor}50` : 'rgba(255,255,255,0.1)'}`,
          }}
          title="Envoyer"
        >
          <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <line x1="22" y1="2" x2="11" y2="13" />
            <polygon points="22 2 15 22 11 13 2 9 22 2" />
          </svg>
        </button>
      )}
    </div>
  )
}

'use client'

import { useMemo } from 'react'
import {
  PieChart, Pie, Cell, ResponsiveContainer,
  ComposedChart, Bar, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend,
} from 'recharts'

interface RepartitionStatut {
  statut: string
  count: number
}

interface PaiementMois {
  mois: string
  encaisse: number
  attendu: number
}

interface FinanceChartsProps {
  repartition: RepartitionStatut[]
  evolution: PaiementMois[]
  tauxRecouvrement: number
}

const STATUT_COLORS: Record<string, string> = {
  paye: '#00C853',
  partiellement_paye: '#FFD600',
  en_attente: '#9FA8DA',
  en_retard: '#FF5252',
  annule: '#666',
}

const STATUT_LABELS: Record<string, string> = {
  paye: 'Payé',
  partiellement_paye: 'Partiel',
  en_attente: 'En attente',
  en_retard: 'En retard',
  annule: 'Annulé',
}

function formatK(val: number): string {
  if (val >= 1_000_000) return `${(val / 1_000_000).toFixed(1)}M`
  if (val >= 1_000) return `${(val / 1_000).toFixed(0)}K`
  return val.toString()
}

export function FinanceCharts({ repartition, evolution, tauxRecouvrement }: FinanceChartsProps) {
  const pieData = useMemo(() =>
    repartition.map(r => ({
      name: STATUT_LABELS[r.statut] || r.statut,
      value: r.count,
      color: STATUT_COLORS[r.statut] || '#666',
    })),
  [repartition])

  const total = pieData.reduce((s, d) => s + d.value, 0)

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
      {/* Donut Chart */}
      <div className="bg-ss-bg-secondary rounded-xl border border-ss-border p-5">
        <h3 className="text-sm font-semibold text-ss-text mb-4">Répartition des factures</h3>
        <div className="relative" style={{ height: 240 }}>
          <ResponsiveContainer width="100%" height="100%">
            <PieChart>
              <Pie
                data={pieData}
                cx="50%"
                cy="50%"
                innerRadius={60}
                outerRadius={90}
                dataKey="value"
                paddingAngle={2}
                stroke="none"
              >
                {pieData.map((entry, idx) => (
                  <Cell key={idx} fill={entry.color} />
                ))}
              </Pie>
              <Tooltip
                contentStyle={{
                  backgroundColor: '#1E2547',
                  border: '1px solid #2A3166',
                  borderRadius: '8px',
                  color: '#E0E0E0',
                  fontSize: '12px',
                }}
                formatter={(value, name) => [`${value} facture(s)`, name as string]}
              />
            </PieChart>
          </ResponsiveContainer>
          {/* Label central */}
          <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
            <span className={`text-2xl font-bold ${tauxRecouvrement >= 70 ? 'text-ss-green' : tauxRecouvrement >= 50 ? 'text-ss-gold' : 'text-ss-red'}`}>
              {tauxRecouvrement}%
            </span>
            <span className="text-xs text-ss-text-muted">Recouvrement</span>
          </div>
        </div>
        {/* Légende */}
        <div className="flex flex-wrap gap-3 mt-3 justify-center">
          {pieData.map((d, i) => (
            <div key={i} className="flex items-center gap-1.5">
              <div className="w-2.5 h-2.5 rounded-full" style={{ backgroundColor: d.color }} />
              <span className="text-xs text-ss-text-muted">{d.name} ({d.value})</span>
            </div>
          ))}
        </div>
      </div>

      {/* Bar + Line Chart — 12 mois */}
      <div className="bg-ss-bg-secondary rounded-xl border border-ss-border p-5">
        <h3 className="text-sm font-semibold text-ss-text mb-4">Évolution sur 12 mois</h3>
        <div style={{ height: 240 }}>
          <ResponsiveContainer width="100%" height="100%">
            <ComposedChart data={evolution} margin={{ top: 5, right: 10, left: -15, bottom: 0 }}>
              <CartesianGrid strokeDasharray="3 3" stroke="#2A3166" />
              <XAxis
                dataKey="mois"
                tick={{ fill: '#9FA8DA', fontSize: 10 }}
                axisLine={{ stroke: '#2A3166' }}
              />
              <YAxis
                tickFormatter={formatK}
                tick={{ fill: '#9FA8DA', fontSize: 10 }}
                axisLine={{ stroke: '#2A3166' }}
              />
              <Tooltip
                contentStyle={{
                  backgroundColor: '#1E2547',
                  border: '1px solid #2A3166',
                  borderRadius: '8px',
                  color: '#E0E0E0',
                  fontSize: '12px',
                }}
                formatter={(value, name) => {
                  const formatted = new Intl.NumberFormat('fr-SN').format(Number(value))
                  return [`${formatted} FCFA`, name === 'encaisse' ? 'Encaissé' : 'Attendu']
                }}
              />
              <Legend
                formatter={(value: string) => value === 'encaisse' ? 'Encaissé' : 'Attendu'}
                wrapperStyle={{ fontSize: '11px', color: '#9FA8DA' }}
              />
              <Bar dataKey="encaisse" fill="#00BCD4" radius={[3, 3, 0, 0]} barSize={16} />
              <Line
                type="monotone"
                dataKey="attendu"
                stroke="#9FA8DA"
                strokeWidth={2}
                strokeDasharray="5 5"
                dot={false}
              />
            </ComposedChart>
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  )
}

'use client'

import { useState, useCallback } from 'react'
import { formatFCFA } from '@/lib/utils'
import { envoyerRelanceSMS, marquerPayeEspeces, envoyerRelanceWhatsApp } from '@/app/actions/finances'

interface FactureImpayee {
  id: string
  eleve_id: string
  type_frais: string
  montant_total: number
  montant_verse: number
  solde_restant: number
  date_limite: string
  nb_relances: number
  statut: string
  eleve_nom: string
  eleve_prenom: string
  classe_nom: string
  parent_id: string | null
  parent_telephone: string | null
}

interface TableauImpayesProps {
  impayes: FactureImpayee[]
  onRefresh: () => void
}

const STATUT_STYLES: Record<string, string> = {
  en_retard: 'bg-ss-red/15 text-ss-red',
  en_attente: 'bg-ss-gold/15 text-ss-gold',
  partiellement_paye: 'bg-ss-cyan/15 text-ss-cyan',
}

const STATUT_LABELS: Record<string, string> = {
  en_retard: 'En retard',
  en_attente: 'En attente',
  partiellement_paye: 'Partiel',
}

export function TableauImpayes({ impayes, onRefresh }: TableauImpayesProps) {
  const [relancingId, setRelancingId] = useState<string | null>(null)
  const [sendingWhatsApp, setSendingWhatsApp] = useState<string | null>(null)
  const [espModal, setEspModal] = useState<FactureImpayee | null>(null)
  const [montantEsp, setMontantEsp] = useState(0)
  const [refEsp, setRefEsp] = useState('')
  const [saving, setSaving] = useState(false)

  const handleRelance = useCallback(async (factureId: string) => {
    setRelancingId(factureId)
    const result = await envoyerRelanceSMS(factureId)
    if (!result.success) {
      console.error('Relance échouée:', result.error)
    }
    setRelancingId(null)
    onRefresh()
  }, [onRefresh])

  const handleWhatsApp = async (factureId: string) => {
    setSendingWhatsApp(factureId)
    const result = await envoyerRelanceWhatsApp(factureId)
    if (!result.success) {
      alert('Erreur: ' + (result.error || 'Envoi impossible'))
    }
    setSendingWhatsApp(null)
  }

  const handleEspeces = useCallback(async () => {
    if (!espModal || montantEsp <= 0) return
    setSaving(true)
    const result = await marquerPayeEspeces(espModal.id, montantEsp, refEsp)
    if (!result.success) {
      console.error('Erreur espèces:', result.error)
    }
    setSaving(false)
    setEspModal(null)
    setMontantEsp(0)
    setRefEsp('')
    onRefresh()
  }, [espModal, montantEsp, refEsp, onRefresh])

  const joursRetard = (dateLimite: string) => {
    const diff = Date.now() - new Date(dateLimite).getTime()
    const jours = Math.floor(diff / (1000 * 60 * 60 * 24))
    return jours > 0 ? jours : 0
  }

  if (impayes.length === 0) {
    return (
      <div className="bg-ss-bg-secondary rounded-xl border border-ss-border p-8 text-center">
        <span className="text-3xl block mb-2">🎉</span>
        <p className="text-ss-text font-semibold">Aucun impayé en retard</p>
        <p className="text-ss-text-muted text-sm mt-1">Toutes les factures sont à jour.</p>
      </div>
    )
  }

  return (
    <>
      <div className="bg-ss-bg-secondary rounded-xl border border-ss-border overflow-hidden">
        <div className="p-4 border-b border-ss-border flex items-center justify-between">
          <h3 className="text-sm font-semibold text-ss-text">Top impayés ({impayes.length})</h3>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full min-w-[700px]">
            <thead>
              <tr className="border-b border-ss-border bg-ss-bg-card">
                <th className="px-4 py-3 text-left text-xs font-semibold text-ss-text-secondary">Élève</th>
                <th className="px-3 py-3 text-left text-xs font-semibold text-ss-text-secondary">Classe</th>
                <th className="px-3 py-3 text-right text-xs font-semibold text-ss-text-secondary">Montant dû</th>
                <th className="px-3 py-3 text-center text-xs font-semibold text-ss-text-secondary">Depuis</th>
                <th className="px-3 py-3 text-center text-xs font-semibold text-ss-text-secondary">Relances</th>
                <th className="px-3 py-3 text-center text-xs font-semibold text-ss-text-secondary">Statut</th>
                <th className="px-3 py-3 text-right text-xs font-semibold text-ss-text-secondary">Actions</th>
              </tr>
            </thead>
            <tbody>
              {impayes.map((f, idx) => {
                const jours = joursRetard(f.date_limite)
                return (
                  <tr key={f.id} className={`border-b border-ss-border/50 ${idx % 2 === 0 ? '' : 'bg-ss-bg-card/30'}`}>
                    <td className="px-4 py-3">
                      <p className="text-sm font-medium text-ss-text">{f.eleve_prenom} {f.eleve_nom}</p>
                      <p className="text-xs text-ss-text-muted">{f.type_frais}</p>
                    </td>
                    <td className="px-3 py-3 text-sm text-ss-text-secondary">{f.classe_nom}</td>
                    <td className="px-3 py-3 text-right">
                      <span className="text-sm font-bold text-ss-red">{formatFCFA(f.solde_restant)}</span>
                    </td>
                    <td className="px-3 py-3 text-center">
                      <span className={`text-xs font-medium ${jours > 30 ? 'text-ss-red' : jours > 7 ? 'text-ss-gold' : 'text-ss-text-muted'}`}>
                        {jours > 0 ? `${jours}j` : 'Aujourd\'hui'}
                      </span>
                    </td>
                    <td className="px-3 py-3 text-center">
                      <span className="text-xs text-ss-text-muted">{f.nb_relances}</span>
                    </td>
                    <td className="px-3 py-3 text-center">
                      <span className={`text-xs font-medium px-2 py-1 rounded-md ${STATUT_STYLES[f.statut] || 'bg-ss-bg-card text-ss-text-muted'}`}>
                        {STATUT_LABELS[f.statut] || f.statut}
                      </span>
                    </td>
                    <td className="px-3 py-3">
                      <div className="flex items-center justify-end gap-1">
                        <button
                          onClick={() => handleRelance(f.id)}
                          disabled={relancingId === f.id}
                          className="text-xs bg-ss-cyan/10 text-ss-cyan px-2 py-1.5 rounded-lg hover:bg-ss-cyan/20 disabled:opacity-50 min-h-[32px] transition-colors"
                          title="Envoyer SMS de relance"
                        >
                          {relancingId === f.id ? '...' : '📱'}
                        </button>
                        {f.parent_telephone && (
                          <a
                            href={`tel:+221${f.parent_telephone}`}
                            className="text-xs bg-ss-green/10 text-ss-green px-2 py-1.5 rounded-lg hover:bg-ss-green/20 min-h-[32px] transition-colors"
                            title="Appeler le parent"
                          >
                            📞
                          </a>
                        )}
                        <button
                          onClick={() => handleWhatsApp(f.id)}
                          disabled={sendingWhatsApp === f.id}
                          className="flex items-center gap-1 px-3 py-1.5 bg-[#25D366]/10 text-[#25D366] rounded-lg text-xs hover:bg-[#25D366]/20 transition disabled:opacity-50"
                          title="Envoyer rappel WhatsApp"
                        >
                          {sendingWhatsApp === f.id ? '...' : '📱 WA'}
                        </button>
                        <button
                          onClick={() => { setEspModal(f); setMontantEsp(f.solde_restant) }}
                          className="text-xs bg-ss-gold/10 text-ss-gold px-2 py-1.5 rounded-lg hover:bg-ss-gold/20 min-h-[32px] transition-colors"
                          title="Marquer payé en espèces"
                        >
                          💵
                        </button>
                      </div>
                    </td>
                  </tr>
                )
              })}
            </tbody>
          </table>
        </div>
      </div>

      {/* Modal espèces */}
      {espModal && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-end sm:items-center justify-center z-50 p-0 sm:p-4">
          <div className="bg-ss-bg-secondary rounded-t-2xl sm:rounded-2xl w-full sm:max-w-sm border border-ss-border p-5 space-y-4">
            <div className="flex items-center justify-between">
              <h3 className="text-lg font-bold text-ss-text">Paiement espèces</h3>
              <button onClick={() => setEspModal(null)} className="text-ss-text-muted hover:text-ss-text text-xl">✕</button>
            </div>
            <p className="text-sm text-ss-text-secondary">
              {espModal.eleve_prenom} {espModal.eleve_nom} — {formatFCFA(espModal.solde_restant)} dû
            </p>
            <div>
              <label className="block text-sm font-medium text-ss-text-secondary mb-1.5">Montant reçu (FCFA)</label>
              <input
                type="number"
                min={1}
                max={espModal.solde_restant}
                value={montantEsp}
                onChange={e => setMontantEsp(parseInt(e.target.value) || 0)}
                className="w-full bg-ss-bg border border-ss-border text-ss-text rounded-lg px-3 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-ss-cyan"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-ss-text-secondary mb-1.5">Référence reçu</label>
              <input
                type="text"
                value={refEsp}
                onChange={e => setRefEsp(e.target.value)}
                placeholder="Ex: REC-2026-042"
                className="w-full bg-ss-bg border border-ss-border text-ss-text rounded-lg px-3 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-ss-cyan"
              />
            </div>
            <button
              onClick={handleEspeces}
              disabled={saving || montantEsp <= 0}
              className="w-full bg-ss-green text-white py-3 rounded-xl font-bold text-sm min-h-[48px] hover:bg-ss-green/80 disabled:opacity-50 transition-colors"
            >
              {saving ? 'Enregistrement...' : `Enregistrer ${formatFCFA(montantEsp)}`}
            </button>
          </div>
        </div>
      )}
    </>
  )
}

'use client'

import { useState, useCallback, useRef, useEffect, memo } from 'react'
import { createClient } from '@/lib/supabase/client'
import { z } from 'zod'

// Types
interface Eleve {
  id: string
  nom: string
  prenom: string
}

interface NoteRow {
  eleve_id: string
  note: number | null
  absent_eval: boolean
  observation: string | null
}

interface GrilleNotesProps {
  classeId: string
  matiereId: string
  evaluationId: string
  eleves: Eleve[]
  userId: string
  trimestre: number
}

type SyncStatus = 'idle' | 'saving' | 'saved' | 'error'

const noteSchema = z.number().min(0).max(20).multipleOf(0.5).or(z.null())

// Cell component memoized pour performance
const NoteCell = memo(function NoteCell({
  eleveId,
  value,
  isAbsent,
  onChange,
  onAbsent,
  onKeyNav,
  inputRef,
}: {
  eleveId: string
  value: number | null
  isAbsent: boolean
  onChange: (eleveId: string, val: number | null) => void
  onAbsent: (eleveId: string) => void
  onKeyNav: (e: React.KeyboardEvent, eleveId: string) => void
  inputRef: (el: HTMLInputElement | null) => void
}) {
  const bgColor = isAbsent
    ? 'bg-gray-600/30'
    : value !== null && value >= 10
    ? 'bg-ss-green/10 border-ss-green/30'
    : value !== null && value < 10
    ? 'bg-ss-red/10 border-ss-red/30'
    : 'bg-ss-bg border-ss-border'

  if (isAbsent) {
    return (
      <div className="flex items-center gap-1">
        <span className="text-xs text-ss-text-muted font-medium px-2 py-1.5 bg-gray-600/20 rounded">ABS</span>
        <button
          onClick={() => onChange(eleveId, null)}
          className="text-[10px] text-ss-cyan hover:text-ss-text"
          title="Annuler absence"
        >
          ✕
        </button>
      </div>
    )
  }

  return (
    <div className="flex items-center gap-1">
      <input
        ref={inputRef}
        type="number"
        min={0}
        max={20}
        step={0.5}
        value={value !== null ? value : ''}
        onChange={(e) => {
          const raw = e.target.value
          if (raw === '') {
            onChange(eleveId, null)
          } else {
            const num = parseFloat(raw)
            if (!isNaN(num) && num >= 0 && num <= 20) {
              onChange(eleveId, num)
            }
          }
        }}
        onKeyDown={(e) => onKeyNav(e, eleveId)}
        className={`w-14 border rounded px-2 py-1.5 text-center text-sm font-medium text-ss-text focus:outline-none focus:ring-2 focus:ring-ss-cyan ${bgColor}`}
        data-eleve={eleveId}
      />
      <button
        onClick={() => onAbsent(eleveId)}
        className="text-[10px] text-ss-text-muted hover:text-ss-red px-1 py-1 min-w-[28px] min-h-[28px]"
        title="Absent"
      >
        ABS
      </button>
    </div>
  )
})

export function GrilleNotes({ classeId, matiereId, evaluationId, eleves, userId, trimestre }: GrilleNotesProps) {
  const [notes, setNotes] = useState<Map<string, { note: number | null; absent: boolean }>>(new Map())
  const [moyennes, setMoyennes] = useState<Map<string, number>>(new Map())
  const [syncStatus, setSyncStatus] = useState<SyncStatus>('idle')
  const [pendingCount, setPendingCount] = useState(0)
  const supabase = createClient()
  const saveTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null)
  const inputRefs = useRef<Map<string, HTMLInputElement>>(new Map())
  const pendingUpserts = useRef<Map<string, { note: number | null; absent: boolean }>>(new Map())

  // Charger notes existantes
  useEffect(() => {
    async function loadNotes() {
      const { data } = await supabase
        .from('notes')
        .select('*')
        .eq('evaluation_id', evaluationId)

      if (data) {
        const map = new Map<string, { note: number | null; absent: boolean }>()
        for (const row of data as unknown as NoteRow[]) {
          map.set(row.eleve_id, { note: row.note, absent: row.absent_eval })
        }
        setNotes(map)
      }
    }

    async function loadMoyennes() {
      // Charger les moyennes du trimestre pour chaque élève
      const eleveIds = eleves.map(e => e.id)
      if (eleveIds.length === 0) return

      const { data } = await supabase
        .from('v_moyennes_trimestre')
        .select('*')
        .in('eleve_id', eleveIds)
        .eq('matiere_id', matiereId)
        .eq('trimestre', trimestre)

      if (data) {
        const map = new Map<string, number>()
        for (const row of data as unknown as { eleve_id: string; moyenne_matiere: number }[]) {
          map.set(row.eleve_id, row.moyenne_matiere)
        }
        setMoyennes(map)
      }
    }

    loadNotes()
    loadMoyennes()
  }, [evaluationId, matiereId, trimestre, eleves, supabase])

  // Sauvegarder debounced
  const flushSaves = useCallback(async () => {
    const pending = new Map(pendingUpserts.current)
    pendingUpserts.current.clear()
    if (pending.size === 0) return

    setSyncStatus('saving')
    setPendingCount(pending.size)

    let hasError = false
    for (const [eleveId, { note, absent }] of pending) {
      const validated = noteSchema.safeParse(note)
      const finalNote = validated.success ? validated.data : null

      const { error } = await (supabase.from('notes') as any).upsert(
        {
          eleve_id: eleveId,
          evaluation_id: evaluationId,
          note: absent ? null : finalNote,
          absent_eval: absent,
          saisi_par: userId,
        },
        { onConflict: 'eleve_id,evaluation_id' }
      )

      if (error) {
        console.error('Erreur sauvegarde note:', error)
        hasError = true
      }
    }

    setSyncStatus(hasError ? 'error' : 'saved')
    setPendingCount(0)

    if (!hasError) {
      setTimeout(() => setSyncStatus('idle'), 2000)
    }
  }, [evaluationId, userId, supabase])

  const scheduleSave = useCallback((eleveId: string, note: number | null, absent: boolean) => {
    pendingUpserts.current.set(eleveId, { note, absent })
    if (saveTimerRef.current) clearTimeout(saveTimerRef.current)
    saveTimerRef.current = setTimeout(flushSaves, 500)
  }, [flushSaves])

  // Handlers
  const handleNoteChange = useCallback((eleveId: string, val: number | null) => {
    setNotes(prev => {
      const next = new Map(prev)
      next.set(eleveId, { note: val, absent: false })
      return next
    })
    scheduleSave(eleveId, val, false)
  }, [scheduleSave])

  const handleAbsent = useCallback((eleveId: string) => {
    setNotes(prev => {
      const next = new Map(prev)
      next.set(eleveId, { note: null, absent: true })
      return next
    })
    scheduleSave(eleveId, null, true)
  }, [scheduleSave])

  // Navigation clavier
  const handleKeyNav = useCallback((e: React.KeyboardEvent, currentEleveId: string) => {
    if (e.key === 'Enter' || (e.key === 'Tab' && !e.shiftKey)) {
      e.preventDefault()
      const idx = eleves.findIndex(el => el.id === currentEleveId)
      const nextEleve = eleves[idx + 1]
      if (nextEleve) {
        const nextInput = inputRefs.current.get(nextEleve.id)
        nextInput?.focus()
        nextInput?.select()
      }
    }
  }, [eleves])

  // Statistiques
  const allNotes = eleves
    .map(e => notes.get(e.id))
    .filter(n => n && !n.absent && n.note !== null)
    .map(n => n!.note!)

  const classeStats = {
    moyenne: allNotes.length > 0 ? (allNotes.reduce((a, b) => a + b, 0) / allNotes.length) : 0,
    max: allNotes.length > 0 ? Math.max(...allNotes) : 0,
    min: allNotes.length > 0 ? Math.min(...allNotes) : 0,
    nbSup10: allNotes.filter(n => n >= 10).length,
    nbInf10: allNotes.filter(n => n < 10).length,
    total: allNotes.length,
  }

  // Distribution pour le graphique
  const distribution = Array.from({ length: 21 }, (_, i) => ({
    note: i,
    count: allNotes.filter(n => Math.floor(n) === i).length,
  }))

  // Export CSV (léger, pas besoin de xlsx)
  const handleExport = () => {
    const header = 'Nom,Prénom,Note,Observation\n'
    const rows = eleves.map(e => {
      const n = notes.get(e.id)
      const noteStr = n?.absent ? 'ABS' : n?.note?.toString() ?? ''
      return `${e.nom},${e.prenom},${noteStr},`
    }).join('\n')

    const blob = new Blob(['\ufeff' + header + rows], { type: 'text/csv;charset=utf-8;' })
    const url = URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = `notes_evaluation.csv`
    a.click()
    URL.revokeObjectURL(url)
  }

  return (
    <div className="space-y-4">
      {/* Indicateur sync */}
      <div className="flex items-center justify-between">
        <span className="text-xs text-ss-text-muted">
          {eleves.length} élève(s) · {allNotes.length} note(s) saisie(s)
        </span>
        <div className="flex items-center gap-2">
          {syncStatus === 'saving' && (
            <span className="text-xs text-ss-gold flex items-center gap-1">
              <span className="w-2 h-2 bg-ss-gold rounded-full animate-pulse" />
              Enregistrement... ({pendingCount})
            </span>
          )}
          {syncStatus === 'saved' && (
            <span className="text-xs text-ss-green">✅ Enregistré</span>
          )}
          {syncStatus === 'error' && (
            <span className="text-xs text-ss-red">❌ Erreur</span>
          )}
          <button
            onClick={handleExport}
            className="text-xs text-ss-cyan bg-ss-cyan/10 px-3 py-1.5 rounded-lg hover:bg-ss-cyan/20 transition-colors min-h-[32px]"
          >
            📥 Export CSV
          </button>
        </div>
      </div>

      {/* Grille */}
      <div className="bg-ss-bg-secondary rounded-xl border border-ss-border overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full min-w-[400px]">
            <thead>
              <tr className="border-b border-ss-border bg-ss-bg-card">
                <th className="px-4 py-3 text-left text-xs font-semibold text-ss-text-secondary w-[180px]">Élève</th>
                <th className="px-3 py-3 text-center text-xs font-semibold text-ss-text-secondary w-[120px]">Note /20</th>
                <th className="px-3 py-3 text-center text-xs font-semibold text-ss-text-secondary w-[80px]">Moy. trim.</th>
              </tr>
            </thead>
            <tbody>
              {eleves.map((eleve, idx) => {
                const noteData = notes.get(eleve.id)
                const moy = moyennes.get(eleve.id)
                return (
                  <tr
                    key={eleve.id}
                    className={`border-b border-ss-border/50 ${idx % 2 === 0 ? '' : 'bg-ss-bg-card/30'}`}
                  >
                    <td className="px-4 py-2.5">
                      <p className="text-sm font-medium text-ss-text">{eleve.prenom} {eleve.nom}</p>
                    </td>
                    <td className="px-3 py-2.5 text-center">
                      <NoteCell
                        eleveId={eleve.id}
                        value={noteData?.note ?? null}
                        isAbsent={noteData?.absent ?? false}
                        onChange={handleNoteChange}
                        onAbsent={handleAbsent}
                        onKeyNav={handleKeyNav}
                        inputRef={(el) => { if (el) inputRefs.current.set(eleve.id, el) }}
                      />
                    </td>
                    <td className="px-3 py-2.5 text-center">
                      {moy !== undefined ? (
                        <span className={`text-sm font-semibold ${moy >= 10 ? 'text-ss-green' : 'text-ss-red'}`}>
                          {moy.toFixed(1)}
                        </span>
                      ) : (
                        <span className="text-xs text-ss-text-muted">—</span>
                      )}
                    </td>
                  </tr>
                )
              })}
            </tbody>
          </table>
        </div>
      </div>

      {/* Statistiques de classe */}
      {allNotes.length > 0 && (
        <div className="bg-ss-bg-secondary rounded-xl border border-ss-border p-5">
          <h3 className="text-sm font-semibold text-ss-text mb-4">Statistiques de la classe</h3>
          <div className="grid grid-cols-2 sm:grid-cols-5 gap-3 mb-4">
            {[
              { label: 'Moyenne', value: classeStats.moyenne.toFixed(1), color: classeStats.moyenne >= 10 ? 'text-ss-green' : 'text-ss-red' },
              { label: 'Note max', value: classeStats.max.toFixed(1), color: 'text-ss-green' },
              { label: 'Note min', value: classeStats.min.toFixed(1), color: 'text-ss-red' },
              { label: '≥ 10', value: `${classeStats.nbSup10}`, color: 'text-ss-green' },
              { label: '< 10', value: `${classeStats.nbInf10}`, color: 'text-ss-red' },
            ].map(stat => (
              <div key={stat.label} className="bg-ss-bg-card rounded-lg p-3 text-center">
                <p className={`text-lg font-bold ${stat.color}`}>{stat.value}</p>
                <p className="text-xs text-ss-text-muted">{stat.label}</p>
              </div>
            ))}
          </div>

          {/* Distribution */}
          <div className="flex items-end gap-[2px] h-20">
            {distribution.map(d => {
              const maxCount = Math.max(...distribution.map(x => x.count), 1)
              const height = d.count > 0 ? Math.max((d.count / maxCount) * 100, 8) : 0
              return (
                <div key={d.note} className="flex-1 flex flex-col items-center justify-end">
                  {height > 0 && (
                    <div
                      className={`w-full rounded-t-sm ${d.note >= 10 ? 'bg-ss-green/60' : 'bg-ss-red/60'}`}
                      style={{ height: `${height}%` }}
                      title={`${d.note}/20: ${d.count} élève(s)`}
                    />
                  )}
                </div>
              )
            })}
          </div>
          <div className="flex justify-between mt-1">
            <span className="text-[10px] text-ss-text-muted">0</span>
            <span className="text-[10px] text-ss-text-muted">10</span>
            <span className="text-[10px] text-ss-text-muted">20</span>
          </div>
        </div>
      )}
    </div>
  )
}

'use client'

import { useEffect, useRef } from 'react'

interface MapViewProps {
  ecoleLat: number
  ecoleLng: number
  ecoleNom?: string
  rayonM?: number
  profLat?: number
  profLng?: number
  profNom?: string
  zoom?: number
}

export function MapView({
  ecoleLat, ecoleLng, ecoleNom = 'École',
  rayonM = 100,
  profLat, profLng, profNom,
  zoom = 16,
}: MapViewProps) {
  const mapRef = useRef<HTMLDivElement>(null)
  const mapInstanceRef = useRef<any>(null)

  useEffect(() => {
    if (typeof window === 'undefined' || !mapRef.current) return
    // Éviter double init
    if (mapInstanceRef.current) {
      mapInstanceRef.current.remove()
      mapInstanceRef.current = null
    }

    import('leaflet').then((L) => {
      if (!mapRef.current) return

      // Fix icônes Leaflet manquantes en Next.js
      delete (L.Icon.Default.prototype as any)._getIconUrl
      L.Icon.Default.mergeOptions({
        iconRetinaUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon-2x.png',
        iconUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png',
        shadowUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png',
      })

      const map = L.map(mapRef.current, {
        scrollWheelZoom: false,
        dragging: !L.Browser.mobile,
        touchZoom: true,
      }).setView([ecoleLat, ecoleLng], zoom)

      mapInstanceRef.current = map

      L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
        attribution: '&copy; OSM',
      }).addTo(map)

      // Cercle périmètre école
      L.circle([ecoleLat, ecoleLng], {
        radius: rayonM,
        color: '#00C853',
        fillColor: '#00C853',
        fillOpacity: 0.12,
        weight: 2,
      }).addTo(map)

      // Marqueur école
      const ecoleIcon = L.divIcon({
        html: '<div style="background:#00C853;width:28px;height:28px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:14px;border:3px solid #0A0E27;">🏫</div>',
        iconSize: [28, 28],
        iconAnchor: [14, 14],
        className: '',
      })
      L.marker([ecoleLat, ecoleLng], { icon: ecoleIcon })
        .addTo(map)
        .bindPopup(`<b>${ecoleNom}</b><br/>Périmètre: ${rayonM}m`)

      // Marqueur professeur
      if (profLat !== undefined && profLng !== undefined) {
        const profIcon = L.divIcon({
          html: '<div style="background:#00BCD4;width:28px;height:28px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:14px;border:3px solid #0A0E27;">👨‍🏫</div>',
          iconSize: [28, 28],
          iconAnchor: [14, 14],
          className: '',
        })
        L.marker([profLat, profLng], { icon: profIcon })
          .addTo(map)
          .bindPopup(profNom ? `<b>${profNom}</b>` : 'Ma position')

        // Ajuster la vue pour montrer les 2 marqueurs
        const bounds = L.latLngBounds(
          [ecoleLat, ecoleLng],
          [profLat, profLng]
        ).pad(0.3)
        map.fitBounds(bounds, { maxZoom: 17 })
      }
    })

    return () => {
      if (mapInstanceRef.current) {
        mapInstanceRef.current.remove()
        mapInstanceRef.current = null
      }
    }
  }, [ecoleLat, ecoleLng, ecoleNom, rayonM, profLat, profLng, profNom, zoom])

  return (
    <>
      <link rel="stylesheet" href="https://unpkg.com/leaflet@1.9.4/dist/leaflet.css" />
      <div ref={mapRef} className="w-full h-[300px] rounded-xl border border-ss-border" />
    </>
  )
}

'use client'

import { useState, useEffect, useCallback } from 'react'
import { createClient } from '@/lib/supabase/client'
import { MapView } from './MapView'

interface Ecole {
  latitude: number
  longitude: number
  nom: string
  rayon_pointage_m: number
}

interface PointageRecord {
  id: string
  date_pointage: string
  heure_arrivee: string
  statut: string
  minutes_retard: number
  distance_ecole_m: number | null
}

interface PointageGPSProps {
  userId: string
  ecoleId: string
  userName?: string
}

type PointageState = 'idle' | 'acquiring' | 'checking' | 'inserting' | 'success' | 'already' | 'error_gps' | 'error_perimetre' | 'error_server'

function haversineDistance(lat1: number, lon1: number, lat2: number, lon2: number): number {
  const R = 6371000
  const p1 = (lat1 * Math.PI) / 180
  const p2 = (lat2 * Math.PI) / 180
  const dp = ((lat2 - lat1) * Math.PI) / 180
  const dl = ((lon2 - lon1) * Math.PI) / 180
  const a = Math.sin(dp / 2) * Math.sin(dp / 2) + Math.cos(p1) * Math.cos(p2) * Math.sin(dl / 2) * Math.sin(dl / 2)
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a))
}

const STATUT_LABELS: Record<string, { label: string; color: string }> = {
  a_heure: { label: 'À l\'heure', color: 'bg-ss-green/15 text-ss-green' },
  retard_leger: { label: 'Retard léger', color: 'bg-ss-gold/15 text-ss-gold' },
  retard_grave: { label: 'Retard grave', color: 'bg-ss-red/15 text-ss-red' },
  absent: { label: 'Absent', color: 'bg-ss-red/15 text-ss-red' },
}

export function PointageGPS({ userId, ecoleId, userName }: PointageGPSProps) {
  const [state, setState] = useState<PointageState>('idle')
  const [ecole, setEcole] = useState<Ecole | null>(null)
  const [position, setPosition] = useState<{ lat: number; lng: number } | null>(null)
  const [distance, setDistance] = useState<number | null>(null)
  const [todayPointage, setTodayPointage] = useState<PointageRecord | null>(null)
  const [historique, setHistorique] = useState<PointageRecord[]>([])
  const [errorMsg, setErrorMsg] = useState('')
  const supabase = createClient()

  // Charger école + vérifier pointage du jour + historique
  useEffect(() => {
    async function load() {
      // Données école
      if (ecoleId) {
        const { data: ecoleData } = await supabase
          .from('ecoles')
          .select('*')
          .eq('id', ecoleId)
          .single()
        if (ecoleData) {
          setEcole(ecoleData as unknown as Ecole)
        }
      }

      // Pointage aujourd'hui
      const today = new Date().toISOString().split('T')[0]
      const { data: todayData } = await supabase
        .from('pointages_profs')
        .select('*')
        .eq('prof_id', userId)
        .eq('date_pointage', today)
        .maybeSingle()

      if (todayData) {
        setTodayPointage(todayData as unknown as PointageRecord)
        setState('already')
      }

      // Historique 5 derniers
      const { data: histData } = await supabase
        .from('pointages_profs')
        .select('*')
        .eq('prof_id', userId)
        .order('created_at', { ascending: false })
        .limit(5)

      if (histData) {
        setHistorique(histData as unknown as PointageRecord[])
      }
    }
    load()
  }, [userId, ecoleId, supabase])

  const handlePointage = useCallback(async () => {
    setErrorMsg('')
    setState('acquiring')

    // 1. Acquisition GPS
    if (!navigator.geolocation) {
      setState('error_gps')
      setErrorMsg('Votre appareil ne supporte pas la géolocalisation.')
      return
    }

    navigator.geolocation.getCurrentPosition(
      async (pos) => {
        const lat = pos.coords.latitude
        const lng = pos.coords.longitude
        setPosition({ lat, lng })

        // 2. Vérification client du périmètre
        if (ecole) {
          setState('checking')
          const dist = haversineDistance(lat, lng, ecole.latitude, ecole.longitude)
          setDistance(Math.round(dist))

          if (dist > ecole.rayon_pointage_m) {
            setState('error_perimetre')
            setErrorMsg(`Distance détectée : ${Math.round(dist)}m\nPérimètre autorisé : ${ecole.rayon_pointage_m}m`)
            return
          }
        }

        // 3. INSERT dans Supabase
        setState('inserting')
        const { error } = await supabase.from('pointages_profs').insert({
          prof_id: userId,
          ecole_id: ecoleId,
          latitude: lat,
          longitude: lng,
          heure_arrivee: new Date().toISOString(),
        } as any)

        if (error) {
          if (error.message.includes('HORS_PERIMETRE')) {
            const match = error.message.match(/HORS_PERIMETRE:(.+)/)
            setState('error_perimetre')
            setErrorMsg(`Validation serveur : hors périmètre${match ? ` (${match[1].trim()})` : ''}`)
          } else if (error.message.includes('duplicate') || error.message.includes('unique')) {
            setState('already')
          } else {
            setState('error_server')
            setErrorMsg(error.message)
          }
          return
        }

        // 4. Succès
        setState('success')
        if (typeof navigator !== 'undefined' && navigator.vibrate) {
          navigator.vibrate([100, 50, 100])
        }

        // Recharger pointage du jour + historique
        const today = new Date().toISOString().split('T')[0]
        const { data: newPointage } = await supabase
          .from('pointages_profs')
          .select('*')
          .eq('prof_id', userId)
          .eq('date_pointage', today)
          .maybeSingle()
        if (newPointage) {
          setTodayPointage(newPointage as unknown as PointageRecord)
        }

        const { data: histData } = await supabase
          .from('pointages_profs')
          .select('*')
          .eq('prof_id', userId)
          .order('created_at', { ascending: false })
          .limit(5)
        if (histData) {
          setHistorique(histData as unknown as PointageRecord[])
        }
      },
      (geoError) => {
        setState('error_gps')
        const messages: Record<number, string> = {
          1: 'Permission GPS refusée. Activez la localisation dans les paramètres de votre navigateur.',
          2: 'Position non disponible. Vérifiez que le GPS est activé.',
          3: 'Délai d\'acquisition GPS expiré. Réessayez dans un endroit dégagé.',
        }
        setErrorMsg(messages[geoError.code] || geoError.message)
      },
      { enableHighAccuracy: true, timeout: 10000, maximumAge: 0 }
    )
  }, [ecole, userId, ecoleId, supabase])

  const formatHeure = (iso: string) => {
    try {
      return new Date(iso).toLocaleTimeString('fr-SN', { hour: '2-digit', minute: '2-digit' })
    } catch { return iso }
  }

  const formatDate = (dateStr: string) => {
    try {
      return new Date(dateStr).toLocaleDateString('fr-SN', { day: '2-digit', month: 'short' })
    } catch { return dateStr }
  }

  return (
    <div className="space-y-4">
      {/* Bouton pointage / État */}
      <div className="bg-ss-bg-secondary rounded-xl border border-ss-border p-5">
        {/* Déjà pointé */}
        {(state === 'already' || state === 'success') && todayPointage && (
          <div className="text-center">
            {state === 'success' && (
              <div className="text-4xl mb-3 animate-bounce">🎉</div>
            )}
            <div className="w-16 h-16 mx-auto mb-3 rounded-full bg-ss-green/15 flex items-center justify-center">
              <span className="text-3xl">✅</span>
            </div>
            <p className="text-ss-text font-semibold text-lg">
              {state === 'success' ? 'Pointage enregistré !' : 'Vous avez déjà pointé aujourd\'hui'}
            </p>
            <p className="text-ss-text-secondary text-sm mt-1">
              Arrivée à {formatHeure(todayPointage.heure_arrivee)}
            </p>
            {todayPointage.statut && (
              <span className={`inline-block mt-2 text-xs font-medium px-3 py-1 rounded-full ${STATUT_LABELS[todayPointage.statut]?.color || 'bg-ss-bg-card text-ss-text-muted'}`}>
                {STATUT_LABELS[todayPointage.statut]?.label || todayPointage.statut}
                {todayPointage.minutes_retard > 0 && ` (+${todayPointage.minutes_retard} min)`}
              </span>
            )}
            {todayPointage.distance_ecole_m !== null && (
              <p className="text-xs text-ss-text-muted mt-2">
                Distance : {todayPointage.distance_ecole_m}m de l&apos;école
              </p>
            )}
          </div>
        )}

        {/* Erreur GPS */}
        {state === 'error_gps' && (
          <div className="text-center">
            <div className="w-16 h-16 mx-auto mb-3 rounded-full bg-ss-red/15 flex items-center justify-center">
              <span className="text-3xl">📡</span>
            </div>
            <p className="text-ss-text font-semibold">Erreur GPS</p>
            <p className="text-ss-text-secondary text-sm mt-1 whitespace-pre-line">{errorMsg}</p>
            <button
              onClick={handlePointage}
              className="mt-4 bg-ss-cyan text-white px-6 py-3 rounded-xl font-semibold text-sm min-h-[48px] transition-colors hover:bg-ss-cyan/80"
            >
              Réessayer
            </button>
          </div>
        )}

        {/* Erreur périmètre */}
        {state === 'error_perimetre' && (
          <div className="text-center">
            <div className="w-16 h-16 mx-auto mb-3 rounded-full bg-ss-gold/15 flex items-center justify-center">
              <span className="text-3xl">⚠️</span>
            </div>
            <p className="text-ss-text font-semibold">Vous n&apos;êtes pas à l&apos;école</p>
            <p className="text-ss-text-secondary text-sm mt-1 whitespace-pre-line">{errorMsg}</p>
            <p className="text-ss-text-muted text-xs mt-3">
              Si vous pensez que c&apos;est une erreur, contactez le surveillant.
            </p>
            <button
              onClick={handlePointage}
              className="mt-4 bg-ss-bg-card text-ss-text px-6 py-3 rounded-xl font-semibold text-sm min-h-[48px] border border-ss-border transition-colors hover:bg-ss-bg-card/80"
            >
              Réessayer le pointage
            </button>
          </div>
        )}

        {/* Erreur serveur */}
        {state === 'error_server' && (
          <div className="text-center">
            <div className="w-16 h-16 mx-auto mb-3 rounded-full bg-ss-red/15 flex items-center justify-center">
              <span className="text-3xl">❌</span>
            </div>
            <p className="text-ss-text font-semibold">Erreur serveur</p>
            <p className="text-ss-text-secondary text-sm mt-1">{errorMsg}</p>
            <button
              onClick={handlePointage}
              className="mt-4 bg-ss-cyan text-white px-6 py-3 rounded-xl font-semibold text-sm min-h-[48px]"
            >
              Réessayer
            </button>
          </div>
        )}

        {/* État initial / En cours */}
        {(state === 'idle' || state === 'acquiring' || state === 'checking' || state === 'inserting') && (
          <div className="text-center">
            <div className="w-20 h-20 mx-auto mb-4 rounded-full bg-ss-green/15 flex items-center justify-center">
              {state === 'idle' ? (
                <span className="text-4xl">📍</span>
              ) : (
                <div className="w-8 h-8 border-3 border-ss-green border-t-transparent rounded-full animate-spin" />
              )}
            </div>

            {state === 'idle' && (
              <>
                <p className="text-ss-text font-semibold text-lg mb-1">Pointage du jour</p>
                <p className="text-ss-text-secondary text-sm mb-5">
                  {new Date().toLocaleDateString('fr-SN', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' })}
                </p>
              </>
            )}
            {state === 'acquiring' && <p className="text-ss-text-secondary text-sm mb-5">Acquisition GPS en cours...</p>}
            {state === 'checking' && <p className="text-ss-text-secondary text-sm mb-5">Vérification du périmètre...</p>}
            {state === 'inserting' && <p className="text-ss-text-secondary text-sm mb-5">Enregistrement en cours...</p>}

            <button
              onClick={handlePointage}
              disabled={state !== 'idle'}
              className="w-full bg-ss-green text-white py-4 rounded-xl font-semibold text-base min-h-[56px] transition-colors hover:bg-ss-green/90 disabled:opacity-50 disabled:cursor-not-allowed"
            >
              {state === 'idle' ? 'Pointer mon arrivée' : 'Pointage en cours...'}
            </button>

            {ecole && (
              <p className="text-xs text-ss-text-muted mt-3">
                Périmètre autorisé : {ecole.rayon_pointage_m}m autour de {ecole.nom}
              </p>
            )}
          </div>
        )}
      </div>

      {/* Carte */}
      {ecole && (state === 'success' || state === 'already' || state === 'error_perimetre' || position) && (
        <div className="bg-ss-bg-secondary rounded-xl border border-ss-border p-4">
          <h3 className="text-sm font-semibold text-ss-text mb-3">Localisation</h3>
          <MapView
            ecoleLat={ecole.latitude}
            ecoleLng={ecole.longitude}
            ecoleNom={ecole.nom}
            rayonM={ecole.rayon_pointage_m}
            profLat={position?.lat}
            profLng={position?.lng}
            profNom={userName}
          />
          {distance !== null && (
            <p className="text-xs text-ss-text-muted mt-2 text-center">
              Distance : {distance}m — Périmètre : {ecole.rayon_pointage_m}m
            </p>
          )}
        </div>
      )}

      {/* Historique 5 derniers */}
      {historique.length > 0 && (
        <div className="bg-ss-bg-secondary rounded-xl border border-ss-border p-5">
          <h3 className="text-sm font-semibold text-ss-text mb-4">Historique récent</h3>
          <div className="space-y-2">
            {historique.map((p) => {
              const statut = STATUT_LABELS[p.statut]
              return (
                <div key={p.id} className="flex items-center justify-between p-3 bg-ss-bg-card rounded-lg">
                  <div className="flex items-center gap-3 min-w-0">
                    <span className="text-ss-text-secondary text-sm font-medium shrink-0">
                      {formatDate(p.date_pointage)}
                    </span>
                    <span className="text-ss-text text-sm">
                      {formatHeure(p.heure_arrivee)}
                    </span>
                  </div>
                  <div className="flex items-center gap-2 shrink-0">
                    {p.minutes_retard > 0 && (
                      <span className="text-xs text-ss-red">+{p.minutes_retard}min</span>
                    )}
                    <span className={`text-xs font-medium px-2 py-1 rounded-md ${statut?.color || 'bg-ss-bg text-ss-text-muted'}`}>
                      {statut?.label || p.statut}
                    </span>
                  </div>
                </div>
              )
            })}
          </div>
        </div>
      )}
    </div>
  )
}

'use client'

import { useState, useEffect, useCallback } from 'react'

interface CachedData {
  timestamp: number
  data: unknown
}

export function useOffline() {
  const [isOffline, setIsOffline] = useState(false)
  const [lastSync, setLastSync] = useState<Date | null>(null)

  useEffect(() => {
    setIsOffline(!navigator.onLine)

    const handleOnline = () => setIsOffline(false)
    const handleOffline = () => setIsOffline(true)

    window.addEventListener('online', handleOnline)
    window.addEventListener('offline', handleOffline)

    // Charger dernière date de sync
    try {
      const ts = localStorage.getItem('ss_last_sync')
      if (ts) setLastSync(new Date(parseInt(ts)))
    } catch {}

    return () => {
      window.removeEventListener('online', handleOnline)
      window.removeEventListener('offline', handleOffline)
    }
  }, [])

  const cacheData = useCallback((key: string, data: unknown) => {
    try {
      const entry: CachedData = { timestamp: Date.now(), data }
      localStorage.setItem(`ss_cache_${key}`, JSON.stringify(entry))
      localStorage.setItem('ss_last_sync', Date.now().toString())
      setLastSync(new Date())
    } catch {}
  }, [])

  const getCachedData = useCallback(<T,>(key: string): T | null => {
    try {
      const raw = localStorage.getItem(`ss_cache_${key}`)
      if (!raw) return null
      const entry: CachedData = JSON.parse(raw)
      return entry.data as T
    } catch {
      return null
    }
  }, [])

  return { isOffline, lastSync, cacheData, getCachedData }
}

'use client'

import { useEffect, useState } from 'react'
import { createClient } from '@/lib/supabase/client'

export function useRealtime<T>(table: string, filter?: string) {
  const [data, setData] = useState<T[]>([])
  const supabase = createClient()

  useEffect(() => {
    const channel = supabase
      .channel(`realtime-${table}`)
      .on('postgres_changes',
        { event: '*', schema: 'public', table },
        (payload) => {
          if (payload.eventType === 'INSERT') {
            setData(prev => [...prev, payload.new as T])
          } else if (payload.eventType === 'UPDATE') {
            setData(prev => prev.map((item: any) =>
              item.id === (payload.new as any).id ? payload.new as T : item
            ))
          } else if (payload.eventType === 'DELETE') {
            setData(prev => prev.filter((item: any) =>
              item.id !== (payload.old as any).id
            ))
          }
        }
      )
      .subscribe()

    return () => { supabase.removeChannel(channel) }
  }, [table])

  return { data, setData }
}

'use client'

import { useEffect, useState, useCallback } from 'react'
import { usePathname } from 'next/navigation'
import { createClient } from '@/lib/supabase/client'
import { isDemoMode, DEMO_USERS } from '@/lib/demo-data'
import type { Database } from '@/lib/types/database.types'

type Utilisateur = Database['public']['Tables']['utilisateurs']['Row']

function roleFromPath(pathname: string): string {
  if (pathname.startsWith('/professeur')) return 'professeur'
  if (pathname.startsWith('/surveillant')) return 'surveillant'
  if (pathname.startsWith('/parent')) return 'parent'
  if (pathname.startsWith('/eleve')) return 'eleve'
  return 'admin_global'
}

function getDemoUser(pathname: string): Utilisateur | null {
  // Détecter le rôle depuis l'URL d'abord, puis localStorage, puis fallback admin
  const pathRole = roleFromPath(pathname)
  const role = pathRole !== 'admin_global'
    ? pathRole
    : (typeof window !== 'undefined' ? localStorage.getItem('ss_demo_role') : null) || 'admin_global'

  const userMap: Record<string, Utilisateur> = {
    admin_global: DEMO_USERS.admin as Utilisateur,
    professeur: DEMO_USERS.professeur as Utilisateur,
    surveillant: DEMO_USERS.surveillant as Utilisateur,
    parent: DEMO_USERS.parent as Utilisateur,
    eleve: DEMO_USERS.eleve as Utilisateur,
  }
  return userMap[role] || DEMO_USERS.admin as Utilisateur
}

export function useUser() {
  const pathname = usePathname()
  const [user, setUser] = useState<Utilisateur | null>(null)
  const [loading, setLoading] = useState(true)

  const fetchUser = useCallback(async () => {
    // Mode démo : retourner un utilisateur fictif basé sur l'URL
    if (isDemoMode()) {
      setUser(getDemoUser(pathname))
      setLoading(false)
      return
    }

    const supabase = createClient()
    const { data: { session } } = await supabase.auth.getSession()
    if (!session) {
      setUser(null)
      setLoading(false)
      return
    }

    const { data } = await supabase
      .from('utilisateurs')
      .select('*')
      .eq('id', session.user.id)
      .single()

    setUser(data)
    setLoading(false)
  }, [pathname])

  useEffect(() => {
    fetchUser()

    if (isDemoMode()) {
      // Écouter les changements de rôle démo
      const handleStorage = (e: StorageEvent) => {
        if (e.key === 'ss_demo_role') fetchUser()
      }
      window.addEventListener('storage', handleStorage)
      return () => window.removeEventListener('storage', handleStorage)
    }

    const supabase = createClient()
    const { data: { subscription } } = supabase.auth.onAuthStateChange(() => {
      fetchUser()
    })

    return () => subscription.unsubscribe()
  }, [fetchUser])

  const logout = async () => {
    if (isDemoMode()) {
      localStorage.removeItem('ss_demo_role')
      window.location.href = '/login'
      return
    }
    const supabase = createClient()
    await supabase.auth.signOut()
    window.location.href = '/login'
  }

  return { user, loading, logout }
}

// Moteur AI principal — Google Gemini
import { GoogleGenerativeAI, SchemaType, type Content, type Part, type FunctionDeclarationsTool } from '@google/generative-ai'
import { getSystemPrompt } from './system-prompts'
import { getToolsForRole } from './tools'
import { executeTool } from './tools-registry'
import { checkRateLimit } from './rate-limiter'

// Modèles Gemini par ordre de préférence
const MODELS = ['gemini-2.5-flash', 'gemini-2.0-flash', 'gemini-2.0-flash-lite']
const MAX_TOKENS = 2048

interface ChatMessage {
  role: 'user' | 'assistant'
  content: string
}

interface ChatRequest {
  messages: ChatMessage[]
  userRole: string
  userId: string
  conversationId?: string
}

interface ChatResponse {
  content: string
  tokensIn: number
  tokensOut: number
  toolsUsed: string[]
}

function getClient(): GoogleGenerativeAI {
  const apiKey = process.env.GOOGLE_GEMINI_API_KEY
  if (!apiKey) {
    throw new Error('GOOGLE_GEMINI_API_KEY non configurée. Ajoutez-la dans .env.local')
  }
  return new GoogleGenerativeAI(apiKey)
}

// Convertir nos outils au format Gemini function calling
function getGeminiTools(role: string): FunctionDeclarationsTool[] | undefined {
  const tools = getToolsForRole(role)
  if (tools.length === 0) return undefined

  return [{
    functionDeclarations: tools.map(t => ({
      name: t.name,
      description: t.description,
      parameters: {
        type: SchemaType.OBJECT,
        properties: Object.fromEntries(
          Object.entries(t.input_schema.properties || {}).map(([key, val]) => {
            const v = val as Record<string, unknown>
            return [key, {
              type: v.type === 'number' ? SchemaType.NUMBER : SchemaType.STRING,
              description: (v.description as string) || key,
            }]
          })
        ),
        required: t.input_schema.required || [],
      },
    })) as FunctionDeclarationsTool['functionDeclarations'],
  }]
}

// Convertir les messages au format Gemini
function toGeminiHistory(messages: ChatMessage[]): Content[] {
  return messages.slice(0, -1).map(m => ({
    role: m.role === 'assistant' ? 'model' : 'user',
    parts: [{ text: m.content }] as Part[],
  }))
}

export async function chat(request: ChatRequest): Promise<ChatResponse> {
  // Rate limiting
  const rateCheck = checkRateLimit(request.userId, request.userRole)
  if (!rateCheck.allowed) {
    const minutes = Math.ceil(rateCheck.resetIn / 60000)
    return {
      content: `⏳ Limite de messages atteinte. Réessayez dans ${minutes} minute${minutes > 1 ? 's' : ''}.`,
      tokensIn: 0,
      tokensOut: 0,
      toolsUsed: [],
    }
  }

  const genAI = getClient()
  const systemPrompt = getSystemPrompt(request.userRole)
  const geminiTools = getGeminiTools(request.userRole)
  const toolsUsed: string[] = []

  // Préparer l'historique et le dernier message
  const history = toGeminiHistory(request.messages)
  const lastMessage = request.messages[request.messages.length - 1]?.content || ''

  let totalTokensIn = 0
  let totalTokensOut = 0
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  let chatSession: any
  let response: any

  // Essayer chaque modèle jusqu'à ce qu'un fonctionne
  let lastError: Error | null = null
  for (const modelName of MODELS) {
    try {
      const model = genAI.getGenerativeModel({
        model: modelName,
        systemInstruction: systemPrompt,
        tools: geminiTools,
      })
      chatSession = model.startChat({ history })
      const result = await chatSession.sendMessage(lastMessage)
      response = result.response
      lastError = null
      console.log(`[AI] Modèle ${modelName} OK`)
      break
    } catch (err) {
      lastError = err as Error
      console.warn(`[AI] Modèle ${modelName} échoué, essai suivant...`)
      continue
    }
  }

  if (!response || lastError) {
    throw lastError || new Error('Tous les modèles Gemini ont échoué')
  }

  totalTokensIn += response.usageMetadata?.promptTokenCount || 0
  totalTokensOut += response.usageMetadata?.candidatesTokenCount || 0

  // Boucle de function calling (max 5 itérations)
  let iterations = 0
  while (iterations < 5) {
    const functionCalls = response.functionCalls()
    if (!functionCalls || functionCalls.length === 0) break

    iterations++

    // Exécuter chaque function call
    const functionResponses = await Promise.all(
      functionCalls.map(async (fc: { name: string; args?: Record<string, unknown> }) => {
        toolsUsed.push(fc.name)
        const toolResult = await executeTool(
          fc.name,
          (fc.args || {}) as Record<string, unknown>,
          request.userRole
        )
        return {
          functionResponse: {
            name: fc.name,
            response: JSON.parse(toolResult),
          },
        }
      })
    )

    // Renvoyer les résultats à Gemini
    const fcResult = await chatSession.sendMessage(functionResponses as Part[])
    response = fcResult.response

    totalTokensIn += response.usageMetadata?.promptTokenCount || 0
    totalTokensOut += response.usageMetadata?.candidatesTokenCount || 0
  }

  const finalContent = response.text() || "Désolé, je n'ai pas pu générer de réponse."

  return {
    content: finalContent,
    tokensIn: totalTokensIn,
    tokensOut: totalTokensOut,
    toolsUsed,
  }
}

// Version streaming pour le chat web
export async function chatStream(
  request: ChatRequest,
  onChunk: (text: string) => void,
  onDone: (response: ChatResponse) => void
) {
  const rateCheck = checkRateLimit(request.userId, request.userRole)
  if (!rateCheck.allowed) {
    const minutes = Math.ceil(rateCheck.resetIn / 60000)
    const msg = `⏳ Limite atteinte. Réessayez dans ${minutes} min.`
    onChunk(msg)
    onDone({ content: msg, tokensIn: 0, tokensOut: 0, toolsUsed: [] })
    return
  }

  const genAI = getClient()
  const systemPrompt = getSystemPrompt(request.userRole)
  const geminiTools = getGeminiTools(request.userRole)

  const history = toGeminiHistory(request.messages)
  const lastMessage = request.messages[request.messages.length - 1]?.content || ''

  // Essayer chaque modèle
  let chatSession
  for (const modelName of MODELS) {
    try {
      const model = genAI.getGenerativeModel({
        model: modelName,
        systemInstruction: systemPrompt,
        tools: geminiTools,
      })
      chatSession = model.startChat({ history })
      break
    } catch {
      continue
    }
  }
  if (!chatSession) throw new Error('Aucun modèle Gemini disponible')

  let fullContent = ''

  const result = await chatSession.sendMessageStream(lastMessage)

  for await (const chunk of result.stream) {
    const text = chunk.text()
    if (text) {
      onChunk(text)
      fullContent += text
    }
  }

  const response = await result.response
  const tokensIn = response.usageMetadata?.promptTokenCount || 0
  const tokensOut = response.usageMetadata?.candidatesTokenCount || 0

  onDone({
    content: fullContent,
    tokensIn,
    tokensOut,
    toolsUsed: [],
  })
}

'use client'

import { useState, useEffect, useCallback } from 'react'
import { t as translate, type Locale } from './translations'

const STORAGE_KEY = 'smartschool_locale'
const DEFAULT_LOCALE: Locale = 'fr'

function getStoredLocale(): Locale {
  if (typeof window === 'undefined') return DEFAULT_LOCALE
  const stored = localStorage.getItem(STORAGE_KEY)
  if (stored && ['fr', 'wo', 'en', 'ar'].includes(stored)) {
    return stored as Locale
  }
  return DEFAULT_LOCALE
}

export function useLocale() {
  const [locale, setLocaleState] = useState<Locale>(DEFAULT_LOCALE)

  useEffect(() => {
    setLocaleState(getStoredLocale())
  }, [])

  const setLocale = useCallback((newLocale: Locale) => {
    setLocaleState(newLocale)
    if (typeof window !== 'undefined') {
      localStorage.setItem(STORAGE_KEY, newLocale)
    }
  }, [])

  const t = useCallback(
    (key: string) => translate(key, locale),
    [locale]
  )

  return { locale, setLocale, t }
}

// WhatsApp Business via Twilio Sandbox
// Configuration: TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN dans .env.local
// Sandbox WhatsApp: whatsapp:+14155238886

type WhatsAppTemplate = 'facture' | 'paiement_confirme' | 'relance' | 'transport_approche' | 'transport_depart' | 'transport_retard' | 'custom'

interface WhatsAppParams {
  to: string // numéro sénégalais sans indicatif (ex: "771234567")
  template: WhatsAppTemplate
  data: Record<string, string | number>
}

function formatMessage(template: WhatsAppTemplate, data: Record<string, string | number>): string {
  switch (template) {
    case 'facture':
      return `📚 *SmartSchool SN*\n\nBonjour ${data.parentNom},\n\nUne nouvelle facture de *${data.montant} FCFA* a été générée pour *${data.elevePrenom}* (${data.typeFrags}).\n\nDate limite: ${data.dateLimite}\n\n💳 Payez maintenant via Wave ou Orange Money dans l'application SmartSchool.\n\n_École ${data.ecoleNom}_`

    case 'paiement_confirme':
      return `✅ *Paiement confirmé — SmartSchool SN*\n\nBonjour ${data.parentNom},\n\nVotre paiement de *${data.montant} FCFA* pour *${data.elevePrenom}* a été confirmé avec succès.\n\nMerci pour votre règlement ! 🎉\n\n_École ${data.ecoleNom}_`

    case 'relance':
      return `⚠️ *Rappel paiement — SmartSchool SN*\n\nBonjour ${data.parentNom},\n\nNous vous rappelons qu'un montant de *${data.montant} FCFA* est dû pour *${data.elevePrenom}* (${data.typeFrags}).\n\n📅 Date limite dépassée : ${data.dateLimite}\n\nMerci de régulariser rapidement pour éviter toute interruption de scolarité.\n\n_École ${data.ecoleNom}_`

    case 'transport_approche':
      return `🚌 *Bus en approche — SmartSchool SN*\n\nBonjour ${data.parentNom},\n\nLe bus arrivera à l'arrêt *${data.arretNom}* dans environ *${data.minutes} minutes*.\n\n👦 ${data.elevePrenom}\n🚏 ${data.arretNom}\n👨‍✈️ Chauffeur: ${data.chauffeurNom}\n📞 ${data.chauffeurTel}\n\n_${data.ecoleNom}_`

    case 'transport_depart':
      return `🚌 *Départ du bus — SmartSchool SN*\n\nBonjour ${data.parentNom},\n\nLe bus vient de partir sur le trajet *${data.trajetNom}*.\n\nPréparez ${data.elevePrenom} à son arrêt habituel 🎒\n\n_${data.ecoleNom}_`

    case 'transport_retard':
      return `⚠️ *Retard bus — SmartSchool SN*\n\nBonjour ${data.parentNom},\n\nLe bus a un retard estimé de *${data.minutes} minutes*.\n\n${data.raison ? `Raison: ${data.raison}\n\n` : ''}Nous nous excusons pour la gêne occasionnée.\n\n_${data.ecoleNom}_`

    case 'custom':
    default:
      return String(data.message || '')
  }
}

export async function sendWhatsApp({ to, template, data }: WhatsAppParams): Promise<{ success: boolean; error?: string }> {
  const accountSid = process.env.TWILIO_ACCOUNT_SID
  const authToken = process.env.TWILIO_AUTH_TOKEN
  const fromNumber = process.env.TWILIO_WHATSAPP_FROM || 'whatsapp:+14155238886'

  if (!accountSid || !authToken || accountSid.includes('placeholder')) {
    console.log('[WhatsApp] Mode test — message non envoyé (Twilio non configuré)')
    console.log('[WhatsApp] Destinataire:', to)
    console.log('[WhatsApp] Message:', formatMessage(template, data))
    return { success: true } // ne pas bloquer si non configuré
  }

  try {
    // Import dynamique de twilio pour éviter les erreurs côté client
    const twilio = (await import('twilio')).default
    const client = twilio(accountSid, authToken)

    // Formater le numéro sénégalais
    let toFormatted = to.replace(/\s/g, '').replace(/^0/, '')
    if (!toFormatted.startsWith('+')) {
      toFormatted = '+221' + toFormatted
    }

    await client.messages.create({
      from: fromNumber,
      to: `whatsapp:${toFormatted}`,
      body: formatMessage(template, data),
    })

    return { success: true }
  } catch (err: any) {
    console.error('[WhatsApp] Erreur envoi:', err.message)
    return { success: false, error: err.message }
  }
}
